CREATE OR REPLACE VIEW role_rules_view AS
SELECT rr.role_id,
       rr.role_name,
       rf.function_id,
       rf.function_name,
       r.object,
       r.action,
       r.description AS rule_description
FROM rbac_roles rr
         JOIN rbac_role_functions rrf ON rr.role_id = rrf.role_id
         JOIN rbac_functions rf ON rrf.function_id = rf.function_id
         JOIN rbac_function_rules rfr ON rf.function_id = rfr.function_id
         JOIN rbac_rules r ON rfr.rule_id = r.rule_id
WHERE rr.tenant_id = rrf.tenant_id AND rf.tenant_id = rfr.tenant_id AND r.tenant_id = rfr.tenant_id;

