-- Products Table
CREATE TABLE IF NOT EXISTS financial_products (
                                        tenant_id TEXT NOT NULL,
                                        id TEXT NOT NULL PRIMARY KEY,
                                        product_type TEXT NOT NULL,
                                        product_code TEXT NOT NULL UNIQUE,
                                        product_name TEXT NOT NULL,
                                        model TEXT,
                                        model_portfolio TEXT,
                                        eligibility_criteria TEXT,
                                        regulatory_compliance TEXT,
                                        description TEXT,
                                        created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
                                        updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE INDEX IF NOT EXISTS idx_financial_products_tenant_id ON financial_products(tenant_id);
CREATE UNIQUE INDEX IF NOT EXISTS uq_financial_products_tenant_id_product_code ON financial_products(tenant_id, product_code);
CREATE UNIQUE INDEX IF NOT EXISTS uq_financial_products_tenant_id_product_name ON financial_products(tenant_id, product_name);

-- Accounts Table
CREATE TABLE IF NOT EXISTS financial_accounts (
                                        tenant_id TEXT NOT NULL,
                                        id TEXT NOT NULL PRIMARY KEY,
                                        account_number TEXT NOT NULL,
                                        open_date DATE NOT NULL,
                                        status TEXT NOT NULL,
                                        primary_owner_id TEXT NOT NULL,
                                        secondary_owner_id TEXT,
                                        beneficiary_id TEXT,
                                        product_id TEXT NOT NULL,
                                        closed_date DATE,
                                        tax_status TEXT,
                                        currency_code TEXT NOT NULL DEFAULT 'USD',
                                        account_notes TEXT,
                                        service_agreement_details JSONB DEFAULT '{}'::JSONB,
                                        created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
                                        updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
                                        FOREIGN KEY (primary_owner_id) REFERENCES clients(id) ON DELETE RESTRICT,
                                        FOREIGN KEY (secondary_owner_id) REFERENCES clients(id) ON DELETE SET NULL,
                                        FOREIGN KEY (beneficiary_id) REFERENCES clients(id) ON DELETE SET NULL,
                                        FOREIGN KEY (product_id) REFERENCES financial_products(id) ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS idx_financial_accounts_tenant_id ON financial_accounts(tenant_id);
