-- ╔═════ 20241031194446-client_org_members_view.sql ═════╗
ALTER TABLE clients ADD COLUMN is_primary BOOLEAN NOT NULL DEFAULT FALSE;
-- This view is used to get the info of members of a client organisation
CREATE OR REPLACE VIEW client_organisation_members_view AS
WITH client_addresses AS (
    SELECT 
        cav.client_id,
        jsonb_object_agg(
            cav.address_type,
            jsonb_build_object(
                'address_line1', cav.address_line1,
                'address_line2', cav.address_line2,
                'city', cav.city,
                'state', cav.state,
                'zipcode', cav.zipcode,
                'country', cav.country
            )
        ) AS addresses
    FROM client_addresses_view cav
    GROUP BY cav.client_id
)
SELECT 
    -- Person Information
    p.first_name,
    p.last_name,
    p.id as person_id,
    p.date_of_birth as birthdate,
    p.email,
    p.phone,
    
    -- Client Information
    c.id as client_id,
    c.role,
    c.organisation_id as client_organisation_id,
    c.is_primary,
    c.tenant_id,
    -- Address Information
    ca.addresses
FROM 
    clients c
    JOIN persons p ON c.person_id = p.id
    JOIN client_organisations co ON c.organisation_id = co.id
    LEFT JOIN client_addresses ca ON c.id = ca.client_id;

-- ╔═════ 20241101101639-document-table.sql ═════╗
CREATE TABLE IF NOT EXISTS document_catalog (
    id                        TEXT NOT NULL PRIMARY KEY, -- Unique identifier for each document
    tenant_id                TEXT NOT NULL,                              
    external_id              TEXT NOT NULL DEFAULT 'Unknown',                                       -- I would prefer to call this document number but for consistency
    document_type            TEXT NOT NULL,                              -- Document type (e.g., "bank_statement", "tax_return")
    document_subtype         TEXT,                                       -- Additional specificity (e.g., "2023 Tax Return")
    description              TEXT,                                       -- Detailed description of the document
    upload_date              TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP, -- When the document was uploaded
    deleted_at               TIMESTAMP WITH TIME ZONE,                   -- When the document was delete from the catalog
    s3_bucket_name           TEXT NOT NULL,                              -- S3 bucket name where the document is stored
    s3_object_key            TEXT NOT NULL,                              -- S3 object key (path) to locate the document
    file_name                TEXT,                                       -- Original name of the uploaded file
    file_type                TEXT,                                       -- File type or extension (e.g., "pdf", "jpg")
    retention_policy         TEXT,                                   -- Retention duration (e.g., '5 years')
    document_status          TEXT,                                   -- Status tracking for automation etc...
    approved_by              TEXT,                                   -- ID of the user or system that approved the document
    rejection_reason         TEXT,                                   -- Reason if the document is rejected
    access_level             TEXT,                                   -- Access level of the document
    additional_attributes    jsonb DEFAULT '{}'::jsonb,              -- JSONB to hold tags or custom metadata
    created_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS client_documents (
    client_id              TEXT NOT NULL,                
    document_catalog_id            TEXT NOT NULL,                    
    PRIMARY KEY (client_id, document_catalog_id),
    CONSTRAINT fk_client FOREIGN KEY (client_id) REFERENCES clients(id) ON DELETE CASCADE,
    CONSTRAINT fk_document FOREIGN KEY (document_catalog_id) REFERENCES document_catalog(id) ON DELETE CASCADE
);

CREATE TABLE IF NOT EXISTS agent_documents (
    agent_id               TEXT NOT NULL,                  
    document_catalog_id            TEXT NOT NULL,                  
    PRIMARY KEY (agent_id, document_catalog_id),
    CONSTRAINT fk_agent FOREIGN KEY (agent_id) REFERENCES agents(id) ON DELETE CASCADE,
    CONSTRAINT fk_document FOREIGN KEY (document_catalog_id) REFERENCES document_catalog(id) ON DELETE CASCADE
);

CREATE INDEX idx_document_catalog_tenant_id ON document_catalog (tenant_id);
CREATE INDEX idx_document_catalog_document_type ON document_catalog (document_type);
CREATE INDEX idx_document_catalog_upload_date ON document_catalog (upload_date);
CREATE INDEX idx_document_catalog_external_id ON document_catalog (external_id);

-- ╔═════ 20241101110158-service-agreement.sql ═════╗
CREATE TABLE IF NOT EXISTS advisor_repcodes (
    id       TEXT PRIMARY KEY,       
    tenant_id                TEXT NOT NULL,            
    advisor_id               TEXT NOT NULL,            
    repcode                  TEXT NOT NULL,            -- REPCODE associated with the advisor
    description              TEXT,                     -- Description of why this repcode is needed
    is_primary               BOOLEAN DEFAULT FALSE,    -- Indicates if this is the primary REPCODE
    created_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    
    -- Foreign key constraint
    CONSTRAINT fk_advisor FOREIGN KEY (advisor_id) REFERENCES agents(id) ON DELETE CASCADE,
    CONSTRAINT repcode_unique UNIQUE (repcode, tenant_id)
);



CREATE TABLE IF NOT EXISTS service_agreements (
    id     TEXT PRIMARY KEY,        
    tenant_id                TEXT NOT NULL,             
    advisor_id               TEXT NOT NULL,            
    client_id                TEXT NOT NULL,             
    account_id               TEXT NOT NULL,             
    product_id               TEXT NOT NULL,             
    repcode                  TEXT NOT NULL,             -- REPCODE associated with this agreement included as well as advisor_id
    start_date               DATE,
    end_date                 DATE,                      
    allocation_details       jsonb DEFAULT '{}'::jsonb, -- JSONB for flexible allocation details
    fee_details              jsonb DEFAULT '{}'::jsonb, -- JSONB for flexible fee structures
    agreement_details        jsonb DEFAULT '{}'::jsonb, -- JSONB for additional contractual agreement details (structured)
    additional_attributes    jsonb DEFAULT '{}'::jsonb, -- JSONB for additional attributes (key, value)
    created_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    updated_at               TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,
    
    -- Foreign key constraints
    CONSTRAINT fk_advisor FOREIGN KEY (advisor_id) REFERENCES agents(id) ON DELETE CASCADE,
    CONSTRAINT fk_client FOREIGN KEY (client_id) REFERENCES clients(id) ON DELETE CASCADE,
    CONSTRAINT fk_account FOREIGN KEY (account_id) REFERENCES financial_accounts(id) ON DELETE CASCADE,
    CONSTRAINT fk_product FOREIGN KEY (product_id) REFERENCES financial_products(id) ON DELETE CASCADE,
    CONSTRAINT fkey_repcode FOREIGN KEY (repcode, tenant_id) REFERENCES advisor_repcodes(repcode, tenant_id) ON DELETE CASCADE
);

