CREATE VIEW client_document_catalog_view AS
SELECT 
    c.id AS client_id,
    dc.id AS document_catalog_id,
    dc.tenant_id,
    dc.external_id,
    dc.document_type,
    dc.document_subtype,
    dc.description,
    dc.upload_date,
    dc.deleted_at,
    dc.s3_bucket_name,
    dc.s3_object_key,
    dc.file_name,
    dc.file_type,
    dc.retention_policy,
    dc.document_status,
    dc.approved_by,
    dc.rejection_reason,
    dc.access_level,
    dc.additional_attributes,
    dc.created_at AS document_created_at,
    dc.updated_at AS document_updated_at
FROM 
    document_catalog dc
JOIN 
    client_documents cd ON dc.id = cd.document_catalog_id
JOIN 
    clients c ON cd.client_id = c.id;

CREATE VIEW agent_document_catalog_view AS
SELECT 
    a.id AS agent_id,
    dc.id AS document_catalog_id,
    dc.tenant_id,
    dc.external_id,
    dc.document_type,
    dc.document_subtype,
    dc.description,
    dc.upload_date,
    dc.deleted_at,
    dc.s3_bucket_name,
    dc.s3_object_key,
    dc.file_name,
    dc.file_type,
    dc.retention_policy,
    dc.document_status,
    dc.approved_by,
    dc.rejection_reason,
    dc.access_level,
    dc.additional_attributes,
    dc.created_at AS document_created_at,
    dc.updated_at AS document_updated_at
FROM 
    document_catalog dc
JOIN 
    agent_documents ad ON dc.id = ad.document_catalog_id
JOIN 
    agents a ON ad.agent_id = a.id;


CREATE VIEW service_agreement_document_catalog_view AS
SELECT 
    sa.id AS service_agreement_id,
    dc.id AS document_catalog_id,
    dc.tenant_id,
    dc.external_id,
    dc.document_type,
    dc.document_subtype,
    dc.description,
    dc.upload_date,
    dc.deleted_at,
    dc.s3_bucket_name,
    dc.s3_object_key,
    dc.file_name,
    dc.file_type,
    dc.retention_policy,
    dc.document_status,
    dc.approved_by,
    dc.rejection_reason,
    dc.access_level,
    dc.additional_attributes,
    dc.created_at AS document_created_at,
