-- ╔═════ 20241108030940-upsert_client_agent_relationship_udf.sql ═════╗
CREATE OR REPLACE FUNCTION upsert_agent_client_organisation_relationship(
  tenant_id_param TEXT,
  client_external_id TEXT,
  agent_external_id TEXT,
  rel_type TEXT,
  description TEXT,
  created_at TIMESTAMP WITH TIME ZONE,
  updated_at TIMESTAMP WITH TIME ZONE
) RETURNS VOID AS $$
DECLARE
  v_client_id TEXT;
  v_agent_id TEXT;
BEGIN
  -- Check if client_organisation exists. Creates if no and updates if yes
  SELECT id INTO v_client_id
  FROM client_organisations as co
  WHERE co.tenant_id = tenant_id_param AND co.external_id = client_external_id;

  IF v_client_id IS NULL THEN
    -- Create a placeholder client_organisation
    INSERT INTO client_organisations (id, tenant_id, external_id, name, description)
    VALUES ('co_' || gen_random_uuid()::TEXT, tenant_id_param, client_external_id, 'Client Placeholder', 'Placeholder description.')
    RETURNING id INTO v_client_id;
  END IF;

  -- Check if agent exists. Creates if no and updates if yes
  SELECT id INTO v_agent_id
  FROM agents as a
  WHERE a.tenant_id = tenant_id_param AND a.external_id = agent_external_id;

  IF v_agent_id IS NULL THEN
    -- Create a placeholder agent
    INSERT INTO agents (id, tenant_id, external_id, organisation_id)
    VALUES ('ag_' || gen_random_uuid()::TEXT, tenant_id_param, agent_external_id, 'placeholder_organization-id')
    RETURNING id INTO v_agent_id;
  END IF;

  -- Create the relationship
  INSERT INTO agent_client_organisation_relationships (
    id, tenant_id, agent_id, client_organisation_id, relationship_type, description, created_at, updated_at
  )
  VALUES ('aco_' ||gen_random_uuid()::TEXT, tenant_id_param, v_agent_id, v_client_id, rel_type, description, created_at, updated_at)
  ON CONFLICT (tenant_id, client_organisation_id, relationship_type) DO UPDATE SET
    agent_id = CASE
        WHEN EXCLUDED.updated_at > agent_client_organisation_relationships.updated_at THEN EXCLUDED.agent_id
        ELSE agent_client_organisation_relationships.agent_id
    END,
    created_at = LEAST(EXCLUDED.created_at, agent_client_organisation_relationships.created_at),
    updated_at = GREATEST(EXCLUDED.updated_at, agent_client_organisation_relationships.updated_at);
END;
$$ LANGUAGE plpgsql;

