CREATE OR REPLACE FUNCTION upsert_person(
    id TEXT,
    tenant_id_param TEXT,
    external_id_param TEXT,
    title TEXT,
    first_name TEXT,
    middle_name TEXT,
    last_name TEXT,
    suffix TEXT,
    date_of_birth DATE,
    gender TEXT,
    email TEXT,
    phone TEXT,
    nationality TEXT,
    marital_status TEXT,
    ssn TEXT,
    preferred_contact_method TEXT,
    created_at TIMESTAMP WITH TIME ZONE,
    updated_at TIMESTAMP WITH TIME ZONE
) RETURNS VOID AS $$
BEGIN
    INSERT INTO persons (
        id,
        tenant_id,
        external_id,
        title,
        first_name,
        middle_name,
        last_name,
        suffix,
        date_of_birth,
        gender,
        email,
        phone,
        nationality,
        marital_status,
        ssn,
        preferred_contact_method,
        created_at,
        updated_at
    ) 
    VALUES(
        id,
        tenant_id_param,
        external_id_param,
        title,
        first_name,
        middle_name,
        last_name,
        suffix,
        date_of_birth,
        gender,
        email,
        phone,
        nationality,
        marital_status,
        ssn,
        preferred_contact_method,
        created_at,
        updated_at
    )
    ON CONFLICT (tenant_id, external_id) DO UPDATE SET
        title = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.title
            ELSE persons.title
        END,
        first_name = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.first_name
            ELSE persons.first_name
        END,
        middle_name = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.middle_name
            ELSE persons.middle_name
        END,
        last_name = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.last_name
            ELSE persons.last_name
        END,
        suffix = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.suffix
            ELSE persons.suffix
        END,
        date_of_birth = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.date_of_birth
            ELSE persons.date_of_birth
        END,
        gender = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.gender
            ELSE persons.gender
        END,
        email = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.email
            ELSE persons.email
        END,
        phone = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.phone
            ELSE persons.phone
        END,
        nationality = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.nationality
            ELSE persons.nationality
        END,
        marital_status = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.marital_status
            ELSE persons.marital_status
        END,
        ssn = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.ssn
            ELSE persons.ssn
        END,
        preferred_contact_method = CASE
            WHEN EXCLUDED.updated_at > persons.updated_at THEN EXCLUDED.preferred_contact_method
            ELSE persons.preferred_contact_method
        END,
        created_at = LEAST(EXCLUDED.created_at, persons.created_at),
        updated_at = GREATEST(EXCLUDED.updated_at, persons.updated_at);
END;
$$ LANGUAGE plpgsql;

