-- ╔═════ 20241115191831-meetings.sql ═════╗
CREATE TABLE IF NOT EXISTS meetings (
    id TEXT NOT NULL PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    initiating_agent_id TEXT NOT NULL,
    primary_client_id TEXT NOT NULL,
    client_organisation_id TEXT NOT NULL,
    subject TEXT NOT NULL,
    description TEXT,
    start_time TIMESTAMP WITH TIME ZONE NOT NULL,
    end_time TIMESTAMP WITH TIME ZONE NOT NULL,
    location TEXT,
    meeting_link TEXT,
    meeting_type TEXT NOT NULL,
    status TEXT NOT NULL DEFAULT 'scheduled',
    extra_properties JSONB NOT NULL DEFAULT '{}'::JSONB,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_initiating_agent FOREIGN KEY (initiating_agent_id) 
        REFERENCES agents(id) ON DELETE RESTRICT,
    CONSTRAINT fk_primary_client FOREIGN KEY (primary_client_id) 
        REFERENCES clients(id) ON DELETE RESTRICT,
    CONSTRAINT fk_client_organisation FOREIGN KEY (client_organisation_id) 
        REFERENCES client_organisations(id) ON DELETE CASCADE
);

CREATE TYPE attendee_type_enum AS ENUM ('agent', 'client');

CREATE TABLE IF NOT EXISTS meeting_attendees (
    meeting_id TEXT NOT NULL,
    attendee_type attendee_type_enum NOT NULL,
    attendee_id TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (meeting_id, attendee_type, attendee_id),
    CONSTRAINT fk_meeting FOREIGN KEY (meeting_id) 
        REFERENCES meetings(id) ON DELETE CASCADE
);

-- Table for managing meeting documents (many-to-many relationship)
CREATE TABLE IF NOT EXISTS meeting_documents (
    meeting_id TEXT NOT NULL,
    document_catalog_id TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    PRIMARY KEY (meeting_id, document_catalog_id),
    CONSTRAINT fk_meeting FOREIGN KEY (meeting_id) 
        REFERENCES meetings(id) ON DELETE CASCADE,
    CONSTRAINT fk_document FOREIGN KEY (document_catalog_id) 
        REFERENCES document_catalog(id) ON DELETE CASCADE
);

