-- ╔═════ 20241121001403-meetings_remove_client_org.sql ═════╗
-- First drop the view that depends on the column
DROP VIEW IF EXISTS agent_meetings;

-- Now we can drop the foreign key constraint
ALTER TABLE meetings DROP CONSTRAINT fk_client_organisation;

-- And drop the column
ALTER TABLE meetings DROP COLUMN client_organisation_id;

-- Finally recreate the view with the new structure
CREATE OR REPLACE VIEW agent_meetings AS
SELECT DISTINCT m.*,
    c.organisation_id as client_organisation_id,
    array_agg(DISTINCT jsonb_build_object(
        'type', ma.attendee_type,
        'id', ma.attendee_id,
        'first_name', p.first_name,
        'last_name', p.last_name
    )) FILTER (WHERE ma.attendee_id IS NOT NULL) as participants
FROM meetings m
JOIN clients c ON m.primary_client_id = c.id
LEFT JOIN meeting_attendees ma ON m.id = ma.meeting_id
LEFT JOIN (
    SELECT c.id as entity_id, p.first_name, p.last_name 
    FROM clients c 
    JOIN persons p ON c.person_id = p.id
    UNION
    SELECT a.id as entity_id, p.first_name, p.last_name 
    FROM agents a 
    JOIN persons p ON a.person_id = p.id
) p ON ma.attendee_id = p.entity_id
GROUP BY m.id, m.tenant_id, m.initiating_agent_id, m.primary_client_id, 
    m.subject, m.description, m.start_time, m.end_time, m.location, 
    m.meeting_link, m.meeting_type, m.status, m.extra_properties, 
    m.created_at, m.updated_at, c.organisation_id;

