-- ╔═════ 20241122194310-meeting-udf.sql ═════╗
ALTER TABLE clients ALTER COLUMN organisation_id DROP NOT NULL;
ALTER TABLE clients ALTER COLUMN person_id DROP NOT NULL;
ALTER TABLE agents ALTER COLUMN organisation_id DROP NOT NULL;
