CREATE OR REPLACE FUNCTION upsert_meeting(
    id TEXT,
    tenant_id_param TEXT,
    external_id_param TEXT,
    initiating_agent_external_id TEXT,
    primary_client_external_id TEXT,
    subject TEXT,
    description TEXT,
    start_time TIMESTAMP WITH TIME ZONE,
    end_time TIMESTAMP WITH TIME ZONE,
    location TEXT,
    meeting_link TEXT,
    meeting_type TEXT,
    status TEXT,
    extra_properties JSONB,
    created_at TIMESTAMP WITH TIME ZONE,
    updated_at TIMESTAMP WITH TIME ZONE
) RETURNS VOID AS $$
DECLARE
    v_initiating_agent_id TEXT;
    v_primary_client_id TEXT;
BEGIN
    -- Check if initiating agent exists by external_id, create placeholder if not
    SELECT id INTO v_initiating_agent_id
    FROM agents
    WHERE tenant_id = tenant_id_param AND external_id = initiating_agent_external_id;

    IF v_initiating_agent_id IS NULL THEN
        INSERT INTO agents (id, tenant_id, external_id)
        VALUES ('ag_' || gen_random_uuid()::TEXT, tenant_id_param, initiating_agent_external_id)
        RETURNING id INTO v_initiating_agent_id;
    END IF;

    -- Check if primary client exists by external_id, create placeholder if not
    SELECT id INTO v_primary_client_id
    FROM clients
    WHERE tenant_id = tenant_id_param AND external_id = primary_client_external_id;

    IF v_primary_client_id IS NULL THEN
        INSERT INTO clients (id, tenant_id, external_id)
        VALUES ('cl_' || gen_random_uuid()::TEXT, tenant_id_param, primary_client_external_id)
        RETURNING id INTO v_primary_client_id;
    END IF;

    INSERT INTO meetings (
        id,
        tenant_id,
        external_id,
        initiating_agent_id,
        primary_client_id,
        subject,
        description,
        start_time,
        end_time,
        location,
        meeting_link,
        meeting_type,
        status,
        extra_properties,
        created_at,
        updated_at
    ) 
    VALUES (
        id,
        tenant_id_param,
        external_id_param,
        v_initiating_agent_id,
        v_primary_client_id,
        subject,
        description,
        start_time,
        end_time,
        location,
        meeting_link,
        meeting_type,
        COALESCE(status, 'scheduled'),
        COALESCE(extra_properties, '{}'::JSONB),
        created_at,
        updated_at
    )
    ON CONFLICT (tenant_id, external_id) DO UPDATE SET
        initiating_agent_id = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.initiating_agent_id
            ELSE meetings.initiating_agent_id
        END,
        primary_client_id = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.primary_client_id
            ELSE meetings.primary_client_id
        END,
        subject = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.subject
            ELSE meetings.subject
        END,
        description = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.description
            ELSE meetings.description
        END,
        start_time = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.start_time
            ELSE meetings.start_time
        END,
        end_time = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.end_time
            ELSE meetings.end_time
        END,
        location = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.location
            ELSE meetings.location
        END,
        meeting_link = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.meeting_link
            ELSE meetings.meeting_link
        END,
        meeting_type = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.meeting_type
            ELSE meetings.meeting_type
        END,
        status = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.status
            ELSE meetings.status
        END,
        extra_properties = CASE
            WHEN EXCLUDED.updated_at > meetings.updated_at THEN EXCLUDED.extra_properties
            ELSE meetings.extra_properties
        END,
        created_at = LEAST(EXCLUDED.created_at, meetings.created_at),
        updated_at = GREATEST(EXCLUDED.updated_at, meetings.updated_at);
END;
$$ LANGUAGE plpgsql;

