-- ╔═════ 20250108174916-business_group.sql ═════╗
CREATE TABLE IF NOT EXISTS business_group (
    id TEXT PRIMARY KEY NOT NULL,
    external_id TEXT,
    tenant_id TEXT NOT NULL,
    name TEXT NOT NULL,                                 -- Business group name
    group_type TEXT NOT NULL,                           -- Type of grouping (e.g., Region, Sector, Division)
    status TEXT,                                        -- Status of the group (e.g., Active, Inactive)
    description TEXT,                                   -- Freeform description of the group
    additional_attributes jsonb DEFAULT '{}'::jsonb,    -- Ability to add extra fields to the group
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,   -- Timestamp for record creation
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP    -- Timestamp for record updates
);

ALTER TABLE client_organisations
ADD COLUMN business_group_id TEXT,
ADD COLUMN office_id TEXT;

CREATE TABLE IF NOT EXISTS agent_business_group_relationships
(
    id TEXT PRIMARY KEY NOT NULL,                 -- Unique identifier for the relationship
    tenant_id TEXT NOT NULL,                     -- Tenant identifier for multi-tenancy
    agent_id TEXT NOT NULL,                       -- Foreign key to the agent
    business_group_id TEXT NOT NULL,                -- Foreign key to the business_group
    role TEXT NOT NULL,                             -- Role of the agent in the business group
    description TEXT,                                   -- Optional description of the relationship
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP, -- Timestamp for record creation
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP -- Timestamp for record updates
);

CREATE TABLE IF NOT EXISTS office (
    id TEXT PRIMARY KEY NOT NULL,                 -- Unique identifier for the office
    external_id TEXT,                             -- External identifier for the office
    tenant_id TEXT NOT NULL,                      -- Tenant identifier for multi-tenancy
    name TEXT NOT NULL,                           -- Office name
    division TEXT,                                -- Division associated with the office
    market TEXT,                                  -- Market associated with the office
    office_type TEXT,                             -- Type of office (e.g., Primary, Branch)
    status TEXT,                                  -- Status of the office (e.g., Active, Inactive)
    description TEXT,                             -- Optional description of the office
    additional_attributes jsonb DEFAULT '{}'::jsonb, -- Additional attributes for flexibility
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP, -- Timestamp for record creation
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP  -- Timestamp for record updates
);

CREATE TABLE IF NOT EXISTS agent_office_relationships (
    id TEXT PRIMARY KEY NOT NULL,                 -- Unique identifier for the relationship
    tenant_id TEXT NOT NULL,                      -- Tenant identifier for multi-tenancy
    agent_id TEXT NOT NULL,                       -- Foreign key to the agent
    office_id TEXT NOT NULL,                      -- Foreign key to the office
    role TEXT NOT NULL,                           -- Role of the agent in the office (e.g., Manager, Staff)
    description TEXT,                             -- Optional description of the relationship
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP, -- Timestamp for record creation
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP  -- Timestamp for record updates
);

ALTER TABLE contact_details
ADD COLUMN business_group_id TEXT,   -- Adds a column to associate contacts with a business group
ADD COLUMN office_id TEXT;           -- Adds a column to associate contacts with an office

ALTER TABLE address_entity_relationships
ADD COLUMN business_group_id TEXT,   -- Adds a column to associate addresses with a business group
ADD COLUMN office_id TEXT;           -- Adds a column to associate addresses with an office

CREATE OR REPLACE VIEW business_group_addresses_view AS
SELECT aer.id AS relationship_id,
       aer.business_group_id,
       aer.address_type,
       aer.description,
       aer.created_at AS relationship_created_at,
       aer.updated_at AS relationship_updated_at,
       a.id AS address_id,
       a.tenant_id,
       a.address_line1,
       a.address_line2,
       a.city,
       a.state,
       a.zipcode,
       a.country,
       a.created_at AS address_created_at,
       a.updated_at AS address_updated_at
FROM address_entity_relationships aer
         JOIN addresses a ON aer.address_id = a.id
WHERE aer.business_group_id IS NOT NULL;

CREATE OR REPLACE VIEW office_addresses_view AS
SELECT aer.id AS relationship_id,
       aer.office_id,
       aer.address_type,
       aer.description,
       aer.created_at AS relationship_created_at,
       aer.updated_at AS relationship_updated_at,
       a.id AS address_id,
       a.tenant_id,
       a.address_line1,
       a.address_line2,
       a.city,
       a.state,
       a.zipcode,
       a.country,
       a.created_at AS address_created_at,
       a.updated_at AS address_updated_at
FROM address_entity_relationships aer
         JOIN addresses a ON aer.address_id = a.id
WHERE aer.office_id IS NOT NULL;

