-- ╔═════ 20250115170743-rel_dashboard_view_with_office_and_region.sql ═════╗
DROP VIEW IF EXISTS relationships_dashboard_view;
CREATE OR REPLACE VIEW relationships_dashboard_view AS
WITH client_addresses_agg AS (
    SELECT coav.client_organisation_id,
           jsonb_object_agg(coav.address_type, jsonb_build_object('state', coav.state, 'city', coav.city)) AS addresses
    FROM client_organisation_addresses_view coav
    GROUP BY coav.client_organisation_id
), 
client_agents_agg AS (
    SELECT acor.client_organisation_id,
           jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS agents
    FROM agent_client_organisation_relationships acor
    JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
    GROUP BY acor.client_organisation_id
),
business_group_agg AS (
    SELECT bg.id,
           bg.name AS region
    FROM business_groups bg
),
office AS (
    SELECT of.id,
           of.name AS office
    FROM agent_organisations of
)
SELECT 
    co.tenant_id,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    cadd.addresses,
    cag.agents,
    bg_agg.region,
    of.office
FROM client_organisations co
LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
LEFT JOIN client_addresses_agg cadd ON co.id = cadd.client_organisation_id
LEFT JOIN client_agents_agg cag ON co.id = cag.client_organisation_id
LEFT JOIN business_group_agg bg_agg ON co.business_group_id = bg_agg.id
LEFT JOIN office of ON co.office_id = of.id;

