-- ╔═════ 20250117130829-agent_view.sql ═════╗
CREATE OR REPLACE VIEW agent_view AS
SELECT a.id AS agent_id,
    a.tenant_id,
    a.external_id,
    a.organisation_id,
    a.license,
    a.compliance_record,
    a.qualification,
    a.specialization,
    a.advisor_identification,
    a.years_of_experience,
    a.regulatory_status,
    a.type,
    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    a.additional_attributes,
    COALESCE(
        (
            SELECT jsonb_object_agg(aor.role, of.name)
            FROM agent_office_relationships aor
            JOIN office of ON aor.office_id = of.id
            WHERE aor.agent_id = a.id
        ),
        '{}'::jsonb
    ) AS offices,
    COALESCE(
        (
            SELECT jsonb_object_agg(abr.role, bg.name)
            FROM agent_business_group_relationships abr
            JOIN business_groups bg ON abr.business_group_id = bg.id
            WHERE abr.agent_id = a.id
        ),
        '{}'::jsonb
    ) AS regions
FROM agents a
    JOIN persons p ON a.person_id = p.id;

