    p.first_name AS person_first_name,
    p.last_name AS person_last_name,
    co.name AS client_organisation_name,
    cor.role AS role,
    cor.description AS description,
    cor.extra_properties AS extra_properties,
    cor.created_at AS created_at,
    cor.updated_at AS updated_at
FROM client_organisation_relationships cor
JOIN clients c
    ON cor.client_id = c.id
    AND cor.tenant_id = c.tenant_id
LEFT JOIN persons p
    ON c.person_id = p.id
JOIN client_organisations co
    ON cor.client_organisation_id = co.id
    AND cor.tenant_id = co.tenant_id;

