CREATE TYPE blueprint_version_status AS ENUM ('draft', 'published', 'historical', 'archived');

CREATE TABLE IF NOT EXISTS action_blueprint_versions (
    id TEXT PRIMARY KEY,
    tenant_ID TEXT NOT NULL,
    blueprint_id TEXT NOT NULL,
    parent_version_id TEXT,
    version_number TEXT NOT NULL,
    version_notes TEXT NOT NULL,
    status blueprint_version_status NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    deleted_at TIMESTAMP WITH TIME ZONE,
    FOREIGN KEY (blueprint_id) REFERENCES action_blueprints(id) ON DELETE CASCADE,
    FOREIGN KEY (parent_version_id) REFERENCES action_blueprint_versions(id),
    UNIQUE (tenant_id, blueprint_id, version_number)
);

-- Enforce that there is only one published version per blueprint
CREATE UNIQUE INDEX idx_one_published_version
ON action_blueprint_versions (tenant_ID, blueprint_id)
WHERE status = 'published';

ALTER TABLE action_blueprint_components ADD COLUMN blueprint_version_id TEXT;
