ALTER TABLE action_runs ADD COLUMN blueprint_version_id TEXT;
ALTER TABLE action_runs ADD FOREIGN KEY (blueprint_version_id) REFERENCES action_blueprint_versions(id);

-- Create a dummy version for each existing blueprint
INSERT INTO action_blueprint_versions 
    (id, tenant_id, blueprint_id, version_number, version_notes, status, created_at, updated_at)
SELECT
    gen_random_uuid()::TEXT,
    action_blueprints.tenant_id,
    action_blueprints.id,
    'v1.0.0-migrated',
    'Initial version created via automated migration',
    'draft',
    CURRENT_TIMESTAMP,
    CURRENT_TIMESTAMP
FROM action_blueprints;

UPDATE action_blueprint_components abc
SET blueprint_version_id = abv.id
FROM action_blueprint_versions abv
WHERE abc.action_blueprint_id = abv.blueprint_id
AND abc.tenant_id = abv.tenant_id;

UPDATE action_runs ar
SET blueprint_version_id = abv.id
FROM action_blueprint_versions abv
WHERE ar.action_id = abv.blueprint_id
AND ar.tenant_id = abv.tenant_id;

