-- ╔═════ 20250314115326-update_client_org_financial_accounts_view.sql ═════╗
DROP VIEW client_organisation_financial_accounts_view;

CREATE VIEW client_organisation_financial_accounts_view AS
SELECT
    fa.id AS account_id,
    fa.account_number,
    fa.open_date,
    fa.status,
    fa.tax_status,
    fa.currency_code,
    fa.account_notes,
    fa.closed_date,
    fa.additional_attributes,
    fa.created_at AS account_created_at,
    fa.updated_at AS account_updated_at,
    c_org.id AS client_organisation_id,
    c_org.name AS client_organisation_name,
    c_org.client_organisation_type,
    c_org.client_organisation_role,
    c_org.description AS client_organisation_description,
    c_org.relationship_status,
    c.id AS primary_owner_id,
    p.first_name AS primary_owner_first_name,
    p.last_name AS primary_owner_last_name,
    sec_owner.id AS secondary_owner_id,
    sec_person.first_name AS secondary_owner_first_name,
    sec_person.last_name AS secondary_owner_last_name,
    beneficiary.id AS beneficiary_id,
    ben_person.first_name AS beneficiary_first_name,
    ben_person.last_name AS beneficiary_last_name,
    prod.product_name AS product_name,
    prod.product_type AS product_type,
    prod.model AS product_model,
    prod.model_portfolio AS model_portfolio
FROM
    public.financial_accounts fa
        JOIN
    public.clients c ON fa.primary_owner_id = c.id
        JOIN
    public.persons p ON c.person_id = p.id
        JOIN
    public.client_organisations c_org ON c.organisation_id = c_org.id
        LEFT JOIN
    public.clients sec_owner ON fa.secondary_owner_id = sec_owner.id
        LEFT JOIN
    public.persons sec_person ON sec_owner.person_id = sec_person.id
        LEFT JOIN
    public.clients beneficiary ON fa.beneficiary_id = beneficiary.id
        LEFT JOIN
    public.persons ben_person ON beneficiary.person_id = ben_person.id
        JOIN
    public.financial_products prod ON fa.product_id = prod.id;

