    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    a.additional_attributes,
    a.external_id,
    (SELECT COALESCE(jsonb_object_agg(
      cd.role, 
      jsonb_build_object(
        'id', cd.id,
        'type', cd.type,
        'value', cd.value
      )
    ), '{}'::jsonb) FROM contact_details cd WHERE cd.agent_id = a.id) AS contacts
   FROM agents a
     JOIN persons p ON a.person_id = p.id;

CREATE VIEW client_agent_view
 AS
 SELECT c.id AS client_id,
    a.tenant_id,
    a.organisation_id AS agent_organisation_id,
    c.organisation_id AS client_organisation_id,
    a.type,
    a.agent_id,
    a.title,
    a.first_name,
    a.last_name,
    a.suffix,
    acor.relationship_type
   FROM clients c
     JOIN client_organisations co ON c.organisation_id = co.id
     JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id
     JOIN agent_person_view a ON acor.agent_id = a.agent_id;

CREATE VIEW client_organisation_agents_view
 AS
 SELECT a.tenant_id,
    a.organisation_id AS agent_organisation_id,
    co.id AS client_organisation_id,
    a.type,
    a.agent_id,
    a.title,
    a.first_name,
    a.last_name,
    a.suffix,
    acor.relationship_type
   FROM client_organisations co
     JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id
     JOIN agent_person_view a ON acor.agent_id = a.agent_id;

CREATE VIEW agent_business_group_roles AS
SELECT
    abgr.tenant_id,
    abgr.agent_id,
    apv.external_id AS agent_external_id,
    apv.first_name,
    apv.last_name,
    bg.id AS business_group_id,
    bg.name AS business_group_name,
    bg.group_type AS business_group_type,
    bg.status AS business_group_status,
    abgr.role AS agent_role,
    abgr.description AS relationship_description,
    abgr.created_at AS relationship_created_at,
    abgr.updated_at AS relationship_updated_at
FROM
    agent_business_group_relationships abgr
JOIN
    business_groups bg
    ON abgr.business_group_id = bg.id
JOIN
    agent_person_view apv
    ON abgr.agent_id = apv.agent_id;

