    co1.name AS initiating_client_organisation_name,
    cn.participating_entity_type,
    co2.id AS participating_client_organisation_id,
    co2.name AS participating_client_organisation_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value
FROM connections cn
LEFT JOIN client_organisations co1 
    ON cn.initiating_entity_id = co1.id
LEFT JOIN client_organisations co2 
    ON cn.participating_entity_id = co2.id
LEFT JOIN lookups l 
    ON cn.relationship_type = l.id
WHERE cn.initiating_entity_type = 'client_organisation'
  AND cn.participating_entity_type = 'client_organisation';

