-- ╔═════ 20250425090832-rmd-view.sql ═════╗
DROP VIEW IF EXISTS rmd_view;

CREATE OR REPLACE VIEW rmd_view AS
SELECT 
    rmd.id,
    rmd.tenant_id,
    rmd.external_id,
    rmd.financial_account_id,
    rmd.client_organization_id,
    rmd.assigned_to_id,
    rmd.client_id,
    rmd.rmd_year,
    rmd.prior_year_end_balance,
    rmd.life_expectancy_factor,
    rmd.required_amount,
    rmd.ytd_distributions,
    rmd.remaining_amount,
    rmd.distribution_source,
    rmd.federal_withholding_pct,
    rmd.state_withholding_pct,
    rmd.first_year,
    rmd.ten_year_required,
    rmd.status,
    rmd.next_step_date,
    rmd.details,
    rmd.created_at,
    rmd.updated_at,
    rmd.extra_properties,
    fa.account_number AS financial_account_number,
    fa.name AS financial_account_name,
    fa.status AS financial_account_status,
    co.name AS client_organisation_name,
    co.relationship_status AS client_organisation_status,
    co.client_organisation_type,
    co.relationship_status,
    CASE
        WHEN apv.first_name IS NOT NULL THEN apv.first_name
        ELSE NULL
    END AS assigned_agent_first_name,
    CASE
        WHEN apv.last_name IS NOT NULL THEN apv.last_name
        ELSE NULL
    END AS assigned_agent_last_name,
    CASE
        WHEN cpv.first_name IS NOT NULL THEN cpv.first_name
        ELSE NULL
    END AS client_first_name,
    CASE
        WHEN cpv.last_name IS NOT NULL THEN cpv.last_name
        ELSE NULL
    END AS client_last_name
FROM 
    required_minimum_distributions rmd
LEFT JOIN 
    financial_accounts fa ON rmd.financial_account_id = fa.id
LEFT JOIN 
    client_organisations co ON rmd.client_organization_id = co.id
LEFT JOIN 
    agent_person_view apv ON rmd.assigned_to_id = apv.agent_id
LEFT JOIN 
    client_person_view cpv ON rmd.client_id = cpv.client_id;

