    tax_filing_type             TEXT,
    tax_return_type             TEXT,
    filing_status               TEXT,
    tax_return_status           TEXT,
    tax_service_type_1040       TEXT,
    complexity_type             TEXT,
    tax_professional_category   TEXT,
    filing_method               TEXT,
    e_file_status               TEXT,
    extension_filed             BOOLEAN,
    amended_return              BOOLEAN,
    final_year                  BOOLEAN,
    tax_services_final_year     BOOLEAN,
    organizer_sent              BOOLEAN,
    advisor_review_needed       BOOLEAN,
    filing_due_date             DATE,
    date_filed                  TIMESTAMPTZ,
    return_completion_date      DATE,
    document_due_date           DATE,
    document_received_date      DATE,
    e_file_authorization_date   DATE,
    e_file_status_date          DATE,
    organizer_sent_date         DATE,
    adjusted_gross_income       NUMERIC(18,2),
    agi                         NUMERIC(18,2),
    deductions                  NUMERIC(18,2),
    credits                     NUMERIC(18,2),
    charitable_donations        NUMERIC(18,2),
    tax_liability               NUMERIC(18,2),
    prepaid_taxes               NUMERIC(18,2),
    safe_harbor                 NUMERIC(18,2),
    gifting                     NUMERIC(18,2),
    reported_income             NUMERIC(18,2),
    effective_tax_rate          NUMERIC(5,2),
    marginal_tax_rate           NUMERIC(5,2),
    tax_fee                     NUMERIC(10,2),
    payment_method              TEXT,
    invoicing_method            TEXT,
    service_offering            TEXT,
    signature_preference        TEXT,
    completion_window           TEXT,
    created_at                  TIMESTAMPTZ NOT NULL DEFAULT now(),
