CREATE OR REPLACE VIEW public.tax_filings_view AS
SELECT
    tf.*,
    co.name  AS client_organisation_name,
    pas.first_name AS associate_first_name,
    pas.last_name AS associate_last_name,
    pman.first_name AS manager_first_name,
    pman.last_name AS manager_last_name,
    psup.first_name AS support_specialist_first_name,
    psup.last_name AS support_specialist_last_name
FROM        public.tax_filings            tf
LEFT JOIN   public.client_organisations   co
           ON co.id        = tf.client_organisation_id
          AND co.tenant_id = tf.tenant_id
LEFT JOIN   public.agents                 a_as
           ON a_as.id       = tf.tax_associate_id
          AND a_as.tenant_id = tf.tenant_id
LEFT JOIN   public.persons                pas
           ON pas.id       = a_as.person_id
LEFT JOIN   public.agents                 a_man
           ON a_man.id      = tf.tax_manager_id
          AND a_man.tenant_id = tf.tenant_id
LEFT JOIN   public.persons                pman
           ON pman.id      = a_man.person_id
LEFT JOIN   public.agents                 a_sup
           ON a_sup.id      = tf.tax_support_specialist_id
          AND a_sup.tenant_id = tf.tenant_id
LEFT JOIN   public.persons                psup
           ON psup.id      = a_sup.person_id;

-- ╔═════ 20250501130751-add_record_type_to_meetings.sql ═════╗
ALTER TABLE meetings ADD COLUMN record_type TEXT;

-- ╔═════ 20250501134041-add_record_type_to_agent_meetings_view.sql ═════╗
CREATE OR REPLACE VIEW agent_meetings AS  
SELECT DISTINCT m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    c.organisation_id AS client_organisation_id,
    array_agg(DISTINCT jsonb_build_object('type', ma.attendee_type, 'id', ma.attendee_id, 'first_name', p.first_name, 'last_name', p.last_name)) FILTER (WHERE ma.attendee_id IS NOT NULL) AS participants,
	m.record_type
   FROM meetings m
     JOIN clients c ON m.primary_client_id = c.id
     LEFT JOIN meeting_attendees ma ON m.id = ma.meeting_id
     LEFT JOIN ( SELECT c_1.id AS entity_id,
            p_1.first_name,
            p_1.last_name
           FROM clients c_1
             JOIN persons p_1 ON c_1.person_id = p_1.id
        UNION
         SELECT a.id AS entity_id,
            p_1.first_name,
            p_1.last_name
           FROM agents a
             JOIN persons p_1 ON a.person_id = p_1.id) p ON ma.attendee_id = p.entity_id
		
  GROUP BY m.id, m.tenant_id, m.initiating_agent_id, m.primary_client_id, m.subject, m.description, m.start_time, m.end_time, m.location, m.meeting_link, m.meeting_type, m.status, m.extra_properties, m.record_type, m.created_at, m.updated_at, c.organisation_id;

