    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    c.organisation_id AS client_organisation_id,
    co.name AS client_organisation_name,
    array_agg(
        DISTINCT jsonb_build_object(
            'type', ma.attendee_type,
            'id', ma.attendee_id,
            'title', p.title,
            'first_name', p.first_name,
            'middle_name', p.middle_name,
            'last_name', p.last_name
        )
    ) FILTER (WHERE ma.attendee_id IS NOT NULL) AS participants,
    m.record_type
FROM meetings m
JOIN clients c ON m.primary_client_id = c.id
JOIN client_organisations co ON c.organisation_id = co.id
LEFT JOIN meeting_attendees ma ON m.id = ma.meeting_id
LEFT JOIN (
    SELECT
        c1.id AS entity_id,
        p1.title,
        p1.first_name,
        p1.middle_name,
        p1.last_name
    FROM clients c1
    JOIN persons p1 ON c1.person_id = p1.id
    UNION
    SELECT
        a.id AS entity_id,
        p2.title,
        p2.first_name,
        p2.middle_name,
        p2.last_name
    FROM agents a
    JOIN persons p2 ON a.person_id = p2.id
) p ON ma.attendee_id = p.entity_id
GROUP BY
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.record_type,
    m.created_at,
    m.updated_at,
    c.organisation_id,
    co.name;

