ALTER TABLE client_organisations ADD COLUMN client_segmentation TEXT;


CREATE OR REPLACE VIEW public.client_person_view AS
SELECT
    c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    c.investment_goal,
    c.assets,
    c.compliance_record,
    c.documentation,
    c.role,
    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    c.employment_status,
    c.drivers_license_number,
    c.expected_retirement_age,
    c.maiden_name,
    c.occupation,
    c.preferred_name,
    c.retired,
    c.current_employer,
    c.retirement_date,
    c.wedding_anniversary,
    c.personal_interests,
    c.officer_or_director,
    c.security_restrictions,
    c.marketing_salutation,
    c.additional_attributes,
    COALESCE(addr.addresses, '[]'::jsonb) AS addresses,
    COALESCE(cd.contacts, '[]'::jsonb) AS contacts,
    c.external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation
FROM
    clients c
    JOIN persons p ON p.id = c.person_id
    LEFT JOIN LATERAL (
        SELECT jsonb_agg(
            jsonb_build_object(
                'address_type', aer.address_type,
                'description', aer.description,
                'address_line1', a.address_line1,
                'address_line2', a.address_line2,
                'city', a.city,
                'state', a.state,
                'zipcode', a.zipcode,
                'country', a.country
            )
        ) AS addresses
        FROM address_entity_relationships aer
        JOIN addresses a ON a.id = aer.address_id
        WHERE aer.client_id = c.id
    ) addr ON true
    LEFT JOIN LATERAL (
        SELECT jsonb_agg(
            jsonb_build_object(
                'type', cd_1.type,
                'role', cd_1.role,
                'value', cd_1.value
            )
        ) AS contacts
        FROM contact_details cd_1
        WHERE cd_1.client_id = c.id
    ) cd ON true
    LEFT JOIN client_organisations co ON c.organisation_id = co.id;

