DROP VIEW IF EXISTS rmd_view;
CREATE VIEW rmd_view AS
SELECT 
    rmd.id,
    rmd.tenant_id,
    rmd.external_id,
    rmd.financial_account_id,
    rmd.client_organization_id,
    rmd.assigned_to_id,
    rmd.client_id,
    rmd.rmd_year,
    rmd.prior_year_end_balance,
    rmd.life_expectancy_factor,
    rmd.required_amount,
    rmd.ytd_distributions,
    rmd.remaining_amount,
    rmd.distribution_source,
    rmd.federal_withholding_pct,
    rmd.state_withholding_pct,
    rmd.first_year,
    rmd.ten_year_required,
    rmd.status,
    rmd.next_step_date,
    rmd.details,
    rmd.created_at,
    rmd.updated_at,
    rmd.extra_properties,
    fa.external_id as financial_account_external_id,
    fa.account_number AS financial_account_number,
    fa.name AS financial_account_name,
    fa.status AS financial_account_status,
    co.name AS client_organisation_name,
    co.relationship_status AS client_organisation_status,
    co.client_organisation_type,
    co.relationship_status,
        CASE
            WHEN apv.first_name IS NOT NULL THEN apv.first_name
            ELSE NULL::text
        END AS assigned_agent_first_name,
        CASE
            WHEN apv.last_name IS NOT NULL THEN apv.last_name
            ELSE NULL::text
        END AS assigned_agent_last_name,
        CASE
            WHEN cpv.first_name IS NOT NULL THEN cpv.first_name
            ELSE NULL::text
        END AS client_first_name,
        CASE
            WHEN cpv.last_name IS NOT NULL THEN cpv.last_name
            ELSE NULL::text
        END AS client_last_name,
    rmd.outside_account_number
   FROM required_minimum_distributions rmd
     LEFT JOIN financial_accounts fa ON rmd.financial_account_id = fa.id
     LEFT JOIN client_organisations co ON rmd.client_organization_id = co.id
     LEFT JOIN agent_person_view apv ON rmd.assigned_to_id = apv.agent_id
     LEFT JOIN client_person_view cpv ON rmd.client_id = cpv.client_id;

-- ╔═════ 20250508160422-agent_meetings_optimistaion.sql ═════╗
-- First, let's create indexes to support the query optimization
CREATE INDEX IF NOT EXISTS meetings_tenant_initiating_agent_time_idx 
ON meetings(tenant_id, initiating_agent_id, start_time, end_time);

CREATE INDEX IF NOT EXISTS meeting_attendees_meeting_id_idx
ON meeting_attendees(meeting_id, attendee_id);

-- Drop the existing view
DROP VIEW IF EXISTS agent_meetings;

-- Create optimized view
CREATE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id
                
                UNION ALL
                
                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;


CREATE INDEX IF NOT EXISTS meetings_tenant_start_time_idx
ON meetings(tenant_id, start_time);

CREATE INDEX IF NOT EXISTS meeting_attendees_attendee_id_meeting_id_idx
ON meeting_attendees(attendee_id, meeting_id);

