-- ╔═════ 20250515151543-include_team_in_enriched_action_list_view.sql ═════╗
DROP VIEW IF EXISTS enriched_action_runs;

CREATE OR REPLACE VIEW enriched_action_runs AS
WITH client_agents_agg AS (
    SELECT acor.client_organisation_id,
           jsonb_object_agg(acor.relationship_type, jsonb_build_object(
               'agent_id', ap.agent_id, 
               'first_name', ap.first_name, 
               'last_name', ap.last_name
           )) AS agents
    FROM agent_client_organisation_relationships acor
    JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
    GROUP BY acor.client_organisation_id
)
SELECT
    ar.id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    ab.name AS blueprint_name,
    ab.category AS blueprint_category,
    cag.agents
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
    LEFT JOIN action_blueprints ab ON ab.id = ar.action_id
    LEFT JOIN client_agents_agg cag ON co.id = cag.client_organisation_id;

