-- ╔═════ 20250519233902-add_slug_trigger.sql ═════╗
ALTER TABLE action_runs ADD COLUMN slug TEXT;
CREATE FUNCTION make_slug_seq() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
begin
  -- We hash the tenant id to ensure that its a valid identifier for a sequence
  execute format('CREATE SEQUENCE IF NOT EXISTS slug_seq_for_tenant_%s', md5(NEW.tenant_id));
  return NEW;
end
$$;
CREATE TRIGGER make_slug_seq_trigger AFTER INSERT ON action_blueprints FOR EACH ROW EXECUTE PROCEDURE make_slug_seq();
