       ON mgr_p.id         = mgr_a.person_id

-- Tax_Assistant
LEFT JOIN agent_client_organisation_relationships acr_asst
       ON acr_asst.client_organisation_id = tf.client_organisation_id
      AND acr_asst.tenant_id             = tf.tenant_id
      AND acr_asst.relationship_type     = 'Tax Assistant'
LEFT JOIN agents asst_a
       ON asst_a.id        = acr_asst.agent_id
      AND asst_a.tenant_id  = tf.tenant_id
LEFT JOIN persons asst_p
       ON asst_p.id        = asst_a.person_id;

-- ╔═════ 20250521153152-add_meeting_extra_props_to_view.sql ═════╗
CREATE OR REPLACE VIEW agent_meetings AS  SELECT m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    ( SELECT COALESCE(array_agg(DISTINCT jsonb_build_object(
        'type', ma.attendee_type, 
        'id', ma.attendee_id, 
        'title', p.title, 
        'first_name', p.first_name, 
        'middle_name', p.middle_name, 
        'last_name', p.last_name,
        'external_id', p.external_id,
        'extra_properties', ma.extra_properties
    )) FILTER (WHERE ma.attendee_id IS NOT NULL), '{}'::jsonb[]) AS "coalesce"
           FROM meeting_attendees ma
             LEFT JOIN LATERAL ( SELECT entity_data.title,
                    entity_data.first_name,
                    entity_data.middle_name,
                    entity_data.last_name,
					entity_data.external_id
                   FROM ( SELECT c1.id AS entity_id,
                            p1.title,
                            p1.first_name,
                            p1.middle_name,
                            p1.last_name,
							c1.external_id
                           FROM clients c1
                             JOIN persons p1 ON c1.person_id = p1.id
                          WHERE c1.id = ma.attendee_id
                        UNION ALL
                         SELECT a.id AS entity_id,
                            p2.title,
                            p2.first_name,
                            p2.middle_name,
                            p2.last_name,
							a.external_id
                           FROM agents a
                             JOIN persons p2 ON a.person_id = p2.id
                          WHERE a.id = ma.attendee_id) entity_data
                 LIMIT 1) p ON true
          WHERE ma.meeting_id = m.id) AS participants,
    m.record_type
   FROM meetings m
     LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20250522111846-add_client_organisation_enum_to_meeting_attendees.sql ═════╗
-- Add the enum value first
ALTER TYPE attendee_type_enum ADD VALUE IF NOT EXISTS 'client_organisation';

-- Then update the view
CREATE OR REPLACE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name,
                external_id
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id
                
                UNION ALL
                
                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT 
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id
                FROM client_organisations co
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20250522145840-client_extra_props_tax_filings.sql ═════╗
DROP VIEW tax_filings_view;

CREATE OR REPLACE VIEW public.tax_filings_view AS
SELECT
    tf.*,

    -- Existing client‑org and directly‑linked agent name columns … ───────────
    co.name  AS client_organisation_name,
    co.relationship_status AS client_organisation_relationship_status,
    co.external_id AS client_organisation_external_id,
    co.extra_properties AS client_organisation_extra_properties,
    a_as.external_id AS associate_external_id,
    pas.first_name  AS associate_first_name,
    pas.last_name   AS associate_last_name,
    a_man.external_id AS manager_external_id,
    pman.first_name AS manager_first_name,
    pman.last_name  AS manager_last_name,
    a_sup.external_id AS support_specialist_external_id,
    psup.first_name AS support_specialist_first_name,
    psup.last_name  AS support_specialist_last_name,

    -- Relationship‑based agents (one row each, guaranteed by the index)
    assoc_p.external_id  AS client_organisation_tax_associate_external_id,
    assoc_p.title        AS client_organisation_tax_associate_title,
    assoc_p.first_name   AS client_organisation_tax_associate_first_name,
    assoc_p.last_name    AS client_organisation_tax_associate_last_name,

    mgr_p.external_id  AS client_organisation_tax_manager_external_id,
    mgr_p.title        AS client_organisation_tax_manager_title,
    mgr_p.first_name   AS client_organisation_tax_manager_first_name,
    mgr_p.last_name    AS client_organisation_tax_manager_last_name,

    asst_p.external_id  AS client_organisation_tax_assistant_external_id,
    asst_p.title        AS client_organisation_tax_assistant_title,
    asst_p.first_name   AS client_organisation_tax_assistant_first_name,
    asst_p.last_name    AS client_organisation_tax_assistant_last_name

FROM tax_filings tf
/* ───────────────────────── existing joins ──────────────────────────────── */
LEFT JOIN client_organisations   co   ON co.id        = tf.client_organisation_id
                                     AND co.tenant_id = tf.tenant_id
LEFT JOIN agents                 a_as ON a_as.id      = tf.tax_associate_id
                                     AND a_as.tenant_id = tf.tenant_id
LEFT JOIN persons                pas   ON pas.id      = a_as.person_id
LEFT JOIN agents                 a_man ON a_man.id     = tf.tax_manager_id
                                      AND a_man.tenant_id = tf.tenant_id
LEFT JOIN persons                pman  ON pman.id     = a_man.person_id
LEFT JOIN agent_relationship_profiles arp_man ON arp_man.agent_id = a_man.id
LEFT JOIN agents                 a_sup ON a_sup.id     = tf.tax_support_specialist_id
                                      AND a_sup.tenant_id = tf.tenant_id
LEFT JOIN persons                psup  ON psup.id     = a_sup.person_id

/* ─────────────────────── relationship‑based joins ──────────────────────── */
-- Tax_Associate
LEFT JOIN agent_client_organisation_relationships acr_assoc
       ON acr_assoc.client_organisation_id = tf.client_organisation_id
      AND acr_assoc.tenant_id             = tf.tenant_id
      AND acr_assoc.relationship_type     = 'Tax Associate'
LEFT JOIN agents assoc_a
       ON assoc_a.id       = acr_assoc.agent_id
      AND assoc_a.tenant_id = tf.tenant_id
LEFT JOIN persons assoc_p
       ON assoc_p.id       = assoc_a.person_id

-- Tax_Manager
LEFT JOIN agent_client_organisation_relationships acr_mgr
       ON acr_mgr.client_organisation_id = tf.client_organisation_id
      AND acr_mgr.tenant_id             = tf.tenant_id
      AND acr_mgr.relationship_type     = 'Tax Manager'
LEFT JOIN agents mgr_a
       ON mgr_a.id         = acr_mgr.agent_id
      AND mgr_a.tenant_id   = tf.tenant_id
LEFT JOIN persons mgr_p
       ON mgr_p.id         = mgr_a.person_id

-- Tax_Assistant
LEFT JOIN agent_client_organisation_relationships acr_asst
       ON acr_asst.client_organisation_id = tf.client_organisation_id
      AND acr_asst.tenant_id             = tf.tenant_id
      AND acr_asst.relationship_type     = 'Tax Assistant'
LEFT JOIN agents asst_a
       ON asst_a.id        = acr_asst.agent_id
      AND asst_a.tenant_id  = tf.tenant_id
LEFT JOIN persons asst_p
       ON asst_p.id        = asst_a.person_id;

-- ╔═════ 20250523143737-error-view.sql ═════╗
DROP VIEW IF EXISTS sync_file_error_logs_view;

CREATE VIEW sync_file_error_logs_view AS
SELECT
    el.tenant_id,
    el.feed_id                     AS sync_file_id,
    sf.s3_bucket,
    sf.s3_key,
    sf.salesforce_object_type      AS salesforce_object_type,
    sf.status                      AS sync_status,
    sf.updated_at                  AS sync_file_updated_at,
    sf.start_time                  AS sync_file_start_time,
    sf.end_time                    AS sync_file_end_time,
    el.id                          AS error_log_id,
    el.record_id,
    el.error_type,
    el.error_message,
    el.incoming_data_type,
    el.avantos_data_type,
    el.raw_data,
    el.created_at
FROM   error_logs   AS el
JOIN   sync_file   AS sf
       ON  sf.id        = el.feed_id
       AND sf.tenant_id = el.tenant_id;

CREATE INDEX IF NOT EXISTS idx_error_logs_tenant_feed_created
    ON error_logs (tenant_id, feed_id, created_at DESC);

