    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    data JSONB NOT NULL,
    PRIMARY KEY (id),
    UNIQUE (unqork_id)
    -- No foreign key here so we can accept out of order updates.. referential integrity is not critical here.
);

