-- ╔═════ 20250609192126-add_ssn_to_client_org_members_view.sql ═════╗
-- Update the client_organisation_members_view to include SSN, contact details, and additional attributes
CREATE OR REPLACE VIEW client_organisation_members_view AS
WITH client_addresses AS (
    SELECT 
        cav.client_id,
        jsonb_object_agg(
            cav.address_type,
            jsonb_build_object(
                'address_line1', cav.address_line1,
                'address_line2', cav.address_line2,
                'city', cav.city,
                'state', cav.state,
                'zipcode', cav.zipcode,
                'country', cav.country
            )
        ) AS addresses
    FROM client_addresses_view cav
    GROUP BY cav.client_id
)
SELECT 
    p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    ca.addresses,
    -- New columns
    p.ssn,
    c.additional_attributes
FROM 
    clients c
    JOIN persons p ON c.person_id = p.id
    JOIN client_organisations co ON c.organisation_id = co.id
    LEFT JOIN client_addresses ca ON c.id = ca.client_id;

