-- ╔═════ 20250609202204-add-external-id-in-client-organisation-relationships.sql ═════╗
ALTER TABLE client_organisation_relationships ADD COLUMN external_id TEXT NOT NULL default 'unknown_external_id'; -- to avoid having to delete records in all environments
-- No constraint added for (tenant_id, external_id) yet to avoid having to delete all the records

DROP VIEW IF EXISTS client_organisation_relationships_view;
CREATE VIEW client_organisation_relationships_view AS
SELECT
    cor.tenant_id,
    cor.client_id,
    cor.client_organisation_id,
    cor.id AS client_client_organisation_relationship_id,
    cor.external_id AS client_client_organisation_relationship_external_id,
    c.external_id AS client_external_id,
    co.external_id AS client_organisation_external_id,
    p.first_name AS person_first_name,
    p.last_name AS person_last_name,
    co.name AS client_organisation_name,
    cor.role AS role,
    cor.description AS description,
    cor.extra_properties AS extra_properties,
    cor.created_at AS created_at,
    cor.updated_at AS updated_at
FROM client_organisation_relationships cor
JOIN clients c
    ON cor.client_id = c.id
    AND cor.tenant_id = c.tenant_id
LEFT JOIN persons p
    ON c.person_id = p.id
JOIN client_organisations co
    ON cor.client_organisation_id = co.id
    AND cor.tenant_id = co.tenant_id;

-- ╔═════ 20250609204456-add_description_to_relationship_dashboard_view.sql ═════╗
DROP VIEW IF EXISTS relationships_dashboard_view;

CREATE VIEW relationships_dashboard_view AS
SELECT 
    co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    co.next_meeting,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    (
        SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
        FROM address_entity_relationships aer
        JOIN addresses a ON aer.address_id = a.id
        WHERE aer.client_organisation_id = co.id
    ) AS addresses,
    (
        SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name)), '{}'::jsonb) AS "coalesce"
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
    ) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.created_at,
    co.updated_at
FROM 
    client_organisations co
    LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
    LEFT JOIN business_groups bg ON co.business_group_id = bg.id
    LEFT JOIN agent_organisations aof ON co.office_id = aof.id;

-- ╔═════ 20250609223618-update_client_org_members_view_with_contacts.sql ═════╗
-- Drop and recreate the view with email and phone from contact_details
DROP VIEW IF EXISTS client_organisation_members_view;

CREATE VIEW client_organisation_members_view AS
WITH client_addresses AS (
    SELECT cav.client_id,
        jsonb_object_agg(cav.address_type, jsonb_build_object('address_line1', cav.address_line1, 'address_line2', cav.address_line2, 'city', cav.city, 'state', cav.state, 'zipcode', cav.zipcode, 'country', cav.country)) AS addresses
    FROM client_addresses_view cav
    GROUP BY cav.client_id
)
SELECT p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    ca.addresses,
    p.ssn,
    c.additional_attributes,
    -- Add email from contact_details
    (SELECT value FROM contact_details cd 
     WHERE cd.client_id = c.id 
     AND cd.role = 'primary_email' 
     AND cd.type = 'email'
     LIMIT 1) AS email,
    -- Add phone from contact_details
    (SELECT value FROM contact_details cd 
     WHERE cd.client_id = c.id 
     AND cd.role = 'primary_phone' 
     AND cd.type = 'phone'
     LIMIT 1) AS phone
FROM clients c
    JOIN persons p ON c.person_id = p.id
    JOIN client_organisations co ON c.organisation_id = co.id
    LEFT JOIN client_addresses ca ON c.id = ca.client_id;

