-- ╔═════ 20250611124600-add_ai_transcript_id_to_meetings.sql ═════╗
ALTER TABLE meetings ADD COLUMN ai_transcript_id TEXT;

CREATE OR REPLACE VIEW agent_meetings AS  SELECT m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    ( SELECT COALESCE(array_agg(DISTINCT jsonb_build_object(
        'type', ma.attendee_type, 
        'id', ma.attendee_id, 
        'title', p.title, 
        'first_name', p.first_name, 
        'middle_name', p.middle_name, 
        'last_name', p.last_name,
        'external_id', p.external_id,
        'extra_properties', ma.extra_properties
    )) FILTER (WHERE ma.attendee_id IS NOT NULL), '{}'::jsonb[]) AS "coalesce"
           FROM meeting_attendees ma
             LEFT JOIN LATERAL ( SELECT entity_data.title,
                    entity_data.first_name,
                    entity_data.middle_name,
                    entity_data.last_name,
					entity_data.external_id
                   FROM ( SELECT c1.id AS entity_id,
                            p1.title,
                            p1.first_name,
                            p1.middle_name,
                            p1.last_name,
							c1.external_id
                           FROM clients c1
                             JOIN persons p1 ON c1.person_id = p1.id
                          WHERE c1.id = ma.attendee_id
                        UNION ALL
                         SELECT a.id AS entity_id,
                            p2.title,
                            p2.first_name,
                            p2.middle_name,
                            p2.last_name,
							a.external_id
                           FROM agents a
                             JOIN persons p2 ON a.person_id = p2.id
                          WHERE a.id = ma.attendee_id) entity_data
                 LIMIT 1) p ON true
          WHERE ma.meeting_id = m.id) AS participants,
    m.record_type,
    m.ai_transcript_id
   FROM meetings m
     LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

