-- ╔═════ 20250611165812-add_client_org_external_id_to_enriched_views.sql ═════╗
-- Drop and recreate enriched_action_runs view with client_organisation_external_id
DROP VIEW IF EXISTS enriched_action_runs;

CREATE OR REPLACE VIEW enriched_action_runs AS
WITH client_agents_agg AS (
    SELECT acor.client_organisation_id,
           jsonb_object_agg(acor.relationship_type, jsonb_build_object(
               'agent_id', ap.agent_id, 
               'first_name', ap.first_name, 
               'last_name', ap.last_name
           )) AS agents
    FROM agent_client_organisation_relationships acor
    JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
    GROUP BY acor.client_organisation_id
)
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ab.name AS blueprint_name,
    ab.category AS blueprint_category,
    cag.agents
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
    LEFT JOIN action_blueprints ab ON ab.id = ar.action_id
    LEFT JOIN client_agents_agg cag ON co.id = cag.client_organisation_id;

-- Drop and recreate enriched_task view with client_organisation_external_id
DROP VIEW IF EXISTS enriched_task;

CREATE VIEW enriched_task AS
SELECT
    t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.updated_at,
    t.scheduled_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.completed_at,
    t.cancelled_at,
    t.tags,
    ar.id AS action_run_id,
    ar.name AS action_run_name,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id
FROM
    tasks t
    LEFT JOIN action_run_components arc ON arc.action_run_id = t.run_id AND arc.component_key = t.component_key
    LEFT JOIN action_runs ar ON ar.id = arc.action_run_id
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

-- ╔═════ 20250611221535-make_last_updated_at_non_null.sql ═════╗
-- Update existing NULL values to NOW() before making column NOT NULL
UPDATE action_runs SET last_updated_at = COALESCE(last_updated_at, started_at, NOW()) WHERE last_updated_at IS NULL;

-- Make last_updated_at NOT NULL with DEFAULT
ALTER TABLE action_runs 
  ALTER COLUMN last_updated_at SET NOT NULL,
