-- ╔═════ 20250612140826-optimize-client-org-members-view.sql ═════╗
-- Add composite index for filtering clients by tenant and org
CREATE INDEX IF NOT EXISTS idx_clients_tenant_org_id ON clients(tenant_id, organisation_id);

-- Recreate the view without pre-aggregating addresses
DROP VIEW IF EXISTS client_organisation_members_view;

CREATE VIEW client_organisation_members_view AS
SELECT 
    p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    -- Aggregate addresses only for the filtered clients
    COALESCE(
        (SELECT jsonb_object_agg(
            aer.address_type,
            jsonb_build_object(
                'address_line1', a.address_line1,
                'address_line2', a.address_line2,
                'city', a.city,
                'state', a.state,
                'zipcode', a.zipcode,
                'country', a.country
            )
        )
        FROM address_entity_relationships aer
        JOIN addresses a ON aer.address_id = a.id
        WHERE aer.client_id = c.id),
        '{}'::jsonb
    ) AS addresses,
    p.ssn,
    c.additional_attributes,
    -- Email subquery
    (SELECT value 
     FROM contact_details cd 
     WHERE cd.client_id = c.id 
       AND cd.role = 'primary_email' 
       AND cd.type = 'email'
     LIMIT 1) AS email,
    -- Phone subquery
    (SELECT value 
     FROM contact_details cd 
     WHERE cd.client_id = c.id 
       AND cd.role = 'primary_phone' 
       AND cd.type = 'phone'
     LIMIT 1) AS phone
FROM 
    clients c
    JOIN persons p ON c.person_id = p.id;

-- ╔═════ 20250613030257-optimize-enriched-action-runs-view.sql ═════╗
-- Create indexes to optimize enriched_action_runs view performance
CREATE INDEX IF NOT EXISTS idx_action_runs_tenant_id ON action_runs(tenant_id);
CREATE INDEX IF NOT EXISTS idx_action_runs_client_org_id ON action_runs(client_organisation_id);

-- Drop the existing view
DROP VIEW IF EXISTS enriched_action_runs;

-- Create optimized version of enriched_action_runs view
-- Main optimization: Convert CTE to correlated subquery to avoid computing agents for ALL organizations
CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ab.name AS blueprint_name,
    ab.category AS blueprint_category,
    -- Correlated subquery: only computes agents for returned rows
    (
        SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object(
            'agent_id', ap.agent_id, 
            'first_name', ap.first_name, 
            'last_name', ap.last_name
        ))
        FROM agent_client_organisation_relationships acor
        JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id
    ) AS agents
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
    LEFT JOIN action_blueprints ab ON ab.id = ar.action_id;

-- ╔═════ 20250615134216-add_parent_and_blueprint_keys_to_components.sql ═════╗
