-- ╔═════ 20250616114022-create_enriched_task_view_with_blueprint_market_provider.sql ═════╗
-- Drop and recreate enriched_task view with blueprint, market, and data provider columns
DROP VIEW IF EXISTS enriched_task;

CREATE VIEW
    enriched_task AS
SELECT
    t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.completed_at,
    t.cancelled_at,
    t.tags,
    ar.id AS action_run_id,
    ar.name AS action_run_name,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
