);

-- ╔═════ 20250618171533-custom_views.sql ═════╗
CREATE TYPE view_scope_type AS ENUM ('global', 'role', 'personal');

CREATE TABLE custom_views (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    page_id TEXT NOT NULL,
    scope_type view_scope_type NOT NULL,
    role_name TEXT,
    agent_id TEXT REFERENCES agents(id),
    created_by TEXT NOT NULL REFERENCES agents(id),
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
    filters JSONB DEFAULT NULL,
    only_assigned BOOL NOT NULL,
    columns_config JSONB DEFAULT '[]'::jsonb,
    column_order JSONB DEFAULT '[]'::jsonb,
    sorting JSONB DEFAULT '[]'::jsonb,
    CONSTRAINT scope_check CHECK (
        (scope_type = 'global' AND role_name IS NULL AND agent_id IS NULL) OR
        (scope_type = 'role' AND role_name IS NOT NULL AND agent_id IS NULL) OR
        (scope_type = 'personal' AND role_name IS NULL AND agent_id IS NOT NULL)
    )
);

-- ╔═════ 20250618171606-user_view_defaults.sql ═════╗
CREATE TABLE user_view_defaults (
    id TEXT PRIMARY KEY,  
    agent_id TEXT NOT NULL REFERENCES agents(id),
    page_id TEXT NOT NULL,
    view_id TEXT NOT NULL REFERENCES custom_views(id),
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
    UNIQUE(agent_id, page_id)
);

CREATE INDEX idx_user_view_defaults_view_id 
ON user_view_defaults(view_id);

-- ╔═════ 20250618172337-add_meeting_summaries_table.sql ═════╗
CREATE TABLE meeting_summaries (
    id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    meeting_id TEXT NOT NULL,
    summary_content TEXT,
    created_at TIMESTAMP NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP NOT NULL DEFAULT NOW(),
    last_updated_agent_id TEXT NOT NULL,
    CONSTRAINT fk_meeting_summaries_last_updated_agent_id FOREIGN KEY (last_updated_agent_id) 
        REFERENCES agents(id),
    CONSTRAINT fk_meeting_summaries_meeting_id FOREIGN KEY (meeting_id) 
        REFERENCES meetings(id) ON DELETE CASCADE,
    CONSTRAINT unique_meeting_summaries_meeting_id UNIQUE (meeting_id)
);

CREATE TABLE meeting_summaries_versions (
    id TEXT NOT NULL,
    parent_version_id TEXT,
    version_id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    meeting_id TEXT NOT NULL,
    summary_content TEXT,
    created_at TIMESTAMP NOT NULL,
    updated_at TIMESTAMP NOT NULL,
