        THEN (ut.data->'taskTracking'->>'nextStepDate')::timestamptz
        ELSE NULL 
    END AS next_step_date,
    ut.data->'taskTracking'->>'taskWaitingFor' AS who_waiting_on,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskStatus' IN ('Complete', 'Completed') 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamptz
        ELSE NULL 
    END AS completed_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsDiscarded' = 'true' 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamptz
        ELSE NULL 
    END AS cancelled_at,
    CASE 
        WHEN ut.data->'taskTag' IS NOT NULL 
        THEN ARRAY(SELECT jsonb_array_elements_text(ut.data->'taskTag'))
        ELSE ARRAY[]::text[]
    END AS tags,
    uuar.unqork_id AS action_run_id, 
    ut.data->'correspondingActionInformation'->>'actionNickname' AS action_run_name,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.data->'correspondingActionInformation'->>'actionCategory' AS blueprint_category,
    ut.data->'correspondingActionInformation'->>'actionNickname' AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type AS client_organisation_type,
    uuar.data AS action_run_data,
    'unqork' AS source_system
FROM
    unqork_tasks ut
    LEFT JOIN unqork_action_runs uuar ON uuar.unqork_id = ut.unqork_action_run_id
    LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id;

CREATE OR REPLACE VIEW public.client_client_relationships_view AS
SELECT
    cn.id AS connection_id,
    c1.organisation_id AS initiating_organisation_id,
    cn.initiating_entity_type,
    c1.id AS initiating_client_id,
    c1.external_id AS initiating_client_external_id,
    p1.first_name AS initiating_first_name,
    p1.last_name AS initiating_last_name,
    cn.participating_entity_type,
    c2.id AS participating_client_id,
    c2.external_id AS participating_client_external_id,
    p2.first_name AS participating_first_name,
    p2.last_name AS participating_last_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value

FROM connections cn
LEFT JOIN clients c1 ON cn.initiating_entity_id = c1.id
LEFT JOIN persons p1 ON c1.person_id = p1.id
LEFT JOIN clients c2 ON cn.participating_entity_id = c2.id
LEFT JOIN persons p2 ON c2.person_id = p2.id
LEFT JOIN lookups l ON cn.relationship_type = l.id
WHERE cn.initiating_entity_type = 'client'
  AND cn.participating_entity_type = 'client';

CREATE OR REPLACE VIEW client_org_client_org_relationships_view AS
SELECT
    cn.id AS connection_id,
    cn.initiating_entity_type,
    co1.id AS initiating_client_organisation_id,
    co1.external_id AS initiating_client_organisation_external_id,
    co1.name AS initiating_client_organisation_name,
    cn.participating_entity_type,
    co2.id AS participating_client_organisation_id,
    co2.external_id AS participating_client_organisation_external_id,
    co2.name AS participating_client_organisation_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value
FROM connections cn
LEFT JOIN client_organisations co1 
    ON cn.initiating_entity_id = co1.id
LEFT JOIN client_organisations co2 
    ON cn.participating_entity_id = co2.id
LEFT JOIN lookups l 
    ON cn.relationship_type = l.id
WHERE cn.initiating_entity_type = 'client_organisation'
  AND cn.participating_entity_type = 'client_organisation';

-- ╔═════ 20250624182739-convert_timestamps_unblocked_at.sql ═════╗
-- Convert unblocked_at timestamp with time zone

-- First, drop views that depend on the tables we're modifying
DROP VIEW IF EXISTS enriched_task CASCADE;
DROP VIEW IF EXISTS unified_task_view CASCADE;

-- tasks table
ALTER TABLE tasks ALTER COLUMN unblocked_at TYPE TIMESTAMP WITH TIME ZONE;

-- Recreate views after column type changes
CREATE VIEW
    enriched_task AS
SELECT
    t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.completed_at,
    t.cancelled_at,
    t.tags,
    ar.id AS action_run_id,
    ar.name AS action_run_name,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ab.category AS blueprint_category,
    ab.name AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type AS client_organisation_type,
    ar.data AS action_run_data
FROM
    tasks t
    LEFT JOIN action_run_components arc ON arc.action_run_id = t.run_id
    AND arc.component_key = t.component_key
    LEFT JOIN action_runs ar ON ar.id = arc.action_run_id
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
    LEFT JOIN action_blueprints ab ON ab.id = ar.action_id;

CREATE VIEW unified_task_view AS

-- Regular tasks from enriched_task view
SELECT 
    *,
    'avantos' AS source_system
FROM enriched_task

UNION ALL

-- Unqork tasks mapped to the same structure
SELECT 
    ut.id,
    '1' AS tenant_id, -- Only Mercer uses this tables so we can hardcode the tenant id
    NULL AS component_key,
    ut.data->'taskTracking'->>'taskTitle' AS name,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsApprovalTask' = 'checker'
        THEN 'review'
        ELSE 'submission'
    END AS type,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsDiscarded' = 'true' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Complete' THEN 'done'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Completed' THEN 'done'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Pending Approval' THEN 'pending_approval'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Ready to Begin' THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'In Progress' THEN 'in_progress'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Canceled' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Discarded' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Declined' THEN 'rejected'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Waiting' THEN 'waiting'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'To Do' THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' IS NULL THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' = '' THEN 'todo'
        ELSE 'todo'
    END AS status,
    (
        SELECT a.id 
        FROM agents a 
        WHERE a.external_id = ut.data->'taskTracking'->>'taskOwnerSalenticaId'
    ) AS assigned_agent_id,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskScheduledEndDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'taskScheduledEndDate')::timestamptz
        ELSE NULL 
    END AS deadline,
    ARRAY[]::text[] AS permitted_roles, -- Default empty array
    CASE 
        WHEN ut.data->'taskTracking'->>'createdTimestamp_Task' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'createdTimestamp_Task')::timestamptz
        ELSE ut.created_at
    END AS created_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'modifiedTimestamp_Task' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'modifiedTimestamp_Task')::timestamptz
        ELSE ut.updated_at
    END AS last_updated_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskScheduledStartDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'taskScheduledStartDate')::timestamptz
        ELSE NULL 
    END AS scheduled_at,
    NULL AS unblocked_at, -- Unqork tasks don't have unblocked_at
    ut.data,
    NULL AS note, 
    CASE 
        WHEN ut.data->'taskTracking'->>'nextStepDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'nextStepDate')::timestamptz
        ELSE NULL 
    END AS next_step_date,
    ut.data->'taskTracking'->>'taskWaitingFor' AS who_waiting_on,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskStatus' IN ('Complete', 'Completed') 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamptz
        ELSE NULL 
    END AS completed_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsDiscarded' = 'true' 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamptz
        ELSE NULL 
    END AS cancelled_at,
    CASE 
        WHEN ut.data->'taskTag' IS NOT NULL 
        THEN ARRAY(SELECT jsonb_array_elements_text(ut.data->'taskTag'))
        ELSE ARRAY[]::text[]
    END AS tags,
    uuar.unqork_id AS action_run_id, 
    ut.data->'correspondingActionInformation'->>'actionNickname' AS action_run_name,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.data->'correspondingActionInformation'->>'actionCategory' AS blueprint_category,
    ut.data->'correspondingActionInformation'->>'actionNickname' AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type AS client_organisation_type,
    uuar.data AS action_run_data,
    'unqork' AS source_system
FROM
    unqork_tasks ut
    LEFT JOIN unqork_action_runs uuar ON uuar.unqork_id = ut.unqork_action_run_id
    LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id;

-- ╔═════ 20250624193432-add_parent_run_id_to_enriched_action_runs_view.sql ═════╗
-- Add parent_run_id to enriched_action_runs view
DROP VIEW IF EXISTS enriched_action_runs;

CREATE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ab.name AS blueprint_name,
    ab.category AS blueprint_category,
    -- Correlated subquery: only computes agents for returned rows
    (
        SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object(
            'agent_id', ap.agent_id, 
            'first_name', ap.first_name, 
            'last_name', ap.last_name
        ))
        FROM agent_client_organisation_relationships acor
        JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id
    ) AS agents
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
    LEFT JOIN action_blueprints ab ON ab.id = ar.action_id;

