-- ╔═════ 20250625142505-unified_action_runs_view.sql ═════╗
CREATE VIEW unified_action_runs_view AS

-- Regular action runs from enriched_action_runs view
SELECT 
    *,
    'avantos' AS source_system
FROM enriched_action_runs

UNION ALL

-- Unqork action runs mapped to the same structure
SELECT 
    uar.unqork_id as id,
    '1' AS tenant_id, -- Only Mercer uses this tables so we can hardcode the tenant id
    NULL AS action_id,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Completed' THEN 'done'
        WHEN uar.data->>'actionStatus' = 'In Progress' THEN 'in_progress'
        WHEN uar.data->>'actionStatus' = 'Canceled' THEN 'cancelled'
        WHEN uar.data->>'actionStatus' = 'Rejected' THEN 'rejected'
        WHEN uar.data->>'actionStatus' = 'Scheduled' THEN 'scheduled'
        WHEN uar.data->>'actionStatus' = 'Recommended' THEN 'recommended'
        WHEN uar.data->>'actionStatus' = 'Ready to Begin' THEN 'todo'
        WHEN uar.data->>'actionStatus' = 'Declined' THEN 'rejected'
        WHEN uar.data->>'actionStatus' IS NULL THEN 'todo'
        WHEN uar.data->>'actionStatus' = '' THEN 'todo'
        ELSE 'todo'
    END AS status,
   (
        SELECT a.id 
        FROM agents a 
        WHERE a.external_id = uar.data->>'actionOwnerSalenticaId'
    ) AS started_by,
    uar.client_organisation_id,
    CASE 
        WHEN uar.data->>'actionStartDate' IS NOT NULL 
        THEN (uar.data->>'actionStartDate')::date::timestamptz
        ELSE NULL
    END AS started_at,
    (uar.data->>'modifiedTimestamp_Action')::timestamptz AS last_updated_at,
	uar.data->>'actionNickname' as action_run_name,
    uar.data->>'actionId' AS slug,
    NULL AS blueprint_version_id,
    CASE 
        WHEN uar.data->>'actionScheduledStartDate' IS NOT NULL 
        THEN (uar.data->>'actionScheduledStartDate')::date::timestamptz
        ELSE NULL 
    END AS scheduled_at,
    uar.data AS data,
	NULL as recommended,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Canceled'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS cancelled_at,
    uar.data->>'actionContext' AS run_context,
    (uar.data->>'createdTimestamp_Action')::timestamptz AS created_at,
	NULL as ready_at,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Rejected'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS rejected_at,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Completed'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS completed_at,
    (SELECT a.id 
        FROM agents a 
		JOIN contact_details cd ON cd.agent_id = a.id
        WHERE 
			cd.value = uar.data->>'actionOwnerIdCanceled' AND -- unqork uses email as the id for the agent that cancelled the action
			cd.type = 'email' AND
			cd.role = 'primary_email' AND
			cd.tenant_id = '1'
    ) AS cancelled_by,
    uar.data->>'actionReasonEnded' AS cancellation_reason,
    NULL AS recommended_by,
    NULL AS rejection_reason,
    NULL AS rejected_by,
    CASE 
        WHEN uar.data->>'actionDueDate' IS NOT NULL 
        THEN (uar.data->>'actionDueDate')::date::timestamptz
        ELSE NULL 
    END AS deadline,
    NULL as parent_run_id,
    co.name AS client_organisation_name,
    co.client_organisation_type AS client_organisation_type,
    co.external_id AS client_organisation_external_id,
	uar.data->>'actionType' AS blueprint_name,
	uar.data->>'actionCategory' AS blueprint_category,
	( SELECT jsonb_object_agg(acor.relationship_type, 
		jsonb_build_object(
		'agent_id', ap.agent_id, 
		'first_name', ap.first_name, 
		'last_name', ap.last_name
		))
	FROM agent_client_organisation_relationships acor
	JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
	WHERE acor.client_organisation_id = uar.client_organisation_id
	) AS agents,
    'unqork' AS source_system
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

