-- ╔═════ 20250625195530-add_meeting_to_commentable_entity_type.sql ═════╗
-- Create a new enum type with the additional value
CREATE TYPE commentable_entity_type_new AS ENUM ('action_run', 'action_run_component', 'task', 'meeting');

-- Update the comments table to use the new type
-- First, create a temporary column with the new type
ALTER TABLE comments ADD COLUMN entity_type_new commentable_entity_type_new;

-- Copy data to the new column, converting values as needed
UPDATE comments SET entity_type_new = entity_type::text::commentable_entity_type_new;

-- Drop the old column and rename the new one
ALTER TABLE comments DROP COLUMN entity_type;
ALTER TABLE comments RENAME COLUMN entity_type_new TO entity_type;

-- Drop the old type
DROP TYPE commentable_entity_type;

-- Rename the new type to the original name
ALTER TYPE commentable_entity_type_new RENAME TO commentable_entity_type;

