-- ╔═════ 20250626032737-create_meeting_action_run_relationships.sql ═════╗
CREATE TABLE IF NOT EXISTS meeting_action_run_relationships (
    id TEXT NOT NULL PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    meeting_id TEXT NOT NULL,
    action_run_id TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_meeting FOREIGN KEY (meeting_id) 
        REFERENCES meetings(id) ON DELETE CASCADE,
    CONSTRAINT fk_action_run FOREIGN KEY (action_run_id) 
        REFERENCES action_runs(id) ON DELETE CASCADE
);

CREATE INDEX IF NOT EXISTS idx_meeting_action_run_relationships_tenant_id 
    ON meeting_action_run_relationships(tenant_id);

CREATE INDEX IF NOT EXISTS idx_meeting_action_run_relationships_meeting_id 
    ON meeting_action_run_relationships(meeting_id);

-- Create a unique constraint to prevent duplicate relationships
CREATE UNIQUE INDEX IF NOT EXISTS idx_meeting_action_run_relationships_unique 
    ON meeting_action_run_relationships(tenant_id, meeting_id, action_run_id);

-- ╔═════ 20250626131643-add-national-css-coverage-in-client-org.sql ═════╗
ALTER TABLE client_organisations
ADD COLUMN IF NOT EXISTS national_css_coverage BOOLEAN
GENERATED ALWAYS AS (
    COALESCE(extra_properties ->> 'National_CSS_Coverage__c', '') = 'true'
)
STORED;

DROP VIEW relationships_dashboard_view;

CREATE VIEW relationships_dashboard_view AS
SELECT 
    co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    co.next_meeting,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    (
        SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
        FROM address_entity_relationships aer
        JOIN addresses a ON aer.address_id = a.id
        WHERE aer.client_organisation_id = co.id
    ) AS addresses,
    (
        SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name)), '{}'::jsonb) AS "coalesce"
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
    ) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
FROM 
    client_organisations co
    LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
    LEFT JOIN business_groups bg ON co.business_group_id = bg.id
    LEFT JOIN agent_organisations aof ON co.office_id = aof.id;

