-- ╔═════ 20250628113041-fix_unified_task_view_agent_lookup.sql ═════╗
CREATE OR REPLACE VIEW unified_task_view AS

-- Regular tasks from enriched_task view
SELECT 
    *,
    'avantos' AS source_system
FROM enriched_task

UNION ALL

-- Unqork tasks mapped to the same structure
SELECT 
    ut.unqork_id AS id,
    '1' AS tenant_id, -- Only Mercer uses this tables so we can hardcode the tenant id
    NULL AS component_key,
    ut.data->'taskTracking'->>'taskTitle' AS name,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsApprovalTask' = 'checker'
        THEN 'review'
        ELSE 'submission'
    END AS type,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsDiscarded' = 'true' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Complete' THEN 'done'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Completed' THEN 'done'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Pending Approval' THEN 'pending_approval'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Ready to Begin' THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'In Progress' THEN 'in_progress'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Canceled' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Discarded' THEN 'cancelled'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Declined' THEN 'rejected'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'Waiting' THEN 'waiting'
        WHEN ut.data->'taskTracking'->>'taskStatus' = 'To Do' THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' IS NULL THEN 'todo'
        WHEN ut.data->'taskTracking'->>'taskStatus' = '' THEN 'todo'
        ELSE 'todo'
    END AS status,
    (
        SELECT a.id 
        FROM agents a 
        WHERE a.external_id = ut.data->'taskTracking'->>'taskOwnerSalenticaId'
        AND a.tenant_id = '1'  -- Match the specific tenant (Mercer)
    ) AS assigned_agent_id,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskScheduledEndDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'taskScheduledEndDate')::timestamp
        ELSE NULL 
    END AS deadline,
    ARRAY[]::text[] AS permitted_roles, -- Default empty array
    CASE 
        WHEN ut.data->'taskTracking'->>'createdTimestamp_Task' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'createdTimestamp_Task')::timestamp
        ELSE ut.created_at
    END AS created_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'modifiedTimestamp_Task' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'modifiedTimestamp_Task')::timestamp
        ELSE ut.updated_at
    END AS last_updated_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskScheduledStartDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'taskScheduledStartDate')::timestamp
        ELSE NULL 
    END AS scheduled_at,
    NULL AS unblocked_at, -- Unqork tasks don't have unblocked_at
    ut.data,
    NULL AS note, 
    CASE 
        WHEN ut.data->'taskTracking'->>'nextStepDate' IS NOT NULL 
        THEN (ut.data->'taskTracking'->>'nextStepDate')::timestamp
        ELSE NULL 
    END AS next_step_date,
    ut.data->'taskTracking'->>'taskWaitingFor' AS who_waiting_on,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskStatus' IN ('Complete', 'Completed') 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamp
        ELSE NULL 
    END AS completed_at,
    CASE 
        WHEN ut.data->'taskTracking'->>'taskIsDiscarded' = 'true' 
             AND ut.data->'taskTracking'->>'taskCompletedTimestamp' IS NOT NULL
        THEN (ut.data->'taskTracking'->>'taskCompletedTimestamp')::timestamp
        ELSE NULL 
    END AS cancelled_at,
    CASE 
        WHEN ut.data->'taskTag' IS NOT NULL 
        THEN ARRAY(SELECT jsonb_array_elements_text(ut.data->'taskTag'))
        ELSE ARRAY[]::text[]
    END AS tags,
    uuar.unqork_id AS action_run_id, 
    ut.data->'correspondingActionInformation'->>'actionNickname' AS action_run_name,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.data->'correspondingActionInformation'->>'actionCategory' AS blueprint_category,
    ut.data->'correspondingActionInformation'->>'actionType' AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type AS client_organisation_type,
    uuar.data AS action_run_data,
    'unqork' AS source_system
FROM
    unqork_tasks ut
    LEFT JOIN unqork_action_runs uuar ON uuar.unqork_id = ut.unqork_action_run_id
    LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id;

-- ╔═════ 20250628113116-fix_unified_action_run_view_agent_lookup.sql ═════╗
CREATE OR REPLACE VIEW unified_action_runs_view AS

-- Regular action runs from enriched_action_runs view
SELECT 
    *,
    'avantos' AS source_system
FROM enriched_action_runs

UNION ALL

-- Unqork action runs mapped to the same structure
SELECT 
    uar.unqork_id as id,
    '1' AS tenant_id, -- Only Mercer uses this tables so we can hardcode the tenant id
    NULL AS action_id,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Completed' THEN 'done'
        WHEN uar.data->>'actionStatus' = 'In Progress' THEN 'in_progress'
        WHEN uar.data->>'actionStatus' = 'Canceled' THEN 'cancelled'
        WHEN uar.data->>'actionStatus' = 'Rejected' THEN 'rejected'
        WHEN uar.data->>'actionStatus' = 'Scheduled' THEN 'scheduled'
        WHEN uar.data->>'actionStatus' = 'Recommended' THEN 'recommended'
        WHEN uar.data->>'actionStatus' = 'Ready to Begin' THEN 'todo'
        WHEN uar.data->>'actionStatus' = 'Declined' THEN 'rejected'
        WHEN uar.data->>'actionStatus' IS NULL THEN 'todo'
        WHEN uar.data->>'actionStatus' = '' THEN 'todo'
        ELSE 'todo'
    END AS status,
   (
        SELECT a.id 
        FROM agents a 
        WHERE a.external_id = uar.data->>'actionOwnerSalenticaId'
        AND a.tenant_id = '1'  -- Match the specific tenant (Mercer)
    ) AS started_by,
    uar.client_organisation_id,
    CASE 
        WHEN uar.data->>'actionStartDate' IS NOT NULL 
        THEN (uar.data->>'actionStartDate')::date::timestamptz
        ELSE NULL
    END AS started_at,
    (uar.data->>'modifiedTimestamp_Action')::timestamptz AS last_updated_at,
	uar.data->>'actionNickname' as action_run_name,
    uar.data->>'actionId' AS slug,
    NULL AS blueprint_version_id,
    CASE 
        WHEN uar.data->>'actionScheduledStartDate' IS NOT NULL 
        THEN (uar.data->>'actionScheduledStartDate')::date::timestamptz
        ELSE NULL 
    END AS scheduled_at,
    uar.data AS data,
	NULL as recommended,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Canceled'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS cancelled_at,
    uar.data->>'actionContext' AS run_context,
    (uar.data->>'createdTimestamp_Action')::timestamptz AS created_at,
	NULL as ready_at,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Rejected'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS rejected_at,
    CASE 
        WHEN uar.data->>'actionEndDate' IS NOT NULL AND uar.data->>'actionStatus' = 'Completed'
        THEN (uar.data->>'actionEndDate')::date::timestamptz
        ELSE NULL 
    END AS completed_at,
    (SELECT a.id 
        FROM agents a 
		JOIN contact_details cd ON cd.agent_id = a.id
        WHERE 
			cd.value = uar.data->>'actionOwnerIdCanceled' AND -- unqork uses email as the id for the agent that cancelled the action
			cd.type = 'email' AND
			cd.role = 'primary_email' AND
			cd.tenant_id = '1' AND
			a.tenant_id = '1'  -- Also match the agent's tenant_id
    ) AS cancelled_by,
    uar.data->>'actionReasonEnded' AS cancellation_reason,
    NULL AS recommended_by,
    NULL AS rejection_reason,
    NULL AS rejected_by,
    CASE 
        WHEN uar.data->>'actionDueDate' IS NOT NULL 
        THEN (uar.data->>'actionDueDate')::date::timestamptz
        ELSE NULL 
    END AS deadline,
    NULL as parent_run_id,
    co.name AS client_organisation_name,
    co.client_organisation_type AS client_organisation_type,
    co.external_id AS client_organisation_external_id,
	uar.data->>'actionType' AS blueprint_name,
	uar.data->>'actionCategory' AS blueprint_category,
	( SELECT jsonb_object_agg(acor.relationship_type, 
		jsonb_build_object(
		'agent_id', ap.agent_id, 
		'first_name', ap.first_name, 
		'last_name', ap.last_name
		))
	FROM agent_client_organisation_relationships acor
	JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
	WHERE acor.client_organisation_id = uar.client_organisation_id
	) AS agents,
    'unqork' AS source_system
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- ╔═════ 20250628131432-add_blueprint_version_environments.sql ═════╗
CREATE TABLE blueprint_version_environments (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    blueprint_id TEXT NOT NULL,
    blueprint_version_id TEXT NOT NULL,
    environment TEXT NOT NULL,
    tagged_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    tagged_by_agent_id TEXT NOT NULL,
    promotion_notes TEXT,
    deleted_at TIMESTAMP WITH TIME ZONE,
    FOREIGN KEY (blueprint_version_id) REFERENCES action_blueprint_versions(id) ON DELETE CASCADE,
    FOREIGN KEY (tagged_by_agent_id) REFERENCES agents(id)
);

-- Ensure only one active version per blueprint per environment
CREATE UNIQUE INDEX idx_one_version_per_env_per_blueprint
ON blueprint_version_environments (tenant_id, blueprint_id, environment)
WHERE deleted_at IS NULL;

