    (SELECT a.id 
     FROM agents a 
     WHERE a.external_id = ((ut.data -> 'taskTracking'::text) ->> 'taskOwnerSalenticaId'::text) 
     AND a.tenant_id = '1'::text) AS assigned_agent_id,
    CASE 
        WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskScheduledEndDate'::text) 
        THEN ((ut.data -> 'taskTracking'::text) ->> 'taskScheduledEndDate'::text)::timestamp WITH TIME ZONE
        ELSE NULL::timestamp WITH TIME ZONE
    END AS deadline,
    ARRAY[]::text[] AS permitted_roles,
    COALESCE(
        CASE 
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'createdTimestamp_Task'::text) 
            THEN ((ut.data -> 'taskTracking'::text) ->> 'createdTimestamp_Task'::text)::timestamp WITH TIME ZONE
            ELSE NULL::timestamp WITH TIME ZONE
        END, ut.created_at) AS created_at,
    COALESCE(
        CASE 
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'modifiedTimestamp_Task'::text) 
            THEN ((ut.data -> 'taskTracking'::text) ->> 'modifiedTimestamp_Task'::text)::timestamp WITH TIME ZONE
            ELSE NULL::timestamp WITH TIME ZONE
        END, ut.updated_at) AS last_updated_at,
    CASE 
        WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskScheduledStartDate'::text) 
        THEN ((ut.data -> 'taskTracking'::text) ->> 'taskScheduledStartDate'::text)::timestamp WITH TIME ZONE
        ELSE NULL::timestamp WITH TIME ZONE
    END AS scheduled_at,
    NULL::timestamp WITH TIME ZONE AS unblocked_at,
    ut.data,
    NULL::text AS note,
    CASE 
        WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'nextStepDate'::text) 
        THEN ((ut.data -> 'taskTracking'::text) ->> 'nextStepDate'::text)::timestamp WITH TIME ZONE
        ELSE NULL::timestamp WITH TIME ZONE
    END AS next_step_date,
    (ut.data -> 'taskTracking'::text) ->> 'taskWaitingFor'::text AS who_waiting_on,
    CASE 
        WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) IN ('Complete', 'Completed') AND is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)
        THEN ((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)::timestamp WITH TIME ZONE
        ELSE NULL::timestamp WITH TIME ZONE
    END AS completed_at,
    CASE 
        WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) IN ('Canceled', 'Discarded') AND is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)
        THEN ((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)::timestamp WITH TIME ZONE
        ELSE NULL::timestamp WITH TIME ZONE
    END AS cancelled_at,
    CASE 
        WHEN (ut.data -> 'taskTag'::text) IS NOT NULL 
        THEN ARRAY(SELECT jsonb_array_elements_text(ut.data -> 'taskTag'::text))
        ELSE ARRAY[]::text[]
    END AS tags,
    0::bigint AS total_time_waiting_ms, -- Default to 0 for unqork tasks
    uar.unqork_id AS action_run_id,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionNickname'::text AS action_run_name,
    ut.environment,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionCategory'::text AS blueprint_category,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionType'::text AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    uar.data AS action_run_data,
    'unqork'::text AS source_system
FROM unqork_tasks ut
    LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
    LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id;

-- ╔═════ 20250707205656-add_email_to_agent_meeting_participants.sql ═════╗
-- Update the agent_meetings view to include primary_email in participants
CREATE OR REPLACE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties,
                'primary_email', p.primary_email
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name,
                external_id,
                primary_email
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id,
                    cd1.value AS primary_email
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                LEFT JOIN contact_details cd1 ON cd1.client_id = c1.id 
                    AND cd1.role = 'primary_email'
                    AND cd1.type = 'email'
                WHERE c1.id = ma.attendee_id

                UNION ALL

                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id,
                    cd2.value AS primary_email
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                LEFT JOIN contact_details cd2 ON cd2.agent_id = a.id 
                    AND cd2.role = 'primary_email'
                    AND cd2.type = 'email'
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT 
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id,
                    cd3.value AS primary_email
                FROM client_organisations co
                LEFT JOIN contact_details cd3 ON cd3.client_organisation_id = co.id 
                    AND cd3.role = 'primary_email'
                    AND cd3.type = 'email'
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type,
    m.ai_transcript_id
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20250708145703-add_started_at_to_tasks.sql ═════╗
-- Add started_at column to tasks table
ALTER TABLE tasks ADD COLUMN started_at TIMESTAMP WITH TIME ZONE;

-- Drop and recreate enriched_task view with started_at column
DROP VIEW IF EXISTS enriched_task CASCADE;

CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.completed_at,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    ar.id AS action_run_id,
    ar.name AS action_run_name,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data
   FROM tasks t
     LEFT JOIN action_run_components arc ON arc.action_run_id = t.run_id AND arc.component_key = t.component_key
     LEFT JOIN action_runs ar ON ar.id = arc.action_run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

-- Drop and recreate unified_task_view with started_at column
DROP VIEW IF EXISTS unified_task_view;

CREATE VIEW unified_task_view AS
SELECT et.id,
    et.tenant_id,
    et.component_key,
    et.name,
    et.type,
    et.status,
    et.assigned_agent_id,
    et.deadline,
    et.permitted_roles,
    et.created_at,
    et.last_updated_at,
    et.scheduled_at,
    et.unblocked_at,
    et.started_at,
    et.data,
    et.note,
    et.next_step_date,
    et.who_waiting_on,
    et.completed_at,
    et.cancelled_at,
    et.tags,
    et.total_time_waiting_ms,
    et.action_run_id,
    et.action_run_name,
    et.environment,
    et.client_organisation_id,
    et.client_organisation_name,
    et.client_organisation_external_id,
    et.blueprint_category,
    et.blueprint_name,
    et.client_organisation_extra_properties,
    et.client_organisation_type,
    et.action_run_data,
    'avantos'::text AS source_system
   FROM enriched_task et
UNION ALL
 SELECT ut.unqork_id AS id,
    '1'::text AS tenant_id,
    NULL::text AS component_key,
    (ut.data -> 'taskTracking'::text) ->> 'taskTitle'::text AS name,
        CASE
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskIsApprovalTask'::text) = 'checker'::text THEN 'review'::text
            ELSE 'submission'::text
        END AS type,
        CASE
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskIsDiscarded'::text) = 'true'::text THEN 'cancelled'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Complete'::text THEN 'done'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Completed'::text THEN 'done'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Pending Approval'::text THEN 'pending_approval'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Ready to Begin'::text THEN 'todo'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'In Progress'::text THEN 'in_progress'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Canceled'::text THEN 'cancelled'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Discarded'::text THEN 'cancelled'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Declined'::text THEN 'rejected'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'Waiting'::text THEN 'waiting'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = 'To Do'::text THEN 'todo'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) IS NULL THEN 'todo'::text
            WHEN ((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = ''::text THEN 'todo'::text
            ELSE 'todo'::text
        END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = ((ut.data -> 'taskTracking'::text) ->> 'taskOwnerSalenticaId'::text) AND a.tenant_id = '1'::text) AS assigned_agent_id,
        CASE
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskScheduledEndDate'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'taskScheduledEndDate'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END AS deadline,
    ARRAY[]::text[] AS permitted_roles,
    COALESCE(
        CASE
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'createdTimestamp_Task'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'createdTimestamp_Task'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END, ut.created_at) AS created_at,
    COALESCE(
        CASE
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'modifiedTimestamp_Task'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'modifiedTimestamp_Task'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END, ut.updated_at) AS last_updated_at,
        CASE
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskScheduledStartDate'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'taskScheduledStartDate'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END AS scheduled_at,
    NULL::timestamp with time zone AS unblocked_at,
    NULL::timestamp with time zone AS started_at,
    ut.data,
    NULL::text AS note,
        CASE
            WHEN is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'nextStepDate'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'nextStepDate'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END AS next_step_date,
    (ut.data -> 'taskTracking'::text) ->> 'taskWaitingFor'::text AS who_waiting_on,
        CASE
            WHEN (((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = ANY (ARRAY['Complete'::text, 'Completed'::text])) AND is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END AS completed_at,
        CASE
            WHEN (((ut.data -> 'taskTracking'::text) ->> 'taskStatus'::text) = ANY (ARRAY['Canceled'::text, 'Discarded'::text])) AND is_valid_iso_timestamp((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text) THEN ((ut.data -> 'taskTracking'::text) ->> 'taskEndTimestamp'::text)::timestamp with time zone
            ELSE NULL::timestamp with time zone
        END AS cancelled_at,
        CASE
            WHEN (ut.data -> 'taskTag'::text) IS NOT NULL THEN ARRAY( SELECT jsonb_array_elements_text(ut.data -> 'taskTag'::text) AS jsonb_array_elements_text)
            ELSE ARRAY[]::text[]
        END AS tags,
    0::bigint AS total_time_waiting_ms,
    uar.unqork_id AS action_run_id,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionNickname'::text AS action_run_name,
    ut.environment,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionCategory'::text AS blueprint_category,
    (ut.data -> 'correspondingActionInformation'::text) ->> 'actionType'::text AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    uar.data AS action_run_data,
    'unqork'::text AS source_system
   FROM unqork_tasks ut
     LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
     LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id;

-- ╔═════ 20250709174753-fix_unqork_action_runs_mapping.sql ═════╗
CREATE OR REPLACE VIEW unified_action_runs_view AS

-- Regular action runs from enriched_action_runs view
SELECT 
    *,
    'avantos' AS source_system
FROM enriched_action_runs

UNION ALL

-- Unqork action runs mapped to the same structure
SELECT 
    uar.unqork_id as action_run_id,
    '1' AS tenant_id, -- Only Mercer uses this tables so we can hardcode the tenant id
    NULL AS action_id,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Completed' THEN 'done'
        WHEN uar.data->>'actionStatus' = 'In Progress' THEN 'in_progress'
        WHEN uar.data->>'actionStatus' = 'Canceled' THEN 'cancelled'
        WHEN uar.data->>'actionStatus' = 'Rejected' THEN 'rejected'
        WHEN uar.data->>'actionStatus' = 'Scheduled' THEN 'scheduled'
        WHEN uar.data->>'actionStatus' = 'Recommended' THEN 'recommended'
        WHEN uar.data->>'actionStatus' = 'Ready to Begin' THEN 'todo'
        WHEN uar.data->>'actionStatus' = 'Declined' THEN 'rejected'
        WHEN uar.data->>'actionStatus' IS NULL THEN 'todo'
        WHEN uar.data->>'actionStatus' = '' THEN 'todo'
        ELSE 'todo'
    END AS status,
   (
        SELECT a.id 
        FROM agents a 
        WHERE a.external_id = uar.data->>'actionOwnerSalenticaId'
        AND a.tenant_id = '1'  -- Match the specific tenant (Mercer)
    ) AS started_by,
    uar.client_organisation_id,
    CASE 
        WHEN is_valid_iso_timestamp(uar.data->>'actionStartDate')
        THEN (uar.data->>'actionStartDate')::timestamptz
        ELSE NULL 
    END AS started_at,
    CASE 
        WHEN is_valid_iso_timestamp(uar.data->>'modifiedTimestamp_Action')
        THEN (uar.data->>'modifiedTimestamp_Action')::timestamptz
        ELSE NULL 
    END AS last_updated_at,
	uar.data->>'actionNickname' as action_run_name,
    uar.data->>'actionId' AS slug,
    NULL AS blueprint_version_id,
    CASE 
        WHEN is_valid_iso_timestamp(uar.data->>'actionScheduledStartDate')
        THEN (uar.data->>'actionScheduledStartDate')::timestamptz
        ELSE NULL 
    END AS scheduled_at,
    uar.data AS data,
	NULL as recommended,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Canceled'
			 AND is_valid_iso_timestamp(uar.data->>'actionEndDate')
        THEN (uar.data->>'actionEndDate')::timestamptz
        ELSE NULL 
    END AS cancelled_at,
    uar.data->>'actionContext' AS run_context,
    CASE 
        WHEN is_valid_iso_timestamp(uar.data->>'createdTimestamp_Action')
        THEN (uar.data->>'createdTimestamp_Action')::timestamptz
        ELSE NULL 
    END AS created_at,
	NULL as ready_at,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Rejected' 
             AND is_valid_iso_timestamp(uar.data->>'actionEndDate')
        THEN (uar.data->>'actionEndDate')::timestamptz
        ELSE NULL 
    END AS rejected_at,
    CASE 
        WHEN uar.data->>'actionStatus' = 'Completed'
             AND is_valid_iso_timestamp(uar.data->>'actionEndDate')
        THEN (uar.data->>'actionEndDate')::timestamptz
        ELSE NULL 
    END AS completed_at,
    (SELECT a.id 
        FROM agents a 
		JOIN contact_details cd ON cd.agent_id = a.id
        WHERE 
			cd.value = uar.data->>'actionOwnerIdCanceled' AND -- unqork uses email as the id for the agent that cancelled the action
			cd.type = 'email' AND
			cd.role = 'primary_email' AND
			cd.tenant_id = '1' AND
			a.tenant_id = '1'  -- Also match the agent's tenant_id
    ) AS cancelled_by,
    uar.data->>'actionReasonEnded' AS cancellation_reason,
    NULL AS recommended_by,
    NULL AS rejection_reason,
    NULL AS rejected_by,
    CASE 
        WHEN is_valid_iso_timestamp(uar.data->>'actionDueDate')
        THEN (uar.data->>'actionDueDate')::timestamptz
        ELSE NULL 
    END AS deadline,
    NULL as parent_run_id,
    uar.environment,
	uar.data->>'actionType' AS blueprint_name,
	uar.data->>'actionCategory' AS blueprint_category,
    co.name AS client_organisation_name,
    co.client_organisation_type AS client_organisation_type,
    co.external_id AS client_organisation_external_id,
	( SELECT jsonb_object_agg(acor.relationship_type, 
		jsonb_build_object(
		'agent_id', ap.agent_id, 
		'first_name', ap.first_name, 
		'last_name', ap.last_name
		))
	FROM agent_client_organisation_relationships acor
	JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
	WHERE acor.client_organisation_id = uar.client_organisation_id
	) AS agents,
    'unqork' AS source_system
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- ╔═════ 20250709193645-unqork_full_view_perf.sql ═════╗
/* ===================================================================
   20250709_unqork_full_view_perf.sql
   Adds immutable helpers, persisted JSON-derived columns (incl. tags),
   supporting indexes, and rewrites unified_task_view.
   =================================================================== */

----------------------------------------------------------------------
-- 0.  Immutable helper functions
----------------------------------------------------------------------

-- Safe ISO-8601 → timestamptz cast (returns NULL on parse failure)
CREATE OR REPLACE FUNCTION safe_iso_timestamptz(txt text)
RETURNS timestamptz
LANGUAGE plpgsql
IMMUTABLE STRICT AS
$$
BEGIN
  BEGIN
    RETURN txt::timestamptz;
  EXCEPTION WHEN others THEN
    RETURN NULL;
  END;
END;
$$;
-- Turn a JSON array into text[]
CREATE OR REPLACE FUNCTION jsonb_text_array(j jsonb)
RETURNS text[]
LANGUAGE sql
IMMUTABLE STRICT AS
$$
  SELECT array_agg(elem)
  FROM   jsonb_array_elements_text(j) AS t(elem);
$$;
----------------------------------------------------------------------
-- 1.  Persisted (generated STORED) columns on unqork_tasks
----------------------------------------------------------------------

ALTER TABLE unqork_tasks
  ADD COLUMN IF NOT EXISTS task_title              text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskTitle')) STORED,
  ADD COLUMN IF NOT EXISTS task_status             text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskStatus')) STORED,
  ADD COLUMN IF NOT EXISTS task_is_approval_task   text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskIsApprovalTask')) STORED,
  ADD COLUMN IF NOT EXISTS task_is_discarded       text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskIsDiscarded')) STORED,
  ADD COLUMN IF NOT EXISTS task_owner_salentica_id text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskOwnerSalenticaId')) STORED,
  ADD COLUMN IF NOT EXISTS task_waiting_for        text        GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskWaitingFor')) STORED,

  ADD COLUMN IF NOT EXISTS task_deadline           timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'taskScheduledEndDate')) STORED,
  ADD COLUMN IF NOT EXISTS task_sched_start        timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'taskScheduledStartDate')) STORED,
  ADD COLUMN IF NOT EXISTS task_created_ts         timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'createdTimestamp_Task')) STORED,
  ADD COLUMN IF NOT EXISTS task_modified_ts        timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'modifiedTimestamp_Task')) STORED,
  ADD COLUMN IF NOT EXISTS task_next_step_date     timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'nextStepDate')) STORED,
  ADD COLUMN IF NOT EXISTS task_end_ts             timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data -> 'taskTracking' ->> 'taskEndTimestamp')) STORED,

  ADD COLUMN IF NOT EXISTS action_nickname         text        GENERATED ALWAYS AS ((data -> 'correspondingActionInformation' ->> 'actionNickname')) STORED,
  ADD COLUMN IF NOT EXISTS action_category         text        GENERATED ALWAYS AS ((data -> 'correspondingActionInformation' ->> 'actionCategory')) STORED,
  ADD COLUMN IF NOT EXISTS action_type             text        GENERATED ALWAYS AS ((data -> 'correspondingActionInformation' ->> 'actionType')) STORED,

  ADD COLUMN IF NOT EXISTS task_tags               text[]      GENERATED ALWAYS AS (
      COALESCE(jsonb_text_array(data -> 'taskTag'), ARRAY[]::text[])
  ) STORED;

----------------------------------------------------------------------
-- 2.  Recreate unified_task_view using the new columns
----------------------------------------------------------------------

CREATE OR REPLACE VIEW unified_task_view AS
/* ----- Avantos / enriched_task branch (unchanged) ------------------ */
SELECT
    et.id, et.tenant_id, et.component_key, et.name, et.type, et.status,
    et.assigned_agent_id, et.deadline, et.permitted_roles,
    et.created_at, et.last_updated_at, et.scheduled_at,
    et.unblocked_at, et.started_at, et.data, et.note, et.next_step_date,
    et.who_waiting_on, et.completed_at, et.cancelled_at, et.tags,
    et.total_time_waiting_ms, et.action_run_id, et.action_run_name,
    et.environment, et.client_organisation_id, et.client_organisation_name,
    et.client_organisation_external_id, et.blueprint_category,
    et.blueprint_name, et.client_organisation_extra_properties,
    et.client_organisation_type, et.action_run_data,
    'avantos' AS source_system
FROM   enriched_task et

UNION ALL

/* ----- Unqork branch (column-based) -------------------------------- */
SELECT
    ut.unqork_id                                   AS id,
    '1'                                            AS tenant_id,
    NULL                                           AS component_key,
    ut.task_title                                  AS name,
    CASE WHEN ut.task_is_approval_task = 'checker'
         THEN 'review' ELSE 'submission' END       AS type,

    CASE
        WHEN ut.task_is_discarded = 'true'                     THEN 'cancelled'
        WHEN ut.task_status IN ('Complete','Completed')        THEN 'done'
        WHEN ut.task_status = 'Pending Approval'               THEN 'pending_approval'
        WHEN ut.task_status = 'Ready to Begin'                 THEN 'todo'
        WHEN ut.task_status = 'In Progress'                    THEN 'in_progress'
        WHEN ut.task_status IN ('Canceled','Discarded')        THEN 'cancelled'
        WHEN ut.task_status = 'Declined'                       THEN 'rejected'
        WHEN ut.task_status = 'Waiting'                        THEN 'waiting'
        WHEN ut.task_status IS NULL OR ut.task_status = ''     THEN 'todo'
        ELSE 'todo'
    END                                           AS status,

    a.id                                          AS assigned_agent_id,
    ut.task_deadline                              AS deadline,
    ARRAY[]::text[]                               AS permitted_roles,
    COALESCE(ut.task_created_ts,  ut.created_at)  AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at)  AS last_updated_at,
    ut.task_sched_start                           AS scheduled_at,
    NULL::timestamptz                             AS unblocked_at,
    NULL::timestamptz                             AS started_at,
    ut.data,
    NULL                                          AS note,
    ut.task_next_step_date                        AS next_step_date,
    ut.task_waiting_for                           AS who_waiting_on,

    CASE WHEN ut.task_status IN ('Complete','Completed')
         THEN ut.task_end_ts END                 AS completed_at,
    CASE WHEN ut.task_status IN ('Canceled','Discarded')
         THEN ut.task_end_ts END                 AS cancelled_at,

    ut.task_tags                                  AS tags,   -- persisted array

    0::bigint                                     AS total_time_waiting_ms,
    uar.unqork_id                                 AS action_run_id,
    ut.action_nickname                            AS action_run_name,
    ut.environment,
    ut.client_organisation_id,
    co.name                                       AS client_organisation_name,
    co.external_id                                AS client_organisation_external_id,
    ut.action_category                            AS blueprint_category,
    ut.action_type                                AS blueprint_name,
    co.extra_properties                           AS client_organisation_extra_properties,
    co.client_organisation_type,
    uar.data                                      AS action_run_data,
    'unqork'                                      AS source_system
FROM   unqork_tasks            ut
LEFT   JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT   JOIN client_organisations  co ON co.id       = ut.client_organisation_id
LEFT   JOIN agents               a  ON a.external_id = ut.task_owner_salentica_id
                                     AND a.tenant_id = '1';

----------------------------------------------------------------------
-- 3.  Supporting indexes (built as part of migration)
----------------------------------------------------------------------

-- Fast "ORDER BY task_title / pagination" in Unqork branch
CREATE INDEX IF NOT EXISTS idx_unqork_tasks_title_id
          ON unqork_tasks (task_title, unqork_id);

-- Join to agents by owner ID
CREATE INDEX IF NOT EXISTS idx_unqork_tasks_owner
          ON unqork_tasks (task_owner_salentica_id);

-- ╔═════ 20250709194524-create_client_view_for_search_page.sql ═════╗
CREATE OR REPLACE VIEW client_search_view AS
SELECT
    c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name) AS name,
    c.external_id,
    -- Use separate subqueries for each contact type to avoid cross-contamination
    (SELECT cd.value::text 
     FROM contact_details cd 
     WHERE cd.client_id = c.id AND cd.role = 'preferred_phone' 
     LIMIT 1) AS preferred_phone,
    (SELECT cd.value::text 
     FROM contact_details cd 
     WHERE cd.client_id = c.id AND cd.role = 'preferred_email' 
     LIMIT 1) AS preferred_email,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.relationship_status as client_organisation_relationship_status,
    -- Wealth Advisor name
    CONCAT_WS(' ', 
        wealth_advisor_person.first_name, 
        wealth_advisor_person.middle_name, 
        wealth_advisor_person.last_name
    ) AS client_organisation_wealth_advisor_name
FROM
    clients c
    JOIN persons p ON p.id = c.person_id
    LEFT JOIN client_organisations co ON c.organisation_id = co.id
    -- Join to get Wealth Advisor
    LEFT JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id 
        AND acor.relationship_type = 'Wealth Advisor'
    LEFT JOIN agents wealth_advisor_agent ON acor.agent_id = wealth_advisor_agent.id
    LEFT JOIN persons wealth_advisor_person ON wealth_advisor_agent.person_id = wealth_advisor_person.id;

