-- ╔═════ 20250710175227-add_blueprint_descriptions_to_enriched_views.sql ═════╗
-- Add blueprint description columns to enriched_action_runs view
DROP VIEW IF EXISTS meeting_enriched_action_runs CASCADE;
DROP VIEW IF EXISTS unified_action_runs_view CASCADE;
DROP VIEW IF EXISTS enriched_action_runs CASCADE;

-- Recreate enriched_action_runs with blueprint description columns
CREATE VIEW enriched_action_runs AS
SELECT 
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ab.description AS blueprint_description,
    ab.short_description AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents
FROM action_runs ar
LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
LEFT JOIN action_blueprints ab ON ab.id = ar.action_id;

-- Recreate unified_action_runs_view with blueprint description columns
CREATE VIEW unified_action_runs_view AS
SELECT 
    enriched_action_runs.action_run_id,
    enriched_action_runs.tenant_id,
    enriched_action_runs.action_id,
    enriched_action_runs.status,
    enriched_action_runs.started_by,
    enriched_action_runs.client_organisation_id,
    enriched_action_runs.started_at,
    enriched_action_runs.last_updated_at,
    enriched_action_runs.action_run_name,
    enriched_action_runs.slug,
    enriched_action_runs.blueprint_version_id,
    enriched_action_runs.scheduled_at,
    enriched_action_runs.data,
    enriched_action_runs.recommended,
    enriched_action_runs.cancelled_at,
    enriched_action_runs.run_context,
    enriched_action_runs.created_at,
    enriched_action_runs.ready_at,
    enriched_action_runs.rejected_at,
    enriched_action_runs.completed_at,
    enriched_action_runs.cancelled_by,
    enriched_action_runs.cancellation_reason,
    enriched_action_runs.recommended_by,
    enriched_action_runs.rejection_reason,
    enriched_action_runs.rejected_by,
    enriched_action_runs.deadline,
    enriched_action_runs.parent_run_id,
    enriched_action_runs.environment,
    enriched_action_runs.blueprint_name,
    enriched_action_runs.blueprint_category,
    enriched_action_runs.blueprint_description,
    enriched_action_runs.blueprint_short_description,
    enriched_action_runs.client_organisation_name,
    enriched_action_runs.client_organisation_type,
    enriched_action_runs.client_organisation_external_id,
    enriched_action_runs.agents,
    'avantos'::text AS source_system
FROM enriched_action_runs
UNION ALL
SELECT 
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN (uar.data ->> 'actionStatus'::text) = 'Completed'::text THEN 'done'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'In Progress'::text THEN 'in_progress'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Canceled'::text THEN 'cancelled'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Rejected'::text THEN 'rejected'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Scheduled'::text THEN 'scheduled'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Recommended'::text THEN 'recommended'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Ready to Begin'::text THEN 'todo'::text
        WHEN (uar.data ->> 'actionStatus'::text) = 'Declined'::text THEN 'rejected'::text
        WHEN (uar.data ->> 'actionStatus'::text) IS NULL THEN 'todo'::text
        WHEN (uar.data ->> 'actionStatus'::text) = ''::text THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = (uar.data ->> 'actionOwnerSalenticaId'::text) AND a.tenant_id = '1'::text) AS started_by,
    uar.client_organisation_id,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'actionStartDate'::text) THEN (uar.data ->> 'actionStartDate'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS started_at,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'modifiedTimestamp_Action'::text) THEN (uar.data ->> 'modifiedTimestamp_Action'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS last_updated_at,
    uar.data ->> 'actionNickname'::text AS action_run_name,
    NULL::text AS slug,
    NULL::text AS blueprint_version_id,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'scheduledDate'::text) THEN (uar.data ->> 'scheduledDate'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS scheduled_at,
    uar.data,
    false AS recommended,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'canceledDate'::text) THEN (uar.data ->> 'canceledDate'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS cancelled_at,
    NULL::text AS run_context,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'createdTimestamp_Action'::text) THEN (uar.data ->> 'createdTimestamp_Action'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'rejectedDate'::text) THEN (uar.data ->> 'rejectedDate'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS rejected_at,
    CASE
        WHEN is_valid_iso_timestamp(uar.data ->> 'completedDate'::text) THEN (uar.data ->> 'completedDate'::text)::timestamp with time zone
        ELSE NULL::timestamp with time zone
    END AS completed_at,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = (uar.data ->> 'canceledBySalenticaId'::text) AND a.tenant_id = '1'::text) AS cancelled_by,
    uar.data ->> 'cancelReason'::text AS cancellation_reason,
    NULL::text AS recommended_by,
    uar.data ->> 'rejectionReason'::text AS rejection_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = (uar.data ->> 'rejectedBySalenticaId'::text) AND a.tenant_id = '1'::text) AS rejected_by,
    NULL::timestamp with time zone AS deadline,
    NULL::text AS parent_run_id,
    NULL::text AS environment,
    uar.data ->> 'actionType'::text AS blueprint_name,
    uar.data ->> 'actionCategory'::text AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    NULL::jsonb AS agents,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- Recreate meeting_enriched_action_runs view with blueprint description columns
CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

