-- add task_unblocked_at, task_cancelled_by, and task_cancellation_reason columns to unqork_tasks table
ALTER TABLE unqork_tasks
ADD COLUMN IF NOT EXISTS task_unblocked_at        timestamptz GENERATED ALWAYS AS (
    safe_iso_timestamptz(data ->> 'taskReadyToBeginDate')) STORED,
ADD COLUMN IF NOT EXISTS task_cancelled_by         text        GENERATED ALWAYS AS ((data ->> 'taskOwnerCanceled')) STORED,
