-- ╔═════ 20250714133721-add_missing_fields_from_unqork_action_runs.sql ═════╗
/* ===================================================================
   Add materialized columns for Unqork action runs to improve query 
   performance
   =================================================================== */

----------------------------------------------------------------------
-- 1.  Persisted (generated STORED) columns on unqork_action_runs
----------------------------------------------------------------------

ALTER TABLE unqork_action_runs
  ADD COLUMN IF NOT EXISTS action_status             text        GENERATED ALWAYS AS (data ->> 'actionStatus') STORED,
  ADD COLUMN IF NOT EXISTS action_owner_salentica_id text        GENERATED ALWAYS AS (data ->> 'actionOwnerSalenticaId') STORED,
  ADD COLUMN IF NOT EXISTS action_nickname           text        GENERATED ALWAYS AS (data ->> 'actionNickname') STORED,
  ADD COLUMN IF NOT EXISTS action_type               text        GENERATED ALWAYS AS (data ->> 'actionType') STORED,
  ADD COLUMN IF NOT EXISTS action_category           text        GENERATED ALWAYS AS (data ->> 'actionCategory') STORED,
  ADD COLUMN IF NOT EXISTS canceled_by_salentica_id  text        GENERATED ALWAYS AS (data ->> 'canceledBySalenticaId') STORED,
  ADD COLUMN IF NOT EXISTS cancel_reason             text        GENERATED ALWAYS AS (data ->> 'cancelReason') STORED,
  ADD COLUMN IF NOT EXISTS rejection_reason          text        GENERATED ALWAYS AS (data ->> 'rejectionReason') STORED,
  ADD COLUMN IF NOT EXISTS rejected_by_salentica_id  text        GENERATED ALWAYS AS (data ->> 'rejectedBySalenticaId') STORED,
  ADD COLUMN IF NOT EXISTS action_id                 text        GENERATED ALWAYS AS (data ->> 'actionId') STORED,
  ADD COLUMN IF NOT EXISTS action_rel_id             text        GENERATED ALWAYS AS (data ->> 'actionRelId') STORED,
  ADD COLUMN IF NOT EXISTS action_current_task_title text        GENERATED ALWAYS AS (data ->> 'actionCurrentTaskTitle') STORED,
  ADD COLUMN IF NOT EXISTS action_due_date           text        GENERATED ALWAYS AS (data ->> 'actionDueDate') STORED,
  ADD COLUMN IF NOT EXISTS action_no                 text        GENERATED ALWAYS AS (data ->> 'actionNo') STORED,
  ADD COLUMN IF NOT EXISTS action_owner_canceled     text        GENERATED ALWAYS AS (data ->> 'actionOwnerCanceled') STORED,
  ADD COLUMN IF NOT EXISTS action_owner_user_id      text        GENERATED ALWAYS AS (data ->> 'actionOwnerUserId') STORED,
  ADD COLUMN IF NOT EXISTS action_rel_servicing_name text        GENERATED ALWAYS AS (data ->> 'actionRelServicingName') STORED,
  ADD COLUMN IF NOT EXISTS action_rel_type           text        GENERATED ALWAYS AS (data ->> 'actionRelType') STORED,
  ADD COLUMN IF NOT EXISTS action_context            text        GENERATED ALWAYS AS (data ->> 'actionContext') STORED,
  
  -- Financial account related fields (nested in actionData)
  ADD COLUMN IF NOT EXISTS account_number            text        GENERATED ALWAYS AS (
      data -> 'actionData' ->> 'accountNumber') STORED,
  ADD COLUMN IF NOT EXISTS financial_account_id      text        GENERATED ALWAYS AS (
      data -> 'actionData' ->> 'financialAccountId') STORED,
  
  ADD COLUMN IF NOT EXISTS action_start_date         timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'actionStartDate')) STORED,
  ADD COLUMN IF NOT EXISTS action_end_date           timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'actionEndDate')) STORED,
  ADD COLUMN IF NOT EXISTS modified_timestamp_action timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'modifiedTimestamp_Action')) STORED,
  ADD COLUMN IF NOT EXISTS scheduled_date            timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'scheduledDate')) STORED,
  ADD COLUMN IF NOT EXISTS canceled_date             timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'canceledDate')) STORED,
  ADD COLUMN IF NOT EXISTS created_timestamp_action  timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'createdTimestamp_Action')) STORED,
  ADD COLUMN IF NOT EXISTS rejected_date             timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'rejectedDate')) STORED,
  ADD COLUMN IF NOT EXISTS completed_date            timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'completedDate')) STORED;

----------------------------------------------------------------------
-- 2.  Supporting indexes (only for frequently queried columns)
----------------------------------------------------------------------

-- Fast "ORDER BY action_nickname / pagination" in Unqork branch
CREATE INDEX IF NOT EXISTS idx_unqork_action_runs_nickname_id
          ON unqork_action_runs (action_nickname, unqork_id);

-- Join to agents by owner ID
CREATE INDEX IF NOT EXISTS idx_unqork_action_runs_owner
          ON unqork_action_runs (action_owner_salentica_id);

----------------------------------------------------------------------
-- 3.  Recreate unified_action_runs_view using the new columns
----------------------------------------------------------------------

DROP VIEW IF EXISTS unified_action_runs_view CASCADE;

-- Recreate enriched_action_runs first (no changes, but needed for dependency)
DROP VIEW IF EXISTS enriched_action_runs CASCADE;

CREATE VIEW enriched_action_runs AS
SELECT 
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    ar.status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ab.description AS blueprint_description,
    ab.short_description AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents
FROM action_runs ar
LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
LEFT JOIN action_blueprints ab ON ab.id = ar.action_id;

-- Recreate unified_action_runs_view using the new materialized columns for better performance
CREATE VIEW unified_action_runs_view AS
SELECT 
    enriched_action_runs.action_run_id,
    enriched_action_runs.tenant_id,
    enriched_action_runs.action_id,
    enriched_action_runs.status,
    enriched_action_runs.started_by,
    enriched_action_runs.client_organisation_id,
    enriched_action_runs.started_at,
    enriched_action_runs.last_updated_at,
    enriched_action_runs.action_run_name,
    enriched_action_runs.slug,
    enriched_action_runs.blueprint_version_id,
    enriched_action_runs.scheduled_at,
    enriched_action_runs.data,
    enriched_action_runs.recommended,
    enriched_action_runs.cancelled_at,
    enriched_action_runs.run_context,
    enriched_action_runs.created_at,
    enriched_action_runs.ready_at,
    enriched_action_runs.rejected_at,
    enriched_action_runs.completed_at,
    enriched_action_runs.cancelled_by,
    enriched_action_runs.cancellation_reason,
    enriched_action_runs.recommended_by,
    enriched_action_runs.rejection_reason,
    enriched_action_runs.rejected_by,
    enriched_action_runs.deadline,
    enriched_action_runs.parent_run_id,
    enriched_action_runs.environment,
    enriched_action_runs.blueprint_name,
    enriched_action_runs.blueprint_category,
    enriched_action_runs.blueprint_description,
    enriched_action_runs.blueprint_short_description,
    enriched_action_runs.client_organisation_name,
    enriched_action_runs.client_organisation_type,
    enriched_action_runs.client_organisation_external_id,
    enriched_action_runs.agents,
    'avantos'::text AS source_system
FROM enriched_action_runs
UNION ALL

/* ----- Unqork branch (using materialized columns) ------------------ */
SELECT 
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'done'::text
        WHEN uar.action_status = 'In Progress' THEN 'in_progress'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.action_owner_salentica_id 
            AND a.tenant_id = '1') AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    NULL::text AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    -- Build custom data object with only extra Unqork fields that don't map to standard columns
    jsonb_build_object(
        'action_id', uar.action_id,
        'action_rel_id', uar.action_rel_id,
        'action_current_task_title', uar.action_current_task_title,
        'action_no', uar.action_no,
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'action_rel_type', uar.action_rel_type,
        'account_number', uar.account_number,
        'financial_account_id', uar.financial_account_id,
        'current_task', CASE 
            WHEN uar.action_current_task_title IS NOT NULL 
            THEN jsonb_build_object(
                'id', NULL,
                'name', uar.action_current_task_title,
                'status', 'in_progress'  -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE WHEN uar.action_status = 'Recommended' THEN true ELSE false END AS recommended,
    uar.canceled_date AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    uar.rejected_date AS rejected_at,
    uar.completed_date AS completed_at,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.canceled_by_salentica_id 
            AND a.tenant_id = '1') AS cancelled_by,
    uar.cancel_reason AS cancellation_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.idp_subject = uar.action_owner_user_id 
            AND a.tenant_id = '1') AS recommended_by,
    uar.rejection_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.rejected_by_salentica_id 
            AND a.tenant_id = '1') AS rejected_by,
    safe_iso_timestamptz(uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    NULL::text AS environment,
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- Recreate meeting_enriched_action_runs view (dependency)
DROP VIEW IF EXISTS meeting_enriched_action_runs;
CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

