UNION ALL

/* ----- Unqork branch (using materialized columns) ------------------ */
SELECT 
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'done'::text
        WHEN uar.action_status = 'In Progress' THEN 'in_progress'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.action_owner_salentica_id 
            AND a.tenant_id = '1') AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    NULL::text AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    -- Build custom data object with only extra Unqork fields that don't map to standard columns
    jsonb_build_object(
        'action_id', uar.action_id,
        'action_rel_id', uar.action_rel_id,
        'action_current_task_title', uar.action_current_task_title,
        'action_no', uar.action_no,
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'action_rel_type', uar.action_rel_type,
        'account_number', uar.account_number,
        'financial_account_id', uar.financial_account_id,
        'current_task', CASE 
            WHEN uar.action_current_task_title IS NOT NULL 
            THEN jsonb_build_object(
                'id', NULL,
                'name', uar.action_current_task_title,
                'status', 'in_progress'  -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE WHEN uar.action_status = 'Recommended' THEN true ELSE false END AS recommended,
    uar.canceled_date AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    uar.rejected_date AS rejected_at,
    uar.completed_date AS completed_at,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.canceled_by_salentica_id 
            AND a.tenant_id = '1') AS cancelled_by,
    uar.cancel_reason AS cancellation_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.idp_subject = uar.action_owner_user_id 
            AND a.tenant_id = '1') AS recommended_by,
    uar.rejection_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.rejected_by_salentica_id 
            AND a.tenant_id = '1') AS rejected_by,
    safe_iso_timestamptz(uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    NULL::text AS environment,
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.external_id AS client_organisation_external_id,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- Recreate meeting_enriched_action_runs view
CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

-- Recreate enriched_task view
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    ar.action_run_id,
    ar.slug AS action_run_slug,
    ar.action_run_name,
    ar.agents AS action_run_agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name) AS primary_css
   FROM tasks t
     LEFT JOIN action_run_components arc ON arc.action_run_id = t.run_id AND arc.component_key = t.component_key
     LEFT JOIN enriched_action_runs ar ON ar.action_run_id = arc.action_run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

-- Recreate unified_task_view with missing columns
CREATE VIEW unified_task_view AS
SELECT
    et.id, et.tenant_id, et.component_key, et.name, et.type, et.status,
    et.assigned_agent_id, et.deadline, et.permitted_roles,
    et.created_at, et.last_updated_at, et.scheduled_at,
    et.unblocked_at, et.started_at, et.data, et.note, et.next_step_date,
    et.who_waiting_on, et.waiting_for, et.completed_at, et.completed_by, et.cancelled_by, et.cancellation_reason, et.cancelled_at, et.tags,
    et.total_time_waiting_ms, et.action_run_id, et.action_run_slug, et.action_run_name, et.action_run_agents,
    et.environment, et.client_organisation_id, et.client_organisation_name,
    et.client_organisation_external_id, et.blueprint_category,
    et.blueprint_name, et.client_organisation_extra_properties,
    et.client_organisation_type, et.action_run_data, et.primary_css,
    'avantos' AS source_system
FROM   enriched_task et

UNION ALL

SELECT
    ut.unqork_id                                   AS id,
    '1'                                            AS tenant_id,
    NULL                                           AS component_key,
    ut.task_title                                  AS name,
    CASE WHEN ut.task_is_approval_task = 'checker'
         THEN 'review' ELSE 'submission' END       AS type,

    CASE
        WHEN ut.task_is_discarded = 'true'                     THEN 'cancelled'
        WHEN ut.task_status IN ('Complete','Completed')        THEN 'done'
        WHEN ut.task_status = 'Pending Approval'               THEN 'pending_approval'
        WHEN ut.task_status = 'Ready to Begin'                 THEN 'todo'
        WHEN ut.task_status = 'In Progress'                    THEN 'in_progress'
        WHEN ut.task_status IN ('Canceled','Discarded')        THEN 'cancelled'
        WHEN ut.task_status = 'Declined'                       THEN 'rejected'
        WHEN ut.task_status = 'Waiting'                        THEN 'waiting'
        WHEN ut.task_status IS NULL OR ut.task_status = ''     THEN 'todo'
        ELSE 'todo'
    END                                           AS status,

    a.id                                          AS assigned_agent_id,
    ut.task_deadline                              AS deadline,
    ARRAY[]::text[]                               AS permitted_roles,
    COALESCE(ut.task_created_ts,  ut.created_at)  AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at)  AS last_updated_at,
    ut.task_sched_start                           AS scheduled_at,
    ut.task_unblocked_at                          AS unblocked_at,
    NULL::timestamptz                             AS started_at,
    ut.data,
    NULL                                          AS note,
    ut.task_next_step_date                        AS next_step_date,
    ut.task_waiting_for                           AS who_waiting_on,
    ut.task_owner                                 AS waiting_for,

    CASE WHEN ut.task_status IN ('Complete','Completed')
         THEN ut.task_end_ts END                 AS completed_at,
    ut.task_owner                                 AS completed_by,
    ut.task_cancelled_by                          AS cancelled_by,
    ut.task_cancellation_reason                   AS cancellation_reason,
    CASE WHEN ut.task_status IN ('Canceled','Discarded')
         THEN ut.task_end_ts END                 AS cancelled_at,

    ut.task_tags                                  AS tags,   -- persisted array

    0::bigint                                     AS total_time_waiting_ms,
    uar.unqork_id                                 AS action_run_id,
    ut.action_no                                  AS action_run_slug,
    ut.action_nickname                            AS action_run_name,
    uarv.agents                                    AS action_run_agents,
    ut.environment,
    ut.client_organisation_id,
    co.name                                       AS client_organisation_name,
    co.external_id                                AS client_organisation_external_id,
    ut.action_category                            AS blueprint_category,
    ut.action_type                                AS blueprint_name,
    co.extra_properties                           AS client_organisation_extra_properties,
    co.client_organisation_type,
    uar.data                                      AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name) AS primary_css,
    'unqork'                                      AS source_system
FROM   unqork_tasks            ut
LEFT   JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT   JOIN unified_action_runs_view uarv ON uarv.action_run_id = uar.id
LEFT   JOIN client_organisations  co ON co.id       = ut.client_organisation_id
LEFT   JOIN agents               a  ON a.external_id = ut.task_owner_salentica_id
                                     AND a.tenant_id = '1'
LEFT   JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
  AND acor.relationship_type = 'Primary Client Service Specialist'
LEFT   JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

-- ╔═════ 20250715190601-bpc_sla_duration_fix.sql ═════╗
/* ===================================================================
   BPC SLA Duration Fix
   =================================================================== */

-- Update the sla and the approval sla duration to null
update public.action_blueprint_components set sla_duration = null where sla_duration = '0s';

update public.action_blueprint_components set approval_sla_duration = null where approval_sla_duration = '0s';

-- ╔═════ 20250716152619-fix_unqork_action_runs_column_mappings.sql ═════╗
/* ===================================================================
   Fix column mappings for unqork_action_runs table
   - canceledDate should be actionEndDate
   - canceledBySalenticaId should be actionOwnerCanceled (renamed to canceled_by)
   - cancelReason should be actionReasonEnded
   - rejectionReason should be actionReasonEnded
   - scheduledDate should be actionScheduledStartDate
   =================================================================== */

----------------------------------------------------------------------
-- 1. Drop dependent views
----------------------------------------------------------------------
DROP VIEW IF EXISTS unified_task_view CASCADE;
DROP VIEW IF EXISTS enriched_task CASCADE;
DROP VIEW IF EXISTS meeting_enriched_action_runs CASCADE;
DROP VIEW IF EXISTS unified_action_runs_view CASCADE;
DROP VIEW IF EXISTS enriched_action_runs CASCADE;

----------------------------------------------------------------------
-- 2. Drop the old generated columns
----------------------------------------------------------------------
ALTER TABLE unqork_action_runs
  DROP COLUMN IF EXISTS canceled_date,
  DROP COLUMN IF EXISTS canceled_by_salentica_id,
  DROP COLUMN IF EXISTS cancel_reason,
  DROP COLUMN IF EXISTS rejection_reason,
  DROP COLUMN IF EXISTS scheduled_date,
  DROP COLUMN IF EXISTS rejected_by_salentica_id;

----------------------------------------------------------------------
-- 3. Add the corrected generated columns
----------------------------------------------------------------------
ALTER TABLE unqork_action_runs
  ADD COLUMN IF NOT EXISTS canceled_date              timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'actionEndDate')) STORED,
  ADD COLUMN IF NOT EXISTS canceled_by                text        GENERATED ALWAYS AS (
      data ->> 'actionOwnerCanceled') STORED,
  ADD COLUMN IF NOT EXISTS cancel_reason              text        GENERATED ALWAYS AS (
      data ->> 'actionReasonEnded') STORED,
  ADD COLUMN IF NOT EXISTS rejection_reason           text        GENERATED ALWAYS AS (
      data ->> 'actionReasonEnded') STORED,
  ADD COLUMN IF NOT EXISTS scheduled_date             timestamptz GENERATED ALWAYS AS (
      safe_iso_timestamptz(data ->> 'actionScheduledStartDate')) STORED;

----------------------------------------------------------------------
-- 4. Recreate the views exactly as they were, just with the column renamed
----------------------------------------------------------------------

