        'action_no', uar.action_no,
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'action_rel_type', uar.action_rel_type,
        'account_number', uar.account_number,
        'financial_account_id', uar.financial_account_id,
        'current_task', CASE 
            WHEN uar.action_current_task_title IS NOT NULL 
            THEN jsonb_build_object(
                'id', NULL,
                'name', uar.action_current_task_title,
                'status', 'in_progress'  -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE WHEN uar.action_status = 'Recommended' THEN true ELSE false END AS recommended,
    uar.canceled_date AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    uar.rejected_date AS rejected_at,
    uar.completed_date AS completed_at,
    uar.canceled_by AS cancelled_by,  -- Return the name directly for Unqork  
    uar.cancel_reason AS cancellation_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.idp_subject = uar.action_owner_user_id 
            AND a.tenant_id = '1') AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by,  -- No rejected_by data from Unqork
    safe_iso_timestamptz(uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment, -- Get the environment from the unqork_action_runs table instead of hardcoding as null
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- Recreate meeting_enriched_action_runs (no changes)
CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

-- Recreate enriched_task
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    ar.action_run_id,
    ar.slug AS action_run_slug,
    ar.action_run_name,
    ar.agents AS action_run_agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name) AS primary_css
   FROM tasks t
     LEFT JOIN action_run_components arc ON arc.action_run_id = t.run_id AND arc.component_key = t.component_key
     LEFT JOIN enriched_action_runs ar ON ar.action_run_id = arc.action_run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

-- ╔═════ 20250717232857-add_pinned_to_defaults.sql ═════╗
-- Remove the pinned column from custom views since the defaults table will replace it.
ALTER TABLE custom_views DROP COLUMN IF EXISTS pinned;

-- Add the pinned column to the user views default table.
ALTER TABLE user_view_defaults
ADD COLUMN pinned_view_ids TEXT[] NOT NULL DEFAULT '{}';

-- Make the view id column nullable to allow setting pinned views without a default view.
ALTER TABLE user_view_defaults
ALTER COLUMN view_id DROP NOT NULL;

-- Add the tenant id column to the user views default table
ALTER TABLE user_view_defaults
ADD COLUMN tenant_id TEXT;

-- Update existing rows to have tenant_id from the related custom_view
UPDATE user_view_defaults 
SET tenant_id = cv.tenant_id
FROM custom_views cv
WHERE user_view_defaults.view_id = cv.id
AND user_view_defaults.tenant_id IS NULL;

-- For any remaining rows without a tenant_id set as 1
UPDATE user_view_defaults 
SET tenant_id = '1' 
WHERE tenant_id IS NULL;

-- Now make tenant_id NOT NULL after updating existing data
ALTER TABLE user_view_defaults
ALTER COLUMN tenant_id SET NOT NULL;

-- Drop the old unique constraint and create a new one that includes tenant_id
ALTER TABLE user_view_defaults
DROP CONSTRAINT IF EXISTS user_view_defaults_agent_id_page_id_key;

-- Add new unique constraint that includes tenant_id
ALTER TABLE user_view_defaults
ADD CONSTRAINT user_view_defaults_agent_id_page_id_tenant_id_key 
UNIQUE(agent_id, page_id, tenant_id);

-- ╔═════ 20250718173353-fix_unqork_action_runs_status_mapping.sql ═════╗
CREATE OR REPLACE VIEW unified_action_runs_view AS
SELECT 
    enriched_action_runs.action_run_id,
    enriched_action_runs.tenant_id,
    enriched_action_runs.action_id,
