LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id
LEFT JOIN agents a ON a.external_id = ut.task_owner_salentica_id AND a.tenant_id = '1'::text;

-- recreate enriched_task with agents column instead of action_run_agents
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    ar.id AS action_run_id,
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents, -- agents instead of action_run_agents to work with agent directly assigned filter
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name) AS primary_css
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

-- ╔═════ 20250721155053-use_preferred_contact_details_in_client_organisation_members_view.sql ═════╗
-- Update the view to use preferred_email and preferred_phone instead of primary_email and primary_phone
DROP VIEW IF EXISTS client_organisation_members_view;

CREATE VIEW client_organisation_members_view AS
WITH client_contacts AS (
    -- Pre-aggregate contact details to avoid multiple subqueries
    -- Get the most recently created contact for each role, rather than arbitrary single row
    SELECT 
        client_id,
        MAX(email) AS email,
        MAX(phone) AS phone
    FROM (
        SELECT DISTINCT ON (client_id, role)
            client_id,
            CASE WHEN role = 'preferred_email' AND type = 'email' THEN value END AS email,
            CASE WHEN role = 'preferred_phone' AND type = 'phone' THEN value END AS phone
        FROM contact_details
        WHERE (role = 'preferred_email' AND type = 'email')
           OR (role = 'preferred_phone' AND type = 'phone')
        ORDER BY client_id, role, created_at DESC
    ) latest_contacts
    GROUP BY client_id
),
client_addresses_agg AS (
    -- Pre-aggregate addresses for better performance
    SELECT 
        aer.client_id,
        jsonb_object_agg(
            aer.address_type,
            jsonb_build_object(
                'address_line1', a.address_line1,
                'address_line2', a.address_line2,
                'city', a.city,
                'state', a.state,
                'zipcode', a.zipcode,
                'country', a.country
            )
        ) AS addresses
    FROM address_entity_relationships aer
    JOIN addresses a ON aer.address_id = a.id
    GROUP BY aer.client_id
)
SELECT 
    p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    COALESCE(ca.addresses, '{}'::jsonb) AS addresses,
    p.ssn,
    c.additional_attributes,
    cc.email::text as email,
    cc.phone::text as phone
FROM 
    clients c
    JOIN persons p ON c.person_id = p.id
    LEFT JOIN client_contacts cc ON c.id = cc.client_id
    LEFT JOIN client_addresses_agg ca ON c.id = ca.client_id;

