-- ╔═════ 20250723165700-add_client_org_indexes_for_relationship_dashboard_view.sql ═════╗
-- Those indexes seem to work, as EXPLAIN ANALYZE shows the index is used and a faster query

-- For the is_mercer_employee filter
CREATE INDEX IF NOT EXISTS idx_client_organisations_mercer_employee_tenant 
ON client_organisations(tenant_id, is_mercer_employee) 
WHERE is_mercer_employee = true;

-- For the JSON filter
-- Create a composite index that covers both conditions
CREATE INDEX IF NOT EXISTS idx_client_organisations_wealth_advisor_tenant 
ON client_organisations (tenant_id, (extra_properties ->> 'Wealth_Advisor__c'))
WHERE (extra_properties ->> 'Wealth_Advisor__c') IS NOT NULL;

