CREATE VIEW unqork_tasks_view AS
SELECT 
    ut.unqork_id AS id,
    '1'::text AS tenant_id,
    NULL::text AS component_key,
    ut.task_title AS name,
    CASE
        WHEN ut.task_is_approval_task = 'checker'::text THEN 'review'::text
        ELSE 'submission'::text
    END AS type,
    CASE
        WHEN ut.task_is_discarded = 'true'::text THEN 'cancelled'::text
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN 'done'::text
        WHEN ut.task_status = 'Pending Approval'::text THEN 'pending_approval'::text
        WHEN ut.task_status = 'Ready to Begin'::text THEN 'todo'::text
        WHEN ut.task_status = 'In Progress'::text THEN 'in_progress'::text
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN 'cancelled'::text
        WHEN ut.task_status = 'Declined'::text THEN 'rejected'::text
        WHEN ut.task_status = 'Waiting'::text THEN 'waiting'::text
        WHEN ut.task_status IS NULL OR ut.task_status = ''::text THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    a.id AS assigned_agent_id,
    ut.task_deadline AS deadline,
    CASE 
        WHEN ut.permitted_roles IS NULL THEN ARRAY[]::text[]
        ELSE ARRAY[ut.permitted_roles]
    END AS permitted_roles,
    COALESCE(ut.task_created_ts, ut.created_at) AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at) AS last_updated_at,
    ut.task_sched_start AS scheduled_at,
    ut.task_unblocked_at AS unblocked_at,
    NULL::timestamp with time zone AS started_at,
    ut.data,
    NULL::text AS note,
    ut.task_next_step_date AS next_step_date,
    ut.task_waiting_for AS who_waiting_on,
    ut.task_owner AS waiting_for,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS completed_at,
    ut.task_owner AS completed_by,
    ut.task_cancelled_by AS cancelled_by,
    ut.task_cancellation_reason AS cancellation_reason,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS cancelled_at,
    ut.task_tags AS tags,
    0::bigint AS total_time_waiting_ms,
    uar.unqork_id AS action_run_id,
    uar.action_id AS action_number, -- add action_id as action_number because it's the name client is used to.
    ut.action_no AS action_run_slug,
    ut.action_nickname AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents, -- rename as agents to work with agent directly assigned filter
    ut.environment,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.action_category AS blueprint_category,
    ut.action_type AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    jsonb_build_object(
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'dataProviderName', uar.data_provider_name
            )
        ),
        'financial_account_id', uar.financial_account_id
    )  AS action_run_data,
    NULL::jsonb AS primary_css,
    'unqork'::text AS source_system,
    co.client_segmentation AS client_segmentation
FROM unqork_tasks ut
LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id
LEFT JOIN agents a ON a.external_id = ut.task_owner_salentica_id AND a.tenant_id = '1'::text;

