-- ╔═════ 20250730152244-optimize-members-view.sql ═════╗
CREATE OR REPLACE VIEW client_organisation_members_view AS
SELECT
    p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    COALESCE(
        (
            SELECT jsonb_object_agg(
                aer.address_type,
                jsonb_build_object(
                    'address_line1', a.address_line1,
                    'address_line2', a.address_line2,
                    'city', a.city,
                    'state', a.state,
                    'zipcode', a.zipcode,
                    'country', a.country
                )
            )
            FROM address_entity_relationships aer
            JOIN addresses a ON a.id = aer.address_id
            WHERE aer.client_id = c.id
        ),
        '{}'::jsonb
    ) AS addresses,
    p.ssn,
    c.additional_attributes,
    (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.client_id = c.id
          AND cd.role = 'preferred_email'
          AND cd.type = 'email'
        ORDER BY cd.created_at DESC
        LIMIT 1
    ) AS email,
    (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.client_id = c.id
          AND cd.role = 'preferred_phone'
          AND cd.type = 'phone'
        ORDER BY cd.created_at DESC
        LIMIT 1
    ) AS phone
FROM clients c
JOIN persons p ON p.id = c.person_id;

