-- ╔═════ 20250811211000-update_views_for_soft_delete.sql ═════╗
-- Update client_person_view to filter out soft-deleted clients
CREATE OR REPLACE VIEW public.client_person_view AS
 SELECT c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    c.investment_goal,
    c.assets,
    c.compliance_record,
    c.documentation,
    c.role,
    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    c.employment_status,
    c.drivers_license_number,
    c.expected_retirement_age,
    c.maiden_name,
    c.occupation,
    c.preferred_name,
    c.retired,
    c.current_employer,
    c.retirement_date,
    c.wedding_anniversary,
    c.personal_interests,
    c.officer_or_director,
    c.security_restrictions,
    c.marketing_salutation,
    c.additional_attributes,
    COALESCE(addr.addresses, '[]'::jsonb) AS addresses,
    COALESCE(cd.contacts, '[]'::jsonb) AS contacts,
    c.external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation
   FROM clients c
     JOIN persons p ON p.id = c.person_id
     LEFT JOIN LATERAL ( SELECT jsonb_agg(jsonb_build_object('address_type', aer.address_type, 'description', aer.description, 'address_line1', a.address_line1, 'address_line2', a.address_line2, 'city', a.city, 'state', a.state, 'zipcode', a.zipcode, 'country', a.country)) AS addresses
           FROM address_entity_relationships aer
             JOIN addresses a ON a.id = aer.address_id
          WHERE aer.client_id = c.id) addr ON true
     LEFT JOIN LATERAL ( SELECT jsonb_agg(jsonb_build_object('type', cd_1.type, 'role', cd_1.role, 'value', cd_1.value)) AS contacts
           FROM contact_details cd_1
          WHERE cd_1.client_id = c.id) cd ON true
     LEFT JOIN client_organisations co ON c.organisation_id = co.id
   WHERE c.deleted_at IS NULL;  -- Added filter for soft-deleted clients

-- Update client_organisation_agents_view to filter out soft-deleted client organisations
CREATE OR REPLACE VIEW public.client_organisation_agents_view AS
 SELECT a.tenant_id,
    a.organisation_id AS agent_organisation_id,
    co.id AS client_organisation_id,
    a.type,
    a.agent_id,
    a.external_id,
    a.title,
    a.first_name,
    a.last_name,
    a.suffix,
    acor.relationship_type,
    a.contacts
   FROM client_organisations co
     JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id
     JOIN agent_person_view a ON acor.agent_id = a.agent_id
   WHERE co.deleted_at IS NULL;  -- Added filter for soft-deleted client organisations

-- Update client_agent_view to filter out soft-deleted clients
CREATE OR REPLACE VIEW public.client_agent_view AS
 SELECT c.id AS client_id,
    a.tenant_id,
    a.organisation_id AS agent_organisation_id,
    c.organisation_id AS client_organisation_id,
    a.type,
    a.agent_id,
    a.title,
    a.first_name,
    a.last_name,
    a.suffix,
    acor.relationship_type
   FROM clients c
     JOIN client_organisations co ON c.organisation_id = co.id
     JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id
     JOIN agent_person_view a ON acor.agent_id = a.agent_id
   WHERE c.deleted_at IS NULL  -- Added filter for soft-deleted clients
     AND co.deleted_at IS NULL;  -- Added filter for soft-deleted client organisations

-- Update client_search_view to filter out soft-deleted clients and client organisations
CREATE OR REPLACE VIEW public.client_search_view AS
 SELECT c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    concat_ws(' '::text, p.first_name, p.middle_name, p.last_name) AS name,
    c.external_id,
    ( SELECT cd.value
           FROM contact_details cd
          WHERE cd.client_id = c.id AND cd.role = 'preferred_phone'::text
         LIMIT 1) AS preferred_phone,
    ( SELECT cd.value
           FROM contact_details cd
          WHERE cd.client_id = c.id AND cd.role = 'preferred_email'::text
         LIMIT 1) AS preferred_email,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.relationship_status AS client_organisation_relationship_status,
    concat_ws(' '::text, wealth_advisor_person.first_name, wealth_advisor_person.middle_name, wealth_advisor_person.last_name) AS client_organisation_wealth_advisor_name
   FROM clients c
     JOIN persons p ON p.id = c.person_id
     LEFT JOIN client_organisations co ON c.organisation_id = co.id
     LEFT JOIN agent_client_organisation_relationships acor ON co.id = acor.client_organisation_id AND acor.relationship_type = 'Wealth Advisor'::text
     LEFT JOIN agents wealth_advisor_agent ON acor.agent_id = wealth_advisor_agent.id
     LEFT JOIN persons wealth_advisor_person ON wealth_advisor_agent.person_id = wealth_advisor_person.id
   WHERE c.deleted_at IS NULL  -- Added filter for soft-deleted clients
     AND (co.deleted_at IS NULL OR co.id IS NULL);  -- Added filter for soft-deleted client organisations (allowing NULL org)

-- Update client_organisation_members_view to filter out soft-deleted clients
CREATE OR REPLACE VIEW public.client_organisation_members_view AS
 SELECT p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    c.id AS client_id,
    c.role,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    COALESCE(( SELECT jsonb_object_agg(aer.address_type, jsonb_build_object('address_line1', a.address_line1, 'address_line2', a.address_line2, 'city', a.city, 'state', a.state, 'zipcode', a.zipcode, 'country', a.country)) AS jsonb_object_agg
           FROM address_entity_relationships aer
             JOIN addresses a ON a.id = aer.address_id
          WHERE aer.client_id = c.id), '{}'::jsonb) AS addresses,
    p.ssn,
    c.additional_attributes,
    ( SELECT cd.value
           FROM contact_details cd
          WHERE cd.client_id = c.id AND cd.role = 'preferred_email'::text AND cd.type = 'email'::text
          ORDER BY cd.created_at DESC
         LIMIT 1) AS email,
    ( SELECT cd.value
           FROM contact_details cd
          WHERE cd.client_id = c.id AND cd.role = 'preferred_phone'::text AND cd.type = 'phone'::text
          ORDER BY cd.created_at DESC
         LIMIT 1) AS phone
   FROM clients c
     JOIN persons p ON p.id = c.person_id
   WHERE c.deleted_at IS NULL;  -- Added filter for soft-deleted clients

-- ╔═════ 20250811220000-update_connection_views_for_soft_delete.sql ═════╗
-- Update client_client_relationships_view to filter out soft-deleted clients
CREATE OR REPLACE VIEW public.client_client_relationships_view AS
 SELECT cn.id AS connection_id,
    c1.organisation_id AS initiating_organisation_id,
    cn.initiating_entity_type,
    c1.id AS initiating_client_id,
    c1.external_id AS initiating_client_external_id,
    p1.first_name AS initiating_first_name,
    p1.last_name AS initiating_last_name,
    cn.participating_entity_type,
    c2.id AS participating_client_id,
    c2.external_id AS participating_client_external_id,
    p2.first_name AS participating_first_name,
    p2.last_name AS participating_last_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value
   FROM connections cn
     LEFT JOIN clients c1 ON cn.initiating_entity_id = c1.id
     LEFT JOIN persons p1 ON c1.person_id = p1.id
     LEFT JOIN clients c2 ON cn.participating_entity_id = c2.id
     LEFT JOIN persons p2 ON c2.person_id = p2.id
     LEFT JOIN lookups l ON cn.relationship_type = l.id
  WHERE cn.initiating_entity_type = 'client'::text 
    AND cn.participating_entity_type = 'client'::text
    AND (c1.deleted_at IS NULL OR c1.id IS NULL)  -- Filter out soft-deleted initiating clients
    AND (c2.deleted_at IS NULL OR c2.id IS NULL); -- Filter out soft-deleted participating clients

-- ╔═════ 20250811230000-update_client_org_relationships_view_for_soft_delete.sql ═════╗
-- Update client_organisation_relationships_view to filter out soft-deleted clients and client organisations
CREATE OR REPLACE VIEW public.client_organisation_relationships_view AS
 SELECT cor.tenant_id,
    cor.client_id,
    cor.client_organisation_id,
    cor.id AS client_client_organisation_relationship_id,
    cor.external_id AS client_client_organisation_relationship_external_id,
    c.external_id AS client_external_id,
    co.external_id AS client_organisation_external_id,
    p.first_name AS person_first_name,
    p.last_name AS person_last_name,
    co.name AS client_organisation_name,
    cor.role,
    cor.description,
    cor.extra_properties,
    cor.created_at,
    cor.updated_at
   FROM client_organisation_relationships cor
     JOIN clients c ON cor.client_id = c.id AND cor.tenant_id = c.tenant_id
     LEFT JOIN persons p ON c.person_id = p.id
     JOIN client_organisations co ON cor.client_organisation_id = co.id AND cor.tenant_id = co.tenant_id
   WHERE c.deleted_at IS NULL  -- Filter out soft-deleted clients
     AND co.deleted_at IS NULL; -- Filter out soft-deleted client organisations

-- ╔═════ 20250812000000-update_relationships_dashboard_view_for_soft_delete.sql ═════╗
-- Update relationships_dashboard_view to filter out soft-deleted client organisations
CREATE OR REPLACE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    co.next_meeting,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
   WHERE co.deleted_at IS NULL; -- Added filter for soft-deleted client organisations

