-- ╔═════ 20250814202111-update_client_org_relationship_unique_constraints.sql ═════╗
-- First, delete any rows that still have the default value
DELETE FROM client_organisation_relationships 
WHERE external_id = 'unknown_external_id';

-- Drop the view that depends on this table
DROP VIEW IF EXISTS client_organisation_relationships_view;

-- Drop the old unique constraint
DROP INDEX IF EXISTS idx_client_org_relationship_unique;

-- Drop the existing external_id index (if it exists without tenant_id)
DROP INDEX IF EXISTS idx_client_org_relationships_external_id;

-- Remove the default value and remove not null constraint
ALTER TABLE client_organisation_relationships 
  ALTER COLUMN external_id DROP DEFAULT,
  ALTER COLUMN external_id DROP NOT NULL;

-- Add unique index on external_id (with tenant_id for proper isolation)
CREATE UNIQUE INDEX idx_client_org_relationships_external_id 
  ON client_organisation_relationships(tenant_id, external_id);

-- Recreate the view
CREATE VIEW client_organisation_relationships_view AS
 SELECT cor.tenant_id,
    cor.client_id,
    cor.client_organisation_id,
    cor.id AS client_client_organisation_relationship_id,
    cor.external_id AS client_client_organisation_relationship_external_id,
    c.external_id AS client_external_id,
    co.external_id AS client_organisation_external_id,
    p.first_name AS person_first_name,
    p.last_name AS person_last_name,
    co.name AS client_organisation_name,
    cor.role,
    cor.description,
    cor.extra_properties,
    cor.created_at,
    cor.updated_at
   FROM client_organisation_relationships cor
     JOIN clients c ON cor.client_id = c.id AND cor.tenant_id = c.tenant_id
     LEFT JOIN persons p ON c.person_id = p.id
     JOIN client_organisations co ON cor.client_organisation_id = co.id AND cor.tenant_id = co.tenant_id
  WHERE c.deleted_at IS NULL AND co.deleted_at IS NULL;

