CREATE VIEW public.client_org_opportunities_view AS
 SELECT opps.id,
    opps.tenant_id,
    opps.external_id,
    opps.client_organisation_id,
    opps.name,
    opps.opportunity_type,
    opps.status,
    opps.probability,
    opps.next_step,
    opps.description,
    opps.expected_close_date,
    opps.created_at,
    opps.updated_at,
    opps.extra_properties,
    opps.owner_id,
    opps.is_closed,
    opps.amount,
    opps.expected_revenue,
    opps.relationship_type,
    opps.lead_source,
    opps.import_type,
    opps.closed_amount,
    opps.record_type,
    opps.amount_transferred,
    opps.prospective_external_id,
    opps.prospective_id,
    opps.next_step_date,
    opps.probability_categorisation,
    opps.next_meeting_date,
    orgs.client_organisation_type,
    orgs.relationship_status AS client_organisation_status,
    orgs.name AS client_organisation_name,
    orgs.external_id AS client_organisation_external_id,
    orgs.extra_properties AS client_organisation_extra_properties,
    orgs.growth_opportunity_next_step_date as client_organisation_growth_opportunity_next_step_date,
    p.name AS prospective_name,
    p.client_organisation_type AS prospective_type
   FROM client_org_opportunities opps
     JOIN client_organisations orgs ON opps.client_organisation_id = orgs.id
     LEFT JOIN client_organisations p ON opps.prospective_id = p.id
   WHERE orgs.deleted_at IS NULL  -- Filter out soft-deleted client organisations
     AND (p.deleted_at IS NULL OR p.id IS NULL); -- Filter out soft-deleted prospective organisations (allowing NULL)

