CREATE VIEW unqork_action_runs_view AS
SELECT 
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.action_owner_salentica_id 
            AND a.tenant_id = '1') AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum, -- add aum from client organisation
    -- Build custom data object with standardized structure
    jsonb_build_object(
        'action_id', uar.action_id,
        'action_rel_segment', uar.action_rel_segment,
        'action_rel_id', uar.action_rel_id,
        'action_current_task_title', uar.action_current_task_title,
        'action_no', uar.action_no,
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'action_rel_type', uar.action_rel_type,
        'actionDescription', uar.action_description,
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'custodianName', uar.custodian_name
            )
        ),
        'financial_account_id', uar.financial_account_id,
        'current_task', CASE 
            WHEN uar.action_current_task_title IS NOT NULL 
            THEN jsonb_build_object(
                'id', NULL,
                'name', uar.action_current_task_title,
                'status', 'in_progress'  -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE WHEN uar.action_status = 'Recommended' THEN true ELSE false END AS recommended,
    CASE WHEN uar.action_status = 'Canceled' THEN uar.action_end_date ELSE NULL END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE WHEN uar.action_status = 'Declined' THEN uar.action_end_date ELSE NULL END AS rejected_at,
    CASE WHEN uar.action_status = 'Completed' THEN uar.action_end_date ELSE NULL END AS completed_at,
    uar.canceled_by AS cancelled_by,  -- Return the name directly for Unqork  
    uar.cancel_reason AS cancellation_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.idp_subject = uar.action_owner_user_id 
            AND a.tenant_id = '1') AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by,  -- No rejected_by data from Unqork
    safe_iso_timestamptz(uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment, -- Get the environment from the unqork_action_runs table instead of hardcoding as null
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    (
        SELECT jsonb_object_agg(
            acor.relationship_type,
            jsonb_build_object(
                'agent_id', a.id,
                'external_id', a.external_id,
                'first_name', p.first_name,
                'last_name', p.last_name,
                'middle_name', p.middle_name
            )
        ) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

CREATE VIEW unqork_tasks_view AS
SELECT 
    ut.unqork_id AS id,
    '1'::text AS tenant_id,
    NULL::text AS component_key,
    ut.task_title AS name,
    CASE
        WHEN ut.task_is_approval_task = 'checker'::text THEN 'review'::text
        ELSE 'submission'::text
    END AS type,
    CASE
        WHEN ut.task_is_discarded = 'true'::text THEN 'cancelled'::text
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN 'done'::text
        WHEN ut.task_status = 'Pending Approval'::text THEN 'pending_approval'::text
        WHEN ut.task_status = 'Ready to Begin'::text THEN 'todo'::text
        WHEN ut.task_status = 'In Progress'::text THEN 'in_progress'::text
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN 'cancelled'::text
        WHEN ut.task_status = 'Declined'::text THEN 'rejected'::text
        WHEN ut.task_status = 'Waiting'::text THEN 'waiting'::text
        WHEN ut.task_status = 'Scheduled'::text THEN 'scheduled'::text
        WHEN ut.task_status = '' THEN 'blocked'::text
        ELSE 'blocked'::text
    END AS status,
    a.id AS assigned_agent_id,
    ut.task_deadline AS deadline,
    CASE 
        WHEN ut.permitted_roles IS NULL THEN ARRAY[]::text[]
        ELSE ARRAY[ut.permitted_roles]
    END AS permitted_roles,
    COALESCE(ut.task_created_ts, ut.created_at) AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at) AS last_updated_at,
    ut.task_sched_start AS scheduled_at,
    ut.task_unblocked_at AS unblocked_at,
    NULL::timestamp with time zone AS started_at,
    ut.data,
    NULL::text AS note,
    ut.task_next_step_date AS next_step_date,
    ut.task_waiting_for AS who_waiting_on,
    ut.task_waiting_for_item AS waiting_for,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS completed_at,
    ut.task_owner AS completed_by,
    ut.task_cancelled_by AS cancelled_by,
    ut.task_cancellation_reason AS cancellation_reason,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS cancelled_at,
    ut.task_tags AS tags,
    0::bigint AS total_time_waiting_ms,
    uar.unqork_id AS action_run_id,
    uar.action_id AS action_number, -- add action_id as action_number because it's the name client is used to.
    uar.action_id AS action_run_slug, -- use action_id for the slug replacement. this is correct.
    ut.action_nickname AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents, -- rename as agents to work with agent directly assigned filter
    ut.environment,
    ut.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.action_category AS blueprint_category,
    ut.action_type AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    co.approx_aum AS aum, -- add aum from client organisation
    jsonb_build_object(
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'Action Description', jsonb_build_object(
            'value', uar.action_description
        ),
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'dataProviderName', uar.data_provider_name,
                'custodianName', uar.custodian_name -- add custodian name from unqork action
            )
        ),
        'financial_account_id', uar.financial_account_id
    )  AS action_run_data,
    NULL::jsonb AS primary_css,
    'unqork'::text AS source_system,
    co.client_segmentation AS client_segmentation
FROM unqork_tasks ut
LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id
LEFT JOIN agents a ON a.external_id = NULLIF(ut.task_owner_salentica_id, '') AND a.tenant_id = '1'::text;

CREATE VIEW enriched_action_runs AS
SELECT 
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    -- Add Case when for recommended status
      CASE
          WHEN ar.status = 'draft' AND ar.recommended = true THEN 'recommended'
          ELSE ar.status
      END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.approx_aum AS aum, -- add aum from client organisation
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents
FROM action_runs ar
LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    ar.id AS action_run_id,
    NULL::text AS action_number, -- there's no action_number in the action_runs table
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name, 'external_id', ap.external_id) AS primary_css,
    co.client_segmentation AS client_segmentation,
    co.approx_aum AS aum -- add aum from client organisation
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

-- ╔═════ 20250826043330-add_contact_details_to_agent_meetings.sql ═════╗
-- Update the agent_meetings view to include all contact details as JSONB
CREATE OR REPLACE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties,
                'contact_details', p.contact_details
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name,
                external_id,
                contact_details
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd1.role,
                            cd1.value
                        )
                        FROM contact_details cd1
                        WHERE cd1.client_id = c1.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id

                UNION ALL

                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd2.role,
                            cd2.value
                        )
                        FROM contact_details cd2
                        WHERE cd2.agent_id = a.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT 
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd3.role,
                            cd3.value
                        )
                        FROM contact_details cd3
                        WHERE cd3.client_organisation_id = co.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM client_organisations co
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type,
    m.ai_transcript_id
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20250826183241-add_next_step_to_actions.sql ═════╗
-- Add next_step_date column to action_runs & unqork_action_runs tables 
-- This will be populated by the orchestrator when tasks change state
ALTER TABLE action_runs 
ADD COLUMN next_step_date TIMESTAMP WITH TIME ZONE;

ALTER TABLE unqork_action_runs 
ADD COLUMN next_step_date TIMESTAMP WITH TIME ZONE;

-- Update views to include the new column
DROP VIEW IF EXISTS enriched_action_runs CASCADE;
DROP VIEW IF EXISTS unqork_action_runs_view CASCADE;
DROP VIEW IF EXISTS meeting_enriched_action_runs CASCADE;

-- Recreate enriched_action_runs with next_step_date from table
CREATE VIEW enriched_action_runs AS
SELECT 
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    -- Add Case when for recommended status
      CASE
          WHEN ar.status = 'draft' AND ar.recommended = true THEN 'recommended'
          ELSE ar.status
      END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.approx_aum AS aum,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
           FROM agent_client_organisation_relationships acor
             JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
          WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents
FROM action_runs ar
LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

-- Recreate unqork_action_runs_view with next_step_date from table
CREATE VIEW unqork_action_runs_view AS
SELECT 
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    ( SELECT a.id
           FROM agents a
          WHERE a.external_id = uar.action_owner_salentica_id 
            AND a.tenant_id = '1') AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum,
    -- Build custom data object with standardized structure
    jsonb_build_object(
        'action_id', uar.action_id,
        'action_rel_segment', uar.action_rel_segment,
        'action_rel_id', uar.action_rel_id,
        'action_current_task_title', uar.action_current_task_title,
        'action_no', uar.action_no,
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'action_rel_type', uar.action_rel_type,
        'actionDescription', uar.action_description,
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'custodianName', uar.custodian_name -- add custodian name in same path as avantos actions
            )
        ),
        'financial_account_id', uar.financial_account_id,
        'current_task', CASE 
            WHEN uar.action_current_task_title IS NOT NULL 
            THEN jsonb_build_object(
                'id', NULL,
                'name', uar.action_current_task_title,
                'status', 'in_progress'  -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE WHEN uar.action_status = 'Recommended' THEN true ELSE false END AS recommended,
    CASE WHEN uar.action_status = 'Canceled' THEN uar.action_end_date ELSE NULL END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE WHEN uar.action_status = 'Declined' THEN uar.action_end_date ELSE NULL END AS rejected_at,
    CASE WHEN uar.action_status = 'Completed' THEN uar.action_end_date ELSE NULL END AS completed_at,
    uar.canceled_by AS cancelled_by,  -- Return the name directly for Unqork  
    uar.cancel_reason AS cancellation_reason,
    ( SELECT a.id
           FROM agents a
          WHERE a.idp_subject = uar.action_owner_user_id 
            AND a.tenant_id = '1') AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by,  -- No rejected_by data from Unqork
    safe_iso_timestamptz(uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment, -- Get the environment from the unqork_action_runs table instead of hardcoding as null
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    (
        SELECT jsonb_object_agg(
            acor.relationship_type,
            jsonb_build_object(
                'agent_id', a.id,
                'external_id', a.external_id,
                'first_name', p.first_name,
                'last_name', p.last_name,
                'middle_name', p.middle_name
            )
        ) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    uar.next_step_date,
    'unqork'::text AS source_system
FROM unqork_action_runs uar
LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

CREATE VIEW meeting_enriched_action_runs AS
SELECT 
    marr.id as relationship_id,
    marr.tenant_id,
    marr.meeting_id,
    marr.action_run_id,
    marr.created_at as relationship_created_at,
    marr.updated_at as relationship_updated_at,
    ear.action_run_name as action_run_name,
    ear.status as action_run_status,
    ear.created_at as action_run_created_at,
    ear.blueprint_name,
    ear.blueprint_description,
    ear.blueprint_short_description
FROM meeting_action_run_relationships marr
JOIN enriched_action_runs ear ON ear.action_run_id = marr.action_run_id;

-- Initialize next_step_date for existing non-Unqork action runs
-- Find the earliest next_step_date from active tasks (todo, in_progress, waiting)
-- This is expensive so we only do this once
UPDATE action_runs 
SET next_step_date = (
    SELECT MIN(t.next_step_date)
    FROM tasks t
    WHERE t.run_id = action_runs.id
    AND t.status IN ('todo', 'in_progress', 'waiting')
    AND t.next_step_date IS NOT NULL
)
WHERE next_step_date IS NULL;

