-- ╔═════ 20250904130450-widget_customization.sql ═════╗
-- Table for widget type definitions
CREATE TABLE IF NOT EXISTS widget_definitions (
    id TEXT PRIMARY KEY NOT NULL,
    name TEXT NOT NULL UNIQUE,                              -- Globally unique widget name (e.g., 'meetings', 'actions', 'insights')
    display_name TEXT NOT NULL,                             -- User-friendly display name
    description TEXT,
    config_schema JSONB DEFAULT '{}'::JSONB,                -- Schema/shape of widget configuration (React component props interface)
    default_width INTEGER DEFAULT 2,
    default_height INTEGER DEFAULT 2,
    min_width INTEGER DEFAULT 1,
    min_height INTEGER DEFAULT 1,
    max_width INTEGER DEFAULT 4,
    max_height INTEGER DEFAULT 4,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP
);

-- Table for page widget availability (which widgets are available on which pages)
CREATE TABLE IF NOT EXISTS page_widget_availability (
    id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    page TEXT NOT NULL,
    widget_definition_id TEXT NOT NULL,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_page_widget_availability_widget_definition 
        FOREIGN KEY (widget_definition_id) 
        REFERENCES widget_definitions(id) 
        ON DELETE CASCADE
);

-- Create unique index to prevent duplicate page-widget combinations per tenant
CREATE UNIQUE INDEX IF NOT EXISTS idx_page_widget_availability_unique 
    ON page_widget_availability(tenant_id, page, widget_definition_id);

-- Create index for page lookups
CREATE INDEX IF NOT EXISTS idx_page_widget_availability_page 
    ON page_widget_availability(tenant_id, page);

-- Table for individual widget instances per agent/page
CREATE TABLE IF NOT EXISTS widgets (
    id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    agent_id TEXT NOT NULL,
    page TEXT NOT NULL,
    widget_definition_id TEXT NOT NULL,
    x INTEGER,
    y INTEGER,
    width INTEGER,
    height INTEGER,
    config JSONB DEFAULT '{}'::JSONB,                       -- Widget configuration values (instance of config_schema)
    is_visible BOOLEAN DEFAULT true,
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT fk_widgets_agent 
        FOREIGN KEY (agent_id) 
        REFERENCES agents(id) 
        ON DELETE CASCADE,
    CONSTRAINT fk_widgets_widget_definition 
        FOREIGN KEY (widget_definition_id) 
        REFERENCES widget_definitions(id) 
        ON DELETE CASCADE
);

-- Create compound index for agent+page lookups
CREATE INDEX IF NOT EXISTS idx_widgets_agent_page 
    ON widgets(tenant_id, agent_id, page);

-- Create unique constraint to ensure one widget type per agent per page
CREATE UNIQUE INDEX IF NOT EXISTS idx_widgets_unique 
    ON widgets(tenant_id, agent_id, page, widget_definition_id);

-- Table for admin-defined default widget layouts per page
CREATE TABLE IF NOT EXISTS page_default_widgets (
    id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    page TEXT NOT NULL,
    widget_definition_id TEXT NOT NULL,
    x INTEGER,
    y INTEGER,
    width INTEGER,
    height INTEGER,
    is_visible BOOLEAN DEFAULT true,
    config JSONB DEFAULT '{}'::JSONB,                       -- Default widget configuration for new users
    created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_by TEXT,
    CONSTRAINT fk_page_default_widgets_widget_definition 
        FOREIGN KEY (widget_definition_id) 
        REFERENCES widget_definitions(id) 
        ON DELETE CASCADE,
    CONSTRAINT fk_page_default_widgets_updated_by 
        FOREIGN KEY (updated_by) 
        REFERENCES agents(id) 
        ON DELETE SET NULL
);

-- Create index for page lookups
CREATE INDEX IF NOT EXISTS idx_page_default_widgets_page 
    ON page_default_widgets(tenant_id, page);

-- Create unique index to prevent duplicate default widgets per page per tenant
CREATE UNIQUE INDEX IF NOT EXISTS idx_page_default_widgets_unique 
    ON page_default_widgets(tenant_id, page, widget_definition_id);

