-- ╔═════ 20250912092641-team_client_organisation_relationships.sql ═════╗
-- 
-- Team-Client Organisation Relationships Migration
-- 
-- IMPLEMENTATION NOTES:
-- - Extends BusinessGroupService rather than creating separate service
-- - Uses soft delete pattern with deleted_at/deleted_by fields
-- - Transaction-aware methods (AddTeamToClientOrganisationTx, RemoveTeamFromClientOrganisationTx)
-- - Service layer manages transactions, repository provides Tx methods
-- - View-based queries for current (non-deleted) assignments
-- - Follows existing codebase patterns from business group relationships
--
CREATE TABLE IF NOT EXISTS
    team_client_organisation_relationships (
        id TEXT PRIMARY KEY NOT NULL, -- Unique identifier for the relationship
        tenant_id TEXT NOT NULL, -- Tenant identifier for multi-tenancy
        client_organisation_id TEXT NOT NULL, -- Foreign key to the client organisation
        business_group_id TEXT NOT NULL, -- Foreign key to the business group (team)
        role TEXT NOT NULL, -- Role of the team for this client (e.g., "primary", "support", "advisory")
        description TEXT, -- Optional description of the relationship
        additional_properties JSONB DEFAULT '{}'::JSONB, -- Additional flexible attributes for the relationship
        created_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP, -- Timestamp for record creation
        updated_at TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP, -- Timestamp for record updates
        deleted_at TIMESTAMPTZ, -- Timestamp for soft delete
        deleted_by TEXT -- Who performed the deletion
    );

-- Unique constraint: one role per team per client organisation (only for non-deleted records)
CREATE UNIQUE INDEX team_client_organisation_relationships_idx ON team_client_organisation_relationships (
    tenant_id,
    client_organisation_id,
    business_group_id,
    role
)
WHERE
    deleted_at IS NULL;

-- Performance indexes
CREATE INDEX idx_team_client_org_rel_client_org_id ON team_client_organisation_relationships (client_organisation_id);

CREATE INDEX idx_team_client_org_rel_business_group_id ON team_client_organisation_relationships (business_group_id);

CREATE INDEX idx_team_client_org_rel_tenant_id ON team_client_organisation_relationships (tenant_id);

-- Index for soft delete performance (only non-deleted records)
CREATE INDEX idx_team_client_org_rel_deleted_at ON team_client_organisation_relationships (deleted_at)
WHERE
    deleted_at IS NULL;

-- Create view for current (non-deleted) team assignments with business group details
CREATE OR REPLACE VIEW
    team_client_organisation_assignments_view AS
SELECT
    tcor.id,
    tcor.tenant_id,
    tcor.client_organisation_id,
    tcor.business_group_id,
    tcor.role,
    tcor.description,
    tcor.additional_properties,
    tcor.created_at,
    tcor.updated_at,
    co.external_id as client_organisation_external_id,
    co.name as client_organisation_name,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    bg.additional_attributes as business_group_additional_attributes,
    bg.created_at as business_group_created_at,
    bg.updated_at as business_group_updated_at
FROM
    team_client_organisation_relationships tcor
    JOIN business_groups bg ON tcor.business_group_id = bg.id
    JOIN client_organisations co ON tcor.client_organisation_id = co.id
WHERE
    tcor.deleted_at IS NULL;

-- Only show non-deleted team assignments

