-- ╔═════ 20250916080417-business-group-catagorisationm.sql ═════╗
CREATE TABLE IF NOT EXISTS business_group_coverage (
    id TEXT NOT NULL PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    business_group_id TEXT NOT NULL,      -- References business_groups where group_type = 'advisor_team'
    coverage_lookup_id TEXT NOT NULL,     -- References lookups.id where category = 'business_group_coverage'
    priority INTEGER NOT NULL DEFAULT 1, -- Lower = higher priority (0 = highest, 1 = high, etc.)
    capacity_limit INTEGER,               -- Optional: max clients for this specific coverage
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT CURRENT_TIMESTAMP,

    CONSTRAINT fk_business_group_coverage_lookup
        FOREIGN KEY (coverage_lookup_id) REFERENCES lookups(id)
);

CREATE INDEX IF NOT EXISTS idx_business_group_coverage_tenant_id ON business_group_coverage(tenant_id);
CREATE INDEX IF NOT EXISTS idx_business_group_coverage_group ON business_group_coverage(tenant_id, business_group_id);
CREATE INDEX IF NOT EXISTS idx_business_group_coverage_lookup ON business_group_coverage(tenant_id, coverage_lookup_id);
CREATE INDEX IF NOT EXISTS idx_business_group_coverage_priority ON business_group_coverage(tenant_id, coverage_lookup_id, priority);

CREATE VIEW business_group_coverage_view AS
SELECT
    bgc.id,
    bgc.tenant_id,
    bgc.business_group_id,
    bg.name AS business_group_name,
    bgc.coverage_lookup_id,
    l.value AS coverage_value,
    l.description AS coverage_description,
    bgc.priority,
    bgc.capacity_limit,
    bgc.created_at,
    bgc.updated_at
FROM business_group_coverage bgc
LEFT JOIN lookups l ON bgc.coverage_lookup_id = l.id
LEFT JOIN business_groups bg ON bgc.business_group_id = bg.id;

-- ╔═════ 20250916153607-bus-group-search.sql ═════╗
-- Create comprehensive view for business group coverage details
-- This view shows ALL business groups and their coverage assignments (if any)
-- Business groups without coverage will have NULL coverage fields but still show agent/client counts
CREATE VIEW business_group_coverage_detail_view AS
SELECT
    MAX(bgc.id) as coverage_id,
    bg.tenant_id,
    MAX(l.id) as lookup_id,
    MAX(l.category) as category,
    MAX(l.value) as coverage_value,
    MAX(l.description) as coverage_description,
    MAX(l.external_id) as coverage_external_id,
    bg.id as business_group_id,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    MAX(bgc.priority) as priority,
    MAX(bgc.capacity_limit) as capacity_limit,
    COUNT(DISTINCT abgr.agent_id) as agent_count,
    COUNT(DISTINCT tcor.client_organisation_id) as client_organisation_count,

    -- Aggregated agents as JSONB (always present if business group has agents)
    COALESCE(
        json_agg(
            jsonb_build_object(
                'agent_id', a.id,
                'first_name', COALESCE(p.first_name, apv.first_name),
                'last_name', COALESCE(p.last_name, apv.last_name),
                'title', COALESCE(p.title, apv.title),
                'email', email_contacts.value,
                'phone', phone_contacts.value,
                'role', abgr.role,
                'description', abgr.description,
                'license', a.license,
                'years_of_experience', a.years_of_experience,
                'specialization', a.specialization
            ) ORDER BY
                CASE abgr.role
                    WHEN 'lead_advisor' THEN 1
                    WHEN 'manager' THEN 2
                    WHEN 'senior_advisor' THEN 3
                    WHEN 'advisor' THEN 4
                    WHEN 'secondary_advisor' THEN 5
                    WHEN 'associate_advisor' THEN 6
                    WHEN 'junior_advisor' THEN 7
                    WHEN 'analyst' THEN 8
                    WHEN 'secretary' THEN 9
                    ELSE 10
                END,
                COALESCE(p.last_name, apv.last_name), COALESCE(p.first_name, apv.first_name)
        ) FILTER (WHERE a.id IS NOT NULL),
        '[]'::json
    )::jsonb as agents,

    -- Timestamps - use business group timestamps if no coverage, otherwise coverage timestamps
    COALESCE(MAX(bgc.created_at), bg.created_at) as created_at,
    COALESCE(MAX(bgc.updated_at), bg.updated_at) as updated_at

FROM business_groups bg
-- LEFT JOIN to coverage so business groups without coverage still appear
LEFT JOIN business_group_coverage bgc ON bg.id = bgc.business_group_id AND bgc.tenant_id = bg.tenant_id
-- LEFT JOIN to lookups (will be NULL for business groups without coverage)
LEFT JOIN lookups l ON bgc.coverage_lookup_id = l.id
-- Always join agent relationships to show team composition
LEFT JOIN agent_business_group_relationships abgr ON bg.id = abgr.business_group_id AND abgr.tenant_id = bg.tenant_id
LEFT JOIN agents a ON abgr.agent_id = a.id AND a.tenant_id = bg.tenant_id
LEFT JOIN persons p ON a.person_id = p.id AND p.tenant_id = bg.tenant_id
-- Fallback to agent_person_view for denormalized data
LEFT JOIN agent_person_view apv ON a.id = apv.agent_id AND apv.tenant_id = bg.tenant_id
-- Contact details joins using the correct agent_id column
LEFT JOIN contact_details email_contacts ON a.id = email_contacts.agent_id
    AND email_contacts.tenant_id = bg.tenant_id
    AND email_contacts.role = 'preferred_email'
    AND email_contacts.type = 'email'
LEFT JOIN contact_details phone_contacts ON a.id = phone_contacts.agent_id
    AND phone_contacts.tenant_id = bg.tenant_id
    AND phone_contacts.role = 'preferred_phone'
    AND phone_contacts.type = 'phone'
LEFT JOIN team_client_organisation_relationships tcor ON bg.id = tcor.business_group_id
    AND tcor.tenant_id = bg.tenant_id
    AND tcor.deleted_at IS NULL
WHERE bg.status IS NOT NULL
GROUP BY
    bg.tenant_id,
    bg.id, bg.name, bg.external_id, bg.group_type, bg.status, bg.description,
    bg.created_at, bg.updated_at
ORDER BY
    -- Sort covered groups first, then uncovered groups
    CASE WHEN MAX(l.value) IS NOT NULL THEN 0 ELSE 1 END,
    MAX(l.value),
    MAX(bgc.priority),
    bg.name;

-- Create indexes to optimize view performance
CREATE INDEX IF NOT EXISTS idx_business_group_coverage_detail_search
ON business_group_coverage (tenant_id, priority);

CREATE INDEX IF NOT EXISTS idx_agent_business_group_relationships_search
ON agent_business_group_relationships (tenant_id, business_group_id);

CREATE INDEX IF NOT EXISTS idx_team_client_org_relationships_search
ON team_client_organisation_relationships (tenant_id, business_group_id, deleted_at);

