-- ╔═════ 20250918133506-add_manager_id_to_agent_person_view.sql ═════╗
CREATE OR REPLACE VIEW agent_person_view AS
SELECT
    a.id AS agent_id,
    a.tenant_id,
    a.organisation_id,
    a.license,
    a.compliance_record,
    a.qualification,
    a.specialization,
    a.advisor_identification,
    a.years_of_experience,
    a.regulatory_status,
    a.type,
    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    a.additional_attributes,
    a.external_id,
    (
        SELECT COALESCE(
            jsonb_object_agg(
                cd.role,
                jsonb_build_object('id', cd.id, 'type', cd.type, 'value', cd.value)
            ),
            '{}'::jsonb
        )
        FROM contact_details cd
        WHERE cd.agent_id = a.id
    ) AS contacts,
    a.created_at,
    a.updated_at,
    a.idp_subject,
    a.active,
    a.manager_id
FROM agents a
JOIN persons p ON a.person_id = p.id;

-- ╔═════ 20250918153223-agent_team_hierarchy_view.sql ═════╗
-- View to get team hierarchy information for managers
CREATE OR REPLACE VIEW agent_team_hierarchy_view AS
WITH RECURSIVE team_hierarchy AS (
    -- Base case: Start with all agents who are managers (have direct reports)
    SELECT DISTINCT
        m.id AS root_manager_id,
        a.id AS agent_id,
        a.tenant_id,
        a.external_id,
        a.manager_id,
        a.organisation_id,
        a.type AS agent_type,
        a.active,
        a.idp_subject,
        p.first_name,
        p.middle_name,
        p.last_name,
        p.title,
        0 AS level,
        ARRAY[a.id] AS path,
        a.id = m.id AS is_root
    FROM agents a
    JOIN persons p ON a.person_id = p.id
    JOIN agents m ON m.tenant_id = a.tenant_id
    WHERE a.tenant_id = m.tenant_id
        AND (a.manager_id = m.id OR a.id = m.id)
        AND EXISTS (
            -- Only include managers who have at least one direct report
            SELECT 1 FROM agents sub
            WHERE sub.manager_id = m.id
            AND sub.tenant_id = m.tenant_id
        )

    UNION ALL

    -- Recursive case: Get all subordinates
    SELECT
        th.root_manager_id,
        a.id AS agent_id,
        a.tenant_id,
        a.external_id,
        a.manager_id,
        a.organisation_id,
        a.type AS agent_type,
        a.active,
        a.idp_subject,
        p.first_name,
        p.middle_name,
        p.last_name,
        p.title,
        th.level + 1 AS level,
        th.path || a.id AS path,
        false AS is_root
    FROM team_hierarchy th
    JOIN agents a ON a.manager_id = th.agent_id AND a.tenant_id = th.tenant_id
    JOIN persons p ON a.person_id = p.id
    WHERE NOT a.id = ANY(th.path) -- Prevent cycles
)
SELECT
    th.root_manager_id,
    th.agent_id,
    th.tenant_id,
    th.external_id,
    th.manager_id,
    th.organisation_id,
    th.agent_type,
    th.active,
    th.idp_subject,
    th.first_name,
    th.middle_name,
    th.last_name,
    th.title,
    th.level,
    th.path,
    th.is_root,
    -- Get primary email from contact_details
    (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.agent_id = th.agent_id
        AND cd.role = 'primary_email'
        LIMIT 1
    ) AS email,
    -- Count direct reports for this agent
    (
        SELECT COUNT(*)
        FROM agents sub
        WHERE sub.manager_id = th.agent_id
        AND sub.tenant_id = th.tenant_id
    ) AS direct_reports_count
FROM team_hierarchy th
ORDER BY th.root_manager_id, th.level, th.last_name, th.first_name;

-- View to get summary information about all teams
CREATE OR REPLACE VIEW agent_team_summary_view AS
WITH team_stats AS (
    SELECT
        a.id AS manager_id,
        a.tenant_id,
        a.external_id,
        a.organisation_id,
        a.type AS agent_type,
        a.active,
        p.first_name,
        p.middle_name,
        p.last_name,
        p.title,
        -- Get primary email
        (
            SELECT cd.value
            FROM contact_details cd
            WHERE cd.agent_id = a.id
            AND cd.role = 'primary_email'
            LIMIT 1
        ) AS email,
        -- Count direct reports
        (
            SELECT COUNT(*)
            FROM agents sub
            WHERE sub.manager_id = a.id
            AND sub.tenant_id = a.tenant_id
        ) AS direct_reports_count
    FROM agents a
    JOIN persons p ON a.person_id = p.id
    WHERE EXISTS (
        -- Only include agents who have at least one direct report
        SELECT 1 FROM agents sub
        WHERE sub.manager_id = a.id
        AND sub.tenant_id = a.tenant_id
    )
)
SELECT
    ts.*,
    -- Calculate total reports (all levels below)
    (
        SELECT COUNT(DISTINCT agent_id) - 1 -- Subtract 1 to exclude the manager themselves
        FROM agent_team_hierarchy_view
        WHERE root_manager_id = ts.manager_id
        AND tenant_id = ts.tenant_id
    ) AS total_reports_count
FROM team_stats ts;

-- ╔═════ 20250918191526-add_extra_properties_to_client_org_relationships_view.sql ═════╗
DROP VIEW IF EXISTS client_org_client_org_relationships_view;
CREATE VIEW client_org_client_org_relationships_view AS
SELECT
    cn.id AS connection_id,
    cn.initiating_entity_type,
    co1.id AS initiating_client_organisation_id,
    co1.external_id AS initiating_client_organisation_external_id,
    co1.name AS initiating_client_organisation_name,
    cn.participating_entity_type,
    co2.id AS participating_client_organisation_id,
    co2.external_id AS participating_client_organisation_external_id,
    co2.name AS participating_client_organisation_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value,
    cn.extra_properties AS connection_extra_properties,
    cn.created_at,
    cn.updated_at
FROM connections cn
LEFT JOIN client_organisations co1
    ON cn.initiating_entity_id = co1.id
LEFT JOIN client_organisations co2
    ON cn.participating_entity_id = co2.id
LEFT JOIN lookups l
    ON cn.relationship_type = l.id
WHERE cn.initiating_entity_type = 'client_organisation'
  AND cn.participating_entity_type = 'client_organisation';

DROP VIEW IF EXISTS client_client_relationships_view;
CREATE VIEW client_client_relationships_view AS
SELECT
    cn.id AS connection_id,
    c1.organisation_id AS initiating_organisation_id,
    cn.initiating_entity_type,
    c1.id AS initiating_client_id,
    c1.external_id AS initiating_client_external_id,
    p1.first_name AS initiating_first_name,
    p1.last_name AS initiating_last_name,
    cn.participating_entity_type,
    c2.id AS participating_client_id,
    c2.external_id AS participating_client_external_id,
    p2.first_name AS participating_first_name,
    p2.last_name AS participating_last_name,
    cn.relationship_type AS relationship_type_id,
    l.category AS relationship_category,
    l.value AS relationship_type_value,
    cn.extra_properties AS connection_extra_properties,
    cn.created_at,
    cn.updated_at
FROM connections cn
LEFT JOIN clients c1
    ON cn.initiating_entity_id = c1.id
LEFT JOIN persons p1
    ON c1.person_id = p1.id
LEFT JOIN clients c2
    ON cn.participating_entity_id = c2.id
LEFT JOIN persons p2
    ON c2.person_id = p2.id
LEFT JOIN lookups l
    ON cn.relationship_type = l.id
WHERE cn.initiating_entity_type = 'client'
  AND cn.participating_entity_type = 'client'
  AND (c1.deleted_at IS NULL OR c1.id IS NULL)
  AND (c2.deleted_at IS NULL OR c2.id IS NULL);

-- ╔═════ 20250918224427-add_end_date_to_vpoc_onboarding.sql ═════╗
DROP VIEW IF EXISTS vpoc_onboarding_view;

ALTER TABLE vpoc_onboarding
    ADD COLUMN end_date TIMESTAMP WITH TIME ZONE;

CREATE VIEW vpoc_onboarding_view AS
SELECT
    vo.id,
    vo.tenant_id,
    vo.primary_client_id,
    vo.relationship_id,
    vo.action_ids,
    vo.started_at,
    vo.end_date,
    cpv.first_name AS primary_client_first_name,
    cpv.last_name AS primary_client_last_name,
    corv.client_organisation_id,
    corv.client_organisation_name,
    corv.role AS relationship_role,
    corv.description AS relationship_description
FROM vpoc_onboarding vo
JOIN client_person_view cpv
    ON vo.primary_client_id = cpv.client_id
    AND vo.tenant_id = cpv.tenant_id
JOIN client_organisation_relationships_view corv
    ON vo.relationship_id = corv.client_client_organisation_relationship_id
    AND vo.tenant_id = corv.tenant_id;

-- ╔═════ 20250919140756-add_business_group_coverage_lookup_summary_view.sql ═════╗
-- Create view for business group coverage lookup summary
-- This view aggregates coverage lookups with team counts, agent totals, and business group details
CREATE VIEW business_group_coverage_lookup_summary_view AS
SELECT
    l.id as lookup_id,
    l.tenant_id,
    l.category,
    l.value as coverage_value,
    l.description as coverage_description,
    l.external_id as coverage_external_id,
    COALESCE(COUNT(DISTINCT bgc.business_group_id), 0) as team_count,
    COALESCE(SUM(bg_data.agent_count), 0) as total_agents,
    COALESCE(SUM(bg_data.client_count), 0) as total_clients,
    COALESCE(
        JSON_AGG(
            CASE
                WHEN bgc.business_group_id IS NOT NULL THEN
                    JSON_BUILD_OBJECT(
                        'business_group_id', bg_data.business_group_id,
                        'business_group_name', bg_data.business_group_name,
                        'business_group_external_id', bg_data.business_group_external_id,
                        'agent_count', bg_data.agent_count,
                        'client_count', bg_data.client_count,
                        'priority', bgc.priority,
                        'capacity_limit', bgc.capacity_limit
                    )
                ELSE NULL
            END
            ORDER BY bgc.priority ASC NULLS LAST, bg_data.business_group_name ASC
        ) FILTER (WHERE bgc.business_group_id IS NOT NULL),
        '[]'
    )::jsonb as business_groups
FROM lookups l
LEFT JOIN business_group_coverage bgc ON l.id = bgc.coverage_lookup_id
LEFT JOIN (
    SELECT
        bg.id as business_group_id,
        bg.tenant_id,
        bg.name as business_group_name,
        bg.external_id as business_group_external_id,
        COALESCE(agent_counts.agent_count, 0) as agent_count,
        COALESCE(client_counts.client_count, 0) as client_count
    FROM business_groups bg
    LEFT JOIN (
        SELECT
            abgr.business_group_id,
            abgr.tenant_id,
            COUNT(DISTINCT abgr.agent_id) as agent_count
        FROM agent_business_group_relationships abgr
        GROUP BY abgr.business_group_id, abgr.tenant_id
    ) agent_counts ON bg.id = agent_counts.business_group_id AND bg.tenant_id = agent_counts.tenant_id
    LEFT JOIN (
        SELECT
            tco.business_group_id,
            tco.tenant_id,
            COUNT(DISTINCT tco.client_organisation_id) as client_count
        FROM team_client_organisation_relationships tco
        WHERE tco.deleted_at IS NULL
        GROUP BY tco.business_group_id, tco.tenant_id
    ) client_counts ON bg.id = client_counts.business_group_id AND bg.tenant_id = client_counts.tenant_id
) bg_data ON bgc.business_group_id = bg_data.business_group_id AND bgc.tenant_id = bg_data.tenant_id
WHERE l.category IS NOT NULL
GROUP BY l.id, l.tenant_id, l.category, l.value, l.description, l.external_id
ORDER BY l.value ASC;

-- Create indexes to optimize view performance
CREATE INDEX IF NOT EXISTS idx_business_group_coverage_lookup_summary
ON business_group_coverage (tenant_id, coverage_lookup_id, priority);

CREATE INDEX IF NOT EXISTS idx_lookups_coverage_summary
ON lookups (tenant_id, category, value);

-- ╔═════ 20250919153821-add_taskNo_column_in_unqork_tasks.sql ═════╗
ALTER TABLE unqork_tasks ADD COLUMN IF NOT EXISTS task_no INTEGER GENERATED ALWAYS AS ((data -> 'taskTracking' ->> 'taskNo')::INTEGER) STORED;

DROP VIEW IF EXISTS unqork_tasks_view;

CREATE VIEW unqork_tasks_view AS
SELECT 
    ut.unqork_id AS id,
    '1'::text AS tenant_id,
    NULL::text AS component_key,
    ut.task_title AS name,
    CASE
        WHEN ut.task_is_approval_task = 'checker'::text THEN 'review'::text
        ELSE 'submission'::text
    END AS type,
    CASE
        WHEN ut.task_is_discarded = 'true'::text THEN 'cancelled'::text
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN 'done'::text
        WHEN ut.task_status = 'Pending Approval'::text THEN 'pending_approval'::text
        WHEN ut.task_status = 'Ready to Begin'::text THEN 'todo'::text
        WHEN ut.task_status = 'In Progress'::text THEN 'in_progress'::text
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN 'cancelled'::text
        WHEN ut.task_status = 'Declined'::text THEN 'rejected'::text
        WHEN ut.task_status = 'Waiting'::text THEN 'waiting'::text
        WHEN ut.task_status = 'Scheduled'::text THEN 'scheduled'::text
        WHEN ut.task_status = '' THEN 'blocked'::text
        ELSE 'blocked'::text
    END AS status,
    a.id AS assigned_agent_id,
    ut.task_deadline AS deadline,
    CASE 
        WHEN ut.permitted_roles IS NULL THEN ARRAY[]::text[]
        ELSE ARRAY[ut.permitted_roles]
    END AS permitted_roles,
    COALESCE(ut.task_created_ts, ut.created_at) AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at) AS last_updated_at,
    ut.task_sched_start AS scheduled_at,
    ut.task_unblocked_at AS unblocked_at,
    NULL::timestamp with time zone AS started_at,
    ut.data,
    NULL::text AS note,
    ut.task_next_step_date AS next_step_date,
    ut.task_waiting_for AS who_waiting_on,
    ut.task_waiting_for_item AS waiting_for,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS completed_at,
    ut.task_owner AS completed_by,
    ut.task_cancelled_by AS cancelled_by,
    ut.task_cancellation_reason AS cancellation_reason,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS cancelled_at,
    ut.task_tags AS tags,
    0::bigint AS total_time_waiting_ms,
    uar.unqork_id AS action_run_id,
    uar.action_id AS action_number, -- add action_id as action_number because it's the name client is used to.
    uar.action_id AS action_run_slug, -- use action_id for the slug replacement. this is correct.
    ut.action_nickname AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents, -- rename as agents to work with agent directly assigned filter
    ut.environment,
    ut.client_organisation_id,
    ut.task_no AS task_no, -- add the generated task_no column here
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.action_category AS blueprint_category,
    ut.action_type AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    co.approx_aum AS aum, -- add aum from client organisation
    jsonb_build_object(
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'Action Description', jsonb_build_object(
            'value', uar.action_description
        ),
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'dataProviderName', uar.data_provider_name,
                'custodianName', uar.custodian_name -- add custodian name from unqork action
            )
        ),
        'financial_account_id', uar.financial_account_id
    )  AS action_run_data,
    NULL::jsonb AS primary_css,
    'unqork'::text AS source_system,
    co.client_segmentation AS client_segmentation
FROM unqork_tasks ut
LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id
LEFT JOIN agents a ON a.external_id = NULLIF(ut.task_owner_salentica_id, '') AND a.tenant_id = '1'::text;

-- ╔═════ 20250921090005-add-coverages-jsonb-to-view.sql ═════╗
-- Drop the existing view
DROP VIEW IF EXISTS business_group_coverage_detail_view;

-- Recreate view with additional coverages JSONB array (non-breaking change)
-- Keeps existing single coverage fields for backward compatibility
-- Adds new 'coverages' field with ALL coverage assignments as JSONB array
CREATE VIEW business_group_coverage_detail_view AS
SELECT
    MAX(bgc.id) as coverage_id,
    bg.tenant_id,
    MAX(l.id) as lookup_id,
    MAX(l.category) as category,
    MAX(l.value) as coverage_value,
    MAX(l.description) as coverage_description,
    MAX(l.external_id) as coverage_external_id,
    bg.id as business_group_id,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    MAX(bgc.priority) as priority,
    MAX(bgc.capacity_limit) as capacity_limit,
    COUNT(DISTINCT abgr.agent_id) as agent_count,
    COUNT(DISTINCT tcor.client_organisation_id) as client_organisation_count,

    -- NEW: All coverage assignments as JSONB array
    COALESCE(
        json_agg(
            jsonb_build_object(
                'coverage_id', bgc.id,
                'lookup_id', l.id,
                'category', l.category,
                'value', l.value,
                'description', l.description,
                'external_id', l.external_id,
                'priority', bgc.priority,
                'capacity_limit', bgc.capacity_limit,
                'created_at', bgc.created_at,
                'updated_at', bgc.updated_at
            ) ORDER BY bgc.priority, l.category, l.value
        ) FILTER (WHERE bgc.id IS NOT NULL),
        '[]'::json
    )::jsonb as coverages,

    -- Aggregated agents as JSONB (always present if business group has agents)
    COALESCE(
        json_agg(
            jsonb_build_object(
                'agent_id', a.id,
                'first_name', COALESCE(p.first_name, apv.first_name),
                'last_name', COALESCE(p.last_name, apv.last_name),
                'title', COALESCE(p.title, apv.title),
                'email', email_contacts.value,
                'phone', phone_contacts.value,
                'role', abgr.role,
                'description', abgr.description,
                'license', a.license,
                'years_of_experience', a.years_of_experience,
                'specialization', a.specialization
            ) ORDER BY
                CASE abgr.role
                    WHEN 'lead_advisor' THEN 1
                    WHEN 'manager' THEN 2
                    WHEN 'senior_advisor' THEN 3
                    WHEN 'advisor' THEN 4
                    WHEN 'secondary_advisor' THEN 5
                    WHEN 'associate_advisor' THEN 6
                    WHEN 'junior_advisor' THEN 7
                    WHEN 'analyst' THEN 8
                    WHEN 'secretary' THEN 9
                    ELSE 10
                END,
                COALESCE(p.last_name, apv.last_name), COALESCE(p.first_name, apv.first_name)
        ) FILTER (WHERE a.id IS NOT NULL),
        '[]'::json
    )::jsonb as agents,

    -- Timestamps - use business group timestamps if no coverage, otherwise coverage timestamps
    COALESCE(MAX(bgc.created_at), bg.created_at) as created_at,
    COALESCE(MAX(bgc.updated_at), bg.updated_at) as updated_at

FROM business_groups bg
-- LEFT JOIN to coverage so business groups without coverage still appear
LEFT JOIN business_group_coverage bgc ON bg.id = bgc.business_group_id AND bgc.tenant_id = bg.tenant_id
-- LEFT JOIN to lookups (will be NULL for business groups without coverage)
LEFT JOIN lookups l ON bgc.coverage_lookup_id = l.id
-- Always join agent relationships to show team composition
LEFT JOIN agent_business_group_relationships abgr ON bg.id = abgr.business_group_id AND abgr.tenant_id = bg.tenant_id
LEFT JOIN agents a ON abgr.agent_id = a.id AND a.tenant_id = bg.tenant_id
LEFT JOIN persons p ON a.person_id = p.id AND p.tenant_id = bg.tenant_id
-- Fallback to agent_person_view for denormalized data
LEFT JOIN agent_person_view apv ON a.id = apv.agent_id AND apv.tenant_id = bg.tenant_id
-- Contact details joins using the correct agent_id column
LEFT JOIN contact_details email_contacts ON a.id = email_contacts.agent_id
    AND email_contacts.tenant_id = bg.tenant_id
    AND email_contacts.role = 'preferred_email'
    AND email_contacts.type = 'email'
LEFT JOIN contact_details phone_contacts ON a.id = phone_contacts.agent_id
    AND phone_contacts.tenant_id = bg.tenant_id
    AND phone_contacts.role = 'preferred_phone'
    AND phone_contacts.type = 'phone'
LEFT JOIN team_client_organisation_relationships tcor ON bg.id = tcor.business_group_id
    AND tcor.tenant_id = bg.tenant_id
    AND tcor.deleted_at IS NULL
WHERE bg.status IS NOT NULL
GROUP BY
    bg.tenant_id,
    bg.id, bg.name, bg.external_id, bg.group_type, bg.status, bg.description,
    bg.created_at, bg.updated_at
ORDER BY
    -- Sort covered groups first, then uncovered groups
    CASE WHEN MAX(l.value) IS NOT NULL THEN 0 ELSE 1 END,
    MAX(l.value),
    MAX(bgc.priority),
    bg.name;

-- ╔═════ 20250922134615-add-extra-prop-to-business_group_client_organisation_assignments_view.sql ═════╗
DROP VIEW IF EXISTS business_group_client_organisation_assignments_view;

CREATE OR REPLACE VIEW business_group_client_organisation_assignments_view AS
SELECT
    tcor.id,
    tcor.tenant_id,
    tcor.client_organisation_id,
    tcor.business_group_id,
    tcor.role,
    tcor.description,
    tcor.additional_properties,
    tcor.created_at,
    tcor.updated_at,
    co.external_id as client_organisation_external_id,
    co.name as client_organisation_name,
    co.extra_properties as client_organisation_extra_properties,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    bg.additional_attributes as business_group_additional_attributes,
    bg.created_at as business_group_created_at,
    bg.updated_at as business_group_updated_at,
    co.client_segmentation,
    COALESCE(client_counts.client_count, 0) as client_count
FROM team_client_organisation_relationships tcor
    JOIN business_groups bg ON tcor.business_group_id = bg.id
    JOIN client_organisations co ON tcor.client_organisation_id = co.id
    LEFT JOIN (
        SELECT
            c.organisation_id,
            COUNT(DISTINCT c.id) as client_count
        FROM clients c
        WHERE c.deleted_at IS NULL  -- Only count active clients
        GROUP BY c.organisation_id
    ) client_counts ON co.id = client_counts.organisation_id
WHERE tcor.deleted_at IS NULL;

-- ╔═════ 20250922154343-add-extra-prop-to-business_group_coverage_lookup_summary_view.sql ═════╗
DROP VIEW IF EXISTS business_group_coverage_lookup_summary_view;

CREATE VIEW business_group_coverage_lookup_summary_view AS
SELECT
    l.id as lookup_id,
    l.tenant_id,
    l.category,
    l.value as coverage_value,
    l.description as coverage_description,
    l.external_id as coverage_external_id,
    COALESCE(COUNT(DISTINCT bgc.business_group_id), 0) as team_count,
    COALESCE(SUM(bg_data.agent_count), 0) as total_agents,
    COALESCE(SUM(bg_data.client_count), 0) as total_clients,
    COALESCE(
        JSON_AGG(
            CASE
                WHEN bgc.business_group_id IS NOT NULL THEN
                    JSON_BUILD_OBJECT(
                        'business_group_id', bg_data.business_group_id,
                        'business_group_name', bg_data.business_group_name,
                        'business_group_external_id', bg_data.business_group_external_id,
                        'business_group_extra_properties', bg_data.business_group_extra_properties,
                        'agent_count', bg_data.agent_count,
                        'client_count', bg_data.client_count,
                        'priority', bgc.priority,
                        'capacity_limit', bgc.capacity_limit
                    )
                ELSE NULL
            END
            ORDER BY bgc.priority ASC NULLS LAST, bg_data.business_group_name ASC
        ) FILTER (WHERE bgc.business_group_id IS NOT NULL),
        '[]'
    )::jsonb as business_groups
FROM lookups l
LEFT JOIN business_group_coverage bgc ON l.id = bgc.coverage_lookup_id
LEFT JOIN (
    SELECT
        bg.id as business_group_id,
        bg.tenant_id,
        bg.name as business_group_name,
        bg.external_id as business_group_external_id,
        bg.additional_attributes as business_group_extra_properties,
        COALESCE(agent_counts.agent_count, 0) as agent_count,
        COALESCE(client_counts.client_count, 0) as client_count
    FROM business_groups bg
    LEFT JOIN (
        SELECT
            abgr.business_group_id,
            abgr.tenant_id,
            COUNT(DISTINCT abgr.agent_id) as agent_count
        FROM agent_business_group_relationships abgr
        GROUP BY abgr.business_group_id, abgr.tenant_id
    ) agent_counts ON bg.id = agent_counts.business_group_id AND bg.tenant_id = agent_counts.tenant_id
    LEFT JOIN (
        SELECT
            tco.business_group_id,
            tco.tenant_id,
            COUNT(DISTINCT tco.client_organisation_id) as client_count
        FROM team_client_organisation_relationships tco
        WHERE tco.deleted_at IS NULL
        GROUP BY tco.business_group_id, tco.tenant_id
    ) client_counts ON bg.id = client_counts.business_group_id AND bg.tenant_id = client_counts.tenant_id
) bg_data ON bgc.business_group_id = bg_data.business_group_id AND bgc.tenant_id = bg_data.tenant_id
WHERE l.category IS NOT NULL
GROUP BY l.id, l.tenant_id, l.category, l.value, l.description, l.external_id
ORDER BY l.value ASC;

-- ╔═════ 20250922163542-add-extra-prop-to-business_group_coverage_detail_view.sql ═════╗
DROP VIEW IF EXISTS business_group_coverage_detail_view;

CREATE VIEW business_group_coverage_detail_view AS
SELECT
    MAX(bgc.id) as coverage_id,
    bg.tenant_id,
    MAX(l.id) as lookup_id,
    MAX(l.category) as category,
    MAX(l.value) as coverage_value,
    MAX(l.description) as coverage_description,
    MAX(l.external_id) as coverage_external_id,
    bg.id as business_group_id,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    bg.additional_attributes as business_group_extra_properties,
    MAX(bgc.priority) as priority,
    MAX(bgc.capacity_limit) as capacity_limit,
    COUNT(DISTINCT abgr.agent_id) as agent_count,
    COUNT(DISTINCT tcor.client_organisation_id) as client_organisation_count,
    COALESCE(
        json_agg(
            jsonb_build_object(
                'coverage_id', bgc.id,
                'lookup_id', l.id,
                'category', l.category,
                'value', l.value,
                'description', l.description,
                'external_id', l.external_id,
                'priority', bgc.priority,
                'capacity_limit', bgc.capacity_limit,
                'created_at', bgc.created_at,
                'updated_at', bgc.updated_at
            ) ORDER BY bgc.priority, l.category, l.value
        ) FILTER (WHERE bgc.id IS NOT NULL),
        '[]'::json
    )::jsonb as coverages,
    COALESCE(
        json_agg(
            jsonb_build_object(
                'agent_id', a.id,
                'first_name', COALESCE(p.first_name, apv.first_name),
                'last_name', COALESCE(p.last_name, apv.last_name),
                'title', COALESCE(p.title, apv.title),
                'email', email_contacts.value,
                'phone', phone_contacts.value,
                'role', abgr.role,
                'description', abgr.description,
                'license', a.license,
                'years_of_experience', a.years_of_experience,
                'specialization', a.specialization
            ) ORDER BY
                CASE abgr.role
                    WHEN 'lead_advisor' THEN 1
                    WHEN 'manager' THEN 2
                    WHEN 'senior_advisor' THEN 3
                    WHEN 'advisor' THEN 4
                    WHEN 'secondary_advisor' THEN 5
                    WHEN 'associate_advisor' THEN 6
                    WHEN 'junior_advisor' THEN 7
                    WHEN 'analyst' THEN 8
                    WHEN 'secretary' THEN 9
                    ELSE 10
                END,
                COALESCE(p.last_name, apv.last_name), COALESCE(p.first_name, apv.first_name)
        ) FILTER (WHERE a.id IS NOT NULL),
        '[]'::json
    )::jsonb as agents,

    -- Timestamps - use business group timestamps if no coverage, otherwise coverage timestamps
    COALESCE(MAX(bgc.created_at), bg.created_at) as created_at,
    COALESCE(MAX(bgc.updated_at), bg.updated_at) as updated_at

FROM business_groups bg
-- LEFT JOIN to coverage so business groups without coverage still appear
LEFT JOIN business_group_coverage bgc ON bg.id = bgc.business_group_id AND bgc.tenant_id = bg.tenant_id
-- LEFT JOIN to lookups (will be NULL for business groups without coverage)
LEFT JOIN lookups l ON bgc.coverage_lookup_id = l.id
-- Always join agent relationships to show team composition
LEFT JOIN agent_business_group_relationships abgr ON bg.id = abgr.business_group_id AND abgr.tenant_id = bg.tenant_id
LEFT JOIN agents a ON abgr.agent_id = a.id AND a.tenant_id = bg.tenant_id
LEFT JOIN persons p ON a.person_id = p.id AND p.tenant_id = bg.tenant_id
-- Fallback to agent_person_view for denormalized data
LEFT JOIN agent_person_view apv ON a.id = apv.agent_id AND apv.tenant_id = bg.tenant_id
-- Contact details joins using the correct agent_id column
LEFT JOIN contact_details email_contacts ON a.id = email_contacts.agent_id
    AND email_contacts.tenant_id = bg.tenant_id
    AND email_contacts.role = 'preferred_email'
    AND email_contacts.type = 'email'
LEFT JOIN contact_details phone_contacts ON a.id = phone_contacts.agent_id
    AND phone_contacts.tenant_id = bg.tenant_id
    AND phone_contacts.role = 'preferred_phone'
    AND phone_contacts.type = 'phone'
LEFT JOIN team_client_organisation_relationships tcor ON bg.id = tcor.business_group_id
    AND tcor.tenant_id = bg.tenant_id
    AND tcor.deleted_at IS NULL
WHERE bg.status IS NOT NULL
GROUP BY
    bg.tenant_id,
    bg.id, bg.name, bg.external_id, bg.group_type, bg.status, bg.description,
    bg.created_at, bg.updated_at
ORDER BY
    -- Sort covered groups first, then uncovered groups
    CASE WHEN MAX(l.value) IS NOT NULL THEN 0 ELSE 1 END,
    MAX(l.value),
    MAX(bgc.priority),
    bg.name;

-- ╔═════ 20250923130536-optimize_business_group_client_org_assignments.sql ═════╗
DROP VIEW IF EXISTS business_group_client_organisation_assignments_view;

CREATE VIEW business_group_client_organisation_assignments_view AS
SELECT
    tcor.id,
    tcor.tenant_id,
    tcor.client_organisation_id,
    tcor.business_group_id,
    tcor.role,
    tcor.description,
    tcor.additional_properties,
    tcor.created_at,
    tcor.updated_at,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.extra_properties AS client_organisation_extra_properties,
    bg.name AS business_group_name,
    bg.external_id AS business_group_external_id,
    bg.group_type AS business_group_type,
    bg.status AS business_group_status,
    bg.description AS business_group_description,
    bg.additional_attributes AS business_group_additional_attributes,
    bg.created_at AS business_group_created_at,
    bg.updated_at AS business_group_updated_at,
    co.client_segmentation,
    COALESCE(client_counts.client_count, 0) AS client_count
FROM team_client_organisation_relationships tcor
    JOIN business_groups bg ON tcor.business_group_id = bg.id
    JOIN client_organisations co ON tcor.client_organisation_id = co.id
    LEFT JOIN (
        SELECT
            orgs.tenant_id,
            orgs.client_organisation_id,
            COUNT(c.id) AS client_count
        FROM (
            SELECT DISTINCT tenant_id, client_organisation_id
            FROM team_client_organisation_relationships
            WHERE deleted_at IS NULL
        ) orgs
        JOIN clients c ON c.organisation_id = orgs.client_organisation_id
                       AND c.tenant_id = orgs.tenant_id
        WHERE c.deleted_at IS NULL
        GROUP BY orgs.tenant_id, orgs.client_organisation_id
    ) client_counts ON client_counts.tenant_id = tcor.tenant_id
                   AND client_counts.client_organisation_id = tcor.client_organisation_id
WHERE tcor.deleted_at IS NULL;

