DROP VIEW IF EXISTS meeting_enriched_action_runs;

ALTER TABLE action_runs
ADD COLUMN is_journey BOOLEAN NOT NULL DEFAULT FALSE;

CREATE OR REPLACE VIEW
    enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    -- Add Case when for recommended status
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.market as client_organisation_market,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

