-- ╔═════ 20251007131526-fix-business-group-coverage-view-cartesian-product.sql ═════╗
-- Drop the existing view
DROP VIEW IF EXISTS business_group_coverage_detail_view;

CREATE VIEW business_group_coverage_detail_view AS
SELECT
    bg.tenant_id,
    bg.id as business_group_id,
    bg.name as business_group_name,
    bg.external_id as business_group_external_id,
    bg.group_type as business_group_type,
    bg.status as business_group_status,
    bg.description as business_group_description,
    bg_extra_properties.business_group_extra_properties,

    coverage_agg.coverage_id,
    coverage_agg.lookup_id,
    coverage_agg.category,
    coverage_agg.coverage_value,
    coverage_agg.coverage_description,
    coverage_agg.coverage_external_id,
    coverage_agg.priority,
    coverage_agg.capacity_limit,

    COALESCE(coverage_agg.coverages, '[]'::jsonb) as coverages,

    -- Agent and client counts
    COALESCE(agent_agg.agent_count, 0) as agent_count,
    COALESCE(client_org_count.client_organisation_count, 0) as client_organisation_count,

    -- Aggregated agents as JSONB (no duplicates!)
    COALESCE(agent_agg.agents, '[]'::jsonb) as agents,

    -- Timestamps - use coverage timestamps if available, otherwise business group timestamps
    COALESCE(coverage_agg.created_at, bg.created_at) as created_at,
    COALESCE(coverage_agg.updated_at, bg.updated_at) as updated_at

FROM business_groups bg

-- Get extra properties as JSONB
LEFT JOIN LATERAL (
    SELECT bg2.additional_attributes::jsonb as business_group_extra_properties
    FROM business_groups bg2
    WHERE bg2.id = bg.id
) bg_extra_properties ON true

LEFT JOIN LATERAL (
    SELECT
        MAX(bgc.id) as coverage_id,
        MAX(l.id) as lookup_id,
        MAX(l.category) as category,
        MAX(l.value) as coverage_value,
        MAX(l.description) as coverage_description,
        MAX(l.external_id) as coverage_external_id,
        MAX(bgc.priority) as priority,
        MAX(bgc.capacity_limit) as capacity_limit,
        MAX(bgc.created_at) as created_at,
        MAX(bgc.updated_at) as updated_at,
        -- Build JSONB array of ALL coverages without duplicates
        COALESCE(
            jsonb_agg(
                jsonb_build_object(
                    'coverage_id', bgc.id,
                    'lookup_id', l.id,
                    'category', l.category,
                    'value', l.value,
                    'description', l.description,
                    'external_id', l.external_id,
                    'priority', bgc.priority,
                    'capacity_limit', bgc.capacity_limit,
                    'created_at', bgc.created_at,
                    'updated_at', bgc.updated_at
                ) ORDER BY bgc.priority, l.category, l.value
            ) FILTER (WHERE bgc.id IS NOT NULL),
            '[]'::jsonb
        ) as coverages
    FROM business_group_coverage bgc
    LEFT JOIN lookups l ON bgc.coverage_lookup_id = l.id
    WHERE bgc.business_group_id = bg.id
      AND bgc.tenant_id = bg.tenant_id
) coverage_agg ON true

-- Aggregate agents independently (fixes cartesian product with coverages)
LEFT JOIN LATERAL (
    SELECT
        COUNT(DISTINCT abgr.agent_id)::integer as agent_count,
        -- Build JSONB array of ALL agents without duplicates
        COALESCE(
            jsonb_agg(
                jsonb_build_object(
                    'agent_id', a.id,
                    'first_name', COALESCE(p.first_name, apv.first_name),
                    'last_name', COALESCE(p.last_name, apv.last_name),
                    'title', COALESCE(p.title, apv.title),
                    'email', email_contacts.value,
                    'phone', phone_contacts.value,
                    'role', abgr.role,
                    'description', abgr.description,
                    'license', a.license,
                    'years_of_experience', a.years_of_experience,
                    'specialization', a.specialization
                ) ORDER BY
                    CASE abgr.role
                        WHEN 'lead_advisor' THEN 1
                        WHEN 'manager' THEN 2
                        WHEN 'senior_advisor' THEN 3
                        WHEN 'advisor' THEN 4
                        WHEN 'secondary_advisor' THEN 5
                        WHEN 'associate_advisor' THEN 6
                        WHEN 'junior_advisor' THEN 7
                        WHEN 'analyst' THEN 8
                        WHEN 'secretary' THEN 9
                        ELSE 10
                    END,
                    COALESCE(p.last_name, apv.last_name),
                    COALESCE(p.first_name, apv.first_name)
            ) FILTER (WHERE a.id IS NOT NULL),
            '[]'::jsonb
        ) as agents
    FROM agent_business_group_relationships abgr
    LEFT JOIN agents a ON abgr.agent_id = a.id AND a.tenant_id = bg.tenant_id
    LEFT JOIN persons p ON a.person_id = p.id AND p.tenant_id = bg.tenant_id
    LEFT JOIN agent_person_view apv ON a.id = apv.agent_id AND apv.tenant_id = bg.tenant_id
    LEFT JOIN contact_details email_contacts ON a.id = email_contacts.agent_id
        AND email_contacts.tenant_id = bg.tenant_id
        AND email_contacts.role = 'preferred_email'
        AND email_contacts.type = 'email'
    LEFT JOIN contact_details phone_contacts ON a.id = phone_contacts.agent_id
        AND phone_contacts.tenant_id = bg.tenant_id
        AND phone_contacts.role = 'preferred_phone'
        AND phone_contacts.type = 'phone'
    WHERE abgr.business_group_id = bg.id
      AND abgr.tenant_id = bg.tenant_id
) agent_agg ON true

-- Count client organisations independently
LEFT JOIN LATERAL (
    SELECT COUNT(DISTINCT tcor.client_organisation_id)::integer as client_organisation_count
    FROM team_client_organisation_relationships tcor
    WHERE tcor.business_group_id = bg.id
      AND tcor.tenant_id = bg.tenant_id
      AND tcor.deleted_at IS NULL
) client_org_count ON true

WHERE bg.status IS NOT NULL

ORDER BY
    -- Sort covered groups first, then uncovered groups
    CASE WHEN coverage_agg.coverage_value IS NOT NULL THEN 0 ELSE 1 END,
    coverage_agg.coverage_value,
    coverage_agg.priority,
    bg.name;

-- ╔═════ 20251007190003-remove-parent-run-id-fk-constraint.sql ═════╗
-- Dropping this because in journeys, child actions are created before their parents.
-- We've had a chicken or the egg problem in several cases around when action runs are created
-- vs when action components are advanced. We need to rethink the architecture here more wholistically
-- as its a bit of mess right now.
-- https://linear.app/avantos/issue/ACT-512/rethink-when-action-runs-get-created-and-how-that-interacts-with
ALTER TABLE action_runs
DROP CONSTRAINT action_runs_parent_run_id_fkey;

-- ╔═════ 20251008122123-add-template-to-view-type-enum.sql ═════╗
-- Safe addition of new enum value outside of constraint logic
ALTER TYPE view_scope_type ADD VALUE 'template';

-- ╔═════ 20251008122158-add-description-and-update-scope-check.sql ═════╗
-- Add new column
ALTER TABLE custom_views ADD COLUMN description TEXT;

-- Update the constraint with new scope logic using role_names and 'template'
ALTER TABLE custom_views DROP CONSTRAINT IF EXISTS scope_check;

ALTER TABLE custom_views ADD CONSTRAINT scope_check CHECK (
    (scope_type = 'global' AND role_names IS NULL AND agent_id IS NULL) OR
    (scope_type = 'role' AND role_names IS NOT NULL AND cardinality(role_names) > 0 AND agent_id IS NULL) OR
    (scope_type = 'personal' AND role_names IS NULL AND agent_id IS NOT NULL) OR
    (scope_type = 'template' AND role_names IS NULL AND agent_id IS NULL)
);

