-- ╔═════ 20251013162527-add-emails-for-tax-roles.sql ═════╗
DROP VIEW IF EXISTS tax_filings_view;

CREATE VIEW tax_filings_view AS
SELECT
  tf.id,
  tf.tenant_id,
  tf.external_id,
  tf.client_organisation_id,
  tf.tax_associate_id,
  tf.tax_manager_id,
  tf.tax_support_specialist_id,
  tf.tax_year,
  tf.tax_filing_type,
  tf.tax_return_type,
  tf.filing_status,
  tf.tax_return_status,
  tf.tax_service_type_1040,
  tf.complexity_type,
  tf.tax_professional_category,
  tf.filing_method,
  tf.e_file_status,
  tf.extension_filed,
  tf.amended_return,
  tf.final_year,
  tf.tax_services_final_year,
  tf.organizer_sent,
  tf.advisor_review_needed,
  tf.filing_due_date,
  tf.date_filed,
  tf.return_completion_date,
  tf.document_due_date,
  tf.document_received_date,
  tf.e_file_authorization_date,
  tf.e_file_status_date,
  tf.organizer_sent_date,
  tf.adjusted_gross_income,
  tf.agi,
  tf.deductions,
  tf.credits,
  tf.charitable_donations,
  tf.tax_liability,
  tf.prepaid_taxes,
  tf.safe_harbor,
  tf.gifting,
  tf.reported_income,
  tf.effective_tax_rate,
  tf.marginal_tax_rate,
  tf.tax_fee,
  tf.payment_method,
  tf.invoicing_method,
  tf.service_offering,
  tf.signature_preference,
  tf.completion_window,
  tf.created_at,
  tf.updated_at,
  tf.extra_properties,
  co.name AS client_organisation_name,
  co.relationship_status AS client_organisation_relationship_status,
  co.external_id AS client_organisation_external_id,
  co.extra_properties AS client_organisation_extra_properties,
  a_as.external_id AS tax_associate_external_id,
  pas.first_name AS tax_associate_first_name,
  pas.last_name AS tax_associate_last_name,
  email_as.value AS tax_associate_email,
  a_man.external_id AS tax_manager_external_id,
  pman.first_name AS tax_manager_first_name,
  pman.last_name AS tax_manager_last_name,
  email_man.value AS tax_manager_email,
  a_sup.external_id AS tax_support_specialist_external_id,
  psup.first_name AS tax_support_specialist_first_name,
  psup.last_name AS tax_support_specialist_last_name,
  email_sup.value AS tax_support_specialist_email,
  assoc_p.external_id AS client_organisation_tax_associate_external_id,
  assoc_p.title AS client_organisation_tax_associate_title,
  assoc_p.first_name AS client_organisation_tax_associate_first_name,
  assoc_p.last_name AS client_organisation_tax_associate_last_name,
  email_assoc.value AS client_organisation_tax_associate_email,
  mgr_p.external_id AS client_organisation_tax_manager_external_id,
  mgr_p.title AS client_organisation_tax_manager_title,
  mgr_p.first_name AS client_organisation_tax_manager_first_name,
  mgr_p.last_name AS client_organisation_tax_manager_last_name,
  email_mgr.value AS client_organisation_tax_manager_email,
  asst_p.external_id AS client_organisation_tax_assistant_external_id,
  asst_p.title AS client_organisation_tax_assistant_title,
  asst_p.first_name AS client_organisation_tax_assistant_first_name,
  asst_p.last_name AS client_organisation_tax_assistant_last_name,
  email_asst.value AS client_organisation_tax_assistant_email

FROM tax_filings tf
LEFT JOIN client_organisations co
  ON co.id = tf.client_organisation_id AND co.tenant_id = tf.tenant_id

-- Main Tax Associate (from filing direct assignment)
LEFT JOIN agents a_as
  ON a_as.id = tf.tax_associate_id AND a_as.tenant_id = tf.tenant_id
LEFT JOIN persons pas
  ON pas.id = a_as.person_id
LEFT JOIN contact_details email_as ON a_as.id = email_as.agent_id
  AND email_as.tenant_id = tf.tenant_id
  AND email_as.role = 'primary_email'
  AND email_as.type = 'email'

-- Main Tax Manager (from filing direct assignment)
LEFT JOIN agents a_man
  ON a_man.id = tf.tax_manager_id AND a_man.tenant_id = tf.tenant_id
LEFT JOIN persons pman
  ON pman.id = a_man.person_id
LEFT JOIN contact_details email_man ON a_man.id = email_man.agent_id
  AND email_man.tenant_id = tf.tenant_id
  AND email_man.role = 'primary_email'
  AND email_man.type = 'email'

-- Main Support Specialist (from filing direct assignment)
LEFT JOIN agents a_sup
  ON a_sup.id = tf.tax_support_specialist_id AND a_sup.tenant_id = tf.tenant_id
LEFT JOIN persons psup
  ON psup.id = a_sup.person_id
LEFT JOIN contact_details email_sup ON a_sup.id = email_sup.agent_id
  AND email_sup.tenant_id = tf.tenant_id
  AND email_sup.role = 'primary_email'
  AND email_sup.type = 'email'

-- Only one "Tax Associate"
LEFT JOIN LATERAL (
  SELECT acr.*
  FROM agent_client_organisation_relationships acr
  WHERE acr.client_organisation_id = tf.client_organisation_id
    AND acr.tenant_id = tf.tenant_id
    AND acr.relationship_type = 'Tax Associate'
  ORDER BY acr.updated_at DESC
  LIMIT 1
) acr_assoc ON TRUE
LEFT JOIN agents assoc_a ON assoc_a.id = acr_assoc.agent_id AND assoc_a.tenant_id = tf.tenant_id
LEFT JOIN persons assoc_p ON assoc_p.id = assoc_a.person_id
LEFT JOIN contact_details email_assoc ON assoc_a.id = email_assoc.agent_id
  AND email_assoc.tenant_id = tf.tenant_id
  AND email_assoc.role = 'primary_email'
  AND email_assoc.type = 'email'

-- Only one "Tax Manager"
LEFT JOIN LATERAL (
  SELECT acr.*
  FROM agent_client_organisation_relationships acr
  WHERE acr.client_organisation_id = tf.client_organisation_id
    AND acr.tenant_id = tf.tenant_id
    AND acr.relationship_type = 'Tax Manager'
  ORDER BY acr.updated_at DESC
  LIMIT 1
) acr_mgr ON TRUE
LEFT JOIN agents mgr_a ON mgr_a.id = acr_mgr.agent_id AND mgr_a.tenant_id = tf.tenant_id
LEFT JOIN persons mgr_p ON mgr_p.id = mgr_a.person_id
LEFT JOIN contact_details email_mgr ON mgr_a.id = email_mgr.agent_id
  AND email_mgr.tenant_id = tf.tenant_id
  AND email_mgr.role = 'primary_email'
  AND email_mgr.type = 'email'

-- Only one "Tax Assistant"
LEFT JOIN LATERAL (
  SELECT acr.*
  FROM agent_client_organisation_relationships acr
  WHERE acr.client_organisation_id = tf.client_organisation_id
    AND acr.tenant_id = tf.tenant_id
    AND acr.relationship_type = 'Tax Assistant'
  ORDER BY acr.updated_at DESC
  LIMIT 1
) acr_asst ON TRUE
LEFT JOIN agents asst_a ON asst_a.id = acr_asst.agent_id AND asst_a.tenant_id = tf.tenant_id
LEFT JOIN persons asst_p ON asst_p.id = asst_a.person_id
LEFT JOIN contact_details email_asst ON asst_a.id = email_asst.agent_id
  AND email_asst.tenant_id = tf.tenant_id
  AND email_asst.role = 'primary_email'
  AND email_asst.type = 'email';

-- ╔═════ 20251013184655-add_expected_completion_date_to_enriched_action_runs.sql ═════╗
----------------------------------------------------------------------
-- Add expected_completion_date to enriched_action_runs view
----------------------------------------------------------------------
CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.market as client_organisation_market,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

CREATE OR REPLACE VIEW unqork_action_runs_view AS
SELECT
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL
        OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.external_id = uar.action_owner_salentica_id
            AND a.tenant_id = '1'
    ) AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum,
    -- Build custom data object with standardized structure
    jsonb_build_object(
        'action_id',
        uar.action_id,
        'action_rel_segment',
        uar.action_rel_segment,
        'action_rel_id',
        uar.action_rel_id,
        'action_current_task_title',
        uar.action_current_task_title,
        'action_no',
        uar.action_no,
        'action_owner_canceled',
        uar.action_owner_canceled,
        'action_owner_user_id',
        uar.action_owner_user_id,
        'action_rel_servicing_name',
        uar.action_rel_servicing_name,
        'action_rel_type',
        uar.action_rel_type,
        'actionDescription',
        uar.action_description,
        'financialAccountObject',
        jsonb_build_object(
            'value',
            jsonb_build_object(
                'accountNumber',
                uar.account_number,
                'id',
                uar.financial_account_id,
                'actionRelId',
                uar.action_rel_id,
                'custodianName',
                uar.custodian_name -- add custodian name in same path as avantos actions
            )
        ),
        'financial_account_id',
        uar.financial_account_id,
        'current_task',
        CASE
            WHEN uar.action_current_task_title IS NOT NULL THEN jsonb_build_object(
                'id',
                NULL,
                'name',
                uar.action_current_task_title,
                'status',
                'in_progress' -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE
        WHEN uar.action_status = 'Recommended' THEN true
        ELSE false
    END AS recommended,
    CASE
        WHEN uar.action_status = 'Canceled' THEN uar.action_end_date
        ELSE NULL
    END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE
        WHEN uar.action_status = 'Declined' THEN uar.action_end_date
        ELSE NULL
    END AS rejected_at,
    CASE
        WHEN uar.action_status = 'Completed' THEN uar.action_end_date
        ELSE NULL
    END AS completed_at,
    uar.canceled_by AS cancelled_by, -- Return the name directly for Unqork  
    uar.cancel_reason AS cancellation_reason,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.idp_subject = uar.action_owner_user_id
            AND a.tenant_id = '1'
    ) AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by, -- No rejected_by data from Unqork
    safe_iso_timestamptz (uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment, -- Get the environment from the unqork_action_runs table instead of hardcoding as null
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.market as client_organisation_market,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    a.id,
                    'external_id',
                    a.external_id,
                    'first_name',
                    p.first_name,
                    'last_name',
                    p.last_name,
                    'middle_name',
                    p.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agents a ON acor.agent_id = a.id
            JOIN persons p ON a.person_id = p.id
        WHERE
            acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    uar.next_step_date,
    'unqork'::text AS source_system,
    NULL::timestamp with time zone AS expected_completion_date
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- ╔═════ 20251014235012-add_agent_oauth_tokens_table.sql ═════╗
