-- ╔═════ 20251017102828-add_cron_job_queued_to_enriched_tasks_view.sql ═════╗
DROP VIEW IF EXISTS enriched_task;
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
	t.cron_job_queued,
    ar.id AS action_run_id,
    NULL::text AS action_number, -- there's no action_number in the action_runs table
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name, 'external_id', ap.external_id) AS primary_css,
    co.client_segmentation AS client_segmentation,
    co.approx_aum AS aum -- add aum from client organisation
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id;

