-- ╔═════ 20251021172909-add-parent-external-id-in-meeting.sql ═════╗
ALTER TABLE meetings ADD COLUMN IF NOT EXISTS parent_external_id text GENERATED ALWAYS AS ((extra_properties ->> 'Parent__c')) STORED;

DROP VIEW IF EXISTS agent_meetings;

CREATE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    m.parent_external_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties,
                'contact_details', p.contact_details
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name,
                external_id,
                contact_details
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd1.role,
                            cd1.value
                        )
                        FROM contact_details cd1
                        WHERE cd1.client_id = c1.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id

                UNION ALL

                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd2.role,
                            cd2.value
                        )
                        FROM contact_details cd2
                        WHERE cd2.agent_id = a.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT 
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd3.role,
                            cd3.value
                        )
                        FROM contact_details cd3
                        WHERE cd3.client_organisation_id = co.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM client_organisations co
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type,
    m.ai_transcript_id
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20251022123644-add_auto_submit_approve_conditions.sql ═════╗
