-- ╔═════ 20251022143603-add_growth_opportunity_next_step_date_to_relationships_dashboard_view.sql ═════╗
-- Add growth_opportunity_next_step_date to relationships_dashboard_view
DROP VIEW IF EXISTS public.relationships_dashboard_view;

CREATE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    co.next_meeting,
    co.growth_opportunity_next_step_date,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
  WHERE co.deleted_at IS NULL;

-- ╔═════ 20251023090700-create_meeting_summaries_replication_index.sql ═════╗
-- Index to support efficient watermark-based queries for CDC replication
-- This index enables the MeetingSummaryReader to efficiently query for changed records
-- using the pattern: WHERE tenant_id = $1 AND updated_at > $2 ORDER BY updated_at
CREATE INDEX IF NOT EXISTS idx_meeting_summaries_replication
  ON meeting_summaries(tenant_id, updated_at);

-- ╔═════ 20251023090701-create_meeting_summaries_replication_view.sql ═════╗
-- View that joins meeting_summaries with meetings to provide all necessary fields for CDC replication
-- This view includes the external_id from the meetings table (which contains the Salesforce Event.Id)
-- to enable correlation during upsert operations to Salesforce
CREATE VIEW meeting_summaries_for_replication AS
SELECT
    ms.id AS summary_id,
    ms.tenant_id,
    ms.meeting_id,
    m.external_id AS external_id,        -- Salesforce Event.Id (from meetings.external_id)
    ms.summary_content,
    ms.is_attested,
    ms.attesting_agent_id,
    ms.attested_at,
    ms.is_ai_enhanced,
    ms.created_at AS summary_created_at,
    ms.updated_at AS summary_updated_at, -- WATERMARK FIELD for incremental processing
    m.subject AS meeting_subject,
    m.start_time AS meeting_start_time,
    m.end_time AS meeting_end_time,
    m.meeting_type
FROM meeting_summaries ms
INNER JOIN meetings m ON ms.meeting_id = m.id;

-- ╔═════ 20251023090702-create_cdc_replication_state_table.sql ═════╗
-- Table to track CDC replication state per (tenant, source_table, destination) triple
-- Stores watermark timestamps, status, error information, and retry counts
CREATE TABLE cdc_replication_state (
    id TEXT PRIMARY KEY NOT NULL,
    tenant_id TEXT NOT NULL,
    source_table VARCHAR(255) NOT NULL,
    destination_name VARCHAR(255) NOT NULL,
    replication_watermark TIMESTAMP WITH TIME ZONE,
    last_replication_at TIMESTAMP WITH TIME ZONE,
    last_replication_status VARCHAR(50) NOT NULL DEFAULT 'pending',
    last_replication_error TEXT,
    records_replicated_last BIGINT,
    retry_count INTEGER NOT NULL DEFAULT 0,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),

    UNIQUE(tenant_id, source_table, destination_name)
);

-- Index for efficient lookup by tenant, source, and destination
CREATE INDEX idx_cdc_replication_state_lookup
    ON cdc_replication_state(tenant_id, source_table, destination_name);

-- Index for monitoring failed replications
CREATE INDEX idx_cdc_replication_state_status
    ON cdc_replication_state(last_replication_status, updated_at);

