-- ╔═════ 20251110140427-create_unqork_comment_normalized_view.sql ═════╗
DROP VIEW IF EXISTS unqork_comment_normalized_view;

-- Create a normalized view of unqork_comments that matches the comments table structure
-- This allows filtering and querying both tables with the same field names
CREATE VIEW unqork_comment_normalized_view AS
SELECT 
    uc.id,
    uc.tenant_id,
    -- Extract entity_id from actionSubId or meetingSubId
    COALESCE(data->>'actionSubId', data->>'meetingSubId', '') AS entity_id,
    -- Determine entity_type based on which field exists
    CASE 
        WHEN data->>'actionSubId' IS NOT NULL THEN 'action_run'::commentable_entity_type
        WHEN data->>'meetingSubId' IS NOT NULL THEN 'meeting'::commentable_entity_type
        ELSE NULL
    END AS entity_type,
    COALESCE(data->>'comment', '') AS text,
    COALESCE(data->>'addedBy', uc.owner, '') AS created_by,
    -- Convert created timestamp to TIMESTAMP WITH TIME ZONE
    uc.created::TIMESTAMP WITH TIME ZONE AS created_at,
    uc.unqork_id AS external_id,
    CASE 
        WHEN data->'commentTag' IS NULL THEN ARRAY[]::text[]
        WHEN jsonb_typeof(data->'commentTag') = 'array' THEN
            ARRAY(SELECT jsonb_array_elements_text(data->'commentTag'))
        ELSE ARRAY[]::text[]
    END AS tagged_users
FROM unqork_comments uc;

-- ╔═════ 20251110154939-add_current_snapshot_to_enriched_action_runs.sql ═════╗
-- Add current snapshot data to enriched_action_runs view
-- We can use CREATE OR REPLACE VIEW to add a column at the end
-- Dependent views that use SELECT * will automatically pick up the new column
CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.market as client_organisation_market,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date,
    -- Correlated subquery to get the most recent snapshot data for this action run
    ( SELECT ards.data
      FROM action_run_data_snapshots ards
      WHERE ards.action_run_id = ar.id
      ORDER BY ards.created_at DESC
      LIMIT 1
    ) AS current_snapshot_data
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id;

-- Note: unified_action_runs_view and meeting_enriched_action_runs depend on this view
-- If they use SELECT *, they will automatically include the new column
-- If they use explicit column lists, they may need to be updated separately

-- ╔═════ 20251112204200-add-client-org-external-id-to-agent-meetings.sql ═════╗
CREATE OR REPLACE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    m.parent_external_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties,
                'contact_details', p.contact_details
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT 
                title,
                first_name,
                middle_name,
                last_name,
                external_id,
                contact_details
            FROM (
                SELECT 
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd1.role,
                            cd1.value
                        )
                        FROM contact_details cd1
                        WHERE cd1.client_id = c1.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id

                UNION ALL

                SELECT 
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd2.role,
                            cd2.value
                        )
                        FROM contact_details cd2
                        WHERE cd2.agent_id = a.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT 
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd3.role,
                            cd3.value
                        )
                        FROM contact_details cd3
                        WHERE cd3.client_organisation_id = co.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM client_organisations co
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type,
    m.ai_transcript_id,
    co.external_id AS client_organisation_external_id
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20251112232159-optimize_meeting_list_performance.sql ═════╗
-- Index to optimize meeting list queries filtered by initiating agent
-- This partial index only includes meetings with a client_organisation_id (non-null)
-- Supports queries like: WHERE tenant_id = ? AND initiating_agent_id = ? AND start_time < ? AND client_organisation_id IS NOT NULL
CREATE INDEX IF NOT EXISTS idx_meetings_initiating_agent_filters
ON meetings(tenant_id, initiating_agent_id, start_time)
WHERE client_organisation_id IS NOT NULL;

-- Partial index for unattested meeting summaries to optimize joins
-- Only indexes rows where is_attested = false (much smaller index)
-- Supports queries that filter on is_attested = false
CREATE INDEX IF NOT EXISTS idx_meeting_summaries_unattested
ON meeting_summaries(meeting_id, is_attested)
WHERE is_attested = false;

-- ╔═════ 20251117191957-add_soft_delete_to_action_runs.sql ═════╗
-- Add soft delete columns to action_runs table
