-- Add composite indexes for tenant queries with soft delete filtering
CREATE INDEX idx_action_runs_tenant_deleted ON action_runs(tenant_id, deleted_at);
CREATE INDEX idx_action_run_components_tenant_deleted ON action_run_components(tenant_id, deleted_at);
CREATE INDEX idx_tasks_tenant_deleted ON tasks(tenant_id, deleted_at);

