CREATE OR REPLACE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
	t.cron_job_queued,
    ar.id AS action_run_id,
    NULL::text AS action_number, -- there's no action_number in the action_runs table
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name, 'external_id', ap.external_id) AS primary_css,
    co.client_segmentation AS client_segmentation,
    co.approx_aum AS aum -- add aum from client organisation
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id 
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id
	 WHERE t.deleted_at IS NULL;

-- ╔═════ 20251120102423-create_enriched_action_runs_with_snapshot_view.sql ═════╗
-- Create enriched_action_runs_with_snapshot view for warehouse export and snapshot APIs
-- This view computes current_snapshot_data on-demand by aggregating task data
-- No persistent snapshot table needed - snapshots are computed from tasks

CREATE VIEW enriched_action_runs_with_snapshot AS
SELECT
    -- All columns from enriched_action_runs
    ear.action_run_id,
    ear.tenant_id,
    ear.action_id,
    ear.status,
    ear.started_by,
    ear.client_organisation_id,
    ear.started_at,
    -- last_updated_at represents when this view's data last changed
    -- This is the max of the action run update time and any completed task update time
    GREATEST(
        ear.last_updated_at,
        COALESCE((
            SELECT MAX(t.last_updated_at)
            FROM tasks t
            WHERE t.run_id = ear.action_run_id
                AND t.status = 'complete'
                AND t.last_updated_at IS NOT NULL
        ), ear.last_updated_at)
    ) AS last_updated_at,
    ear.action_run_name,
    ear.slug,
    ear.blueprint_version_id,
    ear.scheduled_at,
    ear.data,
    ear.recommended,
    ear.cancelled_at,
    ear.run_context,
    ear.created_at,
    ear.ready_at,
    ear.rejected_at,
    ear.completed_at,
    ear.cancelled_by,
    ear.cancellation_reason,
    ear.recommended_by,
    ear.rejection_reason,
    ear.rejected_by,
    ear.deadline,
    ear.parent_run_id,
    ear.environment,
    ear.blueprint_name,
    ear.blueprint_category,
    ear.blueprint_description,
    ear.blueprint_short_description,
    ear.next_step_date,
    ear.client_organisation_name,
    ear.client_organisation_type,
    ear.client_segmentation,
    ear.client_organisation_external_id,
    ear.client_organisation_national_css_coverage,
    ear.client_organisation_market,
    ear.aum,
    ear.agents,
    ear.is_journey,
    ear.expected_completion_date,
    -- Compute current snapshot by aggregating completed task data
    -- Later task values override earlier ones (ORDER BY completed_at, id)
    (
        SELECT jsonb_object_agg(
            kv.key,
            kv.value ORDER BY t.completed_at, t.id
        ) FILTER (WHERE kv.key IS NOT NULL)
        FROM tasks t
        CROSS JOIN LATERAL jsonb_each(t.data) as kv(key, value)
        WHERE t.run_id = ear.action_run_id
            AND t.status = 'complete'
            AND t.completed_at IS NOT NULL
            AND t.data IS NOT NULL
            AND t.data != 'null'::jsonb
            AND jsonb_typeof(t.data) = 'object'
    ) AS current_snapshot_data
FROM enriched_action_runs ear;

-- Create index to optimize snapshot aggregation and max timestamp queries
-- This supports both the WHERE clause in the snapshot subquery and the max(last_updated_at) query
CREATE INDEX IF NOT EXISTS idx_tasks_run_id_completed
    ON tasks(run_id, status, completed_at, last_updated_at)
    WHERE status = 'complete' AND data IS NOT NULL;

-- ╔═════ 20251120102600-drop_action_run_data_snapshots_table.sql ═════╗
-- Drop the action_run_data_snapshots table
-- We've moved to computing snapshots on-demand from the enriched_action_runs_with_snapshot view
-- This table was created by migration 20251109210338 and modified by the soft delete migration 20251117191957
-- It's no longer needed as snapshot data is now aggregated from tasks in real-time

-- First, update enriched_action_runs view to remove the current_snapshot_data column that references the table
CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    co.market as client_organisation_market,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg (
                acor.relationship_type,
                jsonb_build_object (
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date,
    -- Return NULL for current_snapshot_data since we no longer maintain this in the base view
    -- Use enriched_action_runs_with_snapshot view for snapshot data
    NULL::jsonb AS current_snapshot_data
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
WHERE
    ar.deleted_at IS NULL;

-- Now we can safely drop the table without CASCADE since no views depend on it
DROP TABLE IF EXISTS action_run_data_snapshots;

-- ╔═════ 20251120110550-add_component_task_priorities_to_blueprint_versions.sql ═════╗
ALTER TABLE action_blueprint_versions
ADD COLUMN component_task_priorities JSONB;

-- ╔═════ 20251121095149-fix_enriched_action_runs_snapshot_status.sql ═════╗
-- Drop the existing view
DROP VIEW IF EXISTS enriched_action_runs_with_snapshot;

-- Recreate with LATERAL join for snapshot computation (much faster for large datasets)
CREATE VIEW enriched_action_runs_with_snapshot AS
SELECT
    ear.action_run_id,
    ear.tenant_id,
    ear.action_id,
    ear.status,
    ear.started_by,
    ear.client_organisation_id,
    ear.started_at,
    GREATEST(
        ear.last_updated_at,
        COALESCE(task_max.max_last_updated_at, ear.last_updated_at)
    ) AS last_updated_at,
    ear.action_run_name,
    ear.slug,
    ear.blueprint_version_id,
    ear.scheduled_at,
    ear.data,
    ear.recommended,
    ear.cancelled_at,
    ear.run_context,
    ear.created_at,
    ear.ready_at,
    ear.rejected_at,
    ear.completed_at,
    ear.cancelled_by,
    ear.cancellation_reason,
    ear.recommended_by,
    ear.rejection_reason,
    ear.rejected_by,
    ear.deadline,
    ear.parent_run_id,
    ear.environment,
    ear.blueprint_name,
    ear.blueprint_category,
    ear.blueprint_description,
    ear.blueprint_short_description,
    ear.next_step_date,
    ear.client_organisation_name,
    ear.client_organisation_type,
    ear.client_segmentation,
    ear.client_organisation_external_id,
    ear.client_organisation_national_css_coverage,
    ear.client_organisation_market,
    ear.aum,
    ear.agents,
    ear.is_journey,
    ear.expected_completion_date,
    snap.current_snapshot_data
FROM enriched_action_runs ear
LEFT JOIN LATERAL (
    SELECT MAX(t.last_updated_at) as max_last_updated_at
    FROM tasks t
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.last_updated_at IS NOT NULL
        AND t.data IS NOT NULL
) task_max ON true
-- LATERAL join to compute snapshot from done tasks
LEFT JOIN LATERAL (
    SELECT jsonb_object_agg(
        kv.key,
        kv.value ORDER BY t.completed_at, t.id
    ) FILTER (WHERE kv.key IS NOT NULL) AS current_snapshot_data
    FROM tasks t
    CROSS JOIN LATERAL jsonb_each(t.data) as kv(key, value)
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.completed_at IS NOT NULL
        AND t.data IS NOT NULL
        AND t.data <> 'null'::jsonb
        AND jsonb_typeof(t.data) = 'object'
) snap ON true;

-- Drop old index and create new one with correct status
DROP INDEX IF EXISTS idx_tasks_run_id_completed;
CREATE INDEX IF NOT EXISTS idx_tasks_run_id_completed
    ON tasks(run_id, status, completed_at, last_updated_at)
    WHERE status = 'done' AND data IS NOT NULL;

