-- ╔═════ 20251128093617-client_fts_tokenized_search_text.sql ═════╗
-- Increase statement timeout for materialized view recreation (10 minutes)
SET statement_timeout = '600s';

-- Drop and recreate the client_fts materialized view with tokenized search_text
-- This enables proper highlighting that shows which field matched
DROP MATERIALIZED VIEW IF EXISTS client_fts;

-- Create a MATERIALIZED VIEW for client full-text search
-- This pre-computes tsvector for fast searching with indexes
-- search_text uses tokenized format with escaped values for highlighting:
--   Format: ||token_name||escaped_value||...
--   Escaping: \ -> \\, | -> \| (to prevent delimiter injection)
CREATE MATERIALIZED VIEW client_fts AS
SELECT
    c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    -- Display text for search results
    CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name) AS display_text,
    -- Raw search text with token separators for highlighting
    -- Format: ||token_name||escaped_value for each searchable field
    -- Values are escaped: \ -> \\, | -> \| to prevent delimiter injection
    '||name||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||external_id||' || REPLACE(REPLACE(COALESCE(c.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||org_external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||org_name||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||email||' || REPLACE(REPLACE(COALESCE((SELECT cd.value::text FROM contact_details cd WHERE cd.client_id = c.id AND cd.role = 'preferred_email' LIMIT 1), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||phone||' || REPLACE(REPLACE(COALESCE((SELECT cd.value::text FROM contact_details cd WHERE cd.client_id = c.id AND cd.role = 'preferred_phone' LIMIT 1), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||advisor||' || REPLACE(REPLACE(COALESCE(
        (SELECT string_agg(CONCAT_WS(' ', wa_p.first_name, wa_p.middle_name, wa_p.last_name), ' ')
         FROM agent_client_organisation_relationships wa_acor
         JOIN agents wa_a ON wa_acor.agent_id = wa_a.id
         JOIN persons wa_p ON wa_a.person_id = wa_p.id
         WHERE wa_acor.client_organisation_id = co.id
           AND wa_acor.relationship_type = 'Wealth Advisor'), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    -- Weight A: Client name (highest priority)
    -- Weight B: External IDs (medium-high priority)
    -- Weight C: Organisation name, contacts (medium priority)
    -- Weight D: Wealth advisor names (lower priority)
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(c.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(
        (SELECT cd.value::text FROM contact_details cd WHERE cd.client_id = c.id AND cd.role = 'preferred_email' LIMIT 1), ''
    )), 'C') ||
    setweight(to_tsvector('simple', COALESCE(
        (SELECT cd.value::text FROM contact_details cd WHERE cd.client_id = c.id AND cd.role = 'preferred_phone' LIMIT 1), ''
    )), 'C') ||
    setweight(to_tsvector('simple', COALESCE(
        -- Aggregate all Wealth Advisor names (avoids duplicate rows, allows searching by any advisor)
        (SELECT string_agg(CONCAT_WS(' ', wa_p.first_name, wa_p.middle_name, wa_p.last_name), ' ')
         FROM agent_client_organisation_relationships wa_acor
         JOIN agents wa_a ON wa_acor.agent_id = wa_a.id
         JOIN persons wa_p ON wa_a.person_id = wa_p.id
         WHERE wa_acor.client_organisation_id = co.id
           AND wa_acor.relationship_type = 'Wealth Advisor'), ''
    )), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(c.created_at, c.updated_at, p.created_at, p.updated_at) AS updated_at
FROM
    clients c
    JOIN persons p ON p.id = c.person_id
    LEFT JOIN client_organisations co ON c.organisation_id = co.id;

-- Create unique index on client_id for efficient lookups and REFRESH CONCURRENTLY support
CREATE UNIQUE INDEX idx_client_fts_client_id ON client_fts (client_id);

-- Create index on tenant_id for tenant filtering
CREATE INDEX idx_client_fts_tenant_id ON client_fts (tenant_id);

-- Create GIN index on search_vector for fast full-text search
CREATE INDEX idx_client_fts_search_vector ON client_fts USING gin (search_vector);

-- Create GIN index on search_text for trigram similarity search
CREATE INDEX idx_client_fts_search_text_trgm ON client_fts USING gin (search_text gin_trgm_ops);

-- Create index for recency sorting
CREATE INDEX idx_client_fts_updated_at ON client_fts (updated_at DESC NULLS LAST);

-- Composite index for tenant + updated_at (common query pattern)
CREATE INDEX idx_client_fts_tenant_updated ON client_fts (tenant_id, updated_at DESC NULLS LAST);

