-- ╔═════ 20251128093618-client_organisation_fts_tokenized_search_text.sql ═════╗
-- Increase statement timeout for materialized view recreation (10 minutes)
SET statement_timeout = '600s';

-- Drop and recreate the client_organisation_fts materialized view with tokenized search_text
-- This enables proper highlighting that shows which field matched
DROP MATERIALIZED VIEW IF EXISTS client_organisation_fts;

-- Create a MATERIALIZED VIEW for client organisation full-text search
-- This pre-computes tsvector for fast searching with indexes
-- search_text uses tokenized format with escaped values for highlighting:
--   Format: ||token_name||escaped_value||...
--   Escaping: \ -> \\, | -> \| (to prevent delimiter injection)
CREATE MATERIALIZED VIEW client_organisation_fts AS
SELECT
    co.id AS client_organisation_id,
    co.tenant_id,
    -- Display text: client org name + primary agent (Wealth Advisor)
    CASE
        WHEN wa.agent_name IS NOT NULL THEN co.name || ' (' || wa.agent_name || ')'
        ELSE co.name
    END AS display_text,
    -- Raw search text with token separators for highlighting
    -- Format: ||token_name||escaped_value for each searchable field
    -- Values are escaped: \ -> \\, | -> \| to prevent delimiter injection
    '||name||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||description||' || REPLACE(REPLACE(COALESCE(co.description, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||region||' || REPLACE(REPLACE(COALESCE(bg.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||office||' || REPLACE(REPLACE(COALESCE(aof.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agent_org||' || REPLACE(REPLACE(COALESCE(ao.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agents||' || REPLACE(REPLACE(COALESCE(all_agents.agent_names, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    -- Weight A: Client org name (highest priority)
    -- Weight B: External ID + Agent names (high priority)
    -- Weight C: Region, office, agent org (medium priority)
    -- Weight D: Description (lower priority)
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(all_agents.agent_names, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(bg.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(aof.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(ao.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(co.description, '')), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(co.created_at, co.updated_at) AS updated_at
FROM
    client_organisations co
    LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
    LEFT JOIN business_groups bg ON co.business_group_id = bg.id
    LEFT JOIN agent_organisations aof ON co.office_id = aof.id
    -- Get primary agent (Wealth Advisor) for display text
    LEFT JOIN LATERAL (
        SELECT CONCAT_WS(' ', p.first_name, p.last_name) AS agent_name
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
          AND acor.relationship_type = 'Wealth Advisor'
        LIMIT 1
    ) wa ON true
    -- Get ALL agent names for search (aggregated)
    LEFT JOIN LATERAL (
        SELECT string_agg(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), ' ') AS agent_names
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
    ) all_agents ON true
WHERE co.deleted_at IS NULL;

-- Create unique index on client_organisation_id for efficient lookups and REFRESH CONCURRENTLY support
CREATE UNIQUE INDEX idx_client_organisation_fts_id ON client_organisation_fts (client_organisation_id);

-- Create index on tenant_id for tenant filtering
CREATE INDEX idx_client_organisation_fts_tenant_id ON client_organisation_fts (tenant_id);

-- Create GIN index on search_vector for fast full-text search
CREATE INDEX idx_client_organisation_fts_search_vector ON client_organisation_fts USING gin (search_vector);

-- Create GIN index on search_text for trigram similarity search
CREATE INDEX idx_client_organisation_fts_search_text_trgm ON client_organisation_fts USING gin (search_text gin_trgm_ops);

-- Create index for recency sorting
CREATE INDEX idx_client_organisation_fts_updated_at ON client_organisation_fts (updated_at DESC NULLS LAST);

-- Composite index for tenant + updated_at (common query pattern)
CREATE INDEX idx_client_organisation_fts_tenant_updated ON client_organisation_fts (tenant_id, updated_at DESC NULLS LAST);

