-- ╔═════ 20251128113210-create_fts_refresh_state_table.sql ═════╗
-- Table to track FTS materialized view refresh state
-- Used for change detection (watermark comparison) and monitoring
CREATE TABLE fts_refresh_state (
    view_name VARCHAR(100) PRIMARY KEY,
    -- Current status: pending, in_progress, success, failed, skipped
    status VARCHAR(50) NOT NULL DEFAULT 'pending',
    started_at TIMESTAMP WITH TIME ZONE,
    completed_at TIMESTAMP WITH TIME ZONE,
    last_source_watermark TIMESTAMP WITH TIME ZONE,
    last_error TEXT,
    last_duration_ms BIGINT,
    -- Cumulative counters for monitoring
    total_refresh_count BIGINT NOT NULL DEFAULT 0,
    total_skip_count BIGINT NOT NULL DEFAULT 0,
    total_error_count BIGINT NOT NULL DEFAULT 0,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

-- Auto-update updated_at on any change
CREATE OR REPLACE FUNCTION update_fts_refresh_state_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
CREATE TRIGGER trg_fts_refresh_state_updated_at
    BEFORE UPDATE ON fts_refresh_state
    FOR EACH ROW
    EXECUTE FUNCTION update_fts_refresh_state_updated_at();

-- No seed data - rows are created on first use by the service

CREATE INDEX idx_fts_refresh_state_status ON fts_refresh_state(status);

