CREATE INDEX idx_unqork_action_run_fts_client_org_id ON unqork_action_run_fts (client_organisation_id);

-- Create GIN index on search_vector for fast full-text search
CREATE INDEX idx_unqork_action_run_fts_search_vector ON unqork_action_run_fts USING gin (search_vector);

-- Create GIN index on search_text for trigram similarity search
CREATE INDEX idx_unqork_action_run_fts_search_text_trgm ON unqork_action_run_fts USING gin (search_text gin_trgm_ops);

-- Create index for recency sorting
CREATE INDEX idx_unqork_action_run_fts_updated_at ON unqork_action_run_fts (updated_at DESC NULLS LAST);

-- Composite index for tenant + updated_at (common query pattern)
CREATE INDEX idx_unqork_action_run_fts_tenant_updated ON unqork_action_run_fts (tenant_id, updated_at DESC NULLS LAST);

