-- ╔═════ 20251205182620-add_client_org_type_to_vpoc_onboarding.sql ═════╗
DROP VIEW IF EXISTS vpoc_onboarding_view;

CREATE VIEW vpoc_onboarding_view AS
SELECT
    vo.id,
    vo.tenant_id,
    vo.primary_client_id,
    vo.relationship_id,
    vo.action_ids,
    vo.started_at,
    vo.end_date,
    cpv.first_name AS primary_client_first_name,
    cpv.last_name AS primary_client_last_name,
    corv.client_organisation_id,
    corv.client_organisation_name,
    cpv.client_organisation_type, -- Add client organisation type to the view from client_person_view
    corv.role AS relationship_role,
    corv.description AS relationship_description
FROM vpoc_onboarding vo
JOIN client_person_view cpv
    ON vo.primary_client_id = cpv.client_id
    AND vo.tenant_id = cpv.tenant_id
JOIN client_organisation_relationships_view corv
    ON vo.relationship_id = corv.client_client_organisation_relationship_id
    AND vo.tenant_id = corv.tenant_id;

-- ╔═════ 20251206092745-add_external_ids_to_fts_views.sql ═════╗
-- Add external_id fields to FTS materialized views for navigation support
-- - client_fts: add contact_external_id, relationship_external_id
-- - financial_account_fts: add financial_account_external_id, relationship_external_id
-- - client_organisation_fts: add client_organisation_external_id, relationship_external_id
-- - task_fts: add relationship_external_id

SET statement_timeout = '600s';

-- ============================================================================
-- 1. UPDATE client_fts - Add contact_external_id, relationship_external_id
-- ============================================================================
DROP MATERIALIZED VIEW IF EXISTS client_fts;

CREATE MATERIALIZED VIEW client_fts AS
SELECT
    c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    -- Display text for search results
    CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name) AS display_text,
    -- display_fields: Structured JSONB for rich client rendering
    jsonb_build_object(
        'contact_name', CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name),
        'contact_id', c.id,
        'contact_external_id', c.external_id,
        'relationship_name', co.name,
        'relationship_id', co.id,
        'relationship_external_id', co.external_id,
        'advisor', wa.agent_name,
        'preferred_phone', preferred_phone.value,
        'preferred_email', preferred_email.value
    ) AS display_fields,
    -- Raw search text with token separators for highlighting
    '||name||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||external_id||' || REPLACE(REPLACE(COALESCE(c.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||org_external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||org_name||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||email||' || REPLACE(REPLACE(COALESCE(preferred_email.value, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||phone||' || REPLACE(REPLACE(COALESCE(preferred_phone.value, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||advisor||' || REPLACE(REPLACE(COALESCE(wa.agent_name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(c.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(preferred_email.value, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(preferred_phone.value, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(wa.agent_name, '')), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(c.created_at, c.updated_at, p.created_at, p.updated_at) AS updated_at
FROM
    clients c
    JOIN persons p ON p.id = c.person_id
    LEFT JOIN client_organisations co ON c.organisation_id = co.id
    -- Get preferred email
    LEFT JOIN LATERAL (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.client_id = c.id AND cd.role = 'preferred_email'
        LIMIT 1
    ) preferred_email ON true
    -- Get preferred phone
    LEFT JOIN LATERAL (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.client_id = c.id AND cd.role = 'preferred_phone'
        LIMIT 1
    ) preferred_phone ON true
    -- Get primary Wealth Advisor
    LEFT JOIN LATERAL (
        SELECT CONCAT_WS(' ', wa_p.first_name, wa_p.last_name) AS agent_name
        FROM agent_client_organisation_relationships wa_acor
        JOIN agents wa_a ON wa_acor.agent_id = wa_a.id
        JOIN persons wa_p ON wa_a.person_id = wa_p.id
        WHERE wa_acor.client_organisation_id = co.id
          AND wa_acor.relationship_type = 'Wealth Advisor'
        LIMIT 1
    ) wa ON true
WHERE c.deleted_at IS NULL;

CREATE UNIQUE INDEX idx_client_fts_client_id ON client_fts (client_id);
CREATE INDEX idx_client_fts_tenant_id ON client_fts (tenant_id);
CREATE INDEX idx_client_fts_search_vector ON client_fts USING gin (search_vector);
CREATE INDEX idx_client_fts_search_text_trgm ON client_fts USING gin (search_text gin_trgm_ops);
CREATE INDEX idx_client_fts_updated_at ON client_fts (updated_at DESC NULLS LAST);
CREATE INDEX idx_client_fts_tenant_updated ON client_fts (tenant_id, updated_at DESC NULLS LAST);

-- ============================================================================
-- 2. UPDATE financial_account_fts - Add financial_account_external_id, relationship_external_id
-- ============================================================================
DROP MATERIALIZED VIEW IF EXISTS financial_account_fts;

CREATE MATERIALIZED VIEW financial_account_fts AS
SELECT
    fa.id AS financial_account_id,
    fa.tenant_id,
    fa.client_organisation_id,
    -- Display text: Account Name (Account Number)
    CASE
        WHEN fa.name IS NOT NULL AND fa.name != ''
        THEN fa.name || ' (' || fa.account_number || ')'
        ELSE fa.account_number
    END AS display_text,
    -- display_fields: Structured JSONB for rich client rendering
    jsonb_build_object(
        'fa_number', fa.account_number,
        'fa_id', fa.id,
        'financial_account_external_id', fa.external_id,
        'relationship_name', co.name,
        'relationship_id', fa.client_organisation_id,
        'relationship_external_id', co.external_id,
        'name', fa.name,
        'custodian', fa.custodian,
        'cash_balance', fa.cash_balance,
        'total_balance', fa.balance
    ) AS display_fields,
    -- Raw search text with token separators for highlighting
    '||account||' || REPLACE(REPLACE(COALESCE(fa.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||account_number||' || REPLACE(REPLACE(COALESCE(fa.account_number, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||external_id||' || REPLACE(REPLACE(COALESCE(fa.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||relationship_external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||primary_owner||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', po_p.first_name, po_p.middle_name, po_p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||secondary_owner||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', so_p.first_name, so_p.middle_name, so_p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||beneficiary||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', ben_p.first_name, ben_p.middle_name, ben_p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||client||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||product||' || REPLACE(REPLACE(COALESCE(prod.product_name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||custodian||' || REPLACE(REPLACE(COALESCE(fa.custodian, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    setweight(to_tsvector('simple', COALESCE(fa.name, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(fa.account_number, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(fa.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', po_p.first_name, po_p.middle_name, po_p.last_name), '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', so_p.first_name, so_p.middle_name, so_p.last_name), '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', ben_p.first_name, ben_p.middle_name, ben_p.last_name), '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(fa.custodian, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(prod.product_name, '')), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(fa.created_at, fa.updated_at) AS updated_at
FROM
    financial_accounts fa
    LEFT JOIN clients po ON fa.primary_owner_id = po.id
    LEFT JOIN persons po_p ON po.person_id = po_p.id
    LEFT JOIN clients so ON fa.secondary_owner_id = so.id
    LEFT JOIN persons so_p ON so.person_id = so_p.id
    LEFT JOIN clients ben ON fa.beneficiary_id = ben.id
    LEFT JOIN persons ben_p ON ben.person_id = ben_p.id
    LEFT JOIN client_organisations co ON fa.client_organisation_id = co.id
    LEFT JOIN financial_products prod ON fa.product_id = prod.id;

CREATE UNIQUE INDEX idx_financial_account_fts_id ON financial_account_fts (financial_account_id);
CREATE INDEX idx_financial_account_fts_tenant_id ON financial_account_fts (tenant_id);
CREATE INDEX idx_financial_account_fts_client_org_id ON financial_account_fts (client_organisation_id);
CREATE INDEX idx_financial_account_fts_search_vector ON financial_account_fts USING gin (search_vector);
CREATE INDEX idx_financial_account_fts_search_text_trgm ON financial_account_fts USING gin (search_text gin_trgm_ops);
CREATE INDEX idx_financial_account_fts_updated_at ON financial_account_fts (updated_at DESC NULLS LAST);
CREATE INDEX idx_financial_account_fts_tenant_updated ON financial_account_fts (tenant_id, updated_at DESC NULLS LAST);

-- ============================================================================
-- 3. UPDATE client_organisation_fts - Add client_organisation_external_id, relationship_external_id
-- ============================================================================
DROP MATERIALIZED VIEW IF EXISTS client_organisation_fts;

CREATE MATERIALIZED VIEW client_organisation_fts AS
SELECT
    co.id AS client_organisation_id,
    co.tenant_id,
    -- Display text: client org name + primary agent (Wealth Advisor)
    CASE
        WHEN wa.agent_name IS NOT NULL THEN co.name || ' (' || wa.agent_name || ')'
        ELSE co.name
    END AS display_text,
    -- display_fields: Structured JSONB for rich client rendering
    jsonb_build_object(
        'relationship_name', co.name,
        'relationship_id', co.id,
        'client_organisation_external_id', co.external_id,
        'relationship_external_id', co.external_id,
        'advisor', wa.agent_name,
        'offering', co.client_organisation_type,
        'type', co.client_organisation_role
    ) AS display_fields,
    -- Raw search text with token separators for highlighting
    '||name||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||description||' || REPLACE(REPLACE(COALESCE(co.description, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||region||' || REPLACE(REPLACE(COALESCE(bg.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||office||' || REPLACE(REPLACE(COALESCE(aof.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agent_org||' || REPLACE(REPLACE(COALESCE(ao.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agents||' || REPLACE(REPLACE(COALESCE(all_agents.agent_names, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(all_agents.agent_names, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(bg.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(aof.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(ao.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(co.description, '')), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(co.created_at, co.updated_at) AS updated_at
FROM
    client_organisations co
    LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
    LEFT JOIN business_groups bg ON co.business_group_id = bg.id
    LEFT JOIN agent_organisations aof ON co.office_id = aof.id
    -- Get primary agent (Wealth Advisor) for display
    LEFT JOIN LATERAL (
        SELECT CONCAT_WS(' ', p.first_name, p.last_name) AS agent_name
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
          AND acor.relationship_type = 'Wealth Advisor'
        LIMIT 1
    ) wa ON true
    -- Get ALL agent names for search (aggregated)
    LEFT JOIN LATERAL (
        SELECT string_agg(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), ' ') AS agent_names
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = co.id
    ) all_agents ON true
WHERE co.deleted_at IS NULL;

CREATE UNIQUE INDEX idx_client_organisation_fts_id ON client_organisation_fts (client_organisation_id);
CREATE INDEX idx_client_organisation_fts_tenant_id ON client_organisation_fts (tenant_id);
CREATE INDEX idx_client_organisation_fts_search_vector ON client_organisation_fts USING gin (search_vector);
CREATE INDEX idx_client_organisation_fts_search_text_trgm ON client_organisation_fts USING gin (search_text gin_trgm_ops);
CREATE INDEX idx_client_organisation_fts_updated_at ON client_organisation_fts (updated_at DESC NULLS LAST);
CREATE INDEX idx_client_organisation_fts_tenant_updated ON client_organisation_fts (tenant_id, updated_at DESC NULLS LAST);

-- ============================================================================
-- 4. UPDATE task_fts - Add relationship_external_id
-- ============================================================================
DROP MATERIALIZED VIEW IF EXISTS task_fts;

CREATE MATERIALIZED VIEW task_fts AS
SELECT
    t.id AS task_id,
    t.tenant_id,
    ar.client_organisation_id,
    -- Display text: Task Name (Status)
    t.name || ' (' || t.status || ')' AS display_text,
    -- display_fields: Structured JSONB for rich client rendering
    jsonb_build_object(
        'task_name', t.name,
        'task_id', t.id,
        'relationship_name', co.name,
        'relationship_id', ar.client_organisation_id,
        'relationship_external_id', co.external_id,
        'action_name', ar.name,
        'blueprint_name', ar.blueprint_name,
        'status', t.status,
        'agent_name', CONCAT_WS(' ', agent_p.first_name, agent_p.last_name),
        'due_date', t.deadline
    ) AS display_fields,
    -- Raw search text with token separators for highlighting
    '||task||' || REPLACE(REPLACE(COALESCE(t.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||action||' || REPLACE(REPLACE(COALESCE(ar.name, '')::text, E'\\', E'\\\\'), '|', E'\\|') ||
    '||blueprint||' || REPLACE(REPLACE(COALESCE(ar.blueprint_name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||client||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||relationship_external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agent||' || REPLACE(REPLACE(COALESCE(CONCAT_WS(' ', agent_p.first_name, agent_p.middle_name, agent_p.last_name), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||notes||' || REPLACE(REPLACE(COALESCE(t.note, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||tags||' || REPLACE(REPLACE(COALESCE(array_to_string(t.tags, ' '), ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||status||' || REPLACE(REPLACE(COALESCE(t.status, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    setweight(to_tsvector('simple', COALESCE(t.name, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(ar.name, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(ar.blueprint_name, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(CONCAT_WS(' ', agent_p.first_name, agent_p.middle_name, agent_p.last_name), '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(t.note, '')), 'D') ||
    setweight(to_tsvector('simple', COALESCE(array_to_string(t.tags, ' '), '')), 'D') ||
    setweight(to_tsvector('simple', COALESCE(t.status, '')), 'D')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(t.created_at, t.last_updated_at) AS updated_at
FROM
    tasks t
    INNER JOIN action_runs ar ON t.run_id = ar.id
    LEFT JOIN client_organisations co ON ar.client_organisation_id = co.id
    LEFT JOIN agents agent ON t.assigned_agent_id = agent.id
    LEFT JOIN persons agent_p ON agent.person_id = agent_p.id
WHERE
    t.deleted_at IS NULL
    AND t.cancelled_at IS NULL;

CREATE UNIQUE INDEX idx_task_fts_id ON task_fts (task_id);
CREATE INDEX idx_task_fts_tenant_id ON task_fts (tenant_id);
CREATE INDEX idx_task_fts_client_org_id ON task_fts (client_organisation_id);
CREATE INDEX idx_task_fts_search_vector ON task_fts USING gin (search_vector);
CREATE INDEX idx_task_fts_search_text_trgm ON task_fts USING gin (search_text gin_trgm_ops);
CREATE INDEX idx_task_fts_updated_at ON task_fts (updated_at DESC NULLS LAST);
CREATE INDEX idx_task_fts_tenant_updated ON task_fts (tenant_id, updated_at DESC NULLS LAST);

