-- ╔═════ 20251209142005-cron_job_configs.sql ═════╗
-- Cron job configuration table for dynamic job management
CREATE TABLE cron_job_configs (
    id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
    job_name TEXT NOT NULL UNIQUE,
    schedule TEXT NOT NULL,                    -- Cron expression (e.g., "*/5 * * * *")
    enabled BOOLEAN NOT NULL DEFAULT true,
    description TEXT,

    -- Execution controls
    timeout_seconds INTEGER DEFAULT 300,       -- Max execution time before kill
    max_retries INTEGER DEFAULT 0,             -- Number of retry attempts on failure
    retry_delay_seconds INTEGER DEFAULT 60,    -- Delay between retries

    -- Concurrency control (cross-node singleton execution)
    allow_concurrent BOOLEAN DEFAULT false,    -- Allow overlapping executions across nodes
    advisory_lock_key BIGINT NOT NULL,         -- Postgres advisory lock ID for cross-node coordination

    -- Metadata
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_by TEXT                            -- Who last modified (for audit)
);

-- Index for polling efficiency
CREATE INDEX idx_cron_job_configs_updated_at ON cron_job_configs (updated_at);

-- Ensure advisory lock keys are unique to prevent conflicts
CREATE UNIQUE INDEX idx_cron_job_configs_advisory_lock_key ON cron_job_configs (advisory_lock_key);

-- Advisory lock key ranges:
-- 1000: FTS sequential refresh global lock
-- 1001-1099: Reserved for FTS refresh views (see fts_refresh_service.go)
-- 2001-2999: Reserved for cron jobs
-- Jobs should use keys in the 2001+ range to avoid conflicts

-- Trigger to auto-update updated_at
CREATE OR REPLACE FUNCTION update_cron_job_configs_updated_at()
RETURNS TRIGGER AS $$
BEGIN
    NEW.updated_at = NOW();
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;
CREATE TRIGGER cron_job_configs_updated_at_trigger
    BEFORE UPDATE ON cron_job_configs
    FOR EACH ROW
    EXECUTE FUNCTION update_cron_job_configs_updated_at();

-- ╔═════ 20251209142044-cron_system_state.sql ═════╗
-- System-wide cron manager state (singleton row pattern)
-- Used for global pause/resume functionality during maintenance
CREATE TABLE cron_system_state (
    id TEXT PRIMARY KEY DEFAULT 'singleton' CHECK (id = 'singleton'),
    paused BOOLEAN NOT NULL DEFAULT false,
    paused_at TIMESTAMP WITH TIME ZONE,
    paused_by TEXT,
    pause_reason TEXT,
    resume_at TIMESTAMP WITH TIME ZONE,        -- Optional: auto-resume time
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

-- Insert singleton row
INSERT INTO cron_system_state (id, paused) VALUES ('singleton', false);

-- Reuse the trigger function from cron_job_configs for updated_at
CREATE TRIGGER cron_system_state_updated_at_trigger
    BEFORE UPDATE ON cron_system_state
    FOR EACH ROW
    EXECUTE FUNCTION update_cron_job_configs_updated_at();

-- ╔═════ 20251209142107-cron_job_executions.sql ═════╗
-- Cron job execution history for observability and debugging
CREATE TABLE cron_job_executions (
    id TEXT PRIMARY KEY DEFAULT gen_random_uuid()::text,
    job_name TEXT NOT NULL,
    node_id TEXT NOT NULL,                     -- Hostname/instance ID
    started_at TIMESTAMP WITH TIME ZONE NOT NULL,
    completed_at TIMESTAMP WITH TIME ZONE,
    status TEXT NOT NULL,                      -- 'running', 'success', 'failed', 'timeout'
    error_message TEXT,
    duration_ms BIGINT,

    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

-- Index for querying execution history by job
CREATE INDEX idx_cron_job_executions_job_name ON cron_job_executions (job_name, started_at DESC);

-- Index for querying recent executions
CREATE INDEX idx_cron_job_executions_started_at ON cron_job_executions (started_at DESC);

-- Partial index for failed executions (common query pattern)
CREATE INDEX idx_cron_job_executions_failed ON cron_job_executions (status, started_at DESC) WHERE status = 'failed';

