-- ╔═════ 20251222135355-add_new_commentable_entity_types.sql ═════╗
-- Add new values to the existing enum type
-- Note: These operations cannot be run inside a transaction in PostgreSQL < 12
ALTER TYPE commentable_entity_type ADD VALUE IF NOT EXISTS 'opportunity';
ALTER TYPE commentable_entity_type ADD VALUE IF NOT EXISTS 'legacy_action_run';
ALTER TYPE commentable_entity_type ADD VALUE IF NOT EXISTS 'legacy_activity';

-- Recreate the view to ensure it's in sync (optional, but good practice)
DROP VIEW IF EXISTS unqork_comment_normalized_view;

CREATE VIEW unqork_comment_normalized_view AS
SELECT 
    uc.id,
    uc.tenant_id,
    COALESCE(data->>'actionSubId', data->>'meetingSubId', '') AS entity_id,
    CASE 
        WHEN data->>'actionSubId' IS NOT NULL THEN 'action_run'::commentable_entity_type
        WHEN data->>'meetingSubId' IS NOT NULL THEN 'meeting'::commentable_entity_type
        ELSE NULL
    END AS entity_type,
    COALESCE(data->>'comment', '') AS text,
    COALESCE(data->>'addedBy', uc.owner, '') AS created_by,
    uc.created::TIMESTAMP WITH TIME ZONE AS created_at,
    uc.unqork_id AS external_id,
    CASE 
        WHEN data->'commentTag' IS NULL THEN ARRAY[]::text[]
        WHEN jsonb_typeof(data->'commentTag') = 'array' THEN
            ARRAY(SELECT jsonb_array_elements_text(data->'commentTag'))
        ELSE ARRAY[]::text[]
    END AS tagged_users
FROM unqork_comments uc;

-- ╔═════ 20251222150354-create_audit_trail.sql ═════╗
CREATE TABLE IF NOT EXISTS audit_trail (
    id            TEXT PRIMARY KEY,
    tenant_id     TEXT NOT NULL,
    table_name    TEXT NOT NULL,
    record_id     TEXT NOT NULL,
    operation     TEXT NOT NULL CHECK (operation IN ('create', 'update', 'delete')),
    actor_id      TEXT NOT NULL,
    actor_type    TEXT NOT NULL DEFAULT 'agent' CHECK (actor_type IN ('agent', 'system', 'integration')),
    request_id    TEXT,
    occurred_at   TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    payload       JSONB NOT NULL
);

-- Primary query pattern: "show history for this record in this tenant"
CREATE INDEX idx_audit_trail_tenant_record ON audit_trail (tenant_id, record_id, occurred_at DESC);

-- Secondary: "show all changes to table X in tenant Y" (compliance queries)
CREATE INDEX idx_audit_trail_tenant_table ON audit_trail (tenant_id, table_name, occurred_at DESC);

-- Tertiary: time-based scans for archival/retention jobs
CREATE INDEX idx_audit_trail_occurred ON audit_trail (occurred_at DESC);

