-- ╔═════ 20260106155728-create_documents_table.sql ═════╗
CREATE TABLE IF NOT EXISTS documents (
    id                    TEXT PRIMARY KEY,
    tenant_id             TEXT NOT NULL,
    relationship_id       TEXT NOT NULL,              -- Owning relationship
    action_run_id         TEXT,                       -- Nullable servicing event
    storage_mode          TEXT NOT NULL,              -- 'PLATFORM_MANAGED' or 'EXTERNAL'
    storage_provider      TEXT NOT NULL,              -- 'S3', 'GCS', 'BOX', etc.
    storage_container     TEXT NOT NULL,              -- Bucket / container name
    storage_object_key    TEXT NOT NULL,              -- Object key / blob path
    storage_object_version TEXT,                      -- Nullable version ID
    external_object_id    TEXT,                       -- Nullable provider-native ID
    filename              TEXT NOT NULL,              -- Original filename
    content_type          TEXT NOT NULL,              -- MIME type
    file_size_bytes       BIGINT,                     -- Verified size (nullable until verified)
    uploaded_by           TEXT NOT NULL,              -- User/system who initiated upload
    upload_status         TEXT NOT NULL DEFAULT 'INITIATED', -- INITIATED, VERIFIED, FAILED
    created_at            TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at            TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    deleted_at            TIMESTAMP WITH TIME ZONE    -- Soft delete
);

CREATE INDEX IF NOT EXISTS idx_documents_tenant_relationship ON documents (tenant_id, relationship_id, deleted_at);
CREATE INDEX IF NOT EXISTS idx_documents_tenant_action_run ON documents (tenant_id, relationship_id, action_run_id, deleted_at);
CREATE INDEX IF NOT EXISTS idx_documents_storage_key ON documents (storage_container, storage_object_key);

