CREATE OR REPLACE VIEW agent_person_view AS
SELECT a.id AS agent_id,
       a.tenant_id,
       a.organisation_id,
       a.license,
       a.compliance_record,
       a.qualification,
       a.specialization,
       a.advisor_identification,
