-- ╔═════ 20260203093553-create_policies_tables.sql ═════╗
-- policies table
CREATE TABLE IF NOT EXISTS policies (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    external_id TEXT,
    client_organisation_id TEXT NOT NULL,
    primary_client_id TEXT,
    line_of_business TEXT NOT NULL,
    subtype TEXT,
    status TEXT NOT NULL DEFAULT 'Active',
    policy_number TEXT,
    carrier TEXT,
    issue_date TIMESTAMP WITH TIME ZONE,
    effective_date TIMESTAMP WITH TIME ZONE,
    premium_amount NUMERIC(19, 4),
    premium_frequency TEXT,
    face_amount NUMERIC(19, 4),
    additional_attributes JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    deleted_at TIMESTAMP WITH TIME ZONE,
    deleted_by TEXT,
    CONSTRAINT fk_policies_client_organisation
        FOREIGN KEY (client_organisation_id) REFERENCES client_organisations(id),
    CONSTRAINT fk_policies_primary_client
        FOREIGN KEY (primary_client_id) REFERENCES clients(id),
    CONSTRAINT uq_policies_tenant_id UNIQUE (tenant_id, id)
);

-- policy_client_roles table (client-policy junction)
CREATE TABLE IF NOT EXISTS policy_client_roles (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    policy_id TEXT NOT NULL,
    client_id TEXT NOT NULL,
    role TEXT NOT NULL,
    effective_from TIMESTAMP WITH TIME ZONE,
    effective_to TIMESTAMP WITH TIME ZONE,
    additional_attributes JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT fk_policy_client_roles_policy FOREIGN KEY (tenant_id, policy_id) REFERENCES policies(tenant_id, id) ON DELETE CASCADE,
    CONSTRAINT fk_policy_client_roles_client FOREIGN KEY (client_id) REFERENCES clients(id),
    CONSTRAINT uq_policy_client_roles_unique UNIQUE (tenant_id, policy_id, client_id, role)
);

-- policy_agent_relationships table (agent-policy junction)
CREATE TABLE IF NOT EXISTS policy_agent_relationships (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    policy_id TEXT NOT NULL,
    agent_id TEXT NOT NULL,
    role TEXT NOT NULL,
    effective_from TIMESTAMP WITH TIME ZONE,
    effective_to TIMESTAMP WITH TIME ZONE,
    additional_attributes JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT fk_policy_agent_rel_policy FOREIGN KEY (tenant_id, policy_id) REFERENCES policies(tenant_id, id) ON DELETE CASCADE,
    CONSTRAINT fk_policy_agent_rel_agent FOREIGN KEY (agent_id) REFERENCES agents(id),
    CONSTRAINT uq_policy_agent_rel_unique UNIQUE (tenant_id, policy_id, agent_id, role)
);

-- Indexes for policies
CREATE INDEX idx_policies_tenant_id ON policies(tenant_id);
CREATE INDEX idx_policies_external_id ON policies(tenant_id, external_id) WHERE external_id IS NOT NULL;
CREATE INDEX idx_policies_client_organisation ON policies(client_organisation_id);
CREATE INDEX idx_policies_primary_client ON policies(primary_client_id) WHERE primary_client_id IS NOT NULL;
CREATE INDEX idx_policies_status ON policies(tenant_id, status);
CREATE INDEX idx_policies_line_of_business ON policies(tenant_id, line_of_business);
CREATE INDEX idx_policies_not_deleted ON policies(tenant_id) WHERE deleted_at IS NULL;

-- Indexes for policy_client_roles
CREATE INDEX idx_policy_client_roles_tenant_id ON policy_client_roles(tenant_id);
CREATE INDEX idx_policy_client_roles_policy_id ON policy_client_roles(policy_id);
CREATE INDEX idx_policy_client_roles_client_id ON policy_client_roles(client_id);
CREATE INDEX idx_policy_client_roles_role ON policy_client_roles(tenant_id, role);

-- Indexes for policy_agent_relationships
CREATE INDEX idx_policy_agent_rel_tenant_id ON policy_agent_relationships(tenant_id);
CREATE INDEX idx_policy_agent_rel_policy_id ON policy_agent_relationships(policy_id);
CREATE INDEX idx_policy_agent_rel_agent_id ON policy_agent_relationships(agent_id);
CREATE INDEX idx_policy_agent_rel_role ON policy_agent_relationships(tenant_id, role);

-- ╔═════ 20260203131209-add_policies_view.sql ═════╗
-- View for active (non-deleted) policies
CREATE VIEW policies_view AS
SELECT
    id,
    tenant_id,
    external_id,
    client_organisation_id,
    primary_client_id,
    line_of_business,
    subtype,
    status,
    policy_number,
    carrier,
    issue_date,
    effective_date,
    premium_amount,
    premium_frequency,
    face_amount,
    additional_attributes,
    created_at,
    updated_at
FROM policies
WHERE deleted_at IS NULL;

-- ╔═════ 20260203142813-enriched_task_indexes.sql ═════╗
-- Allows index scan to find tasks by tenant and status directly
-- instead of seq scanning ~189K rows in the tasks table
CREATE INDEX IF NOT EXISTS idx_tasks_tenant_status
ON tasks(tenant_id, status) WHERE deleted_at IS NULL;

-- Supports the OR branch: WHERE assigned_agent_id = ?
-- Enables BitmapOr optimization for the combined filter
CREATE INDEX IF NOT EXISTS idx_tasks_tenant_agent
ON tasks(tenant_id, assigned_agent_id) WHERE deleted_at IS NULL;

-- Supports ABAC-driven lookups: WHERE client_organisation_id IN (...) AND environment = ?
-- INCLUDE(id) enables index-only scan for the join condition (ar.id = t.run_id)
CREATE INDEX IF NOT EXISTS idx_action_runs_client_org_env
ON action_runs(client_organisation_id, environment) INCLUDE (id);

-- ╔═════ 20260203143312-add_unique_constraint_policies_external_id.sql ═════╗
-- Add unique constraint on (tenant_id, external_id) for policies table
-- This allows ON CONFLICT upserts based on external_id within a tenant
CREATE UNIQUE INDEX IF NOT EXISTS idx_policies_tenant_external_id_unique
    ON policies(tenant_id, external_id)
    WHERE external_id IS NOT NULL;

-- ╔═════ 20260203222641-add_assigned_agent_name_to_tasks.sql ═════╗
DROP VIEW IF EXISTS enriched_task;
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    assigned_agent_person.first_name AS assigned_agent_first_name,
    assigned_agent_person.last_name AS assigned_agent_last_name,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    t.cron_job_queued,
    ar.id AS action_run_id,
    NULL::text AS action_number, -- there's no action_number in the action_runs table
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ar.status AS action_run_status,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name, 'external_id', ap.external_id) AS primary_css,
    co.client_segmentation AS client_segmentation,
    co.approx_aum AS aum
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id
     LEFT JOIN agent_person_view assigned_agent_person ON assigned_agent_person.agent_id = t.assigned_agent_id AND assigned_agent_person.tenant_id = t.tenant_id
 WHERE t.deleted_at IS NULL;

