-- ╔═════ 20260204112235-add_policies_search_view.sql ═════╗
CREATE VIEW policies_search_view AS
SELECT
    p.id,
    p.tenant_id,
    p.external_id,
    p.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    p.line_of_business,
    p.subtype,
    p.status,
    p.policy_number,
    p.carrier,
    p.issue_date,
    p.effective_date,
    p.premium_amount,
    p.premium_frequency,
    p.face_amount,
    p.additional_attributes,
    p.created_at,
    p.updated_at,
    -- Aggregate clients with their roles
    (
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'client_id', pcr.client_id,
                'client_external_id', c.external_id,
                'client_name', COALESCE(per.first_name || ' ' || per.last_name, ''),
                'role', pcr.role,
                'effective_from', pcr.effective_from,
                'effective_to', pcr.effective_to
            )
        ), '[]'::jsonb)
        FROM policy_client_roles pcr
        LEFT JOIN clients c ON pcr.client_id = c.id AND c.tenant_id = p.tenant_id
        LEFT JOIN persons per ON c.person_id = per.id AND per.tenant_id = p.tenant_id
        WHERE pcr.policy_id = p.id AND pcr.tenant_id = p.tenant_id
    ) AS clients,
    -- Aggregate agents with their roles
    (
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'agent_id', par.agent_id,
                'agent_external_id', a.external_id,
                'agent_name', COALESCE(per.first_name || ' ' || per.last_name, ''),
                'role', par.role,
                'effective_from', par.effective_from,
                'effective_to', par.effective_to
            )
        ), '[]'::jsonb)
        FROM policy_agent_relationships par
        LEFT JOIN agents a ON par.agent_id = a.id AND a.tenant_id = p.tenant_id
        LEFT JOIN persons per ON a.person_id = per.id AND per.tenant_id = p.tenant_id
        WHERE par.policy_id = p.id AND par.tenant_id = p.tenant_id
    ) AS agents
FROM policies p
LEFT JOIN client_organisations co ON p.client_organisation_id = co.id AND co.tenant_id = p.tenant_id
WHERE p.deleted_at IS NULL;

