-- kpi_dimension_definitions table (reference table for dimension keys)
CREATE TABLE IF NOT EXISTS kpi_dimension_definitions (
    key TEXT PRIMARY KEY,
    description TEXT,
    value_type TEXT NOT NULL DEFAULT 'text'
);

-- Seed dimension definitions
INSERT INTO kpi_dimension_definitions (key, description, value_type) VALUES
    ('agent_id', 'Agent identifier for agent-level metrics', 'text'),
    ('action_type', 'Type/category of action', 'text'),
    ('task_type', 'Type of task', 'text'),
    ('team_id', 'Team/business group identifier', 'text'),
    ('blueprint_id', 'Action blueprint identifier', 'text'),
    ('status', 'Status dimension for status-based aggregations', 'text')
ON CONFLICT (key) DO NOTHING;

-- kpi_definitions table
CREATE TABLE IF NOT EXISTS kpi_definitions (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    name TEXT NOT NULL,
    description TEXT,
    unit TEXT NOT NULL,
    period_granularity TEXT NOT NULL,
    allowed_dimensions JSONB NOT NULL DEFAULT '[]'::jsonb,
    numerator_definition TEXT,
    denominator_definition TEXT,
    sla_policy_id TEXT,
    slo_policy_id TEXT,
    status TEXT NOT NULL DEFAULT 'active',
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_kpi_definitions_tenant_name UNIQUE (tenant_id, name)
);

-- kpi_runs table (tracks computation runs)
CREATE TABLE IF NOT EXISTS kpi_runs (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    started_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    finished_at TIMESTAMP WITH TIME ZONE,
    status TEXT NOT NULL DEFAULT 'running',
    period_start DATE NOT NULL,
    period_end DATE NOT NULL,
    values_upserted INTEGER DEFAULT 0,
    error_message TEXT,
    notes TEXT,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

-- kpi_values table (stores computed KPI values)
CREATE TABLE IF NOT EXISTS kpi_values (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    kpi_id TEXT NOT NULL REFERENCES kpi_definitions(id),
    period_start DATE NOT NULL,
    period_end DATE NOT NULL,
    period_granularity TEXT NOT NULL,
    client_organisation_id TEXT NOT NULL,
    dimensions JSONB NOT NULL DEFAULT '{}'::jsonb,
    value NUMERIC NOT NULL,
    numerator NUMERIC,
    denominator NUMERIC,
    status_label TEXT,
    computed_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    run_id TEXT REFERENCES kpi_runs(id),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT uq_kpi_values_unique UNIQUE (tenant_id, kpi_id, client_organisation_id, period_start, period_granularity, dimensions)
);

-- Indexes for kpi_definitions
CREATE INDEX idx_kpi_definitions_tenant_id ON kpi_definitions(tenant_id);
CREATE INDEX idx_kpi_definitions_status ON kpi_definitions(tenant_id, status);
CREATE INDEX idx_kpi_definitions_name ON kpi_definitions(tenant_id, name);

-- Indexes for kpi_runs
CREATE INDEX idx_kpi_runs_tenant_id ON kpi_runs(tenant_id);
CREATE INDEX idx_kpi_runs_started_at ON kpi_runs(tenant_id, started_at DESC);
CREATE INDEX idx_kpi_runs_status ON kpi_runs(tenant_id, status);
CREATE INDEX idx_kpi_runs_period ON kpi_runs(tenant_id, period_start, period_end);

-- Indexes for kpi_values
CREATE INDEX idx_kpi_values_tenant_id ON kpi_values(tenant_id);
CREATE INDEX idx_kpi_values_kpi_id ON kpi_values(tenant_id, kpi_id);
CREATE INDEX idx_kpi_values_client_org ON kpi_values(tenant_id, client_organisation_id);
CREATE INDEX idx_kpi_values_period ON kpi_values(tenant_id, period_start, period_end);
CREATE INDEX idx_kpi_values_run_id ON kpi_values(run_id) WHERE run_id IS NOT NULL;
CREATE INDEX idx_kpi_values_dimensions ON kpi_values USING GIN (dimensions);
CREATE INDEX idx_kpi_values_computed_at ON kpi_values(tenant_id, computed_at DESC);

