-- ╔═════ 20260211180000-add_api_tokens.sql ═════╗
CREATE TABLE IF NOT EXISTS api_tokens (
    id TEXT PRIMARY KEY NOT NULL,
    token_id TEXT NOT NULL UNIQUE,
    tenant_id TEXT NOT NULL,
    name TEXT NOT NULL,
    auth_method TEXT NOT NULL CHECK (auth_method IN ('bearer', 'hmac')),
    token_secret_hash TEXT NULL,
    token_secret_encrypted TEXT NULL,
    scope_type TEXT NOT NULL CHECK (scope_type IN ('role', 'trigger_access')),
    role TEXT NULL,
    expires_at TIMESTAMP WITH TIME ZONE NULL,
    created_by TEXT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    last_used_at TIMESTAMP WITH TIME ZONE NULL,
    is_active BOOLEAN NOT NULL DEFAULT true,
    CONSTRAINT api_tokens_secret_check CHECK (
        (auth_method = 'bearer' AND token_secret_hash IS NOT NULL AND token_secret_encrypted IS NULL) OR
        (auth_method = 'hmac' AND token_secret_encrypted IS NOT NULL AND token_secret_hash IS NULL)
    )
);

CREATE INDEX idx_api_tokens_tenant_id ON api_tokens(tenant_id);
CREATE INDEX idx_api_tokens_token_id ON api_tokens(token_id);
CREATE INDEX idx_api_tokens_token_secret_hash ON api_tokens(token_secret_hash) WHERE token_secret_hash IS NOT NULL;
CREATE INDEX idx_api_tokens_tenant_active ON api_tokens(tenant_id, is_active);

CREATE TABLE IF NOT EXISTS api_token_grants (
    api_token_id TEXT NOT NULL REFERENCES api_tokens(id) ON DELETE CASCADE,
    grant_type TEXT NOT NULL CHECK (grant_type IN ('trigger_service', 'trigger_endpoint', 'custom_js_function')),
    grant_target_id TEXT NOT NULL,
    PRIMARY KEY (api_token_id, grant_type, grant_target_id)
);

CREATE INDEX idx_api_token_grants_api_token_id ON api_token_grants(api_token_id);

-- ╔═════ 20260212222505-add_uhnw_service_level_to_tasks.sql ═════╗
DROP VIEW IF EXISTS enriched_action_runs_with_snapshot;
DROP VIEW IF EXISTS enriched_action_runs;

CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.locked_at,
    ar.locked_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg (
                acor.relationship_type,
                jsonb_build_object (
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date,
    -- Return NULL for current_snapshot_data since we no longer maintain this in the base view
    -- Use enriched_action_runs_with_snapshot view for snapshot data
    NULL::jsonb AS current_snapshot_data
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
WHERE
    ar.deleted_at IS NULL;

CREATE VIEW enriched_action_runs_with_snapshot AS
SELECT
    ear.action_run_id,
    ear.tenant_id,
    ear.action_id,
    ear.status,
    ear.started_by,
    ear.client_organisation_id,
    ear.started_at,
    GREATEST(
        ear.last_updated_at,
        COALESCE(task_max.max_last_updated_at, ear.last_updated_at)
    ) AS last_updated_at,
    ear.action_run_name,
    ear.slug,
    ear.blueprint_version_id,
    ear.scheduled_at,
    ear.data,
    ear.recommended,
    ear.cancelled_at,
    ear.run_context,
    ear.created_at,
    ear.ready_at,
    ear.rejected_at,
    ear.completed_at,
    ear.cancelled_by,
    ear.cancellation_reason,
    ear.locked_at,
    ear.locked_by,
    ear.recommended_by,
    ear.rejection_reason,
    ear.rejected_by,
    ear.deadline,
    ear.parent_run_id,
    ear.environment,
    ear.blueprint_name,
    ear.blueprint_category,
    ear.blueprint_description,
    ear.blueprint_short_description,
    ear.next_step_date,
    ear.client_organisation_name,
    ear.client_organisation_type,
    ear.client_segmentation,
    ear.client_organisation_external_id,
    ear.client_organisation_national_css_coverage,
    ear.client_organisation_uhnw_service_level,
    ear.client_organisation_market,
    ear.aum,
    ear.agents,
    ear.is_journey,
    ear.expected_completion_date,
    snap.current_snapshot_data
FROM enriched_action_runs ear
LEFT JOIN LATERAL (
    SELECT MAX(t.last_updated_at) as max_last_updated_at
    FROM tasks t
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.last_updated_at IS NOT NULL
        AND t.data IS NOT NULL
) task_max ON true
-- LATERAL join to compute snapshot from done tasks
LEFT JOIN LATERAL (
    SELECT jsonb_object_agg(
        kv.key,
        kv.value ORDER BY t.completed_at, t.id
    ) FILTER (WHERE kv.key IS NOT NULL) AS current_snapshot_data
    FROM tasks t
    CROSS JOIN LATERAL jsonb_each(t.data) as kv(key, value)
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.completed_at IS NOT NULL
        AND t.data IS NOT NULL
        AND t.data <> 'null'::jsonb
        AND jsonb_typeof(t.data) = 'object'
) snap ON true;

DROP VIEW IF EXISTS unqork_action_runs_view;

CREATE VIEW unqork_action_runs_view AS
SELECT
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL
        OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.external_id = uar.action_owner_salentica_id
            AND a.tenant_id = '1'
    ) AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum,
    -- Build custom data object with standardized structure
    jsonb_build_object(
        'action_id',
        uar.action_id,
        'action_rel_segment',
        uar.action_rel_segment,
        'action_rel_id',
        uar.action_rel_id,
        'action_current_task_title',
        uar.action_current_task_title,
        'action_no',
        uar.action_no,
        'action_owner_canceled',
        uar.action_owner_canceled,
        'action_owner_user_id',
        uar.action_owner_user_id,
        'action_rel_servicing_name',
        uar.action_rel_servicing_name,
        'action_rel_type',
        uar.action_rel_type,
        'actionDescription',
        uar.action_description,
        'financialAccountObject',
        jsonb_build_object(
            'value',
            jsonb_build_object(
                'accountNumber',
                uar.account_number,
                'id',
                uar.financial_account_id,
                'actionRelId',
                uar.action_rel_id,
                'custodianName',
                uar.custodian_name -- add custodian name in same path as avantos actions
            )
        ),
        'financial_account_id',
        uar.financial_account_id,
        'current_task',
        CASE
            WHEN uar.action_current_task_title IS NOT NULL THEN jsonb_build_object(
                'id',
                NULL,
                'name',
                uar.action_current_task_title,
                'status',
                'in_progress' -- Unqork doesn't provide task status, so we assume in_progress
            )
            ELSE NULL
        END
    ) AS data,
    CASE
        WHEN uar.action_status = 'Recommended' THEN true
        ELSE false
    END AS recommended,
    CASE
        WHEN uar.action_status = 'Canceled' THEN uar.action_end_date
        ELSE NULL
    END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE
        WHEN uar.action_status = 'Declined' THEN uar.action_end_date
        ELSE NULL
    END AS rejected_at,
    CASE
        WHEN uar.action_status = 'Completed' THEN uar.action_end_date
        ELSE NULL
    END AS completed_at,
    uar.canceled_by AS cancelled_by, -- Return the name directly for Unqork
    uar.cancel_reason AS cancellation_reason,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.idp_subject = uar.action_owner_user_id
            AND a.tenant_id = '1'
    ) AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by, -- No rejected_by data from Unqork
    safe_iso_timestamptz (uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment, -- Get the environment from the unqork_action_runs table instead of hardcoding as null
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    a.id,
                    'external_id',
                    a.external_id,
                    'first_name',
                    p.first_name,
                    'last_name',
                    p.last_name,
                    'middle_name',
                    p.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agents a ON acor.agent_id = a.id
            JOIN persons p ON a.person_id = p.id
        WHERE
            acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    uar.next_step_date,
    'unqork'::text AS source_system,
    NULL::timestamp with time zone AS expected_completion_date
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

