CREATE TYPE todo_scope_type AS ENUM ('personal', 'role', 'global');

CREATE TABLE todos (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    environment TEXT,
    is_read BOOLEAN NOT NULL DEFAULT false,
    complete BOOLEAN NOT NULL DEFAULT false,
    due_date TIMESTAMP WITH TIME ZONE,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    completed_at TIMESTAMP WITH TIME ZONE,
    assignee_id TEXT REFERENCES agents(id),
    assignee_first_name TEXT,
    assignee_last_name TEXT,
    title TEXT NOT NULL,
    notes TEXT,
    created_by TEXT NOT NULL REFERENCES agents(id),
    client_organisation_id TEXT REFERENCES client_organisations(id),
    client_organisation_name TEXT,
    tags TEXT[] NOT NULL DEFAULT '{}',
    scope_type todo_scope_type NOT NULL DEFAULT 'personal',
    role_names TEXT[],
    CONSTRAINT todo_scope_check CHECK (
        (scope_type = 'global' AND role_names IS NULL) OR
        (scope_type = 'role' AND role_names IS NOT NULL AND cardinality(role_names) > 0) OR
        (scope_type = 'personal' AND role_names IS NULL)
    )
);

