-- ╔═════ 20260223204548-optimize_agent_team_summary_view.sql ═════╗
DROP VIEW IF EXISTS agent_team_summary_view;

CREATE VIEW agent_team_summary_view AS
WITH RECURSIVE team_hierarchy AS (
    -- Base: direct reports for each manager
    SELECT
        m.id AS root_manager_id,
        a.id AS agent_id,
        m.tenant_id,
        ARRAY[m.id, a.id] AS path
    FROM agents m
    JOIN agents a ON a.manager_id = m.id AND a.tenant_id = m.tenant_id AND a.id != m.id
    WHERE EXISTS (
        SELECT 1 FROM agents sub
        WHERE sub.manager_id = m.id
        AND sub.tenant_id = m.tenant_id
    )

    UNION ALL

    -- Recurse: walk down the tree
    SELECT
        th.root_manager_id,
        a.id,
        th.tenant_id,
        th.path || a.id
    FROM team_hierarchy th
    JOIN agents a ON a.manager_id = th.agent_id AND a.tenant_id = th.tenant_id
    WHERE NOT a.id = ANY(th.path)
),
total_counts AS (
    SELECT root_manager_id, tenant_id, count(DISTINCT agent_id) AS total_reports_count
    FROM team_hierarchy
    GROUP BY root_manager_id, tenant_id
)
SELECT
    a.id AS manager_id,
    a.tenant_id,
    a.external_id,
    a.organisation_id,
    a.type AS agent_type,
    a.active,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.title,
    (
        SELECT cd.value
        FROM contact_details cd
        WHERE cd.agent_id = a.id
        AND cd.role = 'primary_email'
        LIMIT 1
    ) AS email,
    (
        SELECT COUNT(*)
        FROM agents sub
        WHERE sub.manager_id = a.id
        AND sub.tenant_id = a.tenant_id
        AND sub.id != a.id
    ) AS direct_reports_count,
    COALESCE(tc.total_reports_count, 0) AS total_reports_count
FROM agents a
JOIN persons p ON a.person_id = p.id
JOIN total_counts tc ON tc.root_manager_id = a.id AND tc.tenant_id = a.tenant_id;

