-- Recreate the view to include the new columns.
DROP VIEW IF EXISTS client_org_opportunities_view;

CREATE VIEW public.client_org_opportunities_view AS
 SELECT opps.id,
    opps.tenant_id,
    opps.external_id,
    opps.client_organisation_id,
    opps.name,
    opps.opportunity_type,
    opps.status,
    opps.probability,
    opps.next_step,
    opps.description,
    opps.expected_close_date,
    opps.created_at,
    opps.updated_at,
    opps.extra_properties,
    opps.owner_id,
    opps.is_closed,
    opps.amount,
    opps.expected_revenue,
    opps.relationship_type,
    opps.lead_source,
    opps.import_type,
    opps.closed_amount,
    opps.record_type,
    opps.amount_transferred,
    opps.prospective_external_id,
    opps.prospective_id,
    opps.next_step_date,
    opps.probability_categorisation,
    opps.next_meeting_date,
    opps.referrer_type,
    opps.referrer_name,
    opps.referrer_external_id,
    opps.lost_reason,
    opps.lost_competitor,
    opps.lost_notes,
    opps.stage,
    opps.stage_changed_date,
    opps.category,
    opps.sub_category,
    opps.confidence,
    opps.source,
    opps.source_details,
    opps.created_by_agent_id,
    orgs.client_organisation_type,
    orgs.relationship_status AS client_organisation_status,
    orgs.name AS client_organisation_name,
    orgs.external_id AS client_organisation_external_id,
    orgs.extra_properties AS client_organisation_extra_properties,
    orgs.growth_opportunity_next_step_date AS client_organisation_growth_opportunity_next_step_date,
    p.name AS prospective_name,
    p.client_organisation_type AS prospective_type
   FROM client_org_opportunities opps
     JOIN client_organisations orgs ON opps.client_organisation_id = orgs.id
     LEFT JOIN client_organisations p ON opps.prospective_id = p.id
   WHERE orgs.deleted_at IS NULL
     AND (p.deleted_at IS NULL OR p.id IS NULL);

-- ╔═════ 20260227071941-create-client-contracts.sql ═════╗
-- New table: client_contracts (per RFC Section 7.1)
CREATE TABLE IF NOT EXISTS client_contracts (
    id                    TEXT PRIMARY KEY,
    tenant_id             TEXT NOT NULL,
    client_id             TEXT NOT NULL,
    external_id           TEXT NOT NULL,

    source_system         TEXT NOT NULL,
    source_record_type    TEXT NOT NULL,
    relationship_status   TEXT NOT NULL DEFAULT 'Active',

    agency_code           TEXT,
    office_id             TEXT,
    contract_type         TEXT,
    contract_number       TEXT,
    contact_id            TEXT,
    producer_cd           TEXT,

    agent_organisation_id TEXT,
    additional_attributes JSONB NOT NULL DEFAULT '{}'::jsonb,

    created_at            TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at            TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    deleted_at            TIMESTAMP WITH TIME ZONE,
    deleted_by            TEXT,

    CONSTRAINT fk_client_contracts_client
        FOREIGN KEY (client_id) REFERENCES clients(id) ON DELETE CASCADE,
    CONSTRAINT fk_client_contracts_agent_org
        FOREIGN KEY (agent_organisation_id) REFERENCES agent_organisations(id),
    CONSTRAINT uq_client_contracts_external_id
        UNIQUE (tenant_id, external_id),
    CONSTRAINT ck_client_contracts_source_system
        CHECK (source_system IN ('CHUB', 'SMARTOFFICE')),
    CONSTRAINT ck_client_contracts_record_type
        CHECK (source_record_type IN ('chub_client', 'so_client', 'so_prospect')),
    CONSTRAINT ck_client_contracts_status
        CHECK (relationship_status IN ('Active', 'Prospect'))
);

