-- ╔═════ 20260302000001-add_is_journey_to_action_blueprints.sql ═════╗
ALTER TABLE action_blueprints ADD COLUMN is_journey BOOLEAN NOT NULL DEFAULT FALSE;

UPDATE action_blueprints ab
SET is_journey = true
WHERE ab.deleted_at IS NULL
  AND EXISTS (
      SELECT 1 FROM action_blueprint_versions abv
      WHERE abv.blueprint_id = ab.id
        AND abv.tenant_id = ab.tenant_id
        AND abv.deleted_at IS NULL
  )
  AND NOT EXISTS (
      SELECT 1 FROM action_blueprint_versions abv
      WHERE abv.blueprint_id = ab.id
        AND abv.tenant_id = ab.tenant_id
        AND abv.deleted_at IS NULL
        AND abv.is_journey = false
  );

