-- ╔═════ 20260309163920-add_form_rules.sql ═════╗
CREATE TYPE custodian as ENUM (
    'Fidelity',
    'Schwab',
    'Pershing',
    'Pershing Advisors'
);

CREATE TYPE transaction_type as ENUM (
    'New Account',
    'Money Movement'
);

CREATE TABLE registrations (
    id TEXT NOT NULL PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    name TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS idx_registrations_tenant_id ON registrations(tenant_id);
CREATE INDEX IF NOT EXISTS idx_registrations_name ON registrations(name);

CREATE TABLE form_rules (
    id TEXT NOT NULL PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    custodian custodian NOT NULL,
    transaction_type transaction_type NOT NULL,
    registration_id TEXT NOT NULL,
    form_template_id TEXT NOT NULL,
    rules JSONB DEFAULT '{}'::jsonb,
    endpoints JSONB DEFAULT '[]'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    FOREIGN KEY (registration_id) REFERENCES registrations(id),
    FOREIGN KEY (form_template_id) REFERENCES forms(id)
);

CREATE INDEX IF NOT EXISTS idx_form_rules_tenant_id ON form_rules(tenant_id);

-- ╔═════ 20260309182211-create_custodian_push_inbox.sql ═════╗
CREATE TABLE IF NOT EXISTS custodian_push_inbox (
    id                  TEXT PRIMARY KEY,
    tenant_id           TEXT NOT NULL,
    source              TEXT NOT NULL,            -- e.g. "pershing"
    tracking_identifier TEXT NOT NULL,            -- dedup key per push
    event_ids           TEXT[] NOT NULL,          -- custodian event/alert IDs to process
    raw_payload         JSONB NOT NULL DEFAULT '{}',
    created_at          TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at          TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Dedup: same push cannot arrive twice for the same source + tracking key
CREATE UNIQUE INDEX IF NOT EXISTS custodian_push_inbox_source_tracking_idx
    ON custodian_push_inbox(tenant_id, source, tracking_identifier);

CREATE INDEX IF NOT EXISTS custodian_push_inbox_created_at_idx
    ON custodian_push_inbox(tenant_id, source, created_at);

-- ╔═════ 20260309182610-create_custodian_events.sql ═════╗
CREATE TABLE IF NOT EXISTS custodian_events (
    id                   TEXT PRIMARY KEY,
    tenant_id            TEXT NOT NULL,
    source               TEXT NOT NULL,       -- "pershing", "fidelity", ...
    external_id          TEXT NOT NULL,       -- custodian's event/alert ID
    tracking_id          TEXT,                -- push-level dedup key

    category_code        TEXT,
    category             TEXT,
    type_code            TEXT,
    type                 TEXT,
    sub_type_code        TEXT,
    sub_type             TEXT,
    description          TEXT,

    status_code          TEXT,                -- e.g. "ACK", "UNACK"
    status               TEXT,
    event_timestamp      TIMESTAMPTZ,

    account_id           TEXT,
    secondary_account_id TEXT,
    account_name         TEXT,

    agent_external_id    TEXT,               -- unresolved custodian rep/advisor ID
    agent_id             TEXT REFERENCES agents(id) ON DELETE SET NULL,

    is_read              BOOLEAN NOT NULL DEFAULT FALSE,
    metadata             JSONB,              -- source-specific extras

    created_at           TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at           TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

-- Dedup gate: same event cannot be stored twice per source
CREATE UNIQUE INDEX IF NOT EXISTS custodian_events_source_external_idx
    ON custodian_events(tenant_id, source, external_id);

CREATE INDEX IF NOT EXISTS custodian_events_agent_idx
    ON custodian_events(tenant_id, agent_id);

CREATE INDEX IF NOT EXISTS custodian_events_category_idx
    ON custodian_events(tenant_id, source, category_code);

-- ╔═════ 20260310193000-create-position-valuation-ledger.sql ═════╗
CREATE TABLE IF NOT EXISTS position_file_controls (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    source_system TEXT NOT NULL,
    control_key TEXT NOT NULL,
    control_version INTEGER NOT NULL DEFAULT 1,
    status TEXT NOT NULL,
    source_file_key TEXT,
    source_file_checksum TEXT,
    source_batch_id TEXT,
    source_run_date DATE,
    source_ctrl_record_count BIGINT,
    ingested_row_count BIGINT,
    accepted_row_count BIGINT,
    rejected_row_count BIGINT,
    validation_summary JSONB NOT NULL DEFAULT '{}'::jsonb,
    error_summary JSONB NOT NULL DEFAULT '{}'::jsonb,
    started_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    finished_at TIMESTAMP WITH TIME ZONE,
    deleted_at TIMESTAMP WITH TIME ZONE,
    created_by TEXT,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT chk_position_file_controls_status CHECK (
        status IN ('processing', 'finished', 'error', 'deleted')
    ),
    CONSTRAINT chk_position_file_controls_state_timestamps CHECK (
        (status = 'processing' AND finished_at IS NULL AND deleted_at IS NULL)
        OR (status IN ('finished', 'error') AND finished_at IS NOT NULL AND deleted_at IS NULL)
        OR (status = 'deleted' AND deleted_at IS NOT NULL)
    )
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_position_file_controls_tenant_id_id
    ON position_file_controls (tenant_id, id);

CREATE INDEX IF NOT EXISTS idx_position_file_controls_tenant_source_started
    ON position_file_controls (tenant_id, source_system, started_at DESC);

CREATE INDEX IF NOT EXISTS idx_position_file_controls_tenant_key
    ON position_file_controls (tenant_id, source_system, control_key);

CREATE UNIQUE INDEX IF NOT EXISTS uq_position_file_controls_active_finished
    ON position_file_controls (tenant_id, source_system, control_key, control_version)
    WHERE status = 'finished' AND deleted_at IS NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_financial_accounts_tenant_id_id
    ON financial_accounts (tenant_id, id);

CREATE UNIQUE INDEX IF NOT EXISTS uq_financial_products_tenant_id_id
    ON financial_products (tenant_id, id);

CREATE TABLE IF NOT EXISTS position_valuations (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    position_file_control_id TEXT NOT NULL,
    business_date DATE NOT NULL,
    valuation_scope TEXT NOT NULL,
    account_id TEXT,
    sub_account_id TEXT,
    product_id TEXT,
    policy_id TEXT,
    valuation_type TEXT NOT NULL,
    quantity NUMERIC(24, 8),
    valuation_amount NUMERIC(24, 8) NOT NULL,
    currency TEXT NOT NULL,
    unit_price NUMERIC(24, 8),
    price_currency TEXT,
    source_system TEXT NOT NULL,
    source_batch_id TEXT,
    external_row_id TEXT,
    source_file_key TEXT,
    source_business_timestamp TIMESTAMP WITH TIME ZONE,
    row_hash TEXT,
    attributes JSONB NOT NULL DEFAULT '{}'::jsonb,
    ingested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT fk_position_valuations_file_control FOREIGN KEY (tenant_id, position_file_control_id) REFERENCES position_file_controls(tenant_id, id),
    CONSTRAINT fk_position_valuations_account FOREIGN KEY (tenant_id, account_id) REFERENCES financial_accounts(tenant_id, id),
    CONSTRAINT fk_position_valuations_product FOREIGN KEY (tenant_id, product_id) REFERENCES financial_products(tenant_id, id),
    CONSTRAINT fk_position_valuations_policy FOREIGN KEY (tenant_id, policy_id) REFERENCES policies(tenant_id, id),
    CONSTRAINT chk_position_valuations_scope CHECK (
        valuation_scope IN ('ACCOUNT_POSITION', 'POLICY_VALUATION')
    ),
    CONSTRAINT chk_position_valuations_policy_scope CHECK (
        (valuation_scope = 'POLICY_VALUATION' AND policy_id IS NOT NULL)
        OR (valuation_scope = 'ACCOUNT_POSITION')
    )
);

CREATE INDEX IF NOT EXISTS idx_position_valuations_tenant_date
    ON position_valuations (tenant_id, business_date DESC);

CREATE INDEX IF NOT EXISTS idx_position_valuations_tenant_control
    ON position_valuations (tenant_id, position_file_control_id);

CREATE UNIQUE INDEX IF NOT EXISTS uq_position_valuations_file_external_row
    ON position_valuations (tenant_id, position_file_control_id, external_row_id)
    WHERE external_row_id IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_position_valuations_file_row_hash
    ON position_valuations (tenant_id, position_file_control_id, row_hash)
    WHERE external_row_id IS NULL AND row_hash IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_position_valuations_canonical
    ON position_valuations (
        tenant_id,
        business_date,
        valuation_scope,
        account_id,
        sub_account_id,
        product_id,
        policy_id,
        valuation_type,
        currency,
        source_business_timestamp DESC,
        ingested_at DESC,
        id DESC
    );

CREATE OR REPLACE VIEW position_valuations_latest AS
WITH ranked AS (
    SELECT
        pv.id,
        pv.tenant_id,
        pv.position_file_control_id,
        pv.business_date,
        pv.valuation_scope,
        pv.account_id,
        pv.sub_account_id,
        pv.product_id,
        pv.policy_id,
        pv.valuation_type,
        pv.quantity,
        pv.valuation_amount,
        pv.currency,
        pv.unit_price,
        pv.price_currency,
        pv.source_system,
        pv.source_batch_id,
        pv.external_row_id,
        pv.source_file_key,
        pv.source_business_timestamp,
        pv.row_hash,
        pv.attributes,
        pv.ingested_at,
        pv.created_at,
        pfc.finished_at AS file_control_finished_at,
        ROW_NUMBER() OVER (
            PARTITION BY
                pv.tenant_id,
                pv.business_date,
                pv.valuation_scope,
                pv.account_id,
                pv.sub_account_id,
                pv.product_id,
                pv.policy_id,
                pv.valuation_type,
                pv.currency
            ORDER BY
                pv.source_business_timestamp DESC NULLS LAST,
                pfc.finished_at DESC NULLS LAST,
                pv.ingested_at DESC,
                pv.id DESC
        ) AS row_num
    FROM position_valuations pv
    JOIN position_file_controls pfc
        ON pfc.id = pv.position_file_control_id
       AND pfc.tenant_id = pv.tenant_id
    WHERE pfc.status = 'finished'
      AND pfc.deleted_at IS NULL
)
SELECT
    id,
    tenant_id,
    position_file_control_id,
    business_date,
    valuation_scope,
    account_id,
    sub_account_id,
    product_id,
    policy_id,
    valuation_type,
    quantity,
    valuation_amount,
    currency,
    unit_price,
    price_currency,
    source_system,
    source_batch_id,
    external_row_id,
    source_file_key,
    source_business_timestamp,
    row_hash,
    attributes,
    ingested_at,
    created_at,
    file_control_finished_at
FROM ranked
WHERE row_num = 1;

-- ╔═════ 20260311171239-add_signed_jwt_to_api_tokens.sql ═════╗
-- Allow new auth_method value
ALTER TABLE api_tokens DROP CONSTRAINT IF EXISTS api_tokens_auth_method_check;
ALTER TABLE api_tokens ADD CONSTRAINT api_tokens_auth_method_check
    CHECK (auth_method IN ('bearer', 'hmac', 'signed_jwt'));

-- Signed JWT columns
ALTER TABLE api_tokens
    ADD COLUMN IF NOT EXISTS public_certificate TEXT,
    ADD COLUMN IF NOT EXISTS certificate_thumbprint TEXT,
    ADD COLUMN IF NOT EXISTS expected_issuer TEXT,
    ADD COLUMN IF NOT EXISTS expected_audience TEXT,
    ADD COLUMN IF NOT EXISTS jwt_header_name TEXT;

ALTER TABLE api_tokens ALTER COLUMN jwt_header_name SET DEFAULT 'X-JWT-Assertion';
UPDATE api_tokens SET jwt_header_name = 'X-JWT-Assertion' WHERE jwt_header_name IS NULL;
ALTER TABLE api_tokens ALTER COLUMN jwt_header_name SET NOT NULL;

-- Extend secret check: signed_jwt has no secret, has cert and issuer
ALTER TABLE api_tokens DROP CONSTRAINT IF EXISTS api_tokens_secret_check;
ALTER TABLE api_tokens ADD CONSTRAINT api_tokens_secret_check CHECK (
    (auth_method = 'bearer' AND token_secret_hash IS NOT NULL AND token_secret_encrypted IS NULL AND public_certificate IS NULL) OR
    (auth_method = 'hmac' AND token_secret_encrypted IS NOT NULL AND token_secret_hash IS NULL AND public_certificate IS NULL) OR
    (auth_method = 'signed_jwt' AND token_secret_hash IS NULL AND token_secret_encrypted IS NULL AND public_certificate IS NOT NULL AND expected_issuer IS NOT NULL)
);

CREATE INDEX IF NOT EXISTS idx_api_tokens_issuer_active ON api_tokens(expected_issuer, is_active)
    WHERE auth_method = 'signed_jwt';

-- ╔═════ 20260314111434-add_division_to_client_organisations.sql ═════╗
-- Increase statement timeout for backfill UPDATE on large tables (5 minutes)
SET statement_timeout = '300s';

-- Add division column to client_organisations
ALTER TABLE client_organisations ADD COLUMN IF NOT EXISTS division TEXT;

-- Backfill from extra_properties for existing records
UPDATE client_organisations
SET division = extra_properties->>'Division__c'
WHERE extra_properties->>'Division__c' IS NOT NULL
  AND extra_properties->>'Division__c' != ''
  AND division IS NULL;

-- Reset statement timeout to default
SET statement_timeout = '0';

-- Recreate enriched_action_runs to include division
DROP VIEW IF EXISTS enriched_action_runs_with_snapshot;
DROP VIEW IF EXISTS enriched_action_runs;

CREATE OR REPLACE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.locked_at,
    ar.locked_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    co.division as client_organisation_division,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg (
                acor.relationship_type,
                jsonb_build_object (
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date,
    NULL::jsonb AS current_snapshot_data
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
WHERE
    ar.deleted_at IS NULL;

CREATE VIEW enriched_action_runs_with_snapshot AS
SELECT
    ear.action_run_id,
    ear.tenant_id,
    ear.action_id,
    ear.status,
    ear.started_by,
    ear.client_organisation_id,
    ear.started_at,
    GREATEST(
        ear.last_updated_at,
        COALESCE(task_max.max_last_updated_at, ear.last_updated_at)
    ) AS last_updated_at,
    ear.action_run_name,
    ear.slug,
    ear.blueprint_version_id,
    ear.scheduled_at,
    ear.data,
    ear.recommended,
    ear.cancelled_at,
    ear.run_context,
    ear.created_at,
    ear.ready_at,
    ear.rejected_at,
    ear.completed_at,
    ear.cancelled_by,
    ear.cancellation_reason,
    ear.locked_at,
    ear.locked_by,
    ear.recommended_by,
    ear.rejection_reason,
    ear.rejected_by,
    ear.deadline,
    ear.parent_run_id,
    ear.environment,
    ear.blueprint_name,
    ear.blueprint_category,
    ear.blueprint_description,
    ear.blueprint_short_description,
    ear.next_step_date,
    ear.client_organisation_name,
    ear.client_organisation_type,
    ear.client_segmentation,
    ear.client_organisation_external_id,
    ear.client_organisation_national_css_coverage,
    ear.client_organisation_uhnw_service_level,
    ear.client_organisation_market,
    ear.client_organisation_division,
    ear.aum,
    ear.agents,
    ear.is_journey,
    ear.expected_completion_date,
    snap.current_snapshot_data
FROM enriched_action_runs ear
LEFT JOIN LATERAL (
    SELECT MAX(t.last_updated_at) as max_last_updated_at
    FROM tasks t
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.last_updated_at IS NOT NULL
        AND t.data IS NOT NULL
) task_max ON true
LEFT JOIN LATERAL (
    SELECT jsonb_object_agg(
        kv.key,
        kv.value ORDER BY t.completed_at, t.id
    ) FILTER (WHERE kv.key IS NOT NULL) AS current_snapshot_data
    FROM tasks t
    CROSS JOIN LATERAL jsonb_each(t.data) as kv(key, value)
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.completed_at IS NOT NULL
        AND t.data IS NOT NULL
        AND t.data <> 'null'::jsonb
        AND jsonb_typeof(t.data) = 'object'
) snap ON true;

-- Recreate unqork_action_runs_view to include division
DROP VIEW IF EXISTS unqork_action_runs_view;

CREATE VIEW unqork_action_runs_view AS
SELECT
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL
        OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.external_id = uar.action_owner_salentica_id
            AND a.tenant_id = '1'
    ) AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum,
    jsonb_build_object(
        'action_id',
        uar.action_id,
        'action_rel_segment',
        uar.action_rel_segment,
        'action_rel_id',
        uar.action_rel_id,
        'action_current_task_title',
        uar.action_current_task_title,
        'action_no',
        uar.action_no,
        'action_owner_canceled',
        uar.action_owner_canceled,
        'action_owner_user_id',
        uar.action_owner_user_id,
        'action_rel_servicing_name',
        uar.action_rel_servicing_name,
        'action_rel_type',
        uar.action_rel_type,
        'actionDescription',
        uar.action_description,
        'financialAccountObject',
        jsonb_build_object(
            'value',
            jsonb_build_object(
                'accountNumber',
                uar.account_number,
                'id',
                uar.financial_account_id,
                'actionRelId',
                uar.action_rel_id,
                'custodianName',
                uar.custodian_name
            )
        ),
        'financial_account_id',
        uar.financial_account_id,
        'current_task',
        CASE
            WHEN uar.action_current_task_title IS NOT NULL THEN jsonb_build_object(
                'id',
                NULL,
                'name',
                uar.action_current_task_title,
                'status',
                'in_progress'
            )
            ELSE NULL
        END
    ) AS data,
    CASE
        WHEN uar.action_status = 'Recommended' THEN true
        ELSE false
    END AS recommended,
    CASE
        WHEN uar.action_status = 'Canceled' THEN uar.action_end_date
        ELSE NULL
    END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE
        WHEN uar.action_status = 'Declined' THEN uar.action_end_date
        ELSE NULL
    END AS rejected_at,
    CASE
        WHEN uar.action_status = 'Completed' THEN uar.action_end_date
        ELSE NULL
    END AS completed_at,
    uar.canceled_by AS cancelled_by,
    uar.cancel_reason AS cancellation_reason,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.idp_subject = uar.action_owner_user_id
            AND a.tenant_id = '1'
    ) AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by,
    safe_iso_timestamptz (uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment,
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    co.division as client_organisation_division,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    a.id,
                    'external_id',
                    a.external_id,
                    'first_name',
                    p.first_name,
                    'last_name',
                    p.last_name,
                    'middle_name',
                    p.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agents a ON acor.agent_id = a.id
            JOIN persons p ON a.person_id = p.id
        WHERE
            acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    uar.next_step_date,
    'unqork'::text AS source_system,
    NULL::timestamp with time zone AS expected_completion_date
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

-- Recreate enriched_task to include division
DROP VIEW IF EXISTS enriched_task;
CREATE VIEW enriched_task AS
SELECT t.id,
    t.tenant_id,
    t.component_key,
    t.name,
    t.type,
    t.status,
    t.assigned_agent_id,
    assigned_agent_person.first_name AS assigned_agent_first_name,
    assigned_agent_person.last_name AS assigned_agent_last_name,
    t.deadline,
    t.permitted_roles,
    t.created_at,
    t.last_updated_at,
    t.scheduled_at,
    t.unblocked_at,
    t.started_at,
    t.data,
    t.note,
    t.next_step_date,
    t.who_waiting_on,
    t.waiting_for,
    t.completed_at,
    t.completed_by,
    t.cancelled_by,
    t.cancellation_reason,
    t.cancelled_at,
    t.tags,
    t.total_time_waiting_ms,
    t.cron_job_queued,
    ar.id AS action_run_id,
    NULL::text AS action_number,
    ar.slug AS action_run_slug,
    ar.name AS action_run_name,
    ar.status AS action_run_status,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'external_id', ap.external_id, 'middle_name', ap.middle_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = ar.client_organisation_id) AS agents,
    ar.environment,
    co.id AS client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ar.blueprint_category,
    ar.blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    ar.data AS action_run_data,
    jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name, 'middle_name', ap.middle_name, 'external_id', ap.external_id) AS primary_css,
    co.client_segmentation AS client_segmentation,
    co.approx_aum AS aum,
    co.market AS client_organisation_market,
    co.division AS client_organisation_division
   FROM tasks t
     LEFT JOIN action_runs ar ON ar.id = t.run_id
     LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
     LEFT JOIN agent_client_organisation_relationships acor ON acor.client_organisation_id = co.id
       AND acor.relationship_type = 'Primary Client Service Specialist'
     LEFT JOIN agent_person_view ap ON ap.agent_id = acor.agent_id
     LEFT JOIN agent_person_view assigned_agent_person ON assigned_agent_person.agent_id = t.assigned_agent_id AND assigned_agent_person.tenant_id = t.tenant_id
 WHERE t.deleted_at IS NULL;

-- Recreate unqork_tasks_view to include division
DROP VIEW IF EXISTS unqork_tasks_view;
CREATE VIEW unqork_tasks_view AS
SELECT
    ut.unqork_id AS id,
    '1'::text AS tenant_id,
    NULL::text AS component_key,
    ut.task_title AS name,
    CASE
        WHEN ut.task_is_approval_task = 'checker'::text THEN 'review'::text
        ELSE 'submission'::text
    END AS type,
    CASE
        WHEN ut.task_is_discarded = 'true'::text THEN 'cancelled'::text
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN 'done'::text
        WHEN ut.task_status = 'Pending Approval'::text THEN 'pending_approval'::text
        WHEN ut.task_status = 'Ready to Begin'::text THEN 'todo'::text
        WHEN ut.task_status = 'In Progress'::text THEN 'in_progress'::text
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN 'cancelled'::text
        WHEN ut.task_status = 'Declined'::text THEN 'rejected'::text
        WHEN ut.task_status = 'Waiting'::text THEN 'waiting'::text
        WHEN ut.task_status = 'Scheduled'::text THEN 'scheduled'::text
        WHEN ut.task_status = '' THEN 'blocked'::text
        ELSE 'blocked'::text
    END AS status,
    a.id AS assigned_agent_id,
    assigned_agent_person.first_name AS assigned_agent_first_name,
    assigned_agent_person.last_name AS assigned_agent_last_name,
    ut.task_deadline AS deadline,
    CASE
        WHEN ut.permitted_roles IS NULL THEN ARRAY[]::text[]
        ELSE ARRAY[ut.permitted_roles]
    END AS permitted_roles,
    COALESCE(ut.task_created_ts, ut.created_at) AS created_at,
    COALESCE(ut.task_modified_ts, ut.updated_at) AS last_updated_at,
    ut.task_sched_start AS scheduled_at,
    ut.task_unblocked_at AS unblocked_at,
    ut.task_started_at AS started_at,
    ut.data,
    NULL::text AS note,
    ut.task_next_step_date AS next_step_date,
    ut.task_waiting_for AS who_waiting_on,
    ut.task_waiting_for_item AS waiting_for,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS completed_at,
    ut.task_owner AS completed_by,
    ut.task_cancelled_by AS cancelled_by,
    ut.task_cancellation_reason AS cancellation_reason,
    CASE
        WHEN ut.task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN ut.task_end_ts
        ELSE NULL::timestamp with time zone
    END AS cancelled_at,
    ut.task_tags AS tags,
    0::bigint AS total_time_waiting_ms,
    uar.unqork_id AS action_run_id,
    uar.action_id AS action_number,
    uar.action_id AS action_run_slug,
    uar.action_status AS action_run_status,
    ut.action_nickname AS action_run_name,
    ( SELECT jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', ap.agent_id, 'first_name', ap.first_name, 'last_name', ap.last_name)) AS jsonb_object_agg
        FROM agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE acor.client_organisation_id = uar.client_organisation_id) AS agents,
    ut.environment,
    ut.client_organisation_id,
    ut.task_no AS task_no,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    ut.action_category AS blueprint_category,
    ut.action_type AS blueprint_name,
    co.extra_properties AS client_organisation_extra_properties,
    co.client_organisation_type,
    co.approx_aum AS aum,
    jsonb_build_object(
        'action_owner_canceled', uar.action_owner_canceled,
        'action_owner_user_id', uar.action_owner_user_id,
        'action_rel_servicing_name', uar.action_rel_servicing_name,
        'Action Description', jsonb_build_object(
            'value', uar.action_description
        ),
        'financialAccountObject', jsonb_build_object(
            'value', jsonb_build_object(
                'accountNumber', uar.account_number,
                'id', uar.financial_account_id,
                'actionRelId', uar.action_rel_id,
                'dataProviderName', uar.data_provider_name,
                'custodianName', uar.custodian_name
            )
        ),
        'financial_account_id', uar.financial_account_id
    ) AS action_run_data,
    NULL::jsonb AS primary_css,
    'unqork'::text AS source_system,
    co.client_segmentation AS client_segmentation,
    co.market AS client_organisation_market,
    co.division AS client_organisation_division
FROM unqork_tasks ut
LEFT JOIN unqork_action_runs uar ON uar.unqork_id = ut.unqork_action_run_id
LEFT JOIN client_organisations co ON co.id = ut.client_organisation_id
LEFT JOIN agents a ON a.external_id = NULLIF(ut.task_owner_salentica_id, '') AND a.tenant_id = '1'::text
LEFT JOIN agent_person_view assigned_agent_person ON assigned_agent_person.agent_id = a.id AND assigned_agent_person.tenant_id = '1'::text;

