SET allowed_dimensions = allowed_dimensions || '["division", "market"]'::jsonb
WHERE tenant_id = '1'
    AND name IN (
        'actions.total_count',
        'actions.completed_count',
        'actions.completion_rate',
        'actions.in_progress_count',
        'actions.failed_count',
        'actions.cancelled_rate',
        'actions.sla_not_met_pct',
        'actions.avg_completion_time_hours'
    )
    AND NOT allowed_dimensions @> '"division"'::jsonb;

