UPDATE kpi_definitions
SET allowed_dimensions = allowed_dimensions || '["division", "market"]'::jsonb
WHERE tenant_id = '1'
    AND name IN (
        'tasks.total_count',
        'tasks.completed_count',
        'tasks.completion_rate',
        'tasks.in_progress_count',
        'tasks.overdue_count',
        'tasks.avg_completion_time_hours'
    )
