UPDATE kpi_definitions
SET allowed_dimensions = allowed_dimensions || '["role"]'::jsonb
WHERE tenant_id = '1'
    AND name IN (
        'actions.avg_completion_time_hours',
        'actions.completed_count',
        'tasks.avg_completion_time_hours',
        'tasks.completed_count'
    )
    AND NOT allowed_dimensions @> '"role"'::jsonb;

-- ╔═════ 20260315200000-add_temp_legacy_slug_to_action_runs.sql ═════╗
SET statement_timeout = '600s';

ALTER TABLE action_runs ADD COLUMN IF NOT EXISTS temp_legacy_slug TEXT;

DROP VIEW IF EXISTS enriched_action_runs_with_snapshot;
DROP VIEW IF EXISTS enriched_action_runs;

CREATE VIEW enriched_action_runs AS
SELECT
    ar.id AS action_run_id,
    ar.tenant_id,
    ar.action_id,
    CASE
        WHEN ar.status = 'draft'
        AND ar.recommended = true THEN 'recommended'
        ELSE ar.status
    END AS status,
    ar.started_by,
    ar.client_organisation_id,
    ar.started_at,
    ar.last_updated_at,
    ar.name AS action_run_name,
    ar.slug,
    ar.blueprint_version_id,
    ar.scheduled_at,
    ar.data,
    ar.recommended,
    ar.cancelled_at,
    ar.run_context,
    ar.created_at,
    ar.ready_at,
    ar.rejected_at,
    ar.completed_at,
    ar.cancelled_by,
    ar.cancellation_reason,
    ar.recommended_by,
    ar.rejection_reason,
    ar.rejected_by,
    ar.locked_at,
    ar.locked_by,
    ar.deadline,
    ar.parent_run_id,
    ar.environment,
    ar.blueprint_name,
    ar.blueprint_category,
    ar.blueprint_description,
    ar.blueprint_short_description,
    ar.next_step_date,
    ar.temp_legacy_slug,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation as client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    co.division as client_organisation_division,
    co.approx_aum AS aum,
    (
        SELECT
            jsonb_object_agg (
                acor.relationship_type,
                jsonb_build_object (
                    'agent_id',
                    ap.agent_id,
                    'first_name',
                    ap.first_name,
                    'last_name',
                    ap.last_name,
                    'external_id',
                    ap.external_id,
                    'middle_name',
                    ap.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agent_person_view ap ON acor.agent_id = ap.agent_id
        WHERE
            acor.client_organisation_id = ar.client_organisation_id
    ) AS agents,
    ar.is_journey,
    ar.expected_completion_date,
    NULL::jsonb AS current_snapshot_data
FROM
    action_runs ar
    LEFT JOIN client_organisations co ON co.id = ar.client_organisation_id
WHERE
    ar.deleted_at IS NULL;

CREATE VIEW enriched_action_runs_with_snapshot AS
SELECT
    ear.action_run_id,
    ear.tenant_id,
    ear.action_id,
    ear.status,
    ear.started_by,
    ear.client_organisation_id,
    ear.started_at,
    GREATEST(
        ear.last_updated_at,
        COALESCE(task_max.max_last_updated_at, ear.last_updated_at)
    ) AS last_updated_at,
    ear.action_run_name,
    ear.slug,
    ear.blueprint_version_id,
    ear.scheduled_at,
    ear.data,
    ear.recommended,
    ear.cancelled_at,
    ear.run_context,
    ear.created_at,
    ear.ready_at,
    ear.rejected_at,
    ear.completed_at,
    ear.cancelled_by,
    ear.cancellation_reason,
    ear.locked_at,
    ear.locked_by,
    ear.recommended_by,
    ear.rejection_reason,
    ear.rejected_by,
    ear.deadline,
    ear.parent_run_id,
    ear.environment,
    ear.blueprint_name,
    ear.blueprint_category,
    ear.blueprint_description,
    ear.blueprint_short_description,
    ear.next_step_date,
    ear.temp_legacy_slug,
    ear.client_organisation_name,
    ear.client_organisation_type,
    ear.client_segmentation,
    ear.client_organisation_external_id,
    ear.client_organisation_national_css_coverage,
    ear.client_organisation_uhnw_service_level,
    ear.client_organisation_market,
    ear.client_organisation_division,
    ear.aum,
    ear.agents,
    ear.is_journey,
    ear.expected_completion_date,
    snap.current_snapshot_data
FROM enriched_action_runs ear
LEFT JOIN LATERAL (
    SELECT MAX(t.last_updated_at) as max_last_updated_at
    FROM tasks t
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.last_updated_at IS NOT NULL
        AND t.data IS NOT NULL
) task_max ON true
LEFT JOIN LATERAL (
    SELECT jsonb_object_agg(
        kv.key,
        kv.value ORDER BY t.completed_at, t.id
    ) FILTER (WHERE kv.key IS NOT NULL) AS current_snapshot_data
    FROM tasks t
    CROSS JOIN LATERAL jsonb_each(t.data) as kv(key, value)
    WHERE t.run_id = ear.action_run_id
        AND t.status = 'done'
        AND t.completed_at IS NOT NULL
        AND t.data IS NOT NULL
        AND t.data <> 'null'::jsonb
        AND jsonb_typeof(t.data) = 'object'
) snap ON true;

SET statement_timeout = '0';

-- ╔═════ 20260316110000-add-summary-balance-valuations.sql ═════╗
CREATE TABLE IF NOT EXISTS summary_balance_file_controls (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    source_system TEXT NOT NULL,
    control_key TEXT NOT NULL,
    control_version INTEGER NOT NULL DEFAULT 1,
    status TEXT NOT NULL,
    source_file_key TEXT,
    source_file_checksum TEXT,
    source_batch_id TEXT,
    source_run_date DATE,
    source_ctrl_record_count BIGINT,
    ingested_row_count BIGINT,
    accepted_row_count BIGINT,
    rejected_row_count BIGINT,
    validation_summary JSONB NOT NULL DEFAULT '{}'::jsonb,
    error_summary JSONB NOT NULL DEFAULT '{}'::jsonb,
    started_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    finished_at TIMESTAMP WITH TIME ZONE,
    deleted_at TIMESTAMP WITH TIME ZONE,
    created_by TEXT,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT chk_summary_balance_file_controls_status CHECK (
        status IN ('processing', 'finished', 'error', 'deleted')
    ),
    CONSTRAINT chk_summary_balance_file_controls_state_timestamps CHECK (
        (status = 'processing' AND finished_at IS NULL AND deleted_at IS NULL)
        OR (status IN ('finished', 'error') AND finished_at IS NOT NULL AND deleted_at IS NULL)
        OR (status = 'deleted' AND deleted_at IS NOT NULL)
    )
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_summary_balance_file_controls_tenant_id_id
    ON summary_balance_file_controls (tenant_id, id);

CREATE INDEX IF NOT EXISTS idx_summary_balance_file_controls_tenant_source_started
    ON summary_balance_file_controls (tenant_id, source_system, started_at DESC);

CREATE INDEX IF NOT EXISTS idx_summary_balance_file_controls_tenant_key
    ON summary_balance_file_controls (tenant_id, source_system, control_key);

CREATE UNIQUE INDEX IF NOT EXISTS uq_summary_balance_file_controls_active_finished
    ON summary_balance_file_controls (tenant_id, source_system, control_key, control_version)
    WHERE status = 'finished' AND deleted_at IS NULL;

CREATE TABLE IF NOT EXISTS summary_balance_valuations (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    summary_balance_file_control_id TEXT NOT NULL,
    business_date DATE NOT NULL,
    subject_type TEXT NOT NULL,
    subject_id TEXT NOT NULL,
    balance_scope TEXT NOT NULL,
    balance_type TEXT NOT NULL,
    balance_amount NUMERIC(24, 8) NOT NULL,
    currency TEXT NOT NULL,
    source_system TEXT NOT NULL,
    source_batch_id TEXT,
    external_row_id TEXT,
    source_file_key TEXT,
    source_business_timestamp TIMESTAMP WITH TIME ZONE,
    row_hash TEXT,
    attributes JSONB NOT NULL DEFAULT '{}'::jsonb,
    ingested_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT fk_summary_balance_valuations_file_control FOREIGN KEY (tenant_id, summary_balance_file_control_id) REFERENCES summary_balance_file_controls(tenant_id, id),
    CONSTRAINT chk_summary_balance_valuations_subject_type CHECK (
        subject_type IN ('financial_account', 'policy', 'client_organisation', 'agent', 'business_group')
    )
);

CREATE INDEX IF NOT EXISTS idx_summary_balance_valuations_tenant_date
    ON summary_balance_valuations (tenant_id, business_date DESC);

CREATE INDEX IF NOT EXISTS idx_summary_balance_valuations_tenant_control
    ON summary_balance_valuations (tenant_id, summary_balance_file_control_id);

CREATE UNIQUE INDEX IF NOT EXISTS uq_summary_balance_valuations_file_external_row
    ON summary_balance_valuations (tenant_id, summary_balance_file_control_id, external_row_id)
    WHERE external_row_id IS NOT NULL;

CREATE UNIQUE INDEX IF NOT EXISTS uq_summary_balance_valuations_file_row_hash
    ON summary_balance_valuations (tenant_id, summary_balance_file_control_id, row_hash)
    WHERE external_row_id IS NULL AND row_hash IS NOT NULL;

CREATE INDEX IF NOT EXISTS idx_summary_balance_valuations_canonical
    ON summary_balance_valuations (
        tenant_id,
        business_date,
        subject_type,
        subject_id,
        balance_scope,
        balance_type,
        currency,
        source_business_timestamp DESC,
        ingested_at DESC,
        id DESC
    );

CREATE OR REPLACE VIEW summary_balance_valuations_latest AS
WITH ranked AS (
    SELECT
        sbv.id,
        sbv.tenant_id,
        sbv.summary_balance_file_control_id,
        sbv.business_date,
        sbv.subject_type,
        sbv.subject_id,
        sbv.balance_scope,
        sbv.balance_type,
        sbv.balance_amount,
        sbv.currency,
        sbv.source_system,
        sbv.source_batch_id,
        sbv.external_row_id,
        sbv.source_file_key,
        sbv.source_business_timestamp,
        sbv.row_hash,
        sbv.attributes,
        sbv.ingested_at,
        sbv.created_at,
        sbfc.finished_at AS file_control_finished_at,
        ROW_NUMBER() OVER (
            PARTITION BY
                sbv.tenant_id,
                sbv.business_date,
                sbv.subject_type,
                sbv.subject_id,
                sbv.balance_scope,
                sbv.balance_type,
                sbv.currency
            ORDER BY
                sbv.source_business_timestamp DESC NULLS LAST,
                sbfc.finished_at DESC NULLS LAST,
                sbv.ingested_at DESC,
                sbv.id DESC
        ) AS row_num
    FROM summary_balance_valuations sbv
    JOIN summary_balance_file_controls sbfc
        ON sbfc.id = sbv.summary_balance_file_control_id
       AND sbfc.tenant_id = sbv.tenant_id
    WHERE sbfc.status = 'finished'
      AND sbfc.deleted_at IS NULL
)
SELECT
    id,
    tenant_id,
    summary_balance_file_control_id,
    business_date,
    subject_type,
    subject_id,
    balance_scope,
    balance_type,
    balance_amount,
    currency,
    source_system,
    source_batch_id,
    external_row_id,
    source_file_key,
    source_business_timestamp,
    row_hash,
    attributes,
    ingested_at,
    created_at,
    file_control_finished_at
FROM ranked
WHERE row_num = 1;

CREATE TABLE IF NOT EXISTS valuation_subject_links (
    id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    fact_table TEXT NOT NULL,
    fact_id TEXT NOT NULL,
    subject_type TEXT NOT NULL,
    subject_id TEXT NOT NULL,
    relationship_role TEXT NOT NULL,
    source_kind TEXT NOT NULL,
    effective_business_date DATE NOT NULL,
    file_control_id TEXT,
    attributes JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    CONSTRAINT chk_valuation_subject_links_subject_type CHECK (
        subject_type IN ('financial_account', 'policy', 'client_organisation', 'agent', 'business_group')
    ),
    CONSTRAINT chk_valuation_subject_links_fact_table CHECK (
        fact_table IN ('position_valuations', 'summary_balance_valuations')
    ),
    CONSTRAINT chk_valuation_subject_links_source_kind CHECK (
        source_kind IN ('source_asserted', 'derived')
    )
);

CREATE UNIQUE INDEX IF NOT EXISTS uq_valuation_subject_links_unique
    ON valuation_subject_links (
        tenant_id,
        fact_table,
        fact_id,
        subject_type,
        subject_id,
        relationship_role
    );

CREATE INDEX IF NOT EXISTS idx_valuation_subject_links_subject_lookup
    ON valuation_subject_links (
        tenant_id,
        subject_type,
        subject_id,
        effective_business_date DESC,
        fact_table,
        relationship_role
    );

INSERT INTO valuation_subject_links (
    id,
    tenant_id,
    fact_table,
    fact_id,
    subject_type,
    subject_id,
    relationship_role,
    source_kind,
    effective_business_date,
    file_control_id,
    attributes,
    created_at
)
SELECT
    'vsl_' || md5(CONCAT_WS('|', tenant_id, fact_table, fact_id, subject_type, subject_id, relationship_role)),
    tenant_id,
    fact_table,
    fact_id,
    subject_type,
    subject_id,
    relationship_role,
    source_kind,
    effective_business_date,
    file_control_id,
    '{}'::jsonb,
    NOW()
FROM (
    SELECT
        pv.tenant_id,
        'position_valuations' AS fact_table,
        pv.id AS fact_id,
        'financial_account' AS subject_type,
        pv.account_id AS subject_id,
        'direct_subject' AS relationship_role,
        'source_asserted' AS source_kind,
        pv.business_date AS effective_business_date,
        pv.position_file_control_id AS file_control_id
    FROM position_valuations pv
    WHERE pv.account_id IS NOT NULL

    UNION ALL

    SELECT
        pv.tenant_id,
        'position_valuations' AS fact_table,
        pv.id AS fact_id,
        'policy' AS subject_type,
        pv.policy_id AS subject_id,
        'direct_subject' AS relationship_role,
        'source_asserted' AS source_kind,
        pv.business_date AS effective_business_date,
        pv.position_file_control_id AS file_control_id
    FROM position_valuations pv
    WHERE pv.policy_id IS NOT NULL

    UNION ALL

    SELECT
        pv.tenant_id,
        'position_valuations' AS fact_table,
        pv.id AS fact_id,
        'client_organisation' AS subject_type,
        fa.client_organisation_id AS subject_id,
        'rollup_parent' AS relationship_role,
        'derived' AS source_kind,
        pv.business_date AS effective_business_date,
        pv.position_file_control_id AS file_control_id
    FROM position_valuations pv
    JOIN financial_accounts fa
        ON fa.tenant_id = pv.tenant_id
       AND fa.id = pv.account_id
    WHERE fa.client_organisation_id IS NOT NULL

    UNION ALL

    SELECT
        pv.tenant_id,
        'position_valuations' AS fact_table,
        pv.id AS fact_id,
        'client_organisation' AS subject_type,
        p.client_organisation_id AS subject_id,
        'rollup_parent' AS relationship_role,
        'derived' AS source_kind,
        pv.business_date AS effective_business_date,
        pv.position_file_control_id AS file_control_id
    FROM position_valuations pv
    JOIN policies p
        ON p.tenant_id = pv.tenant_id
       AND p.id = pv.policy_id
    WHERE p.client_organisation_id IS NOT NULL
) links;

-- ╔═════ 20260317120000-add_temp_legacy_slug_to_unqork_action_runs.sql ═════╗
SET statement_timeout = '600s';

ALTER TABLE unqork_action_runs ADD COLUMN IF NOT EXISTS temp_legacy_slug TEXT;

DROP VIEW IF EXISTS unqork_action_runs_view;

CREATE VIEW unqork_action_runs_view AS
SELECT
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,
    NULL::text AS action_id,
    CASE
        WHEN uar.action_status = 'Completed' THEN 'complete'::text
        WHEN uar.action_status = 'In Progress' THEN 'processing'::text
        WHEN uar.action_status = 'Canceled' THEN 'cancelled'::text
        WHEN uar.action_status = 'Rejected' THEN 'rejected'::text
        WHEN uar.action_status = 'Scheduled' THEN 'scheduled'::text
        WHEN uar.action_status = 'Recommended' THEN 'recommended'::text
        WHEN uar.action_status = 'Ready to Begin' THEN 'todo'::text
        WHEN uar.action_status = 'Declined' THEN 'rejected'::text
        WHEN uar.action_status IS NULL
        OR uar.action_status = '' THEN 'todo'::text
        ELSE 'todo'::text
    END AS status,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.external_id = uar.action_owner_salentica_id
            AND a.tenant_id = '1'
    ) AS started_by,
    uar.client_organisation_id,
    uar.action_start_date AS started_at,
    uar.modified_timestamp_action AS last_updated_at,
    uar.action_nickname AS action_run_name,
    uar.action_id AS slug,
    NULL::text AS blueprint_version_id,
    uar.scheduled_date AS scheduled_at,
    co.approx_aum AS aum,
    jsonb_build_object(
        'action_id',
        uar.action_id,
        'action_rel_segment',
        uar.action_rel_segment,
        'action_rel_id',
        uar.action_rel_id,
        'action_current_task_title',
        uar.action_current_task_title,
        'action_no',
        uar.action_no,
        'action_owner_canceled',
        uar.action_owner_canceled,
        'action_owner_user_id',
        uar.action_owner_user_id,
        'action_rel_servicing_name',
        uar.action_rel_servicing_name,
        'action_rel_type',
        uar.action_rel_type,
        'actionDescription',
        uar.action_description,
        'financialAccountObject',
        jsonb_build_object(
            'value',
            jsonb_build_object(
                'accountNumber',
                uar.account_number,
                'id',
                uar.financial_account_id,
                'actionRelId',
                uar.action_rel_id,
                'custodianName',
                uar.custodian_name
            )
        ),
        'financial_account_id',
        uar.financial_account_id,
        'current_task',
        CASE
            WHEN uar.action_current_task_title IS NOT NULL THEN jsonb_build_object(
                'id',
                NULL,
                'name',
                uar.action_current_task_title,
                'status',
                'in_progress'
            )
            ELSE NULL
        END
    ) AS data,
    CASE
        WHEN uar.action_status = 'Recommended' THEN true
        ELSE false
    END AS recommended,
    CASE
        WHEN uar.action_status = 'Canceled' THEN uar.action_end_date
        ELSE NULL
    END AS cancelled_at,
    uar.action_context AS run_context,
    uar.created_timestamp_action AS created_at,
    NULL::timestamp with time zone AS ready_at,
    CASE
        WHEN uar.action_status = 'Declined' THEN uar.action_end_date
        ELSE NULL
    END AS rejected_at,
    CASE
        WHEN uar.action_status = 'Completed' THEN uar.action_end_date
        ELSE NULL
    END AS completed_at,
    uar.canceled_by AS cancelled_by,
    uar.cancel_reason AS cancellation_reason,
    (
        SELECT
            a.id
        FROM
            agents a
        WHERE
            a.idp_subject = uar.action_owner_user_id
            AND a.tenant_id = '1'
    ) AS recommended_by,
    uar.rejection_reason,
    NULL::text AS rejected_by,
    safe_iso_timestamptz (uar.action_due_date) AS deadline,
    NULL::text AS parent_run_id,
    uar.environment AS environment,
    uar.action_type AS blueprint_name,
    uar.action_category AS blueprint_category,
    NULL::text AS blueprint_description,
    NULL::text AS blueprint_short_description,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    uar.action_rel_segment AS client_segmentation,
    co.external_id AS client_organisation_external_id,
    co.national_css_coverage as client_organisation_national_css_coverage,
    ((COALESCE(co.extra_properties->>'UHNW_Service_Level__c', '') = 'true')::boolean) AS client_organisation_uhnw_service_level,
    co.market as client_organisation_market,
    co.division as client_organisation_division,
    (
        SELECT
            jsonb_object_agg(
                acor.relationship_type,
                jsonb_build_object(
                    'agent_id',
                    a.id,
                    'external_id',
                    a.external_id,
                    'first_name',
                    p.first_name,
                    'last_name',
                    p.last_name,
                    'middle_name',
                    p.middle_name
                )
            ) AS jsonb_object_agg
        FROM
            agent_client_organisation_relationships acor
            JOIN agents a ON acor.agent_id = a.id
            JOIN persons p ON a.person_id = p.id
        WHERE
            acor.client_organisation_id = uar.client_organisation_id
    ) AS agents,
    uar.next_step_date,
    NULL::text AS temp_legacy_slug,
    'unqork'::text AS source_system,
    NULL::timestamp with time zone AS expected_completion_date
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON co.id = uar.client_organisation_id;

SET statement_timeout = '0';

-- ╔═════ 20260317130000-create-client-organisation-balance-latest.sql ═════╗
CREATE TABLE client_organisation_balance_latest (
    tenant_id               TEXT NOT NULL,
    client_organisation_id  TEXT NOT NULL,
    balance_scope           TEXT NOT NULL,
    balance_type            TEXT NOT NULL,
    currency                TEXT NOT NULL,
    amount                  NUMERIC(24, 8) NOT NULL,
    as_of_business_date     DATE NOT NULL,
    authority               TEXT NOT NULL,
    source_kind             TEXT NOT NULL,
    source_system           TEXT,
    source_fact_table       TEXT,
    source_fact_id          TEXT,
    updated_at              TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),

    PRIMARY KEY (
        tenant_id,
        client_organisation_id,
        balance_scope,
        balance_type,
        currency
    ),

    CONSTRAINT chk_cobl_authority
        CHECK (authority IN ('source_asserted', 'derived', 'legacy_fallback')),

    CONSTRAINT chk_cobl_source_kind
        CHECK (source_kind IN ('summary_balance', 'position_rollup', 'legacy_approx_aum'))
);

CREATE INDEX idx_cobl_tenant_balance_type
    ON client_organisation_balance_latest (tenant_id, balance_scope, balance_type, currency);

CREATE TABLE client_organisation_balance_projection_state (
    tenant_id       TEXT NOT NULL,
    projection_name TEXT NOT NULL,
    watermark       TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT '1970-01-01T00:00:00Z',
    last_run_at     TIMESTAMP WITH TIME ZONE,
    last_duration_ms BIGINT,
    last_error      TEXT,
    total_runs      BIGINT NOT NULL DEFAULT 0,
    updated_at      TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),

    PRIMARY KEY (tenant_id, projection_name)
);

-- ╔═════ 20260317170000-add-projected-aum-to-relationships-dashboard-view.sql ═════╗
DROP VIEW IF EXISTS public.relationships_dashboard_view;

CREATE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    projection_aum.aum,
    co.next_meeting,
    co.growth_opportunity_next_step_date,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN LATERAL (
        SELECT cobl.amount::double precision AS aum
          FROM client_organisation_balance_latest cobl
         WHERE cobl.tenant_id = co.tenant_id
           AND cobl.client_organisation_id = co.id
           AND cobl.balance_scope = 'CLIENT_ORGANISATION_BALANCE'
           AND cobl.balance_type = 'AUM'
           -- TODO: Replace fixed USD with tenant-configured reporting currency.
           AND cobl.currency = 'USD'
     ) projection_aum ON TRUE
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
  WHERE co.deleted_at IS NULL;

-- ╔═════ 20260318103135-remove_status_from_unqork_action_run_fts_display.sql ═════╗
-- Increase statement timeout for materialized view recreation (10 minutes)
SET statement_timeout = '600s';

-- Recreate unqork_action_run_fts with status removed from display_text only
DROP MATERIALIZED VIEW IF EXISTS unqork_action_run_fts;

CREATE MATERIALIZED VIEW unqork_action_run_fts AS
SELECT
    uar.unqork_id AS action_run_id,
    '1'::text AS tenant_id,  -- Unqork is hardcoded to tenant 1
    uar.client_organisation_id,
    -- Display text: Name - Client Org (status removed)
    COALESCE(uar.action_nickname, uar.action_type, 'Unnamed') || ' - ' || COALESCE(co.name, 'Unknown') AS display_text,
    -- display_fields: Structured JSONB for rich client rendering
    -- Uses same field names as action_run_fts for API compatibility
    -- Status mapping matches unqork_action_runs_view for consistency
    jsonb_build_object(
        'action_id', uar.unqork_id,
        'action_nickname', uar.action_nickname,
        'action_name', uar.action_type,
        'action_category', uar.action_category,
        'relationship_name', co.name,
        'relationship_id', uar.client_organisation_id,
        'relationship_external_id', co.external_id,
        'financial_account_external_id', fa.external_id,
        'contact_external_id', primary_contact.external_id,
        'slug', uar.action_id,
        'status', CASE
            WHEN uar.action_status = 'Completed' THEN 'complete'
            WHEN uar.action_status = 'In Progress' THEN 'processing'
            WHEN uar.action_status = 'Canceled' THEN 'cancelled'
            WHEN uar.action_status = 'Rejected' THEN 'rejected'
            WHEN uar.action_status = 'Scheduled' THEN 'scheduled'
            WHEN uar.action_status = 'Recommended' THEN 'recommended'
            WHEN uar.action_status = 'Ready to Begin' THEN 'todo'
            WHEN uar.action_status = 'Declined' THEN 'rejected'
            WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'
            ELSE 'todo'
        END,
        'start_date', uar.action_start_date,
        'due_date', safe_iso_timestamptz(uar.action_due_date),
        'agent_name', agents.primary_agent_name,
        'source_system', 'unqork'
    ) AS display_fields,
    -- Raw search text with token separators for highlighting
    -- Format: ||token_name||escaped_value for each searchable field
    -- Values are escaped: \ -> \\, | -> \| to prevent delimiter injection
    '||action_run||' || REPLACE(REPLACE(COALESCE(uar.action_nickname, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||status||' || REPLACE(REPLACE(COALESCE(
        CASE
            WHEN uar.action_status = 'Completed' THEN 'complete'
            WHEN uar.action_status = 'In Progress' THEN 'processing'
            WHEN uar.action_status = 'Canceled' THEN 'cancelled'
            WHEN uar.action_status = 'Rejected' THEN 'rejected'
            WHEN uar.action_status = 'Scheduled' THEN 'scheduled'
            WHEN uar.action_status = 'Recommended' THEN 'recommended'
            WHEN uar.action_status = 'Ready to Begin' THEN 'todo'
            WHEN uar.action_status = 'Declined' THEN 'rejected'
            WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'
            ELSE 'todo'
        END, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||blueprint||' || REPLACE(REPLACE(COALESCE(uar.action_type, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||category||' || REPLACE(REPLACE(COALESCE(uar.action_category, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||client||' || REPLACE(REPLACE(COALESCE(co.name, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||agent||' || REPLACE(REPLACE(COALESCE(agents.agent_names, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||slug||' || REPLACE(REPLACE(COALESCE(uar.action_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||relationship_external_id||' || REPLACE(REPLACE(COALESCE(co.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||financial_account_external_id||' || REPLACE(REPLACE(COALESCE(fa.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||contact_external_id||' || REPLACE(REPLACE(COALESCE(primary_contact.external_id, ''), E'\\', E'\\\\'), '|', E'\\|') ||
    '||' AS search_text,
    -- Weighted tsvector for full-text search
    -- Weight A: Action run name, Status (highest priority)
    -- Weight B: Blueprint name, Slug, External IDs (high priority)
    -- Weight C: Client org name, Agent names, Category (medium priority)
    setweight(to_tsvector('simple', COALESCE(uar.action_nickname, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(
        CASE
            WHEN uar.action_status = 'Completed' THEN 'complete'
            WHEN uar.action_status = 'In Progress' THEN 'processing'
            WHEN uar.action_status = 'Canceled' THEN 'cancelled'
            WHEN uar.action_status = 'Rejected' THEN 'rejected'
            WHEN uar.action_status = 'Scheduled' THEN 'scheduled'
            WHEN uar.action_status = 'Recommended' THEN 'recommended'
            WHEN uar.action_status = 'Ready to Begin' THEN 'todo'
            WHEN uar.action_status = 'Declined' THEN 'rejected'
            WHEN uar.action_status IS NULL OR uar.action_status = '' THEN 'todo'
            ELSE 'todo'
        END, '')), 'A') ||
    setweight(to_tsvector('simple', COALESCE(uar.action_type, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(uar.action_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(fa.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(primary_contact.external_id, '')), 'B') ||
    setweight(to_tsvector('simple', COALESCE(co.name, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(agents.agent_names, '')), 'C') ||
    setweight(to_tsvector('simple', COALESCE(uar.action_category, '')), 'C')
    AS search_vector,
    -- Timestamp for recency sorting
    GREATEST(uar.modified_timestamp_action, uar.updated_at) AS updated_at
FROM
    unqork_action_runs uar
    LEFT JOIN client_organisations co ON uar.client_organisation_id = co.id
    LEFT JOIN financial_accounts fa ON fa.id = uar.financial_account_id
    -- Get primary contact from relationship (first client by created_at)
    LEFT JOIN LATERAL (
        SELECT c.external_id
        FROM clients c
        WHERE c.organisation_id = uar.client_organisation_id
          AND c.deleted_at IS NULL
        ORDER BY c.created_at ASC
        LIMIT 1
    ) primary_contact ON true
    -- Get agents for the relationship
    LEFT JOIN LATERAL (
        SELECT
            string_agg(CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name), ' ') AS agent_names,
            (SELECT CONCAT_WS(' ', p2.first_name, p2.last_name)
             FROM agent_client_organisation_relationships acor2
             JOIN agents a2 ON acor2.agent_id = a2.id
             LEFT JOIN persons p2 ON a2.person_id = p2.id
             WHERE acor2.client_organisation_id = uar.client_organisation_id
             ORDER BY acor2.created_at ASC
             LIMIT 1) AS primary_agent_name
        FROM agent_client_organisation_relationships acor
        JOIN agents a ON acor.agent_id = a.id
        LEFT JOIN persons p ON a.person_id = p.id
        WHERE acor.client_organisation_id = uar.client_organisation_id
    ) agents ON true;

-- Recreate all indexes
CREATE UNIQUE INDEX idx_unqork_action_run_fts_id ON unqork_action_run_fts (action_run_id);
CREATE INDEX idx_unqork_action_run_fts_tenant_id ON unqork_action_run_fts (tenant_id);
CREATE INDEX idx_unqork_action_run_fts_client_org_id ON unqork_action_run_fts (client_organisation_id);
CREATE INDEX idx_unqork_action_run_fts_search_vector ON unqork_action_run_fts USING gin (search_vector);
CREATE INDEX idx_unqork_action_run_fts_search_text_trgm ON unqork_action_run_fts USING gin (search_text gin_trgm_ops);
CREATE INDEX idx_unqork_action_run_fts_updated_at ON unqork_action_run_fts (updated_at DESC NULLS LAST);
CREATE INDEX idx_unqork_action_run_fts_tenant_updated ON unqork_action_run_fts (tenant_id, updated_at DESC NULLS LAST);

-- Reset statement timeout to default
SET statement_timeout = '0';

-- ╔═════ 20260319124627-add_event_relation_id_to_participant.sql ═════╗
-- Update the agent_meetings view to include event_relation_external_id in participant JSON
CREATE OR REPLACE VIEW agent_meetings AS
SELECT
    m.id,
    m.tenant_id,
    m.initiating_agent_id,
    m.primary_client_id,
    m.subject,
    m.description,
    m.start_time,
    m.end_time,
    m.location,
    m.meeting_link,
    m.meeting_type,
    m.status,
    m.extra_properties,
    m.created_at,
    m.updated_at,
    m.external_id,
    m.client_organisation_id,
    m.parent_external_id,
    co.name AS client_organisation_name,
    (
        SELECT COALESCE(
            array_agg(DISTINCT jsonb_build_object(
                'type', ma.attendee_type,
                'id', ma.attendee_id,
                'title', p.title,
                'first_name', p.first_name,
                'middle_name', p.middle_name,
                'last_name', p.last_name,
                'external_id', p.external_id,
                'extra_properties', ma.extra_properties,
                'contact_details', p.contact_details,
                'event_relation_external_id', ma.external_id
            )) FILTER (WHERE ma.attendee_id IS NOT NULL),
            '{}' :: jsonb[]
        )
        FROM meeting_attendees ma
        LEFT JOIN LATERAL (
            SELECT
                title,
                first_name,
                middle_name,
                last_name,
                external_id,
                contact_details
            FROM (
                SELECT
                    c1.id AS entity_id,
                    p1.title,
                    p1.first_name,
                    p1.middle_name,
                    p1.last_name,
                    c1.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd1.role,
                            cd1.value
                        )
                        FROM contact_details cd1
                        WHERE cd1.client_id = c1.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM clients c1
                JOIN persons p1 ON c1.person_id = p1.id
                WHERE c1.id = ma.attendee_id

                UNION ALL

                SELECT
                    a.id AS entity_id,
                    p2.title,
                    p2.first_name,
                    p2.middle_name,
                    p2.last_name,
                    a.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd2.role,
                            cd2.value
                        )
                        FROM contact_details cd2
                        WHERE cd2.agent_id = a.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM agents a
                JOIN persons p2 ON a.person_id = p2.id
                WHERE a.id = ma.attendee_id

                UNION ALL

                SELECT
                    co.id AS entity_id,
                    NULL as title,
                    co.name as first_name,
                    NULL as middle_name,
                    NULL as last_name,
                    co.external_id,
                    COALESCE(
                        (SELECT jsonb_object_agg(
                            cd3.role,
                            cd3.value
                        )
                        FROM contact_details cd3
                        WHERE cd3.client_organisation_id = co.id),
                        '{}'::jsonb
                    ) AS contact_details
                FROM client_organisations co
                WHERE co.id = ma.attendee_id
            ) entity_data
            LIMIT 1
        ) p ON true
        WHERE ma.meeting_id = m.id
    ) AS participants,
    m.record_type,
    m.ai_transcript_id,
    co.external_id AS client_organisation_external_id,
    m.is_historical,
    m.actions_skipped
FROM meetings m
LEFT JOIN client_organisations co ON m.client_organisation_id = co.id;

-- ╔═════ 20260320001634-add-contact-fields-to-relationships-dashboard-view.sql ═════╗
DROP VIEW IF EXISTS public.relationships_dashboard_view;

CREATE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    projection_aum.aum,
    co.next_meeting,
    co.growth_opportunity_next_step_date,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    ( SELECT CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name)
           FROM clients c
             JOIN persons p ON c.person_id = p.id
          WHERE c.external_id = co.extra_properties->>'SalenticaLMNTS__Secondary_Contact__c'
            AND c.tenant_id = co.tenant_id
          LIMIT 1) AS secondary_contact_full_name,
    ( SELECT CONCAT_WS(' ', p.first_name, p.middle_name, p.last_name)
           FROM agent_relationship_profiles arp
             JOIN agents a ON arp.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE arp.external_id = co.external_id
            AND arp.relationship_type = 'RVP'
            AND arp.tenant_id = co.tenant_id
          LIMIT 1) AS closing_rvp_full_name,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN LATERAL (
        SELECT cobl.amount::double precision AS aum
          FROM client_organisation_balance_latest cobl
         WHERE cobl.tenant_id = co.tenant_id
           AND cobl.client_organisation_id = co.id
           AND cobl.balance_scope = 'CLIENT_ORGANISATION_BALANCE'
           AND cobl.balance_type = 'AUM'
           -- TODO: Replace fixed USD with tenant-configured reporting currency.
           AND cobl.currency = 'USD'
     ) projection_aum ON TRUE
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
  WHERE co.deleted_at IS NULL;

