-- ╔═════ 20260324120427-revert-contact-fields-from-relationships-dashboard-view.sql ═════╗
-- Reverts the expensive correlated subqueries for secondary_contact_full_name
-- and closing_rvp_full_name added in 20260320001634. These caused a ~34x
-- performance regression on the relationship dashboard view.

DROP VIEW IF EXISTS public.relationships_dashboard_view;

CREATE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.approx_aum,
    projection_aum.aum,
    co.next_meeting,
    co.growth_opportunity_next_step_date,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN LATERAL (
        SELECT cobl.amount::double precision AS aum
          FROM client_organisation_balance_latest cobl
         WHERE cobl.tenant_id = co.tenant_id
           AND cobl.client_organisation_id = co.id
           AND cobl.balance_scope = 'CLIENT_ORGANISATION_BALANCE'
           AND cobl.balance_type = 'AUM'
           -- TODO: Replace fixed USD with tenant-configured reporting currency.
           AND cobl.currency = 'USD'
     ) projection_aum ON TRUE
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
  WHERE co.deleted_at IS NULL;

