-- ╔═════ 20260330152215-add_unqork_tasks_status_sort_index.sql ═════╗
CREATE INDEX IF NOT EXISTS idx_unqork_tasks_status_expr_next_step
ON unqork_tasks (
  (CASE
    WHEN task_is_discarded = 'true'::text THEN 'cancelled'::text
    WHEN task_status = ANY (ARRAY['Complete'::text, 'Completed'::text]) THEN 'done'::text
    WHEN task_status = 'Pending Approval'::text THEN 'pending_approval'::text
    WHEN task_status = 'Ready to Begin'::text THEN 'todo'::text
    WHEN task_status = 'In Progress'::text THEN 'in_progress'::text
    WHEN task_status = ANY (ARRAY['Canceled'::text, 'Discarded'::text]) THEN 'cancelled'::text
    WHEN task_status = 'Declined'::text THEN 'rejected'::text
    WHEN task_status = 'Waiting'::text THEN 'waiting'::text
    WHEN task_status = 'Scheduled'::text THEN 'scheduled'::text
    WHEN task_status = ''::text THEN 'blocked'::text
    ELSE 'blocked'::text
  END),
  task_next_step_date
);

