-- ╔═════ 20260403120000-create-policy-fts-incremental-sync.sql ═════╗
-- Incremental FTS sync state table.
-- Cursor semantics use (last_updated_at, last_id) per (fts_name, source_name)
-- to avoid missing rows when multiple records share the same timestamp.
CREATE TABLE IF NOT EXISTS fts_incremental_sync_state (
    fts_name TEXT NOT NULL,
    source_name TEXT NOT NULL,
    last_updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT '1970-01-01T00:00:00Z',
    last_id TEXT NOT NULL DEFAULT '',
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    PRIMARY KEY (fts_name, source_name)
);

CREATE INDEX IF NOT EXISTS idx_fts_incremental_sync_state_fts_name
    ON fts_incremental_sync_state (fts_name);

-- Policy FTS table (incrementally maintained, not a materialized view)
CREATE TABLE IF NOT EXISTS policy_fts (
    policy_id TEXT PRIMARY KEY,
    tenant_id TEXT NOT NULL,
    client_organisation_id TEXT NOT NULL,
    display_text TEXT NOT NULL,
    display_fields JSONB NOT NULL DEFAULT '{}'::jsonb,
    search_text TEXT NOT NULL,
    search_vector tsvector NOT NULL,
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_policy_fts_tenant_id
    ON policy_fts (tenant_id);

CREATE INDEX IF NOT EXISTS idx_policy_fts_client_org_id
    ON policy_fts (client_organisation_id);

CREATE INDEX IF NOT EXISTS idx_policy_fts_search_vector
    ON policy_fts USING gin (search_vector);

CREATE INDEX IF NOT EXISTS idx_policy_fts_search_text_trgm
    ON policy_fts USING gin (search_text gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_policy_fts_updated_at
    ON policy_fts (updated_at DESC NULLS LAST);

CREATE INDEX IF NOT EXISTS idx_policy_fts_tenant_updated
    ON policy_fts (tenant_id, updated_at DESC NULLS LAST);

