-- ╔═════ 20260407120000-migrate-e-signature-to-advanced-array.sql ═════╗
-- Migrate e-signature form elements to use avantos_type 'advanced-array' with arrayType 'envelopes'.
-- Previously, e-signature elements were stored with avantos_type 'e-signature' in the JSON schema.
-- This migration updates form_schema to use 'advanced-array' and ensures form_ui_schema has
-- arrayType 'envelopes' in the options for the corresponding UI elements.

DO $$
DECLARE
    form_rec RECORD;
    prop_key TEXT;
    updated_schema JSONB;
    updated_ui_schema JSONB;
    elem JSONB;
    elem_idx INT;
    e_sig_keys TEXT[];
BEGIN
    FOR form_rec IN
        SELECT id, form_schema, form_ui_schema
        FROM forms
        WHERE EXISTS (
            SELECT 1
            FROM jsonb_each(form_schema->'properties') AS p(key, value)
            WHERE p.value->>'avantos_type' = 'e-signature'
        )
    LOOP
        updated_schema := form_rec.form_schema;
        e_sig_keys := ARRAY[]::TEXT[];

        -- Update avantos_type in form_schema properties
        FOR prop_key IN
            SELECT p.key
            FROM jsonb_each(form_rec.form_schema->'properties') AS p(key, value)
            WHERE p.value->>'avantos_type' = 'e-signature'
        LOOP
            updated_schema := jsonb_set(
                updated_schema,
                ARRAY['properties', prop_key, 'avantos_type'],
                '"advanced-array"'
            );
            e_sig_keys := array_append(e_sig_keys, prop_key);
        END LOOP;

        UPDATE forms SET form_schema = updated_schema WHERE id = form_rec.id;

        -- Update form_ui_schema to ensure arrayType 'envelopes' in options
        IF form_rec.form_ui_schema IS NOT NULL
           AND jsonb_typeof(form_rec.form_ui_schema->'elements') = 'array'
        THEN
            updated_ui_schema := form_rec.form_ui_schema;

            FOR elem_idx IN 0..jsonb_array_length(form_rec.form_ui_schema->'elements') - 1
            LOOP
                elem := form_rec.form_ui_schema->'elements'->elem_idx;

                -- Check if this element's scope matches one of the e-signature properties
                IF elem->>'type' = 'Control' THEN
                    FOR prop_key IN SELECT unnest(e_sig_keys)
                    LOOP
                        IF elem->>'scope' = '#/properties/' || prop_key THEN
                            updated_ui_schema := jsonb_set(
                                updated_ui_schema,
                                ARRAY['elements', elem_idx::TEXT, 'options'],
                                COALESCE(elem->'options', '{}'::jsonb) || '{"arrayType": "envelopes"}'::jsonb
                            );
                        END IF;
                    END LOOP;
                END IF;
            END LOOP;

            UPDATE forms SET form_ui_schema = updated_ui_schema WHERE id = form_rec.id;
        END IF;
    END LOOP;
END $$;

