-- ╔═════ 20260425120000-add-agency-fields-to-policies-search-view.sql ═════╗
DROP VIEW IF EXISTS policies_search_view;

CREATE VIEW policies_search_view AS
SELECT
    p.id,
    p.tenant_id,
    p.external_id,
    p.client_organisation_id,
    co.name AS client_organisation_name,
    co.external_id AS client_organisation_external_id,
    p.line_of_business,
    p.subtype,
    p.status,
    p.policy_number,
    p.carrier,
    p.issue_date,
    p.effective_date,
    p.termination_date,
    p.premium_amount,
    p.premium_frequency,
    p.face_amount,
    p.additional_attributes,
    p.created_at,
    p.updated_at,
    p.agent_organisation_id,
    ao.external_id AS agent_organisation_external_id,
    ao.name AS agent_organisation_name,
    CASE
        WHEN EXISTS (
            SELECT 1
            FROM policy_client_roles pcr
            WHERE pcr.policy_id = p.id
              AND pcr.tenant_id = p.tenant_id
        ) THEN (
            SELECT COALESCE(jsonb_agg(
                jsonb_build_object(
                    'client_id', pcr.client_id,
                    'client_external_id', c.external_id,
                    'client_name', COALESCE(per.first_name || ' ' || per.last_name, ''),
                    'role', pcr.role,
                    'effective_from', pcr.effective_from,
                    'effective_to', pcr.effective_to
                )
            ), '[]'::jsonb)
            FROM policy_client_roles pcr
            LEFT JOIN clients c ON pcr.client_id = c.id AND c.tenant_id = p.tenant_id
            LEFT JOIN persons per ON c.person_id = per.id AND per.tenant_id = p.tenant_id
            WHERE pcr.policy_id = p.id AND pcr.tenant_id = p.tenant_id
        )
        WHEN p.primary_client_id IS NOT NULL THEN (
            SELECT COALESCE(jsonb_agg(
                jsonb_build_object(
                    'client_id', c.id,
                    'client_external_id', c.external_id,
                    'client_name', COALESCE(per.first_name || ' ' || per.last_name, ''),
                    'role', 'Primary',
                    'effective_from', NULL,
                    'effective_to', NULL
                )
            ), '[]'::jsonb)
            FROM clients c
            LEFT JOIN persons per ON c.person_id = per.id AND per.tenant_id = p.tenant_id
            WHERE c.id = p.primary_client_id
              AND c.tenant_id = p.tenant_id
              AND c.deleted_at IS NULL
        )
        ELSE '[]'::jsonb
    END AS clients,
    (
        SELECT COALESCE(jsonb_agg(
            jsonb_build_object(
                'agent_id', par.agent_id,
                'agent_external_id', a.external_id,
                'agent_name', COALESCE(per.first_name || ' ' || per.last_name, ''),
                'role', par.role,
                'effective_from', par.effective_from,
                'effective_to', par.effective_to
            )
        ), '[]'::jsonb)
        FROM policy_agent_relationships par
        LEFT JOIN agents a ON par.agent_id = a.id AND a.tenant_id = p.tenant_id
        LEFT JOIN persons per ON a.person_id = per.id AND per.tenant_id = p.tenant_id
        WHERE par.policy_id = p.id AND par.tenant_id = p.tenant_id
    ) AS agents
FROM policies p
LEFT JOIN client_organisations co ON p.client_organisation_id = co.id AND co.tenant_id = p.tenant_id
LEFT JOIN agent_organisations ao ON p.agent_organisation_id = ao.id AND ao.tenant_id = p.tenant_id
WHERE p.deleted_at IS NULL;

-- ╔═════ 20260425133000-promote-agent-portal-relationship-fields.sql ═════╗
ALTER TABLE clients ADD COLUMN IF NOT EXISTS status TEXT;
ALTER TABLE clients ADD COLUMN IF NOT EXISTS subtype TEXT;
ALTER TABLE client_organisations ADD COLUMN IF NOT EXISTS relationship_start_date DATE;
ALTER TABLE client_organisations ADD COLUMN IF NOT EXISTS last_interaction_date DATE;

CREATE OR REPLACE VIEW public.client_person_view AS
 SELECT c.id AS client_id,
    c.tenant_id,
    c.organisation_id,
    c.investment_goal,
    c.assets,
    c.compliance_record,
    c.documentation,
    c.role,
    p.id AS person_id,
    p.title,
    p.first_name,
    p.middle_name,
    p.last_name,
    p.suffix,
    p.date_of_birth,
    p.gender,
    p.nationality,
    p.marital_status,
    p.ssn,
    p.preferred_contact_method,
    c.employment_status,
    c.drivers_license_number,
    c.expected_retirement_age,
    c.maiden_name,
    c.occupation,
    c.preferred_name,
    c.retired,
    c.current_employer,
    c.retirement_date,
    c.wedding_anniversary,
    c.personal_interests,
    c.officer_or_director,
    c.security_restrictions,
    c.marketing_salutation,
    c.additional_attributes,
    COALESCE(addr.addresses, '[]'::jsonb) AS addresses,
    COALESCE(cd.contacts, '[]'::jsonb) AS contacts,
    c.external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_segmentation,
    c.status,
    c.subtype
   FROM clients c
     JOIN persons p ON p.id = c.person_id
     LEFT JOIN LATERAL ( SELECT jsonb_agg(jsonb_build_object('address_type', aer.address_type, 'description', aer.description, 'address_line1', a.address_line1, 'address_line2', a.address_line2, 'city', a.city, 'state', a.state, 'zipcode', a.zipcode, 'country', a.country)) AS addresses
           FROM address_entity_relationships aer
             JOIN addresses a ON a.id = aer.address_id
          WHERE aer.client_id = c.id) addr ON true
     LEFT JOIN LATERAL ( SELECT jsonb_agg(jsonb_build_object('type', cd_1.type, 'role', cd_1.role, 'value', cd_1.value)) AS contacts
           FROM contact_details cd_1
          WHERE cd_1.client_id = c.id) cd ON true
     LEFT JOIN client_organisations co ON c.organisation_id = co.id
   WHERE c.deleted_at IS NULL;

DROP VIEW IF EXISTS public.client_organisation_members_view;

CREATE VIEW public.client_organisation_members_view AS
SELECT
    p.first_name,
    p.last_name,
    p.id AS person_id,
    p.date_of_birth AS birthdate,
    p.marital_status,
    c.id AS client_id,
    c.role,
    c.status,
    c.subtype,
    c.employment_status,
    c.current_employer,
    c.occupation,
    c.preferred_name,
    c.organisation_id AS client_organisation_id,
    c.is_primary,
    c.tenant_id,
    COALESCE(
        (SELECT jsonb_object_agg(
            aer.address_type,
            jsonb_build_object(
                'address_line1', a.address_line1,
                'address_line2', a.address_line2,
                'city', a.city,
                'state', a.state,
                'zipcode', a.zipcode,
                'country', a.country
            )
        )
        FROM address_entity_relationships aer
        JOIN addresses a ON aer.address_id = a.id
        WHERE aer.client_id = c.id),
        '{}'::jsonb
    ) AS addresses,
    p.ssn,
    c.additional_attributes,
    (SELECT value
     FROM contact_details cd
     WHERE cd.client_id = c.id
       AND cd.role = 'primary_email'
       AND cd.type = 'email'
     LIMIT 1) AS email,
    (SELECT value
     FROM contact_details cd
     WHERE cd.client_id = c.id
       AND cd.role = 'primary_phone'
       AND cd.type = 'phone'
     LIMIT 1) AS phone
FROM clients c
JOIN persons p ON c.person_id = p.id
WHERE c.deleted_at IS NULL;

DROP VIEW IF EXISTS public.relationships_dashboard_view;

CREATE VIEW public.relationships_dashboard_view AS
 SELECT co.tenant_id,
    co.id AS client_organisation_id,
    co.external_id AS client_organisation_external_id,
    co.name AS client_organisation_name,
    co.client_organisation_type,
    co.client_organisation_role,
    co.relationship_status AS client_relationship_status,
    co.relationship_start_date,
    co.last_interaction_date,
    co.approx_aum,
    projection_aum.aum,
    co.next_meeting,
    co.growth_opportunity_next_step_date,
    co.description AS client_organisation_description,
    co.extra_properties AS client_organisation_extra_properties,
    ao.id AS agent_organisation_id,
    ao.name AS agent_organisation_name,
    ao.agent_organisation_type,
    ao.agent_organisation_role,
    ( SELECT COALESCE(jsonb_object_agg(aer.address_type, jsonb_build_object('state', a.state, 'city', a.city)), '{}'::jsonb) AS "coalesce"
           FROM address_entity_relationships aer
             JOIN addresses a ON aer.address_id = a.id
          WHERE aer.client_organisation_id = co.id) AS addresses,
    ( SELECT COALESCE(jsonb_object_agg(acor.relationship_type, jsonb_build_object('agent_id', a.id, 'first_name', p.first_name, 'last_name', p.last_name, 'middle_name', p.middle_name, 'direct_assignment', acor.direct_assignment)), '{}'::jsonb) AS "coalesce"
           FROM agent_client_organisation_relationships acor
             JOIN agents a ON acor.agent_id = a.id
             JOIN persons p ON a.person_id = p.id
          WHERE acor.client_organisation_id = co.id) AS agents,
    bg.name AS region,
    aof.name AS office,
    co.is_mercer_employee,
    co.client_segmentation,
    co.national_css_coverage,
    co.created_at,
    co.updated_at
   FROM client_organisations co
     LEFT JOIN LATERAL (
        SELECT cobl.amount::double precision AS aum
          FROM client_organisation_balance_latest cobl
         WHERE cobl.tenant_id = co.tenant_id
           AND cobl.client_organisation_id = co.id
           AND cobl.balance_scope = 'CLIENT_ORGANISATION_BALANCE'
           AND cobl.balance_type = 'AUM'
           AND cobl.currency = 'USD'
     ) projection_aum ON TRUE
     LEFT JOIN agent_organisations ao ON co.agent_organisation_id = ao.id
     LEFT JOIN business_groups bg ON co.business_group_id = bg.id
     LEFT JOIN agent_organisations aof ON co.office_id = aof.id
  WHERE co.deleted_at IS NULL;

-- ╔═════ 20260426120000-add-ledger-measure-catalog.sql ═════╗
CREATE TABLE valuation_measure_catalog (
    tenant_id TEXT NOT NULL,
    code TEXT NOT NULL,
    fact_model TEXT NOT NULL,
    scope TEXT NOT NULL,
    subject_type TEXT,
    display_name TEXT NOT NULL,
    description TEXT,
    category TEXT NOT NULL,
    value_kind TEXT NOT NULL,
    default_sort_order INTEGER NOT NULL DEFAULT 1000,
    additive_for_aum BOOLEAN NOT NULL DEFAULT FALSE,
    is_displayable BOOLEAN NOT NULL DEFAULT TRUE,
    created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    PRIMARY KEY (tenant_id, code),
    CONSTRAINT chk_valuation_measure_catalog_fact_model CHECK (
        fact_model IN ('position_valuation', 'summary_balance')
    )
);

CREATE INDEX idx_valuation_measure_catalog_tenant_model_scope
    ON valuation_measure_catalog (tenant_id, fact_model, scope, default_sort_order);

ALTER TABLE position_valuations
    ADD COLUMN canonical_valuation_type TEXT,
    ADD COLUMN source_measure_code TEXT,
    ADD COLUMN source_measure_label TEXT,
    ADD COLUMN source_measure_field TEXT;

ALTER TABLE summary_balance_valuations
    ADD COLUMN canonical_balance_type TEXT,
    ADD COLUMN source_measure_code TEXT,
    ADD COLUMN source_measure_label TEXT,
    ADD COLUMN source_measure_field TEXT;

WITH tenant_seed AS (
    SELECT '1'::text AS tenant_id
    UNION
    SELECT DISTINCT tenant_id FROM client_organisations WHERE tenant_id IS NOT NULL
    UNION
    SELECT DISTINCT tenant_id FROM position_file_controls WHERE tenant_id IS NOT NULL
    UNION
    SELECT DISTINCT tenant_id FROM summary_balance_file_controls WHERE tenant_id IS NOT NULL
    UNION
    SELECT DISTINCT tenant_id FROM position_valuations WHERE tenant_id IS NOT NULL
    UNION
    SELECT DISTINCT tenant_id FROM summary_balance_valuations WHERE tenant_id IS NOT NULL
    UNION
    SELECT DISTINCT tenant_id FROM client_organisation_balance_latest WHERE tenant_id IS NOT NULL
),
catalog_seed AS (
    SELECT * FROM (VALUES
        ('MARKET_VALUE', 'position_valuation', 'ACCOUNT_POSITION', 'financial_account', 'Market Value', 'Dated market value for an account position.', 'balance', 'money', 10, TRUE, TRUE),
        ('REP_SPLIT_BALANCE', 'position_valuation', 'ACCOUNT_POSITION', 'financial_account', 'Rep Split Balance', 'Dated balance attributed to a representative split.', 'allocation', 'money', 20, FALSE, TRUE),
        ('CASH_VALUE', 'position_valuation', 'POLICY_VALUATION', 'policy', 'Cash Value', 'Dated policy cash value.', 'policy_value', 'money', 100, FALSE, TRUE),
        ('DEATH_BENEFIT', 'position_valuation', 'POLICY_VALUATION', 'policy', 'Death Benefit', 'Dated policy death benefit value.', 'policy_value', 'money', 110, FALSE, TRUE),
        ('SURRENDER_CHARGE', 'position_valuation', 'POLICY_VALUATION', 'policy', 'Surrender Charge', 'Dated policy surrender charge.', 'charge', 'money', 120, FALSE, TRUE),
        ('LOAN_INTEREST_PAID', 'position_valuation', 'POLICY_VALUATION', 'policy', 'Loan Interest Paid', 'Dated loan interest paid value.', 'loan', 'money', 130, FALSE, TRUE),
        ('ACCOUNT_VALUE', 'position_valuation', 'POLICY_VALUATION', 'policy', 'Account Value', 'Dated policy account value.', 'policy_value', 'money', 140, FALSE, TRUE),
        ('AUM', 'summary_balance', 'CLIENT_ORGANISATION_BALANCE', 'client_organisation', 'Assets Under Management', 'Source-asserted assets under management.', 'balance', 'money', 10, TRUE, TRUE)
    ) AS v(code, fact_model, scope, subject_type, display_name, description, category, value_kind, default_sort_order, additive_for_aum, is_displayable)
)
INSERT INTO valuation_measure_catalog (
    tenant_id,
    code,
    fact_model,
    scope,
    subject_type,
    display_name,
    description,
    category,
    value_kind,
    default_sort_order,
    additive_for_aum,
    is_displayable
)
SELECT
    t.tenant_id,
    c.code,
    c.fact_model,
    c.scope,
    c.subject_type,
    c.display_name,
    c.description,
    c.category,
    c.value_kind,
    c.default_sort_order,
    c.additive_for_aum,
    c.is_displayable
FROM tenant_seed t
CROSS JOIN catalog_seed c
ON CONFLICT (tenant_id, code) DO NOTHING;

UPDATE summary_balance_valuations
SET
    canonical_balance_type = 'AUM',
    source_measure_code = 'AUM__c',
    source_measure_label = 'Salesforce Account AUM',
    source_measure_field = 'AUM__c'
WHERE source_system = 'SALESFORCE'
  AND subject_type = 'client_organisation'
  AND balance_scope = 'CLIENT_ORGANISATION_BALANCE'
  AND balance_type = 'AUM'
  AND canonical_balance_type IS NULL;

UPDATE summary_balance_valuations
SET
    canonical_balance_type = balance_type,
    source_measure_code = COALESCE(source_measure_code, balance_type)
WHERE canonical_balance_type IS NULL;

UPDATE position_valuations
SET
    canonical_valuation_type = CASE valuation_type
        WHEN 'CUSTODIAN_AUM' THEN 'MARKET_VALUE'
        WHEN 'REP_SPLIT' THEN 'REP_SPLIT_BALANCE'
        ELSE valuation_type
    END,
    source_measure_code = COALESCE(source_measure_code, valuation_type)
WHERE source_system = 'GUARDIAN'
  AND canonical_valuation_type IS NULL;

UPDATE position_valuations
SET
    canonical_valuation_type = valuation_type,
    source_measure_code = COALESCE(source_measure_code, valuation_type)
WHERE canonical_valuation_type IS NULL;

DROP VIEW IF EXISTS position_valuations_latest;

CREATE VIEW position_valuations_latest AS
WITH ranked AS (
    SELECT
        pv.id,
        pv.tenant_id,
        pv.position_file_control_id,
        pv.business_date,
        pv.valuation_scope,
        pv.account_id,
        pv.sub_account_id,
        pv.product_id,
        pv.policy_id,
        pv.valuation_type,
        pv.canonical_valuation_type,
        pv.source_measure_code,
        pv.source_measure_label,
        pv.source_measure_field,
        pv.quantity,
        pv.valuation_amount,
        pv.currency,
        pv.unit_price,
        pv.price_currency,
        pv.source_system,
        pv.source_batch_id,
        pv.external_row_id,
        pv.source_file_key,
        pv.source_business_timestamp,
        pv.row_hash,
        pv.attributes,
        pv.ingested_at,
        pv.created_at,
        pfc.finished_at AS file_control_finished_at,
        ROW_NUMBER() OVER (
            PARTITION BY
                pv.tenant_id,
                pv.business_date,
                pv.valuation_scope,
                pv.account_id,
                pv.sub_account_id,
                pv.product_id,
                pv.policy_id,
                pv.valuation_type,
                pv.currency
            ORDER BY
                pv.source_business_timestamp DESC NULLS LAST,
                pfc.finished_at DESC NULLS LAST,
                pv.ingested_at DESC,
                pv.id DESC
        ) AS row_num
    FROM position_valuations pv
    JOIN position_file_controls pfc
        ON pfc.id = pv.position_file_control_id
       AND pfc.tenant_id = pv.tenant_id
    WHERE pfc.status = 'finished'
      AND pfc.deleted_at IS NULL
)
SELECT
    id,
    tenant_id,
    position_file_control_id,
    business_date,
    valuation_scope,
    account_id,
    sub_account_id,
    product_id,
    policy_id,
    valuation_type,
    canonical_valuation_type,
    source_measure_code,
    source_measure_label,
    source_measure_field,
    quantity,
    valuation_amount,
    currency,
    unit_price,
    price_currency,
    source_system,
    source_batch_id,
    external_row_id,
    source_file_key,
    source_business_timestamp,
    row_hash,
    attributes,
    ingested_at,
    created_at,
    file_control_finished_at
FROM ranked
WHERE row_num = 1;

DROP VIEW IF EXISTS summary_balance_valuations_latest;

CREATE VIEW summary_balance_valuations_latest AS
WITH ranked AS (
    SELECT
        sbv.id,
        sbv.tenant_id,
        sbv.summary_balance_file_control_id,
        sbv.business_date,
        sbv.subject_type,
        sbv.subject_id,
        sbv.balance_scope,
        sbv.balance_type,
        sbv.canonical_balance_type,
        sbv.source_measure_code,
        sbv.source_measure_label,
        sbv.source_measure_field,
        sbv.balance_amount,
        sbv.currency,
        sbv.source_system,
        sbv.source_batch_id,
        sbv.external_row_id,
        sbv.source_file_key,
        sbv.source_business_timestamp,
        sbv.row_hash,
        sbv.attributes,
        sbv.ingested_at,
        sbv.created_at,
        sbfc.finished_at AS file_control_finished_at,
        ROW_NUMBER() OVER (
            PARTITION BY
                sbv.tenant_id,
                sbv.business_date,
                sbv.subject_type,
                sbv.subject_id,
                sbv.balance_scope,
                sbv.balance_type,
                sbv.currency
            ORDER BY
                sbv.source_business_timestamp DESC NULLS LAST,
                sbfc.finished_at DESC NULLS LAST,
                sbv.ingested_at DESC,
                sbv.id DESC
        ) AS row_num
    FROM summary_balance_valuations sbv
    JOIN summary_balance_file_controls sbfc
        ON sbfc.id = sbv.summary_balance_file_control_id
       AND sbfc.tenant_id = sbv.tenant_id
    WHERE sbfc.status = 'finished'
      AND sbfc.deleted_at IS NULL
)
SELECT
    id,
    tenant_id,
    summary_balance_file_control_id,
    business_date,
    subject_type,
    subject_id,
    balance_scope,
    balance_type,
    canonical_balance_type,
    source_measure_code,
    source_measure_label,
    source_measure_field,
    balance_amount,
    currency,
    source_system,
    source_batch_id,
    external_row_id,
    source_file_key,
    source_business_timestamp,
    row_hash,
    attributes,
    ingested_at,
    created_at,
    file_control_finished_at
FROM ranked
WHERE row_num = 1;

-- ╔═════ 20260426150000-add-external-system-ids.sql ═════╗
CREATE TABLE external_system_ids (
    id          TEXT        NOT NULL,
    tenant_id   TEXT        NOT NULL,
    entity_type TEXT        NOT NULL CHECK (entity_type IN (
                                'agent', 'client', 'client_organisation', 'agent_organisation'
                            )),
    entity_id   TEXT        NOT NULL,
    system      TEXT        NOT NULL,
    key         TEXT        NOT NULL,
    value       TEXT        NOT NULL,
    valid_until TIMESTAMPTZ,
    created_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    deleted_at  TIMESTAMPTZ,
    deleted_by  TEXT,
    CONSTRAINT external_system_ids_pkey PRIMARY KEY (id),
    CONSTRAINT external_system_ids_unique
        UNIQUE (tenant_id, entity_type, entity_id, system, key)
);

CREATE INDEX external_system_ids_entity_idx
    ON external_system_ids (tenant_id, entity_type, entity_id)
    WHERE deleted_at IS NULL;

CREATE INDEX external_system_ids_expiry_idx
    ON external_system_ids (tenant_id, valid_until)
    WHERE valid_until IS NOT NULL AND deleted_at IS NULL;

-- ╔═════ 20260427131526-tenant_oauth_provider_config.sql ═════╗
CREATE TABLE IF NOT EXISTS tenant_oauth_provider_config (
    id                       TEXT PRIMARY KEY,
    tenant_id                TEXT NOT NULL,
    provider                 TEXT NOT NULL,
    auth_mode                TEXT NOT NULL,

    -- Standard OAuth fields (common across providers + modes)
    client_id                TEXT NOT NULL,
    client_secret            TEXT,
    redirect_uri             TEXT,
    origin                   TEXT,

    -- JWT / keypair fields
    private_key_pem          TEXT,
    private_key_fingerprint  TEXT,

    -- Provider-specific extras (shape validated per (provider, auth_mode) in service layer)
    provider_config          JSONB NOT NULL DEFAULT '{}'::jsonb,

    is_enabled               BOOLEAN NOT NULL DEFAULT TRUE,
    created_at               TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at               TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    created_by               TEXT,
    updated_by               TEXT,

    CONSTRAINT uq_tenant_oauth_provider UNIQUE (tenant_id, provider)
);
CREATE INDEX IF NOT EXISTS idx_tenant_oauth_provider_config_tenant ON tenant_oauth_provider_config(tenant_id);

-- ╔═════ 20260427163037-create_ms_graph_tables.sql ═════╗
CREATE TABLE IF NOT EXISTS msgraph_sync_state (
    id              TEXT NOT NULL PRIMARY KEY DEFAULT gen_random_uuid()::TEXT,
    tenant_id       TEXT NOT NULL,
    user_id         TEXT NOT NULL,
    delta_link      TEXT,
    last_sync_at    TIMESTAMP WITH TIME ZONE,
    sync_status     TEXT NOT NULL DEFAULT 'idle',
    error_message   TEXT,
    window_reset_at TIMESTAMP WITH TIME ZONE,
    created_at      TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at      TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    UNIQUE (tenant_id, user_id)
);

-- ╔═════ 20260428170000-create_file_export_log.sql ═════╗
CREATE TABLE IF NOT EXISTS file_export_log (
    id                TEXT PRIMARY KEY,
    tenant_id         TEXT NOT NULL,
    run_id            TEXT NOT NULL,
    export_type       TEXT NOT NULL CHECK (export_type IN (
                          'warehouse_parquet',
                          'cdc_sftp',
                          'cdc_filenet',
                          'cdc_reconciliation'
                      )),
    destination_name  TEXT NOT NULL,
    destination_uri   TEXT NOT NULL,
    file_path         TEXT NOT NULL,
    file_size_bytes   BIGINT,
    record_count      BIGINT,
    status            TEXT NOT NULL CHECK (status IN ('succeeded', 'failed')),
    error_message     TEXT,
    started_at        TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    completed_at      TIMESTAMP WITH TIME ZONE,
    duration_ms       BIGINT,
    actor_id          TEXT NOT NULL,
    actor_type        TEXT NOT NULL DEFAULT 'system' CHECK (actor_type IN ('agent', 'system', 'integration')),
    request_id        TEXT,
    metadata          JSONB NOT NULL DEFAULT '{}'::jsonb,
    created_at        TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    updated_at        TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(),
    -- Idempotent re-runs of an export run must not double-log the same file.
    CONSTRAINT file_export_log_run_file_unique UNIQUE (tenant_id, run_id, file_path)
);

CREATE INDEX idx_file_export_log_tenant_run         ON file_export_log (tenant_id, run_id, started_at);
CREATE INDEX idx_file_export_log_tenant_status      ON file_export_log (tenant_id, status, started_at DESC);
CREATE INDEX idx_file_export_log_tenant_export_type ON file_export_log (tenant_id, export_type, started_at DESC);
CREATE INDEX idx_file_export_log_started_at         ON file_export_log (started_at);

