-- ╔═════ 20260503120000-client-organisation-fts-incremental.sql ═════╗
SET statement_timeout = '3600s';

DROP MATERIALIZED VIEW IF EXISTS client_organisation_fts;

CREATE TABLE IF NOT EXISTS client_organisation_fts (
    client_organisation_id TEXT                     NOT NULL,
    tenant_id              TEXT                     NOT NULL,
    display_text           TEXT                     NOT NULL,
    display_fields         JSONB                    NOT NULL DEFAULT '{}'::jsonb,
    search_text            TEXT                     NOT NULL,
    search_vector          tsvector                 NOT NULL,
    updated_at             TIMESTAMP WITH TIME ZONE NOT NULL
);

CREATE UNIQUE INDEX IF NOT EXISTS idx_client_organisation_fts_id
    ON client_organisation_fts (client_organisation_id);

CREATE INDEX IF NOT EXISTS idx_client_organisation_fts_tenant_id
    ON client_organisation_fts (tenant_id);

CREATE INDEX IF NOT EXISTS idx_client_organisation_fts_search_vector
    ON client_organisation_fts USING gin(search_vector);

CREATE INDEX IF NOT EXISTS idx_client_organisation_fts_search_text_trgm
    ON client_organisation_fts USING gin(search_text gin_trgm_ops);

CREATE INDEX IF NOT EXISTS idx_client_organisation_fts_updated_at
    ON client_organisation_fts (updated_at DESC NULLS LAST);

CREATE INDEX IF NOT EXISTS idx_client_organisation_fts_tenant_updated
    ON client_organisation_fts (tenant_id, updated_at DESC NULLS LAST);

-- Remove the stale fts_refresh_state row; it is no longer meaningful now that
-- client_organisation_fts is maintained incrementally rather than via REFRESH.
DELETE FROM fts_refresh_state WHERE view_name = 'client_organisation_fts';

-- Seed the incremental sync cursors from the zero watermark. This lets the
-- incremental cron populate the table for both existing data and future loads.
INSERT INTO fts_incremental_sync_state (fts_name, source_name, last_updated_at, last_id, updated_at)
SELECT
    'client_organisation_fts' AS fts_name,
    source_name,
    '1970-01-01T00:00:00Z'::timestamptz AS last_updated_at,
    '' AS last_id,
    NOW() AS updated_at
FROM (
    VALUES
        ('client_organisations'),
        ('agent_client_organisation_relationships'),
        ('persons'),
        ('agents'),
        ('agent_organisations'),
        ('business_groups')
) AS sources(source_name)
ON CONFLICT (fts_name, source_name) DO NOTHING;

