-- ╔═════ 20260506120000-preserve-rep-split-latest-valuations.sql ═════╗
DROP VIEW IF EXISTS position_valuations_latest;

CREATE VIEW position_valuations_latest AS
WITH ranked AS (
    SELECT
        pv.id,
        pv.tenant_id,
        pv.position_file_control_id,
        pv.business_date,
        pv.valuation_scope,
        pv.account_id,
        pv.sub_account_id,
        pv.product_id,
        pv.policy_id,
        pv.valuation_type,
        pv.canonical_valuation_type,
        pv.source_measure_code,
        pv.source_measure_label,
        pv.source_measure_field,
        pv.quantity,
        pv.valuation_amount,
        pv.currency,
        pv.unit_price,
        pv.price_currency,
        pv.source_system,
        pv.source_batch_id,
        pv.external_row_id,
        pv.source_file_key,
        pv.source_business_timestamp,
        pv.row_hash,
        pv.attributes,
        pv.ingested_at,
        pv.created_at,
        pfc.finished_at AS file_control_finished_at,
        ROW_NUMBER() OVER (
            PARTITION BY
                pv.tenant_id,
                pv.business_date,
                pv.valuation_scope,
                pv.account_id,
                pv.sub_account_id,
                pv.product_id,
                pv.policy_id,
                pv.valuation_type,
                CASE
                    WHEN pv.valuation_type = 'REP_SPLIT' THEN COALESCE(pv.attributes->>'linking_external_id', '')
                    ELSE ''
                END,
                pv.currency
            ORDER BY
                pv.source_business_timestamp DESC NULLS LAST,
                pfc.finished_at DESC NULLS LAST,
                pv.ingested_at DESC,
                pv.id DESC
        ) AS row_num
    FROM position_valuations pv
    JOIN position_file_controls pfc
        ON pfc.id = pv.position_file_control_id
       AND pfc.tenant_id = pv.tenant_id
    WHERE pfc.status = 'finished'
      AND pfc.deleted_at IS NULL
)
SELECT
    id,
    tenant_id,
    position_file_control_id,
    business_date,
    valuation_scope,
    account_id,
    sub_account_id,
    product_id,
    policy_id,
    valuation_type,
    canonical_valuation_type,
    source_measure_code,
    source_measure_label,
    source_measure_field,
    quantity,
    valuation_amount,
    currency,
    unit_price,
    price_currency,
    source_system,
    source_batch_id,
    external_row_id,
    source_file_key,
    source_business_timestamp,
    row_hash,
    attributes,
    ingested_at,
    created_at,
    file_control_finished_at
FROM ranked
WHERE row_num = 1;

