-- ╔═════ 20260508120000-scope-client-organisation-aum-projection.sql ═════╗
ALTER TABLE client_organisation_balance_latest
    ADD COLUMN visibility_scope TEXT NOT NULL DEFAULT 'GLOBAL',
    ADD COLUMN visibility_subject_id TEXT NOT NULL DEFAULT '',
    ADD COLUMN visibility_subject_code TEXT NOT NULL DEFAULT '',
    ADD COLUMN balance_basis TEXT NOT NULL DEFAULT 'HOUSEHOLD_AUM',
    ADD COLUMN calculation_mode TEXT NOT NULL DEFAULT 'position_rollup',
    ADD COLUMN metadata JSONB NOT NULL DEFAULT '{}'::jsonb;

ALTER TABLE client_organisation_balance_projection_state
    ADD COLUMN watermark_cursor TEXT NOT NULL DEFAULT '';

UPDATE client_organisation_balance_latest
   SET calculation_mode = CASE
            WHEN source_kind = 'summary_balance' THEN 'summary_balance'
            ELSE 'position_rollup'
       END,
       metadata = jsonb_build_object('balance_basis', 'HOUSEHOLD_AUM')
 WHERE visibility_scope = 'GLOBAL'
   AND visibility_subject_id = ''
   AND balance_basis = 'HOUSEHOLD_AUM';

ALTER TABLE client_organisation_balance_latest
    DROP CONSTRAINT IF EXISTS client_organisation_balance_latest_pkey;

ALTER TABLE client_organisation_balance_latest
    ADD CONSTRAINT client_organisation_balance_latest_pkey PRIMARY KEY (
        tenant_id,
        client_organisation_id,
        balance_scope,
        balance_type,
        currency,
        visibility_scope,
        visibility_subject_id,
        balance_basis
    );

ALTER TABLE client_organisation_balance_latest
    ADD CONSTRAINT chk_cobl_visibility_scope
        CHECK (visibility_scope IN ('GLOBAL', 'AGENT', 'AGENT_CONTRACT')),
    ADD CONSTRAINT chk_cobl_balance_basis
        CHECK (balance_basis IN ('HOUSEHOLD_AUM', 'VISIBLE_ACCOUNT_AUM', 'PRODUCER_SPLIT_AUM', 'HOUSEHOLD_ANNUALIZED_PREMIUM', 'VISIBLE_POLICY_ANNUALIZED_PREMIUM')),
    ADD CONSTRAINT chk_cobl_calculation_mode
        CHECK (calculation_mode IN ('summary_balance', 'position_rollup', 'product_visible_rollup', 'rep_split_rollup', 'policy_visible_rollup'));

DROP INDEX IF EXISTS idx_cobl_tenant_balance_type;

CREATE INDEX idx_cobl_tenant_balance_type
    ON client_organisation_balance_latest (
        tenant_id,
        balance_scope,
        balance_type,
        currency,
        visibility_scope,
        visibility_subject_id,
        balance_basis
    );

CREATE INDEX idx_cobl_dashboard_sort
    ON client_organisation_balance_latest (
        tenant_id,
        visibility_scope,
        visibility_subject_id,
        balance_scope,
        balance_type,
        balance_basis,
        currency,
        amount DESC,
        client_organisation_id
    );

-- Supports the visible_account_agents CTE direct-agent branch in the
-- VISIBLE_ACCOUNT_AUM projection. Existing agent_id and (tenant_id, role)
-- indexes leave the planner without a covering index when scoping by
-- (tenant_id, agent_id, role) to fan out to the financial accounts.
CREATE INDEX IF NOT EXISTS idx_faar_agent_scope
    ON financial_account_agent_relationships (
        tenant_id,
        agent_id,
        role,
        financial_account_id
    );

-- Supports the contract-resolved branch of the same projection where
-- visibility flows through agent_contracts.id; partial so that the index
-- only covers contract-bearing rows.
CREATE INDEX IF NOT EXISTS idx_faar_contract_scope
    ON financial_account_agent_relationships (
        tenant_id,
        agent_contract_id,
        role,
        financial_account_id
    )
    WHERE agent_contract_id IS NOT NULL;

-- Supports the PRODUCER_SPLIT_AUM projection which scans REP_SPLIT rows
-- from position_valuations and joins to agent_contracts on writing_code
-- (extracted from attributes->>'linking_external_id'). The partial index
-- keeps the index small since REP_SPLIT is a minority of valuation rows.
CREATE INDEX IF NOT EXISTS idx_position_valuations_rep_split_latest
    ON position_valuations (
        tenant_id,
        account_id,
        (attributes->>'linking_external_id'),
        currency,
        business_date DESC,
        source_business_timestamp DESC,
        ingested_at DESC,
        id DESC
    )
    WHERE valuation_scope = 'ACCOUNT_POSITION'
      AND valuation_type = 'REP_SPLIT';

-- Supports annualized-premium projection from POLICY_VALUATION rows keyed by
-- policy. The predicate keeps this focused on the generic canonical premium
-- measure populated from client-specific source fields such as CURRNT_ANL_PREM_AM.
CREATE INDEX IF NOT EXISTS idx_position_valuations_policy_annualized_latest
    ON position_valuations (
        tenant_id,
        policy_id,
        currency,
        business_date DESC,
        source_business_timestamp DESC,
        ingested_at DESC,
        id DESC
    )
    WHERE valuation_scope = 'POLICY_VALUATION'
      AND policy_id IS NOT NULL
      AND (
          canonical_valuation_type = 'ANNUALIZED_PREMIUM'
          OR valuation_type = 'ANNUALIZED_PREMIUM'
          OR source_measure_code = 'ANNUALIZED_PREMIUM'
      );

CREATE INDEX IF NOT EXISTS idx_policy_agent_rel_policy_agent_contract
    ON policy_agent_relationships (
        tenant_id,
        policy_id,
        agent_id,
        agent_contract_id
    );

